// todo, su archivo NO se pierde NI se queda colgado: se procesa en cuanto
// la app esté lista (toast "🚀 Procesando X archivos en espera…").
window._appLista = false;
window._colaPreArranque = window._colaPreArranque || [];
// v84: orden por defecto = 'created_at' descendente (lo más recién subido arriba).
// Antes era null (fecha del albarán → matrícula → nº). Ahora si subes un albarán nuevo,
// aparece arriba inmediatamente aunque su fecha de albarán sea antigua. La columna SUBIDO
// es clickable para invertir orden o cambiar por otra.
let sortCol = 'created_at', sortDir = -1;
// v107CP: ORDEN DE SUBIDA con DOS sellos (tanda + página). Resuelve de forma
// limpia y definitiva el problema de albaranes revueltos al subir un archivo
// de varias páginas (causa: se procesan 5 en paralelo, CONCURRENCY=5, y el que
// la IA termina antes se guarda antes → created_at revuelto).
//
//  · _tandaSubida  = nº de TANDA. Sube 1 cada vez que se procesa un archivo
//                     nuevo (o un grupo de imágenes sueltas en una subida).
//                     La tanda más alta es la más reciente → va ARRIBA.
//  · _pagArchivo   = nº de PÁGINA dentro de ese archivo (1,2,3...). Dentro de
//                     una tanda se ordena ascendente → pág 1 arriba del bloque.
//
// Ambos se guardan en columnas REALES de la BD (tanda_subida, pag_archivo)
// para que el orden aguante refrescos (el fallo de v107CP era que el sello
// vivía solo en memoria y loadData lo borraba al recargar).
//
// Base alta para no chocar con histórico viejo (tanda NULL → va al final,
// ordenado como siempre, sin romperse).
window._tandaSubida = window._tandaSubida || 1;
