// ============================================================
// AUTH
// ============================================================
async function initApp() {
  const { data: { session } } = await sb.auth.getSession();
  if (session) {
    await onLogin(session.user);
  }
  // v107J1 (A): la app ya está lista (login mostrado o sesión cargada) → quitar la
  // pantalla de carga inmediata. Si algo fallara antes de aquí, la red de seguridad
  // de 25s la quita igualmente (ver script del splash en el <body>).
  if (window.__hideBootSplash) window.__hideBootSplash();
  sb.auth.onAuthStateChange(async (event, session) => {
    if (event === 'SIGNED_IN' && session) await onLogin(session.user);
    if (event === 'SIGNED_OUT') showLogin();
  });
}

async function doLogin() {
  const email = document.getElementById('loginEmail').value.trim();
  const pass = document.getElementById('loginPass').value;
  const err = document.getElementById('loginErr');
  err.style.display = 'none';
  if (!email || !pass) { err.textContent = 'Introduce email y contraseña'; err.style.display = 'block'; return; }
  const { error } = await sb.auth.signInWithPassword({ email, password: pass });
  if (error) { err.textContent = error.message; err.style.display = 'block'; }
}

async function doLogout() {
  await sb.auth.signOut();
}

// Cargar el mapa de usuarios (id -> nombre) para poder mostrar quién subió cada albarán
async function loadUserMap() {
  try {
    // v101: añadir puede_ver_itv para saber quién puede acceder a la pestaña ITV
    // v107j: añadir puede_ver_neumaticos + empresa_neumaticos para la pestaña Neumáticos.
    // empresa_neumaticos=NULL → ve las 3 subpestañas (admin/gestor). 'TRANSMARGAZ' → solo la suya.
    // v107M: añadir puede_ver_vacaciones para la pestaña Vacaciones.
    // v107N: añadir empresa_vacaciones para filtrar subpestañas (igual que neumáticos pero admin NO ve Transmargaz).
    // v107AE: añadir puede_ver_taller + empresa_taller para la pestaña Taller (mismo patrón que vacaciones).
    const { data, error } = await sb.from('profiles').select('id, name, role, puede_ver_itv, puede_ver_neumaticos, empresa_neumaticos, puede_ver_vacaciones, empresa_vacaciones, puede_ver_taller, empresa_taller, puede_fichar, fichaje_dni, fichaje_empresa, fichaje_cif');
    if (error) { console.warn('No se pudo cargar userMap:', error.message); return; }
    userMap = {};
    (data || []).forEach(p => { userMap[p.id] = {
      name: p.name || '(sin nombre)',
      role: p.role || '',
      puede_ver_itv: !!p.puede_ver_itv,
      puede_ver_neumaticos: !!p.puede_ver_neumaticos,
      empresa_neumaticos: p.empresa_neumaticos || null,
      puede_ver_vacaciones: !!p.puede_ver_vacaciones,
      empresa_vacaciones: p.empresa_vacaciones || null,
      puede_ver_taller: !!p.puede_ver_taller,
      empresa_taller: p.empresa_taller || null,
      puede_fichar: !!p.puede_fichar,
      fichaje_dni: p.fichaje_dni || null,
      fichaje_empresa: p.fichaje_empresa || null,
      fichaje_cif: p.fichaje_cif || null
    }; });
    // v101: si el usuario actual tiene permiso ITV, mostrar la pestaña
    if (currentUser?.id) {
      // v107FF (28/05/2026): si es FICHADOR PURO (empleado de taller que solo
      // ficha), NO ejecutamos toda la lógica de visibilidad de pestañas de
      // abajo (que podría reactivar Albaranes/Subir/Preliquidaciones/Gasoil
      // para "internos del grupo"). onLogin ya dejó visible SOLO la pestaña
      // Fichaje. Aquí solo nos aseguramos de que siga así y salimos.
      if (window._esFichadorPuro) {
        const _tf = document.getElementById('tabFichaje');
        if (_tf) _tf.style.display = 'flex';
        ['tabAlb','tabSubir','tabPreli','tabGas','tabItv','tabNeum','tabVac','tabTaller','tabProduccion','tabAdmin']
          .forEach(idTab => { const el = document.getElementById(idTab); if (el) el.style.display = 'none'; });
        return;
      }
      // v107BC (23/05/2026): RED DE SEGURIDAD #1 — cargas iniciales con timeout y log.
      // ANTES: las 4 cargas (ITV, Neumáticos, Vacaciones, Taller) se lanzaban en paralelo
      //   con .catch silencioso. Si una se quedaba colgada (Storage Supabase, red mala...),
      //   no había timeout: la promesa quedaba viva para siempre y consumía recursos del
      //   navegador, contribuyendo al "tengo que hacer Ctrl+F5 para que la app arranque".
      // AHORA: cada carga se envuelve en una promesa con timeout de 15s. Si tarda más, se
      //   considera fallida (sin romper nada — la pestaña queda vacía hasta que el usuario
      //   entre a ella, donde se reintentará la carga normalmente). Además, log claro en
      //   consola del tiempo que tardó cada una, para que el día que vuelva el problema
      //   sepamos en F12 cuál es la lenta.
      const _CARGA_TIMEOUT_MS = 15000;
      const _cargaConTimeout = (nombre, fnPromesa) => {
        const tStart = Date.now();
        console.log(`[v107BC arranque] cargando ${nombre}...`);
        const timer = new Promise((_, reject) =>
          setTimeout(() => reject(new Error(`Timeout ${_CARGA_TIMEOUT_MS}ms`)), _CARGA_TIMEOUT_MS)
        );
        return Promise.race([fnPromesa(), timer])
          .then(r => {
            const dur = ((Date.now() - tStart) / 1000).toFixed(1);
            console.log(`[v107BC arranque] ${nombre} OK en ${dur}s`);
            return r;
          })
          .catch(e => {
            const dur = ((Date.now() - tStart) / 1000).toFixed(1);
            console.warn(`[v107BC arranque] ${nombre} FALLÓ tras ${dur}s:`, e.message || e);
          });
      };

      const tienePermisoITV = !!userMap[currentUser.id]?.puede_ver_itv;
      const tabItv = document.getElementById('tabItv');
      if (tabItv) tabItv.style.display = tienePermisoITV ? '' : 'none';
      window._tieneITV = tienePermisoITV;
      // v101b: si tiene permiso, cargar ITVs INMEDIATAMENTE al iniciar la app
      // para que el banner global de avisos aparezca en cualquier pestaña, no solo al
      // entrar en la pestaña ITV. Así, desde el momento en que se loguea, ve los avisos.
      if (tienePermisoITV) {
        _cargaConTimeout('ITV', () => loadItvData());
      }
      // v107j: lo mismo para Neumáticos
      const tienePermisoNeum = !!userMap[currentUser.id]?.puede_ver_neumaticos;
      const tabNeum = document.getElementById('tabNeum');
      if (tabNeum) tabNeum.style.display = tienePermisoNeum ? '' : 'none';
      window._tieneNeum = tienePermisoNeum;
      window._empresaNeum = userMap[currentUser.id]?.empresa_neumaticos || null;
      if (tienePermisoNeum) {
        _cargaConTimeout('Neumáticos', () => loadNeumData());
      }
      // v107M: lo mismo para Vacaciones
      const tienePermisoVac = !!userMap[currentUser.id]?.puede_ver_vacaciones;
      const tabVac = document.getElementById('tabVac');
      if (tabVac) tabVac.style.display = tienePermisoVac ? '' : 'none';
      window._tieneVac = tienePermisoVac;
      // v107N: empresa_vacaciones limita qué subpestañas ve (lista separada por comas)
      window._empresaVac = userMap[currentUser.id]?.empresa_vacaciones || null;
      if (tienePermisoVac) {
        _cargaConTimeout('Vacaciones', () => loadVacData());
      }
      // v107AE: lo mismo para Taller (mantenimientos de flota)
      const tienePermisoTaller = !!userMap[currentUser.id]?.puede_ver_taller;
      const tabTaller = document.getElementById('tabTaller');
      if (tabTaller) tabTaller.style.display = tienePermisoTaller ? '' : 'none';
      window._tieneTaller = tienePermisoTaller;
      // empresa_taller limita qué subpestañas ve (igual lógica que vacaciones: admin NO ve Transmargaz)
      window._empresaTaller = userMap[currentUser.id]?.empresa_taller || null;
      if (tienePermisoTaller) {
        _cargaConTimeout('Taller', () => loadTallerData());
      }
      // v107AF: ITV en SOLO LECTURA para usuarios con Taller que NO son admin.
      // El usuario TALLER ve la pestaña ITV y el banner de avisos (para saber
      // qué vehículos preparar) pero NO puede subir documentos, crear citas,
      // editar ni eliminar. La gestión de ITV la sigue llevando admin/oficina.
      const rolActual = (userMap[currentUser.id]?.role || '').toLowerCase();
      // v107H1 (Juan Carlos 02/06/2026): el solo-lectura de ITV es para el usuario TALLER
      // (mecánicos), NO para la oficina. Marta y Mª del Mar tienen acceso a Taller pero
      // SÍ deben poder subir ITV y crear citas. Las excluimos por id de usuario.
      const _ID_MARTA_ITV = '6f657be7-1edd-4d5d-9895-cc6777ebbca1';
      const _ID_MARIADELMAR_ITV = '5059731a-3e41-4578-b61e-96f20b6d8cc8';
      const _esOficinaITV = (currentUser?.id === _ID_MARTA_ITV || currentUser?.id === _ID_MARIADELMAR_ITV);
      window._itvSoloLectura = tienePermisoTaller && rolActual !== 'admin' && !_esOficinaITV;
      if (window._itvSoloLectura) {
        // Aplicar el blindaje en cuanto el DOM esté listo
        setTimeout(_aplicarItvSoloLectura, 100);
      }
      // v107AG: el usuario TALLER (Taller + no admin) no necesita ver
      // Preliquidaciones ni Gasoil (son de gestión de transporte, no de taller).
      // Se ocultan SOLO para él; admin/gestores de transporte las siguen viendo.
      // v107BS: EXCEPCIÓN — María del Mar y logística/Transmargaz SÍ deben ver
      // Gasoil y Preliquidaciones aunque tengan permiso Taller (logística
      // gestiona el Taller de Transmargaz Y necesita Gasoil para subir
      // facturas y ver consumos). Por eso esta regla NO se les aplica a ellas.
      // v107EQ8 (27/05/2026): Marta también queda en la excepción (igual que
      // María del Mar). Empieza el lunes en el mismo rol.
      const _emailAG = (currentUser?.email || '').toLowerCase().trim();
      const _esMariaOLogisticaAG = (_emailAG === 'mariadelmar@typ2014.local'
                                  || _emailAG === 'marta@typ2014.local'
                                  || _emailAG === 'logistica@ttesyportes.2014');
      if (tienePermisoTaller && rolActual !== 'admin' && !_esMariaOLogisticaAG) {
        const tabPreli = document.getElementById('tabPreli');
        const tabGas = document.getElementById('tabGas');
        if (tabPreli) tabPreli.style.display = 'none';
        if (tabGas) tabGas.style.display = 'none';
      }
      // v107BI: ocultar ALBARANES y SUBIR SOLO al usuario Taller PURO
      // (taller@typ2014.local). El error de v107BB era usar la condición
      // amplia "tienePermisoTaller && no admin", que sin querer también
      // ocultaba estas pestañas a transmargaz-logística y a otros
      // subcontratados que SÍ tienen permiso de Taller pero NECESITAN ver y
      // subir albaranes de transporte. Ahora la condición es EXACTA: solo
      // el email taller@typ2014.local pierde estas dos pestañas. TODOS los
      // demás (admin, gestores, subcontratados, transmargaz-logística...)
      // las ven y usan con normalidad.
      const _emailUsuario = (currentUser?.email || '').toLowerCase().trim();
      if (_emailUsuario === 'taller@typ2014.local') {
        // El usuario TALLER puro solo gestiona Taller/Recambios; los
        // albaranes de transporte no le competen.
        const tabAlb = document.getElementById('tabAlb');
        const tabSubir = document.getElementById('tabSubir');
        if (tabAlb) tabAlb.style.display = 'none';
        if (tabSubir) tabSubir.style.display = 'none';
        // CRÍTICO: si la pestaña activa al entrar es Albaranes o Subir (ahora
        // ocultas para él), lo llevamos a su pestaña Taller para que NO se
        // quede con la pantalla en blanco.
        setTimeout(function () {
          try {
            const albActivo = tabAlb && tabAlb.classList.contains('active');
            const subActivo = tabSubir && tabSubir.classList.contains('active');
            if (albActivo || subActivo) {
              switchTab('taller');
            }
          } catch (e) { console.warn('[v107BI] no pude redirigir a Taller:', e); }
        }, 150);
      }

      // ============================================================
      // v107BS: CAPA FINAL DE VISIBILIDAD DE PESTAÑAS (la última que se
      // ejecuta, encima de toda la lógica de permisos por empresa anterior).
      // REGLA: solo 3 personas ven las pestañas de gestión (Preliquidaciones,
      // Gasoil, ITV, Neumáticos, Vacaciones, Taller, Producción, Usuarios):
      //   - Admin (cualquiera con role admin, ej. Juan Carlos)
      //   - María del Mar      → mariadelmar@typ2014.local
      //   - Logística/Transmargaz → logistica@ttesyportes.2014
      // TODOS LOS DEMÁS (gestores que no sean María del Mar, conductores,
      // subcontratados, usuario Taller...) solo ven ALBARANES y SUBIR.
      // IMPORTANTE: esto SOLO muestra/oculta la pestaña entera del menú. NO
      // toca la privacidad interna por empresa (Transmargaz caja cerrada,
      // empresa_neumaticos, empresa_taller, admin sin Transmargaz en Taller,
      // etc.) — todo eso queda EXACTAMENTE igual que antes.
      const _emailFinal = (currentUser?.email || '').toLowerCase().trim();
      const _rolFinal = (userMap[currentUser.id]?.role || '').toLowerCase();
      const _esAdminFinal = (_rolFinal === 'admin') || (currentRole === 'admin');
      const _esMariaDelMar = (_emailFinal === 'mariadelmar@typ2014.local');
      // v107EQ8 (27/05/2026): Marta entra al equipo igual que María del Mar.
      // Ve las mismas pestañas (Preliquidaciones, Gasoil, ITV, Neumáticos,
      // Vacaciones, Taller) limitadas a TYP2014+HISPALIS por sus permisos
      // empresa_* en BD. NO ve Producción ni Usuarios (no es admin).
      const _esMarta       = (_emailFinal === 'marta@typ2014.local');
      const _esLogistica   = (_emailFinal === 'logistica@ttesyportes.2014');
      const _veTodo = _esAdminFinal || _esMariaDelMar || _esMarta || _esLogistica;

      // v107GA: la tarjeta "Autofactura HOLCIM" SOLO la ve/usa el admin (Juan Carlos),
      // aunque la pestaña Facturación la vean también MdM/Marta/Logística. El de CEMEX
      // se queda visible para ellos como hasta ahora.
      try { const _hc = document.getElementById('factHolcimCard'); if (_hc) _hc.style.display = _esAdminFinal ? '' : 'none'; } catch (e) {}
      try { const _pc = document.getElementById('factPromotoraCard'); if (_pc) _pc.style.display = _esAdminFinal ? '' : 'none'; } catch (e) {}

      if (!_veTodo) {
        // No es ninguno de los 3 → ocultar las pestañas extra, dejar solo
        // Albaranes y Subir.
        // v107BY: EXCEPCIÓN — el usuario TALLER (taller@typ2014.local) y
        // cualquier usuario con permiso ITV o Taller SÍ debe seguir viendo
        // ESAS pestañas concretas (es su trabajo). Antes la regla v107BS le
        // ocultaba ITV y Taller sin querer. Ahora: a quien NO ve todo se le
        // ocultan Preli/Gas/Neum/Vac/Producción/Usuarios SIEMPRE, pero ITV y
        // Taller solo se ocultan si NO tiene su permiso correspondiente. Así
        // el usuario Taller recupera ITV y Taller, y un conductor normal
        // (sin esos permisos) sigue viendo solo Albaranes y Subir.
        // v107CP: restaurado tras pisarse sin querer en el trabajo del orden.
        const _permITV    = !!userMap[currentUser.id]?.puede_ver_itv;
        const _permTaller = !!userMap[currentUser.id]?.puede_ver_taller;
        const _ocultarFinal = ['tabPreli', 'tabGas', 'tabNeum', 'tabVac',
          'tabProduccion', 'tabAdmin'];
        if (!_permITV)    _ocultarFinal.push('tabItv');
        if (!_permTaller) _ocultarFinal.push('tabTaller');
        _ocultarFinal.forEach(function (id) {
          const el = document.getElementById(id);
          if (el) el.style.display = 'none';
        });
        // Si tiene permiso ITV/Taller, asegurar que esas pestañas SÍ se ven
        // (por si alguna regla anterior las dejó ocultas).
        if (_permITV) { const e = document.getElementById('tabItv'); if (e) e.style.display = ''; }
        if (_permTaller) { const e = document.getElementById('tabTaller'); if (e) e.style.display = ''; }
        // Si la pestaña activa al entrar quedó oculta, llevarlo a una visible
        // (Taller si tiene permiso, si no Albaranes) para no dejar pantalla
        // en blanco.
        setTimeout(function () {
          try {
            const ocultas = _ocultarFinal;
            const algunaOcultaActiva = ocultas.some(function (id) {
              const e = document.getElementById(id);
              return e && e.classList.contains('active');
            });
            if (algunaOcultaActiva) {
              if (_permTaller) switchTab('taller');
              else if (_permITV) switchTab('itv');
              else switchTab('alb');
            }
          } catch (e) { console.warn('[v107BY] redirigir:', e); }
        }, 200);
      } else {
        // SÍ es admin / María del Mar / logística → garantizar que ven
        // Preliquidaciones y Gasoil SÍ o SÍ (estas dos arrancan ocultas en
        // el HTML o las puede ocultar otra regla anterior; aquí las
        // re-mostramos para los 3 que deben verlas). El resto de pestañas
        // (ITV, Neumáticos, Vacaciones, Taller, Producción, Usuarios) NO se
        // fuerzan aquí: siguen dependiendo de sus permisos por empresa de
        // siempre (puede_ver_itv, empresa_taller, etc.), para NO romper la
        // privacidad (ej. logística no debe ver Producción ni Usuarios).
        // v107FH: Preliquidaciones queda JUBILADA (sustituida por Facturación),
        // así que ya NO la re-mostramos aquí aunque el usuario sea de los 3.
        // Solo re-mostramos Gasoil.
        const tabGasShow = document.getElementById('tabGas');
        if (tabGasShow) tabGasShow.style.display = '';
      }
      // ============================================================

      // v107FA: CAPA INDEPENDIENTE PARA LA PESTAÑA FICHAJE.
      // Se ejecuta SIEMPRE, al margen de toda la lógica anterior, porque el
      // fichaje no sigue el patrón "empresa del grupo": lo ve QUIEN ficha
      // (puede_fichar=TRUE en BD) y el admin (vista completa de todas).
      // - puede_fichar o admin  -> pestaña visible
      // - cualquier otro        -> oculta
      try {
        const _miPerfil = userMap[currentUser.id] || {};
        const _puedeFichar = !!_miPerfil.puede_fichar;
        const _esAdminFichaje = (currentRole === 'admin');
        const _tabFichaje = document.getElementById('tabFichaje');
        if (_tabFichaje) {
          _tabFichaje.style.display = (_puedeFichar || _esAdminFichaje) ? 'flex' : 'none';
        }
      } catch (e) { console.warn('[v107FA] visibilidad Fichaje:', e); }

      // v107FH (28/05/2026): visibilidad de la pestaña Facturación. La ven los
      // mismos que pueden facturar (admin + María del Mar + Marta + Logística),
      // reutilizando el helper _puedeVerFacturacion() ya existente (v107FD).
      try {
        const _tabFact = document.getElementById('tabFacturacion');
        if (_tabFact) _tabFact.style.display = _puedeVerFacturacion() ? 'flex' : 'none';
      } catch (e) { console.warn('[v107FH] visibilidad Facturación:', e); }
    }
  } catch (e) { console.warn('Error en loadUserMap:', e); }
}

// v87: cargar matrículas aprendidas dinámicamente desde Supabase. Se mezclan con
// TRANSPORTISTAS al consultar getTransportista(). Se ejecuta al inicio de la app
// y cada vez que se aprende una nueva matrícula.
async function loadMatriculasAprendidas() {
  try {
    const { data, error } = await sb.from('matriculas_aprendidas').select('matricula, transportista');
    if (error) {
      if (error.message && /does not exist|relation/i.test(error.message)) {
        console.warn('[v87] Tabla matriculas_aprendidas no existe. Crea la tabla en Supabase.');
        return;
      }
      console.warn('[v87] Error cargando matriculas_aprendidas:', error.message);
      return;
    }
    MATRICULAS_APRENDIDAS = {};
    (data || []).forEach(r => {
      const mat = String(r.matricula || '').trim().toUpperCase().replace(/\s+/g,'');
      if (mat && r.transportista) MATRICULAS_APRENDIDAS[mat] = r.transportista;
    });
    console.log(`[v87] ${Object.keys(MATRICULAS_APRENDIDAS).length} matrículas aprendidas cargadas`);
  } catch (e) { console.warn('[v87] Error en loadMatriculasAprendidas:', e); }
}

// Carga la tabla tarjetas_repsol (tarjeta → matrícula → empresa). Igual patrón
// que loadMatriculasAprendidas. Se usa en gasoil para tickets Repsol/SOLRED
// que solo traen el nº de tarjeta y no la matrícula directa.
async function loadTarjetasRepsol() {
  try {
    const { data, error } = await sb.from('tarjetas_repsol').select('tarjeta, matricula, empresa');
    if (error) {
      if (error.message && /does not exist|relation/i.test(error.message)) {
        console.warn('[tarjetas] Tabla tarjetas_repsol no existe todavía. Crea la tabla en Supabase cuando tengas los datos.');
        return;
      }
      console.warn('[tarjetas] Error cargando tarjetas_repsol:', error.message);
      return;
    }
    TARJETAS_REPSOL = {};
    (data || []).forEach(r => {
      // Normalizar la tarjeta: quitar asteriscos, espacios y guiones, mayúsculas.
      // Guardamos por los últimos dígitos (lo que aparece en el ticket: ***0321).
      const tj = String(r.tarjeta || '').replace(/[\s*\-]/g, '').toUpperCase();
      if (tj && r.matricula) {
        TARJETAS_REPSOL[tj] = {
          matricula: String(r.matricula).trim().toUpperCase().replace(/\s+/g, ''),
          empresa: String(r.empresa || '').trim().toUpperCase()
        };
      }
    });
    console.log(`[tarjetas] ${Object.keys(TARJETAS_REPSOL).length} tarjetas Repsol cargadas`);
  } catch (e) { console.warn('[tarjetas] Error en loadTarjetasRepsol:', e); }
}

// Dada una cadena de tarjeta del ticket (ej "***0321" o "************0321"),
// busca su matrícula/empresa. Compara por terminación porque el ticket suele
// ocultar los primeros dígitos con asteriscos.
function buscarTarjetaRepsol(tarjetaTicket) {
  if (!tarjetaTicket) return null;
  const limpia = String(tarjetaTicket).replace(/[\s*\-]/g, '').toUpperCase();
  if (!limpia) return null;
  // 1) Coincidencia exacta
  if (TARJETAS_REPSOL[limpia]) return TARJETAS_REPSOL[limpia];
  // 2) Coincidencia por terminación (el ticket trae solo los últimos dígitos)
  for (const k of Object.keys(TARJETAS_REPSOL)) {
    if (k.endsWith(limpia) || limpia.endsWith(k)) return TARJETAS_REPSOL[k];
  }
  return null;
}

// v87: aprender una matrícula nueva. Inserta o actualiza en Supabase y refresca el diccionario
// en memoria. Se llama desde _processOne cuando un subcontratista identificable sube un
// albarán con matrícula no oficial.
async function aprenderMatricula(matricula, transportista, nombreUsuario) {
  if (!matricula || !transportista) return;
  const clean = String(matricula).trim().toUpperCase().replace(/\s+/g,'');
  if (!clean) return;
  // v106: canonizar el transportista ANTES de guardar para evitar que se aprendan variantes
  // raras ("ARIDFLOT, S.L." en lugar de "ARIDFLOT") que luego contaminan futuros albaranes.
  const transFix = fixTransportista(transportista);
  // Si ya está en TRANSPORTISTAS oficial, no aprender (no sobrescribir el oficial)
  if (TRANSPORTISTAS[clean]) return;
  // Si ya estaba aprendida con el mismo transportista (ya canonizado), no hacer nada
  if (MATRICULAS_APRENDIDAS[clean] === transFix) return;
  try {
    const { error } = await sb.from('matriculas_aprendidas').upsert({
      matricula: clean,
      transportista: transFix,
      aprendido_de: nombreUsuario || '',
      user_id: currentUser?.id || null,
      updated_at: new Date().toISOString()
    }, { onConflict: 'matricula' });
    if (error) {
      console.warn('[v87] No se pudo guardar matrícula aprendida:', error.message);
      return;
    }
    MATRICULAS_APRENDIDAS[clean] = transFix;
    console.log(`📌 [v87] Matrícula aprendida: ${clean} → ${transFix} (de ${nombreUsuario})`);
  } catch (e) { console.warn('[v87] Error en aprenderMatricula:', e); }
}

// Helper: nombre legible del usuario que subió un registro (a partir de su user_id)
function userName(uid) {
  if (!uid) return '—';
  const u = userMap[uid];
  if (!u) return '(otro)';
  return u.name;
}

async function onLogin(user) {
  currentUser = user;
  // Get role from profiles table
  // v107FF (28/05/2026): traemos también los permisos para detectar
  // "fichador puro" (empleado de taller que SOLO ficha). Antes solo
  // pedíamos role,name.
  const { data: profile } = await sb.from('profiles')
    .select('role, name, puede_fichar, puede_ver_itv, puede_ver_taller, puede_ver_neumaticos, puede_ver_vacaciones')
    .eq('id', user.id).single();
  currentRole = profile?.role || 'conductor';
  document.getElementById('loginPage').style.display = 'none';
  document.getElementById('appPage').style.display = 'block';
  document.getElementById('hdrUser').textContent = profile?.name || user.email;
  const roleLabels = { admin: '👑 Admin', gestor: '📋 Gestor', conductor: '🚛 Conductor' };
  const roleClasses = { admin: 'role-admin', gestor: 'role-gestor', conductor: 'role-conductor' };
  const roleEl = document.getElementById('hdrRole');
  roleEl.textContent = roleLabels[currentRole] || currentRole;
  roleEl.className = 'hdr-role ' + (roleClasses[currentRole] || '');

  // v107FF (28/05/2026): FICHADOR PURO (empleado de taller que SOLO ficha).
  // Problema que arregla: estos empleados tienen role='conductor' + puede_fichar=true,
  // así que la app les mostraba la pantalla de Subir Documentos (conductorView) y
  // NUNCA llegaban a ver la pestaña Fichaje (que vive dentro de adminView).
  // Un "fichador puro" es: puede_fichar=true, NO admin, NO gestor, y SIN ningún
  // otro permiso (ITV/taller/neumáticos/vacaciones). Eso describe exactamente a
  // Carlos, César, Oscar y oscarv; deja fuera a María del Mar y Marta (son gestor).
  // A un fichador puro le mostramos la vista con pestañas pero OCULTAMOS TODO
  // menos 🕐 Fichaje, y abrimos esa pestaña directamente.
  const _esFichadorPuro = (currentRole === 'conductor')
    && !!profile?.puede_fichar
    && !profile?.puede_ver_itv
    && !profile?.puede_ver_taller
    && !profile?.puede_ver_neumaticos
    && !profile?.puede_ver_vacaciones;
  window._esFichadorPuro = _esFichadorPuro; // para que loadUserMap no le reactive otras pestañas

  if (currentRole === 'conductor' && !_esFichadorPuro) {
    document.getElementById('conductorView').style.display = 'block';
  } else if (_esFichadorPuro) {
    // Vista con pestañas, pero SOLO Fichaje.
    document.getElementById('adminView').style.display = 'block';
    // Ocultar TODAS las pestañas excepto Fichaje.
    ['tabAlb','tabSubir','tabPreli','tabGas','tabItv','tabNeum','tabVac','tabTaller','tabProduccion','tabAdmin']
      .forEach(idTab => { const el = document.getElementById(idTab); if (el) el.style.display = 'none'; });
    const _tf = document.getElementById('tabFichaje');
    if (_tf) _tf.style.display = 'flex';
    // Cargar el mapa de usuarios (necesario para el fichaje) y abrir Fichaje.
    await loadUserMap();
    try { switchTab('fichaje'); } catch (e) { console.warn('[v107FF] no pude abrir Fichaje:', e); }
    // Quitar el indicador de carga si estuviera.
    const _ind = document.getElementById('v107EQ5Cargando');
    if (_ind) _ind.remove();
    return; // NO seguimos con la carga pesada de admin/gestor (albaranes, etc.)
  } else {
    document.getElementById('adminView').style.display = 'block';
    if (currentRole === 'admin') {
      document.getElementById('tabAdmin').style.display = 'flex';
      // v107g: pestaña Producción solo visible para admin (datos globales de toda la flota).
      // Para gestores como María del Mar queda oculta — no necesitan ver datos consolidados.
      const tProd = document.getElementById('tabProduccion');
      if (tProd) tProd.style.display = 'flex';
    } else {
      // v103b: el botón "Re-corregir TODO" toca el campo transportista (entre otros).
      // Para mantener la política "solo admin cambia transportistas", lo ocultamos a gestores.
      const btnReanalizar = document.getElementById('btnReanalizarTodo');
      if (btnReanalizar) btnReanalizar.style.display = 'none';
    }
    renderSetup();
    await loadUserMap();
    await loadMatriculasAprendidas();
    await loadTarjetasRepsol();
    await loadData();
    // v107EQ5 (27/05/2026): marcar la app como LISTA para aceptar subidas.
    // Causa raíz del bug histórico "falla siempre la 1ª vez que entra":
    // un usuario abre la app en móvil con 4G/5G, ve el botón "Subir" antes
    // de que loadUserMap/loadMatriculasAprendidas/loadTarjetasRepsol/loadData
    // hayan terminado (en su móvil tardan 3-6s; en PC con fibra ~0.8s). Si
    // pulsa Subir antes, addFiles llama a IA con piezas que faltan
    // (_userMap vacío, MATRICULAS_APRENDIDAS vacío…) y se queda colgado.
    // Esta bandera la usaremos en addFiles para encolar el archivo y
    // procesarlo cuando la app esté lista, en vez de fallar en silencio.
    window._appLista = true;
    // Si había archivos en la cola pre-arranque, los procesamos ahora.
    if (window._colaPreArranque && window._colaPreArranque.length > 0) {
      console.log('[v107EQ5] App lista. Procesando ' + window._colaPreArranque.length + ' archivos en cola pre-arranque…');
      const cola = window._colaPreArranque.slice();
      window._colaPreArranque = [];
      try { toast('🚀 Procesando ' + cola.length + ' archivo' + (cola.length===1?'':'s') + ' en espera…', 'ok'); } catch(e) {}
      for (const item of cola) {
        try { await addFiles(item.files, item.type); } catch (e) { console.error('[v107EQ5] error procesando cola pre-arranque:', e); }
      }
    }
    // Quitar el indicador "⏳ Cargando" si está visible.
    const indicador = document.getElementById('v107EQ5Cargando');
    if (indicador) indicador.remove();
  }
}

// Auto-refresh de la cola cada 15s — siempre que haya algo (procesando, en curso o huérfanos).
// Esto actualiza el contador de minutos transcurridos y muestra el aviso de bloqueo si pasa de 2 min,
// y detecta archivos atascados en 'processing' tras un cuelgue.
// v107BC (23/05/2026): RED DE SEGURIDAD #2 — auto-rescate de filas zombi.
// Si hay archivos en 'processing' huérfanos (sin _processingAlb activo) durante más de 3 minutos,
// los marcamos automáticamente como 'error' para que el usuario los pueda reintentar sin refrescar
// la página. ANTES Juan Carlos tenía que pulsar Ctrl+F5 y volver a subir; AHORA la app sola se
// desbloquea y deja la fila lista para reintento con un click.
let _huerfanosDesde = { alb: 0, gas: 0 }; // timestamp desde que se detectaron huérfanos
setInterval(() => {
  const tieneHuerfanosAlb = pendingAlb.some(x => x.status === 'processing');
  const tieneHuerfanosGas = pendingGas.some(x => x.status === 'processing');
  if (_processingAlb || _processingGas || tieneHuerfanosAlb || tieneHuerfanosGas) {
    checkProcessingStuck('alb');
    checkProcessingStuck('gas');
    // v107BC auto-rescate: si quedan huérfanos sin procesamiento activo, contar tiempo
    const now = Date.now();
    const ZOMBI_TIMEOUT_MS = 3 * 60 * 1000; // 3 minutos
    if (tieneHuerfanosAlb && !_processingAlb) {
      if (_huerfanosDesde.alb === 0) _huerfanosDesde.alb = now;
      else if (now - _huerfanosDesde.alb > ZOMBI_TIMEOUT_MS) {
        const zombis = pendingAlb.filter(x => x.status === 'processing');
        zombis.forEach(it => { it.status = 'error'; });
        console.warn(`[v107BC watchdog] ${zombis.length} fila(s) zombi de albaranes marcadas como error tras 3min sin procesar.`);
        try { toast(`🛟 ${zombis.length} archivo(s) atascado(s) marcado(s) como error. Pulsa "Reintentar errores".`, 'warn'); } catch(e) {}
        _huerfanosDesde.alb = 0;
      }
    } else {
      _huerfanosDesde.alb = 0;
    }
    if (tieneHuerfanosGas && !_processingGas) {
      if (_huerfanosDesde.gas === 0) _huerfanosDesde.gas = now;
      else if (now - _huerfanosDesde.gas > ZOMBI_TIMEOUT_MS) {
        const zombis = pendingGas.filter(x => x.status === 'processing');
        zombis.forEach(it => { it.status = 'error'; });
        console.warn(`[v107BC watchdog] ${zombis.length} fila(s) zombi de gasoil marcadas como error tras 3min sin procesar.`);
        try { toast(`🛟 ${zombis.length} ticket(s) atascado(s) marcado(s) como error.`, 'warn'); } catch(e) {}
        _huerfanosDesde.gas = 0;
      }
    } else {
      _huerfanosDesde.gas = 0;
    }
    renderQueues();
  }
}, 15000); // cada 15s para que el aviso de huérfanos se muestre rápido

// ============================================================
// v107EP (26/05/2026) — AUTO-RECUPERACIÓN AL VOLVER AL PRIMER PLANO
// ============================================================
// Problema observado por Juan Carlos: a veces entra a la app después de un
// rato (WhatsApp, móvil bloqueado, otra pestaña), pulsa "Subir albarán" o
// "Eliminar" y no pasa nada — la consola F12 está VACÍA. Hay que refrescar
// para que vuelva a funcionar. Esto es típico de móviles: el navegador
// suspende la pestaña en segundo plano para ahorrar batería, las conexiones
// con Supabase quedan en estado "dormido" y los siguientes clicks no salen.
//
// Solución: cuando la app vuelve a estar visible TRAS más de 60 segundos
// oculta, recargamos datos silenciosamente y avisamos con un toast pequeño.
// No tocamos el flujo de subida en curso. No molestamos si solo fue un vistazo
// rápido (< 60s).
//
// v107ER (27/05/2026) — CUARENTENA DE ARRANQUE.
// Observado por Juan Carlos con Tony (Antonio Martín): la primera vez que un
// conductor abre la app en un móvil/PC, el navegador puede mantener la pestaña
// "hidden" varios segundos mientras carga JS, fuentes y CSS. Después de ese
// primer "hidden→visible" muchos navegadores reportan que la pestaña estuvo
// oculta >60s (porque el tiempo se mide desde que Chrome creó el "tab object",
// no desde que terminó de cargar). Resultado: v107EP se disparaba durante el
// arranque, lanzaba un loadData() PARALELO al inicial, y los clicks posteriores
// para "Subir albarán" se quedaban colgados ("Leyendo con IA..." eterno) porque
// las dos cargas se pisaban entre sí. Cuando refrescaban, la pestaña ya estaba
// "caliente" y v107EP no entraba. De ahí el síntoma "falla siempre la 1ª vez".
// Fix: anotamos el instante de arranque y no aceptamos disparos en los primeros
// 30 segundos. v107EP sigue funcionando para su caso útil (volver de WhatsApp
// tras llevar un rato trabajando), pero no se entromete en el arranque.
const _v107EP_arranquePagina = Date.now();
const _V107EP_CUARENTENA_MS = 30 * 1000; // 30 segundos sin disparar tras arrancar
let _v107EP_ocultaDesde = 0;
const _V107EP_UMBRAL_MS = 60 * 1000; // 60 segundos
document.addEventListener('visibilitychange', async () => {
  if (document.hidden) {
    // La pestaña se acaba de ocultar. Anotamos cuándo.
    _v107EP_ocultaDesde = Date.now();
    return;
  }
  // La pestaña ha vuelto a ser visible.
  if (_v107EP_ocultaDesde === 0) return; // primera vez, todavía no había salido
  const tiempoOculta = Date.now() - _v107EP_ocultaDesde;
  _v107EP_ocultaDesde = 0;
  if (tiempoOculta < _V107EP_UMBRAL_MS) return; // estaba oculta poco tiempo, no hace falta
  // v107ER: cuarentena de arranque. Durante los primeros 30s tras cargar la
  // página, IGNORAR cualquier visibilitychange — son falsos positivos por la
  // carga inicial del navegador, no un usuario que vuelve de otra app.
  const tiempoDesdeArranque = Date.now() - _v107EP_arranquePagina;
  if (tiempoDesdeArranque < _V107EP_CUARENTENA_MS) {
    console.log('[v107ER] visibilitychange detectado durante arranque (' +
      Math.round(tiempoDesdeArranque/1000) + 's tras cargar) — ignorado, evita pisarse con loadData inicial.');
    return;
  }
  // Si está procesando algo activamente, NO interrumpir.
  if (_processingAlb || _processingGas) {
    console.log('[v107EP] vuelta tras ' + Math.round(tiempoOculta/1000) + 's, pero hay procesamiento activo — sin tocar nada.');
    return;
  }
  // Solo si hay sesión activa (no estamos en pantalla de login)
  if (!currentUser) return;
  console.log('[v107EP] vuelta al primer plano tras ' + Math.round(tiempoOculta/1000) + 's oculta. Recargando datos…');
  try {
    // Refrescar la sesión Supabase si está a punto de caducar
    try {
      const { data: { session } } = await sb.auth.getSession();
      if (session && session.expires_at) {
        const ahoraSeg = Math.floor(Date.now() / 1000);
        const segHastaCaducar = session.expires_at - ahoraSeg;
        if (segHastaCaducar < 300) { // menos de 5 minutos
          console.log('[v107EP] sesión cerca de caducar (' + segHastaCaducar + 's). Renovando…');
          await sb.auth.refreshSession();
        }
      }
    } catch (eSes) {
      console.warn('[v107EP] no pude comprobar/renovar sesión:', eSes);
    }
    // Recargar los datos principales (es una sola consulta, rápido)
    await loadData();
    try { toast('🔄 Reconectado', 'ok'); } catch(e) {}
  } catch (e) {
    console.error('[v107EP] error al recargar tras volver al primer plano:', e);
    try { toast('⚠️ Recarga los datos manualmente (F5)', 'warn'); } catch(eT) {}
  }
});

function showLogin() {
  currentUser = null; currentRole = null;
  document.getElementById('loginPage').style.display = 'flex';
  document.getElementById('appPage').style.display = 'none';
  document.getElementById('conductorView').style.display = 'none';
  document.getElementById('adminView').style.display = 'none';
}

// ============================================================
// SUPABASE DB
// ============================================================
async function loadData() {
  // v82: Supabase tiene un límite por defecto de 1000 filas por consulta. Para cargar
  // TODOS los albaranes sin importar la cantidad (10.000+), paginamos por bloques de 1000.
  //
  // v107J0 (04/06/2026): VELOCIDAD DE ARRANQUE. Antes pedíamos las páginas EN SERIE
  // (bloque 1 → esperar → bloque 2 → esperar...), y cada espera se sumaba: con 5.700
  // albaranes eran 6 viajes seguidos al servidor = varios segundos de pantalla en blanco.
  // Ahora: (1) contamos cuántos hay con una consulta ligera (head, sin traer datos),
  // (2) pedimos TODAS las páginas EN PARALELO (Promise.all) y las juntamos al llegar.
  // Misma información exacta; solo cambia que los viajes se hacen a la vez, no en fila.
  const PAGE = 1000;

  // Helper: construye la query con el MISMO filtro de permisos que ya teníamos.
  const _ID_MARTA = '6f657be7-1edd-4d5d-9895-cc6777ebbca1';
  const _ID_MARIADELMAR = '5059731a-3e41-4578-b61e-96f20b6d8cc8';
  const _ID_TRANSMARGAZ = '92687ba2-a91f-401b-b08b-f1231b83dca9';
  // v107H2: la Logística de TRANSMARGAZ (socio) ve TODOS los albaranes igual que Marta y
  // Mª del Mar — se trata como gestor de oficina más, sin filtro por empresa.
  const _gestorInterno = (currentUser?.id === _ID_MARTA
                       || currentUser?.id === _ID_MARIADELMAR
                       || currentUser?.id === _ID_TRANSMARGAZ);
  const _aplicaFiltro = (currentRole === 'gestor' && !_gestorInterno);
  const _mkQuery = (desde, hasta) => {
    let q = sb.from('albaranes').select('*')
      .order('fecha', { ascending: false })
      .order('created_at', { ascending: false })
      .range(desde, hasta);
    if (_aplicaFiltro) q = q.eq('user_id', currentUser.id);
    // v107J51 (FASE 3): si NO estamos en modo "ver todo", solo traer los albaranes
    // SUBIDOS en los últimos 3 meses (created_at). Esto hace el arranque rápido y
    // preparado para crecer (da igual que haya 6.000 o 50.000 en total). El histórico
    // completo se trae a la carta con cargarTodoHistorico() (botón "ver todo").
    if (!window._cargarTodo) {
      const corte = new Date();
      corte.setMonth(corte.getMonth() - 3);
      q = q.gte('created_at', corte.toISOString());
    }
    return q;
  };

  // v107J51: el conteo debe usar el MISMO filtro de 3 meses que la carga, para que el
  // número de páginas cuadre y no se queden filas sin traer.
  const _mkCount = () => {
    let c = sb.from('albaranes').select('id', { count: 'exact', head: true });
    if (_aplicaFiltro) c = c.eq('user_id', currentUser.id);
    if (!window._cargarTodo) {
      const corte = new Date();
      corte.setMonth(corte.getMonth() - 3);
      c = c.gte('created_at', corte.toISOString());
    }
    return c;
  };

  let allRows = [];
  try {
    // (1) Contar cuántas filas hay (consulta ligera: head=true no trae datos, solo el total)
    let countQuery = _mkCount();
    const { count, error: cErr } = await countQuery;

    if (cErr || count == null) {
      // Si el conteo falla por lo que sea, caemos al método de siempre (en serie). No se rompe nada.
      console.warn('[loadData v107J0] conteo falló, uso método en serie:', cErr?.message);
      let from = 0;
      while (true) {
        const { data, error } = await _mkQuery(from, from + PAGE - 1);
        if (error) { toast('Error cargando albaranes: ' + error.message, 'err'); return; }
        if (!data || data.length === 0) break;
        allRows = allRows.concat(data);
        if (data.length < PAGE) break;
        from += PAGE;
        if (from > 50000) break;
      }
    } else {
      // (2) Pedir TODAS las páginas EN PARALELO
      const totalPaginas = Math.max(1, Math.ceil(count / PAGE));
      const promesas = [];
      for (let p = 0; p < totalPaginas; p++) {
        promesas.push(_mkQuery(p * PAGE, p * PAGE + PAGE - 1));
      }
      const resultados = await Promise.all(promesas);
      for (const { data, error } of resultados) {
        if (error) { toast('Error cargando albaranes: ' + error.message, 'err'); return; }
        if (data && data.length) allRows = allRows.concat(data);
      }
    }
  } catch (e) {
    toast('Error cargando albaranes: ' + (e.message || e), 'err');
    return;
  }
  console.log(`[loadData] Cargados ${allRows.length} albaranes desde BD` + (window._cargarTodo ? ' (TODO el histórico)' : ' (últimos 3 meses)'));
  // Asignar db_id e _id a cada registro (necesario para detección de duplicados)
  // v76: además, si la columna manual_edit=true en BD, marcamos _manual en memoria.
  // Así el albarán queda protegido contra reanálisis automáticos en TODA la sesión.
  records = allRows.map(r => ({
    ...r,
    db_id: r.id,
    _id: r.id || (Date.now() + Math.random()),
    _manual: r.manual_edit === true,
    // v107CP: recuperar los sellos de orden desde columnas reales de BD.
    // Albaranes viejos (sin columna) → undefined → se ordenan como antes
    // (no se rompe nada del histórico de ~2940 albaranes).
    _tandaSubida: (typeof r.tanda_subida === 'number') ? r.tanda_subida : undefined,
    _pagArchivo: (typeof r.pag_archivo === 'number') ? r.pag_archivo : undefined
  }));

  // v107CP: BUG FIX del contador de TANDA. Hasta ahora window._tandaSubida
  // empezaba SIEMPRE en 1 al cargar la app, así que cada vez que se refrescaba
  // la página (cambiar de ?v107X a ?v107Y, etc.) el contador se reiniciaba y
  // TODAS las subidas distintas acababan con tanda_subida=1 → se mezclaban
  // entre sí en el listado. Solución: al cargar, mirar la tanda MÁS ALTA que
  // ya hay guardada en la BD y continuar desde la siguiente. Así cada subida
  // tiene un número de tanda ÚNICO de verdad, aunque se refresque mil veces,
  // y el orden entre archivos distintos (lo último subido arriba) funciona.
  try {
    let maxTanda = 0;
    for (const r of allRows) {
      if (typeof r.tanda_subida === 'number' && r.tanda_subida > maxTanda) {
        maxTanda = r.tanda_subida;
      }
    }
    // El próximo archivo que se suba usará maxTanda + 1 (o el contador actual
    // si por lo que sea ya iba más alto en esta misma sesión).
    window._tandaSubida = Math.max(window._tandaSubida || 1, maxTanda + 1);
    console.log('[v107CP] Contador de tanda continúa desde:', window._tandaSubida, '(máx en BD:', maxTanda + ')');
  } catch (eT) {
    console.warn('[v107CP] No se pudo calcular tanda máxima:', eT);
  }

  // v82: idem para gasoil
  let allGas = [];
  let fromG = 0;
  while (true) {
    // v107AO: ordenar por created_at (cuándo se subió) en vez de fecha del
    // ticket, para que el recién subido aparezca SIEMPRE arriba (igual que
    // hicimos en Albaranes). Antes un ticket con fecha antigua se "perdía".
    let queryG = sb.from('gasoil').select('*').order('created_at', { ascending: false }).range(fromG, fromG + PAGE - 1);
    if (currentRole === 'gestor') queryG = queryG.eq('user_id', currentUser.id);
    const { data: gd } = await queryG;
    if (!gd || gd.length === 0) break;
    allGas = allGas.concat(gd);
    if (gd.length < PAGE) break;
    fromG += PAGE;
    if (fromG > 50000) break;
  }
  gasoilRecords = allGas.map(r => ({ ...r, db_id: r.id, _id: r.id || (Date.now() + Math.random()) }));

  // v107Y: ajustar subpestañas visibles de Gasoil según permisos (misma lógica que Vacaciones).
  // window._empresaVac viene de loadUserMap, contiene la lista de empresas permitidas.
  try {
    const empresasGasPermitidas = window._empresaVac
      ? window._empresaVac.split(',').map(s => s.trim())
      : ['TYP2014','HISPALIS','TRANSMARGAZ'];
    ['TYP2014','HISPALIS','TRANSMARGAZ'].forEach(emp => {
      const btn = document.getElementById('gasSub' + emp);
      if (btn) btn.style.display = empresasGasPermitidas.includes(emp) ? '' : 'none';
    });
    // Si la empresa activa no está permitida, cambiar a la primera permitida
    if (!empresasGasPermitidas.includes(gasEmpresaActiva)) {
      gasEmpresaActiva = empresasGasPermitidas[0] || 'TYP2014';
    }
    // Asegurar visual correcto del botón activo
    empresasGasPermitidas.forEach(e => {
      const btn = document.getElementById('gasSub' + e);
      if (!btn) return;
      btn.classList.remove('bp','bs');
      btn.classList.add(e === gasEmpresaActiva ? 'bp' : 'bs');
    });
    // Título inicial
    const tit = document.getElementById('gasEmpresaTitulo');
    if (tit) {
      const labels = {'TYP2014':'TYP2014','HISPALIS':'T. HISPALIS 2016','TRANSMARGAZ':'TRANSMARGAZ 2018'};
      tit.textContent = labels[gasEmpresaActiva] || gasEmpresaActiva;
    }
  } catch (e) { console.warn('[loadData] No se pudieron ajustar subpestañas Gasoil:', e); }

  analyzeRecords();
  applyFilters();
  applyGasFilters();
  // v107CP: mostrar el botón de borrado múltiple si es admin.
  try { _initBorradoMultiple(); } catch (e) { console.warn('[v107CP]', e); }
  // v100b: cada función envuelta en su propio try/catch. Si una falla (error silencioso de
  // antes que dejaba la pantalla con los recuadros vacíos), las demás siguen funcionando
  // y vemos el error claro en consola.
  try { updateStats(); } catch (e) { console.error('[loadData] updateStats() falló:', e); }
  try { renderAlerts(); } catch (e) { console.error('[loadData] renderAlerts() falló:', e); }
  try {
    document.getElementById('tabAlbCount').textContent = records.filter(r => !r._dup).length;
    document.getElementById('tabGasCount').textContent = gasoilRecords.length;
  } catch (e) { console.error('[loadData] contadores pestañas fallaron:', e); }
  // v107: marcar timestamp de última carga. Lo usa switchTab() para refresco inteligente.
  _lastLoadDataTs = Date.now();
  // v107J51 (FASE 3): refrescar el aviso de "mostrando últimos 3 meses" tras cargar.
  try { _actualizarAvisoHistorico(); } catch (e) { console.warn('[J51] aviso histórico:', e); }
}

// v107J51 (FASE 3) — BOTÓN "VER TODO EL HISTÓRICO". Cuando JC necesita un albarán antiguo
// (cosa puntual), pulsa el aviso y esto recarga TODOS los albaranes (sin el filtro de 3
// meses). A partir de ahí ya está todo en memoria, como antes de la Fase 3.
async function cargarTodoHistorico() {
  if (window._cargarTodo) return; // ya está todo cargado
  const aviso = document.getElementById('avisoHistorico');
  if (aviso) aviso.innerHTML = '<span style="color:var(--mu)">⏳ Cargando todo el histórico…</span>';
  window._cargarTodo = true;
  try {
    await loadData();
    toast('✓ Histórico completo cargado', 'ok');
  } catch (e) {
    toast('Error cargando el histórico: ' + (e.message || e), 'err');
    window._cargarTodo = false; // si falla, volver al modo 3 meses
  }
}

// v107J51 (FASE 3) — pinta/actualiza el aviso sobre la tabla de albaranes. Si estamos en
// modo 3 meses, muestra el botón "ver todo". Si ya se cargó todo, lo oculta.
function _actualizarAvisoHistorico() {
  const aviso = document.getElementById('avisoHistorico');
  if (!aviso) return;
  if (window._cargarTodo) {
    aviso.style.display = 'none';
    aviso.innerHTML = '';
  } else {
    aviso.style.display = '';
    aviso.innerHTML = '📅 Mostrando los albaranes de los <b>últimos 3 meses</b> (arranque rápido). '
      + '<a href="#" onclick="cargarTodoHistorico();return false;" style="color:var(--ac);font-weight:700;text-decoration:underline;cursor:pointer">Ver todo el histórico</a> '
      + '<span style="color:var(--mu)">· para fechas más antiguas, cárgalo aquí.</span>';
  }
}

// v107: timestamp de última carga de loadData (para refresco automático en switchTab).
let _lastLoadDataTs = 0;

async function saveRecord(data) {
  // v107CP: ya NO ponemos user_id = currentUser.id de forma ciega. Eso pisaba
  // al dueño original cuando un admin/gestor editaba el albarán de un
  // conductor → el conductor lo perdía de su vista y lo volvía a subir
  // (duplicados). Ahora:
  //   · INSERT (albarán nuevo): user_id = quien lo sube (currentUser).
  //   · UPDATE (albarán existente): NO se toca user_id (se mantiene el
  //     dueño original). Solo se actualiza editado_por con quien edita.
  // Así el conductor sigue viendo SU albarán y ve en la columna nueva
  // "Editado por" quién lo corrigió (admin, oficina, o él mismo).
  const rec = { ...data };
  // v107J39: canonizar el MATERIAL Holcim en el punto único de guardado (después de
  // que TODAS las reglas de origen/destino hayan usado el texto crudo del producto).
  // fixMaterial SOLO cambia los materiales Holcim de la lista (acento, mayúsculas,
  // abreviaturas → forma canónica); cualquier otro material se queda tal cual.
  if (rec.producto) {
    const _matCanon = fixMaterial(rec.producto);
    if (_matCanon && _matCanon !== rec.producto) {
      console.log(`[v107J39 material] "${rec.producto}" → "${_matCanon}"`);
      rec.producto = _matCanon;
    }
  }
  if (!data.db_id) {
    // Es nuevo: el dueño es quien lo sube.
    rec.user_id = currentUser.id;
  } else {
    // Es edición: NO tocar user_id. Solo marcar quién edita.
    delete rec.user_id;
    rec.editado_por = currentUser.id;
  }
  // v76: si el registro está marcado como editado manualmente en memoria (_manual=true),
  // persistirlo en la columna BD manual_edit para que NO se pise al recargar ni al reanalizar.
  if (data._manual === true) rec.manual_edit = true;
  // v107CP: los sellos de orden (_tandaSubida, _pagArchivo) se copian a las
  // columnas REALES (tanda_subida, pag_archivo) ANTES del borrado automático
  // de propiedades "_". Se hace SIEMPRE que el dato traiga sello (no solo en
  // INSERT): cuando un conductor subió el albarán antes, al procesarlo se
  // guarda vía UPDATE y también necesita su sello, si no quedaría NULL y el
  // orden no funcionaría para esos albaranes.
  if (typeof data._tandaSubida === 'number') rec.tanda_subida = data._tandaSubida;
  if (typeof data._pagArchivo === 'number') rec.pag_archivo = data._pagArchivo;
  // Eliminar TODAS las propiedades internas que empiezan por "_" (no son columnas reales de la BD)
  // y db_id (es la id pero la usamos para el WHERE, no para el SET).
  // v91b: bucle automático en vez de lista manual — así cualquier futuro flag interno (_dup,
  // _quality, _manual, _matDesconocida, etc.) se borra solo y no rompe la inserción/update.
  Object.keys(rec).forEach(k => { if (k.startsWith('_')) delete rec[k]; });
  delete rec.db_id;
  // v107EQ2 (26/05/2026): campos auxiliares que la IA puede devolver pero NO son
  // columnas reales de la tabla albaranes. Hay que borrarlos antes del INSERT/UPDATE
  // o Supabase devuelve error PGRST204 "Could not find the X column" (mensaje
  // engañoso: en realidad apunta a otra columna pero el INSERT falla por completo).
  //   · devolucion_palets: bandera que pone la IA cuando lee una Nota de recibo de
  //     devolución (v107EQ). Solo se usa dentro del JS para decidir si mantenemos el
  //     palet como producto. La marca real ya queda en `observaciones` ("DEVOLUCIÓN
  //     PALETS VACÍOS").
  //   · unidad_palet: la IA puede mandar "piezas" para indicar que la cantidad no
  //     son toneladas. Información útil pero no tenemos columna; la marca queda
  //     implícita por el producto ("PALET CEMENTO"/"PALET MORTERO").
  delete rec.devolucion_palets;
  delete rec.unidad_palet;
  // v107EQ3 (26/05/2026): RED DE SEGURIDAD adicional. La columna BD se llama
  // `tractora`, NO `matricula`. Si por error la IA devuelve `matricula` (caso real
  // que pasó al añadir ejemplos del prompt v107EQ con "matricula:..."), lo
  // mapeamos a `tractora` y borramos el campo huérfano. Así un error de
  // nomenclatura en el prompt no rompe el INSERT entero.
  if (rec.matricula !== undefined) {
    if (!rec.tractora) {
      rec.tractora = rec.matricula;
      console.log(`[v107EQ3] mapeé matricula→tractora ("${rec.matricula}") — la columna BD se llama tractora.`);
    }
    delete rec.matricula;
  }
  // v107EQ6 (27/05/2026): RED DE SEGURIDAD FINAL contra error PGRST204
  // "Could not find the X column of albaranes in the schema cache".
  // Caso real reportado por Juan Carlos: albaran Holcim cisterna donde la IA
  // devolvió `materiales: [...]` (array) Y a la vez los campos planos producto/tm.
  // El array `materiales` NO es columna de la BD (cuando hay multimaterial,
  // el código de arriba lo desempaqueta en filas múltiples ANTES de llegar
  // aquí; pero si por lo que sea llega aquí, el INSERT explota). Solución:
  // borrar TODOS los campos auxiliares conocidos que NO son columnas reales.
  // Cualquier OTRO campo desconocido también lo retiramos como red de
  // seguridad extra. Las columnas reales de `albaranes` están en la lista
  // blanca _COLUMNAS_ALBARANES (28 columnas exactas, validadas en Supabase
  // el 27/05/2026 con `information_schema.columns`).
  const _COLUMNAS_ALBARANES = new Set([
    'id', 'user_id', 'albaran', 'fecha', 'proveedor', 'cliente', 'obra', 'planta',
    'tractora', 'remolque', 'tm', 'producto', 'observaciones', 'created_at',
    'updated_at', 'transportista', 'file_url', 'storage_path', 'editado_por',
    'editado_en', 'linea_albaran', 'tanda_subida', 'pagina_subida', 'origen',
    'destino', 'cantidad', 'unidad', 'numero_albaran'
  ]);
  // Limpia campos que no son columnas reales. NO usa la lista anterior para
  // BLOQUEAR (porque puede haber columnas nuevas que olvidé añadir), sino
  // para borrar específicamente los conocidos como auxiliares:
  const _AUX_CAMPOS = ['materiales', 'matricula', 'devolucion_palets', 'unidad_palet',
                       'num_tarjeta', 'empresa_ticket', '_esFactura', '_quality',
                       '_dup', '_dupOf', '_matDesconocida', '_manual',
                       '_fromPending', '_id'];
  for (const k of _AUX_CAMPOS) {
    if (k in rec) {
      console.log(`[v107EQ6] borrando campo auxiliar "${k}" antes del INSERT (no es columna BD)`);
      delete rec[k];
    }
  }
  // v107GN (Juan Carlos 01/06): BLINDAJE contra el error real '22P02 invalid input syntax
  // for type uuid: "undefined"'. En algunos casos db_id llegaba como la CADENA "undefined"
  // o "null" (texto, no valor vacío) — pasaba el if de abajo (texto no vacío = verdadero)
  // pero la BD rechazaba el UPDATE entero por no ser un uuid válido, así que el cambio NO
  // se guardaba y al refrescar volvía atrás. Aquí normalizamos: si db_id no es un id válido,
  // lo tratamos como vacío (→ no intentamos UPDATE con basura).
  let _idValido = data.db_id;
  if (_idValido === undefined || _idValido === null) _idValido = null;
  else {
    const _s = String(_idValido).trim();
    if (_s === '' || _s === 'undefined' || _s === 'null' || _s === 'NaN') _idValido = null;
    else _idValido = _s;
  }

  if (_idValido) {
    // v107GZ (Juan Carlos 02/06/2026): pedimos a Supabase que nos DEVUELVA la fila
    // actualizada (.select()). Sin esto, un UPDATE que no afecta a ninguna fila (por
    // permisos, por id que no encuentra, etc.) devolvía error=null → la app creía que
    // había guardado, pero NO había cambiado nada → al recargar "volvía a lo que leyó".
    // Ahora, si no vuelve ninguna fila, lanzamos error claro para que NO se dé por bueno
    // un guardado fantasma y el usuario sepa que tiene que reintentar.
    const { data: actualizado, error } = await sb.from('albaranes').update(rec).eq('id', _idValido).select();
    if (error) throw error;
    if (!actualizado || actualizado.length === 0) {
      throw new Error('El guardado no modificó ninguna fila (id=' + _idValido + '). Puede ser un tropiezo de conexión o de permisos — reinténtalo.');
    }
  } else if (data.db_id) {
    // Tenía db_id pero NO es válido: NO insertamos un duplicado a ciegas (sería peor).
    // Avisamos con un error claro para que se vea el problema y se reintente bien.
    console.error('[v107GN] db_id inválido al guardar (no es uuid):', JSON.stringify(data.db_id), '— albarán', data.albaran);
    throw new Error('El albarán no tiene un identificador válido (id="' + String(data.db_id) + '"). Refresca la página y vuelve a editarlo.');
  } else {
    const { data: inserted, error } = await sb.from('albaranes').insert(rec).select().single();
    if (error) throw error;
    return inserted.id;
  }
}

async function saveGasRecord(data) {
  const rec = { ...data, user_id: currentUser.id };
  // v107AO: guardar la empresa de la subpestaña donde se subió el ticket.
  // La subpestaña manda; la corrección por matrícula se hace en applyGasFilters.
  if (!rec.empresa_subida && !data.db_id) {
    rec.empresa_subida = gasEmpresaActiva || 'TYP2014';
  }
  // v107AO: 'empresa_ticket' lo devuelve la IA (del prompt v107AO) SOLO para
  // ayudar a clasificar, pero NO es una columna de la tabla gasoil. Hay que
  // quitarlo antes de guardar o Supabase da error "column does not exist".
  delete rec.empresa_ticket;
  delete rec.num_tarjeta;  // igual: ayuda a clasificar pero no es columna gasoil
  delete rec.tarjeta;
  // v98: limpieza de propiedades internas igual que en saveRecord (consistencia)
  Object.keys(rec).forEach(k => { if (k.startsWith('_')) delete rec[k]; });
  delete rec.db_id;
  // v107f: RED DE SEGURIDAD para gasoil. Bug detectado en tickets Repsol:
  // a veces la IA confunde la columna "€/L" (precio por litro, ej. 1,789) con la
  // columna "LITRES" (litros, ej. 484,80). Si los litros leídos están entre 1,2 y 2,2
  // es casi seguro que es un precio €/L. Añadimos aviso a observaciones para que Juan
  // Carlos lo revise (NO descartamos el registro porque podría llevarse un dato legítimo).
  const litrosNum = parseFloat(rec.litros);
  if (!isNaN(litrosNum) && litrosNum >= 1.2 && litrosNum <= 2.2) {
    console.warn(`[v107f gasoil ALERTA] litros=${litrosNum} parece un precio €/L, no litros. Marcando a revisar.`);
    rec.observaciones = (rec.observaciones ? rec.observaciones + ' · ' : '') + '⚠️ A REVISAR: litros entre 1,2-2,2 (¿precio €/L confundido?)';
  }
  // v107f: cross-check con importe y precio_litro. Si tenemos los 3 datos, verificar
  // que litros × precio_litro ≈ importe (margen del 15% para impuestos/redondeos).
  const importeNum = parseFloat(rec.importe);
  const precioNum = parseFloat(rec.precio_litro);
  if (!isNaN(litrosNum) && !isNaN(importeNum) && !isNaN(precioNum) && litrosNum > 0 && precioNum > 0) {
    const importeCalculado = litrosNum * precioNum;
    const desviacion = Math.abs(importeCalculado - importeNum) / importeNum;
    if (desviacion > 0.15) {
      console.warn(`[v107f gasoil ALERTA] No cuadra: ${litrosNum}L × ${precioNum}€/L = ${importeCalculado.toFixed(2)}€ pero importe leído es ${importeNum}€ (desviación ${(desviacion*100).toFixed(0)}%). Marcando a revisar.`);
      rec.observaciones = (rec.observaciones ? rec.observaciones + ' · ' : '') + `⚠️ A REVISAR: no cuadra ${litrosNum}L × ${precioNum}€/L ≠ ${importeNum}€`;
    }
  }
  // v98: si data.db_id existe, hacer UPDATE en lugar de INSERT (necesario para procesar
  // pendientes de gasoil sin crear duplicados — ver fix v98 en _processOne)
  // v107AR: RED DE SEGURIDAD DEFINITIVA contra el error "Could not find the
  // 'X' column of 'gasoil'". La IA a veces devuelve campos que NO son columnas
  // de la tabla gasoil (num_cuenta, importe_total, etc — pasa sobre todo al
  // subir páginas sueltas de facturas SOLRED por el botón de tickets normales).
  // En lugar de ir tapando campo a campo (whack-a-mole infinito), si Supabase
  // rechaza una columna inexistente la quitamos automáticamente y reintentamos.
  // Así nunca se pierde un dato válido y este error no vuelve a salir jamás.
  async function _gasGuardar(esUpdate) {
    for (let intento = 0; intento < 12; intento++) {
      let resp;
      if (esUpdate) {
        resp = await sb.from('gasoil').update(rec).eq('id', data.db_id);
      } else {
        resp = await sb.from('gasoil').insert(rec).select().single();
      }
      if (!resp.error) return esUpdate ? data.db_id : (resp.data && resp.data.id);
      const msg = String(resp.error.message || '');
      const m = msg.match(/Could not find the '([^']+)' column/i);
      if (resp.error.code === 'PGRST204' && m && m[1] && (m[1] in rec)) {
        console.warn('[v107AR gasoil] columna inexistente "' + m[1] + '": la quito y reintento');
        delete rec[m[1]];
        continue;
      }
      throw resp.error;
    }
    throw new Error('No pude guardar el gasoil: demasiadas columnas desconocidas en el ticket');
  }
  if (data.db_id) return await _gasGuardar(true);
  return await _gasGuardar(false);
}

async function deleteRecordDB(dbId) {
  const { error } = await sb.from('albaranes').delete().eq('id', dbId);
  if (error) throw error;
}

// ============================================================
// v107CP — BORRADO MÚLTIPLE de albaranes (solo admin)
// ============================================================
// Permite marcar varios albaranes con casillas y borrarlos de
// golpe, en vez de uno a uno. Diseño CONSERVADOR y SEGURO:
//  · Solo lo ve y usa el admin (el botón está oculto para el resto).
//  · Hay que activar el "modo selección" a propósito (botón) para
//    que aparezcan las casillas → no se borra nada por accidente.
//  · Solo se pueden marcar los albaranes que se ven en pantalla
//    (los filtrados/visibles), nunca "toda la BD" de golpe.
//  · Antes de borrar pide confirmación con el número EXACTO.
//  · Borra de uno en uno por dentro (mismo deleteRecordDB de
//    siempre) → si algo falla, no deja la BD a medias sin avisar.

window._modoSel = false;

// v107J73 — Quién puede usar la selección múltiple (botón Selección + borrar/facturar varios a la vez):
// el admin (Juan Carlos) y, además, Marta y María del Mar (gestoras), identificadas por su UUID. NO se
// abre a todo el rol "gestor" para no dárselo sin querer a otros usuarios (logística, taller…).
function _puedeSeleccionMultiple() {
  try {
    if (typeof _recambiosEsAdmin === 'function' && _recambiosEsAdmin()) return true;
    const _ids = ['6f657be7-1edd-4d5d-9895-cc6777ebbca1',   // Marta
                  '5059731a-3e41-4578-b61e-96f20b6d8cc8'];  // María del Mar
    return _ids.indexOf(currentUser && currentUser.id) !== -1;
  } catch (e) { return false; }
}

// Mostrar el botón "Selección" si el usuario puede usar la selección múltiple (se llama al cargar).
