// v107J61 — sacar el nombre original del archivo desde su URL. Las nuevas se subieron como
// "{timestamp}_{NombreOriginal}"; las antiguas como "{timestamp}_{aleatorio}.ext" (sin nombre útil).
function _nombreArchivoDeUrl(url) {
  try {
    let seg = decodeURIComponent(String(url).split('?')[0].split('/').pop() || '');
    seg = seg.replace(/^\d{10,}_/, '');           // quitar el timestamp de delante
    const base = seg.replace(/\.[^.]+$/, '');      // sin extensión
    // ¿parece el nombre interno aleatorio antiguo? (todo minúsculas/dígitos, sin separadores y largo)
    const pareceAleatorio = base.length >= 8 && /^[a-z0-9]+$/.test(base);
    return pareceAleatorio ? '' : seg;
  } catch (e) { return ''; }
}

// v107J60 — "Facturas subidas" de gasoil: lista SIN repetir (una por PDF subido), para ver de un
// vistazo qué facturas tienes ya cargadas y cuáles te faltan. Agrupa los registros por su file_url
// (una factura mensual se reparte en muchas filas/camiones, todas con el mismo PDF). v107J61: si la
// factura se subió con la versión nueva, muestra su NOMBRE ORIGINAL; si es antigua, muestra empresa + mes.
function verFacturasGasoilSubidas() {
  const panel = document.getElementById('gasFacturasSubidas');
  if (!panel) return;
  if (panel.dataset.open === '1') { panel.style.display = 'none'; panel.dataset.open = '0'; return; }
  const esc = (s) => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const _mes = (f) => { const m = String(f || '').match(/^(\d{1,2})\/(\d{2})\/(\d{4})$/); return m ? (m[2] + '/' + m[3]) : ''; };
  const grupos = new Map();
  (gasoilRecords || []).forEach(r => {
    if (!hasValidUrl(r.file_url)) return;
    let g = grupos.get(r.file_url);
    if (!g) { g = { url: r.file_url, prov: r.proveedor || '', meses: new Set(), n: 0, imp: 0, ts: r.created_at || r._ts || '' }; grupos.set(r.file_url, g); }
    g.n++;
    g.imp += Number(r.importe) || 0;
    if (!g.prov && r.proveedor) g.prov = r.proveedor;
    const mm = _mes(r.fecha); if (mm) g.meses.add(mm);
    const t = r.created_at || r._ts || ''; if (String(t) > String(g.ts)) g.ts = t;
  });
  const arr = [...grupos.values()].sort((a, b) => String(b.ts).localeCompare(String(a.ts)));
  let h = '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">'
    + '<span style="font-weight:700;color:var(--mu)">📎 Facturas de gasoil subidas (' + arr.length + ')</span>'
    + '<button class="btn bs" style="font-size:10px;padding:2px 8px" onclick="verFacturasGasoilSubidas()">✕ Cerrar</button></div>';
  if (!arr.length) {
    h += '<div style="color:var(--mu)">No hay facturas con PDF. (Los repostajes metidos a mano no tienen archivo adjunto.)</div>';
  } else {
    arr.forEach(g => {
      const meses = [...g.meses].sort((a, b) => (a.split('/')[1] + a.split('/')[0]).localeCompare(b.split('/')[1] + b.split('/')[0]));
      const mesTxt = meses.length ? meses.join(', ') : '—';
      const cuando = g.ts ? fmtTS(g.ts) : '';
      const nom = _nombreArchivoDeUrl(g.url);
      const impTxt = g.imp > 0 ? g.imp.toFixed(2).replace('.', ',') + ' €' : '—';
      h += '<div style="padding:5px 0;border-bottom:1px solid var(--bd)">'
        + '<a href="' + g.url + '" target="_blank" rel="noopener" style="color:#7cc4ff;text-decoration:underline">👁 Abrir PDF</a> · '
        + (nom ? '<strong>' + esc(nom) + '</strong> · ' : '')
        + esc(g.prov || 'Proveedor ?') + ' · mes: ' + esc(mesTxt)
        + ' · <strong style="color:var(--ok)">' + impTxt + '</strong>'
        + ' <span style="color:var(--mu)">(' + g.n + ' camiones' + (cuando ? ' · subida ' + esc(cuando) : '') + ')</span></div>';
    });
  }
  panel.innerHTML = h;
  panel.style.display = 'block';
  panel.dataset.open = '1';
}

// ============================================================
// FASE 4b (v107BK): RESUMEN DE CONSUMO de gasoil
// Litros de gasoil (facturas, tabla gasoil) / km recorridos
// (tabla km_periodos) * 100 = L/100km, por camion y periodo.
// El periodo lo manda el Excel de km (mensual/trimestral/anual).
// Respeta la empresa de la subpestaña activa (misma privacidad
// que applyGasFilters).
// ============================================================

// Cache de los periodos de km cargados de Supabase (se rellena
// la primera vez que se abre la vista de consumo).
let _kmPeriodos = null;

// Empresa "duena" de una matricula segun el mapa TRANSPORTISTAS
// (mismo criterio que applyGasFilters: la subpestana donde se
// subio manda, pero si la matricula es de otra empresa del grupo,
// se reasigna al dueno real). Devuelve la subpestana destino
// ('TYP2014' | 'HISPALIS' | 'TRANSMARGAZ').
function _gasEmpresaDeRegistro(r) {
  const CANON_A_TAB = { 'TYP2014':'TYP2014', 'TTES HISPALIS 2016':'HISPALIS', 'TRANSMARGAZ 2018':'TRANSMARGAZ' };
  const mat = String(r.tractora || '').toUpperCase().replace(/[\s-]/g, '');
  const transp = mat ? (TRANSPORTISTAS[mat] || TRANSPORTISTAS[r.tractora]) : null;
  const tabDueño = transp && CANON_A_TAB[transp] ? CANON_A_TAB[transp] : null;
  if (r.empresa_subida) {
    if (tabDueño && tabDueño !== r.empresa_subida) return tabDueño;
    return r.empresa_subida;
  }
  if (!mat) return 'TYP2014';
  if (transp) return tabDueño || 'TYP2014';
  return 'TYP2014';
}

// Convierte fecha "DD/MM/YYYY" o "YYYY-MM-DD" a numero comparable
// YYYYMMDD. Devuelve 0 si no se reconoce.
function _gasFechaNum(s) {
  if (!s) return 0;
  s = String(s).trim();
  let m = s.match(/^(\d{4})-(\d{1,2})-(\d{1,2})/);   // ISO YYYY-MM-DD
  if (m) return parseInt(m[1]) * 10000 + parseInt(m[2]) * 100 + parseInt(m[3]);
  m = s.match(/(\d{1,2})\/(\d{1,2})\/(\d{2,4})/);     // DD/MM/YYYY
  if (m) {
    let y = m[3]; if (y.length === 2) y = '20' + y;
    return parseInt(y) * 10000 + parseInt(m[2]) * 100 + parseInt(m[1]);
  }
  return 0;
}

// Texto "bonito" del periodo: si es justo un mes natural -> "Enero 2026";
// si es justo un anyo natural -> "Año 2025"; si no -> "01/01/2026 - 31/03/2026".
function _gasPeriodoTexto(iniISO, finISO) {
  const MESES = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
  const a = String(iniISO || '').match(/^(\d{4})-(\d{2})-(\d{2})/);
  const b = String(finISO || '').match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (!a || !b) {
    // Sin formato ISO claro: mostrar tal cual lo que haya
    const fmt = (s) => {
      const m = String(s || '').match(/^(\d{4})-(\d{2})-(\d{2})/);
      return m ? m[3] + '/' + m[2] + '/' + m[1] : (s || '?');
    };
    return fmt(iniISO) + ' – ' + fmt(finISO);
  }
  const [_, y1, m1, d1] = a;
  const [__, y2, m2, d2] = b;
  // Ultimo dia del mes m2/y2
  const ultDia = new Date(parseInt(y2), parseInt(m2), 0).getDate();
  // Anyo natural completo
  if (y1 === y2 && m1 === '01' && d1 === '01' && m2 === '12' && d2 === '31') {
    return 'Año ' + y1;
  }
  // Mes natural completo
  if (y1 === y2 && m1 === m2 && d1 === '01' && parseInt(d2) === ultDia) {
    return MESES[parseInt(m1) - 1] + ' ' + y1;
  }
  // Tramo cualquiera
  return d1 + '/' + m1 + '/' + y1 + ' – ' + d2 + '/' + m2 + '/' + y2;
}

// Alterna entre la vista REGISTRO (tabla normal) y la vista CONSUMO.
async function gasToggleConsumo() {
  const vReg = document.getElementById('gasVistaRegistro');
  const vCon = document.getElementById('gasVistaConsumo');
  const btn  = document.getElementById('gasBtnConsumo');
  if (!vReg || !vCon) return;
  const mostrandoConsumo = vCon.style.display !== 'none';
  if (mostrandoConsumo) {
    // Volver al registro normal
    vCon.style.display = 'none';
    vReg.style.display = '';
    if (btn) btn.textContent = '📈 Consumo';
  } else {
    // Mostrar consumo
    vReg.style.display = 'none';
    vCon.style.display = '';
    if (btn) btn.textContent = '📋 Ver registro';
    await gasRenderConsumo();
  }
}

// Calcula y pinta la tabla de consumo para la empresa de la
// subpestana activa (gasEmpresaActiva).
async function gasRenderConsumo() {
  const tbody = document.getElementById('tbodyGasConsumo');
  const empty = document.getElementById('emptyGasConsumo');
  if (!tbody) return;

  // 1) Cargar km_periodos (una sola vez por sesion, se cachea)
  if (_kmPeriodos === null) {
    tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;padding:30px;color:var(--mu);font-family:var(--mn);font-size:11px">Cargando km del tacógrafo…</td></tr>';
    try {
      const { data, error } = await sb.from('km_periodos')
        .select('matricula,empresa,fecha_inicio,fecha_fin,km_diferencia');
      if (error) throw error;
      _kmPeriodos = data || [];
    } catch (e) {
      console.error('[gasRenderConsumo] error cargando km_periodos:', e);
      _kmPeriodos = [];
      tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;padding:30px;color:var(--er);font-family:var(--mn);font-size:11px">Error cargando km del tacógrafo: ' + (e.message || e) + '</td></tr>';
      return;
    }
  }

  const emp = gasEmpresaActiva || 'TYP2014';

  // 2) Periodos de km de ESTA empresa
  const periodosEmp = (_kmPeriodos || []).filter(p => (p.empresa || 'TYP2014') === emp);

  // 3) Repostajes de GASOIL (no adblue) de ESTA empresa, indexados
  //    por matricula -> lista de {fechaNum, litros}
  const litrosPorMat = {};
  gasoilRecords.forEach(r => {
    const tp = String(r.tipo || '').toLowerCase();
    if (tp && tp !== 'gasoil' && tp !== 'gas-oil' && tp !== 'diesel') return; // solo gasoil
    if (_gasEmpresaDeRegistro(r) !== emp) return;                              // solo esta empresa
    const litros = parseFloat(r.litros);
    if (!litros || litros <= 0) return;
    const mat = String(r.tractora || '').toUpperCase().replace(/[\s-]/g, '');
    if (!mat) return;
    (litrosPorMat[mat] = litrosPorMat[mat] || []).push({
      f: _gasFechaNum(r.fecha), litros: litros
    });
  });

  // J17: igual pero para ADBLUE (para la columna AdBlue de consumo).
  const adbluePorMat = {};
  gasoilRecords.forEach(r => {
    const tp = String(r.tipo || '').toLowerCase();
    if (!/adblue|ad-blue|ad blue|urea/.test(tp)) return; // solo adblue
    if (_gasEmpresaDeRegistro(r) !== emp) return;
    const litros = parseFloat(r.litros);
    if (!litros || litros <= 0) return;
    const mat = String(r.tractora || '').toUpperCase().replace(/[\s-]/g, '');
    if (!mat) return;
    (adbluePorMat[mat] = adbluePorMat[mat] || []).push({ f: _gasFechaNum(r.fecha), litros: litros });
  });

  // 4) Leer el filtro de fechas que ha puesto el usuario.
  //    Sin fechas → una fila por bloque de km (modo original).
  //    Con fechas → una fila por camion: suma de los bloques de km
  //    que caen dentro del periodo + litros de gasoil de ese periodo.
  const elD = document.getElementById('gasConDesde');
  const elH = document.getElementById('gasConHasta');
  const desdeStr = elD ? elD.value : '';   // formato YYYY-MM-DD del input date
  const hastaStr = elH ? elH.value : '';
  const desdeN = desdeStr ? _gasFechaNum(desdeStr) : 0;
  const hastaN = hastaStr ? _gasFechaNum(hastaStr) : 0;
  const hayFiltro = desdeN > 0 || hastaN > 0;

  const fmtN = (n, dec) => Number(n).toLocaleString('es-ES', { minimumFractionDigits: dec, maximumFractionDigits: dec });
  let filas = [];

  if (!hayFiltro) {
    // ---- MODO SIN FILTRO: una fila por bloque de km (como antes) ----
    filas = periodosEmp.map(p => {
      const mat = String(p.matricula || '').toUpperCase().replace(/[\s-]/g, '');
      const iniN = _gasFechaNum(p.fecha_inicio);
      const finN = _gasFechaNum(p.fecha_fin);
      let litros = 0, huboLitros = false;
      (litrosPorMat[mat] || []).forEach(x => {
        if (x.f && iniN && finN && x.f >= iniN && x.f <= finN) { litros += x.litros; huboLitros = true; }
      });
      const km = parseInt(p.km_diferencia, 10) || 0;
      let consumo = null;
      if (huboLitros && km > 0) consumo = (litros / km) * 100;
      let adblue = 0;
      (adbluePorMat[mat] || []).forEach(x => {
        if (x.f && iniN && finN && x.f >= iniN && x.f <= finN) adblue += x.litros;
      });
      return {
        mat: p.matricula || '—',
        periodo: _gasPeriodoTexto(p.fecha_inicio, p.fecha_fin),
        orden: mat + '|' + String(iniN).padStart(8, '0'),
        litros: huboLitros ? litros : null,
        adblue: adblue > 0 ? adblue : null,
        km: km > 0 ? km : null,
        consumo: consumo,
        aviso: ''
      };
    });
  } else {
    // ---- MODO CON FILTRO: agrupar por camion en el periodo pedido ----
    // Rango efectivo: si falta una de las dos fechas, se abre por ese lado.
    const rIni = desdeN > 0 ? desdeN : 1;            // desde el principio
    const rFin = hastaN > 0 ? hastaN : 99999999;     // hasta el final

    // Conjunto de matriculas implicadas (las que tienen km o litros)
    const mats = new Set();
    periodosEmp.forEach(p => mats.add(String(p.matricula || '').toUpperCase().replace(/[\s-]/g, '')));
    Object.keys(litrosPorMat).forEach(m => mats.add(m));

    mats.forEach(mat => {
      if (!mat) return;
      // Bloques de km de esta matricula que SOLAPAN con el rango pedido
      const bloques = periodosEmp.filter(p => {
        if (String(p.matricula || '').toUpperCase().replace(/[\s-]/g, '') !== mat) return false;
        const bi = _gasFechaNum(p.fecha_inicio);
        const bf = _gasFechaNum(p.fecha_fin);
        if (!bi || !bf) return false;
        return bf >= rIni && bi <= rFin;   // solapan
      });
      let km = 0, encajeExacto = true;
      bloques.forEach(p => {
        km += parseInt(p.km_diferencia, 10) || 0;
        const bi = _gasFechaNum(p.fecha_inicio);
        const bf = _gasFechaNum(p.fecha_fin);
        // Si el bloque se sale del rango pedido, los km no son 100% del periodo
        if (bi < rIni || bf > rFin) encajeExacto = false;
      });
      // Litros de gasoil de esa matricula DENTRO del rango pedido (exacto)
      let litros = 0, huboLitros = false;
      (litrosPorMat[mat] || []).forEach(x => {
        if (x.f && x.f >= rIni && x.f <= rFin) { litros += x.litros; huboLitros = true; }
      });
      // Si no hay NI km NI litros en el periodo para esta matricula, no la mostramos
      if (!bloques.length && !huboLitros) return;
      let consumo = null;
      if (huboLitros && km > 0) consumo = (litros / km) * 100;
      // J17: adblue de esa matrícula dentro del rango pedido
      let adblue = 0;
      (adbluePorMat[mat] || []).forEach(x => {
        if (x.f && x.f >= rIni && x.f <= rFin) adblue += x.litros;
      });
      // Texto del periodo: lo que pidio el usuario
      const fmtFecha = (s) => { const m = String(s).match(/^(\d{4})-(\d{2})-(\d{2})/); return m ? m[3] + '/' + m[2] + '/' + m[1] : s; };
      let periodoTxt;
      if (desdeStr && hastaStr) periodoTxt = fmtFecha(desdeStr) + ' – ' + fmtFecha(hastaStr);
      else if (desdeStr) periodoTxt = 'Desde ' + fmtFecha(desdeStr);
      else periodoTxt = 'Hasta ' + fmtFecha(hastaStr);
      if (!encajeExacto && bloques.length) periodoTxt += ' *';
      filas.push({
        mat: mat,
        periodo: periodoTxt,
        orden: mat,
        litros: huboLitros ? litros : null,
        adblue: adblue > 0 ? adblue : null,
        km: km > 0 ? km : null,
        consumo: consumo,
        aviso: (!encajeExacto && bloques.length)
          ? 'Los km del tacógrafo de este camión vienen en bloques que no encajan exactamente con las fechas pedidas; el consumo es aproximado.'
          : ''
      });
    });
  }

  // 5) Ordenar por matricula (y dentro, por fecha de inicio)
  filas.sort((a, b) => (a.orden < b.orden ? -1 : a.orden > b.orden ? 1 : 0));
  // J18: guardar la tabla calculada (con su empresa y periodo) para el Excel de consumo.
  window._consumoUltimo = {
    filas: filas, empresa: emp,
    desde: (document.getElementById('gasConDesde') || {}).value || '',
    hasta: (document.getElementById('gasConHasta') || {}).value || ''
  };

  // 6) Pintar
  if (!filas.length) {
    tbody.innerHTML = '';
    if (empty) {
      empty.style.display = 'block';
      empty.textContent = hayFiltro
        ? 'No hay datos de consumo para el periodo seleccionado en esta empresa.'
        : 'No hay datos de consumo todavía. Sube facturas de gasoil y el Excel de km del tacógrafo.';
    }
    return;
  }
  if (empty) empty.style.display = 'none';
  tbody.innerHTML = filas.map(f => {
    const litrosTxt = f.litros != null
      ? fmtN(f.litros, 0) + ' L'
      : '<span style="color:var(--wn)">⚠️ sin factura</span>';
    const kmTxt = f.km != null
      ? fmtN(f.km, 0) + ' km'
      : '<span style="color:var(--wn)">⚠️ sin km</span>';
    const adblueTxt = f.adblue != null
      ? fmtN(f.adblue, 0) + ' L'
      : '<span style="color:var(--mu)">—</span>';
    let consumoTxt;
    if (f.consumo != null) {
      // J15: semáforo con iconos. Rojo/llama >40 (excesivo), ámbar 35-40 (vigilar),
      // verde/hoja <35 (buen consumo).
      let col, icono;
      if (f.consumo > 40) { col = 'var(--er)'; icono = '🔥 '; }
      else if (f.consumo >= 35) { col = 'var(--wn)'; icono = '⚠️ '; }
      else { col = 'var(--ok)'; icono = '🌿 '; }
      consumoTxt = '<strong style="color:' + col + '">' + icono + fmtN(f.consumo, 1) + '</strong>';
    } else if (f.km != null && f.litros == null) {
      // J15: tiene km (el tacógrafo registró movimiento) pero NO hay gasoil
      // registrado en el periodo → aviso rojo tipo "prohibido" para revisar si
      // el vehículo no circula o si falta subir su factura de gasoil.
      consumoTxt = '<span title="Tiene km del tacógrafo pero NO hay gasoil registrado en este periodo. Revisa si el vehículo no está circulando/trabajando o si falta subir su factura de gasoil." style="color:var(--er);font-weight:800;font-family:var(--mn)">⛔ REVISAR</span>';
    } else {
      consumoTxt = '<span style="color:var(--wn)">⚠️</span>';
    }
    const periodoCell = f.aviso
      ? '<td title="' + f.aviso.replace(/"/g, '') + '">' + f.periodo + '</td>'
      : '<td>' + f.periodo + '</td>';
    return '<tr>'
      + '<td class="tag-mat">' + f.mat + '</td>'
      + periodoCell
      + '<td class="tag-tm">' + litrosTxt + '</td>'
      + '<td style="color:var(--in)">' + adblueTxt + '</td>'
      + '<td>' + kmTxt + '</td>'
      + '<td>' + consumoTxt + '</td>'
      + '</tr>';
  }).join('');
}

// v107BL: limpiar las casillas de fecha del consumo y recalcular
function gasConsumoLimpiar() {
  const d = document.getElementById('gasConDesde');
  const h = document.getElementById('gasConHasta');
  if (d) d.value = '';
  if (h) h.value = '';
  gasRenderConsumo();
}

// J18: descargar la tabla de CONSUMO en Excel (negrita y grande, como los demás).
// Usa lo último calculado por gasRenderConsumo (respeta empresa y filtro de fechas).
function exportConsumoExcel() {
  const u = window._consumoUltimo;
  if (!u || !u.filas || !u.filas.length) {
    toast('Abre CONSUMO (y pon un periodo si quieres) antes de descargar', 'err');
    return;
  }
  const rows = [['Matrícula', 'Periodo', 'Litros gasoil', 'AdBlue (L)', 'Km recorridos', 'L/100km']];
  u.filas.forEach(f => {
    rows.push([
      f.mat || '',
      f.periodo || '',
      f.litros != null ? Math.round(f.litros) : '',
      f.adblue != null ? Math.round(f.adblue) : '',
      f.km != null ? f.km : '',
      f.consumo != null ? Number(f.consumo.toFixed(1)) : ''
    ]);
  });
  const ws = XLSX.utils.aoa_to_sheet(rows);
  ws['!cols'] = [{ wch: 12 }, { wch: 28 }, { wch: 14 }, { wch: 12 }, { wch: 14 }, { wch: 12 }];
  const range = XLSX.utils.decode_range(ws['!ref']);
  for (let R = range.s.r; R <= range.e.r; R++) {
    for (let C = range.s.c; C <= range.e.c; C++) {
      const addr = XLSX.utils.encode_cell({ r: R, c: C });
      if (!ws[addr]) ws[addr] = { t: 's', v: '' };
      if (!ws[addr].s) ws[addr].s = {};
      ws[addr].s.alignment = { horizontal: 'center', vertical: 'center' };
      ws[addr].s.font = { bold: true, sz: 13 };
      if (R === 0) ws[addr].s.font = { bold: true, sz: 14 };
    }
  }
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Consumo');
  const hoy = new Date().toISOString().slice(0, 10);
  XLSX.writeFile(wb, `consumo_${u.empresa || 'empresa'}_${hoy}.xlsx`);
  toast('✓ Excel de consumo descargado');
}



function updateStats() {
  try {
    // Excluir pendientes (procesado=false) de las estadísticas — aparecen en su propio banner
    const procesados = records.filter(r => r.procesado !== false);
    const valid = procesados.filter(r => !r._dup), dups = procesados.filter(r => r._dup);
    const warns = procesados.filter(r => !r._dup && (r._quality === 'warn' || r._quality === 'ilegible'));
    const tm = valid.reduce((s, r) => s + (parseFloat(r.tm) || 0), 0);
    const now = new Date();
    const mes = valid.filter(r => { const d = parseDate(r.fecha || ''); if (!d) return false; const dd = new Date(d); return dd.getMonth() === now.getMonth() && dd.getFullYear() === now.getFullYear(); }).length;
    const vehs = new Set(valid.map(r => r.tractora).filter(Boolean)).size;
    const M = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
    const box = document.getElementById('statsBox');
    if (!box) { console.error('[updateStats] No se encontró #statsBox en el DOM'); return; }
    box.innerHTML = `
      <div class="stat"><div class="stat-l">Albaranes válidos</div><div class="stat-v">${valid.length}</div><div class="stat-s">contabilizados</div></div>
      <div class="stat"><div class="stat-l">TN Netas válidas</div><div class="stat-v">${tm.toLocaleString('es-ES',{minimumFractionDigits:3,maximumFractionDigits:3})}</div><div class="stat-s">sin duplicados</div></div>
      <div class="stat"><div class="stat-l">Este mes</div><div class="stat-v">${mes}</div><div class="stat-s">${M[now.getMonth()]} ${now.getFullYear()}</div></div>
      <div class="stat"><div class="stat-l">Vehículos</div><div class="stat-v">${vehs}</div><div class="stat-s">matrículas distintas</div></div>
      <div class="stat" style="--c:var(--er)"><div class="stat-l">Duplicados</div><div class="stat-v" style="color:var(--er)">${dups.length}</div><div class="stat-s">no contabilizados</div></div>
      <div class="stat" style="--c:var(--wn)"><div class="stat-l">A revisar</div><div class="stat-v" style="color:var(--wn)">${warns.length}</div><div class="stat-s">calidad/ilegibles</div></div>`;
    const hdrInfo = document.getElementById('hdrInfo');
    if (hdrInfo) hdrInfo.textContent = valid.length ? `${valid.length} alb · ${tm.toFixed(1)} TN` : '';
    console.log(`[updateStats] OK: ${valid.length} válidos, ${tm.toFixed(1)} TN, ${dups.length} dups, ${warns.length} revisar`);
  } catch (e) {
    // v100b: si algún cálculo falla, mostrar mensaje claro en pantalla en lugar de dejar vacío
    console.error('[updateStats] Error:', e);
    const box = document.getElementById('statsBox');
    if (box) box.innerHTML = `<div class="stat" style="grid-column:1/-1"><div class="stat-l">⚠️ Error calculando estadísticas</div><div class="stat-v" style="font-size:14px;color:var(--er)">${e.message}</div><div class="stat-s">Abrir F12 (consola) y enviar captura</div></div>`;
  }
}

// ============================================================
// MODAL ALBARAN
// ============================================================
const FIELDS = [
  {k:'fecha',l:'Fecha'},{k:'tractora',l:'Matrícula'},{k:'tm',l:'TN Netas'},{k:'precio',l:'Precio (€/TN)'},
  {k:'albaran',l:'Nº Albarán',full:true},{k:'proveedor',l:'Proveedor',full:true},{k:'planta',l:'Origen',full:true},
  {k:'obra',l:'Destino',full:true},{k:'producto',l:'Material',full:true},{k:'cliente',l:'Cliente',full:true},
  {k:'remolque',l:'Remolque'},{k:'transportista',l:'Transportista',full:true},
  {k:'tara_kg',l:'Tara (kg)'},{k:'bruto_kg',l:'Bruto (kg)'},
  {k:'hora_entrada',l:'H. Entrada'},{k:'hora_salida',l:'H. Salida'},{k:'observaciones',l:'Observaciones',full:true},
];

function openModal(id) {
  const r = records.find(x => String(x.db_id) === String(id) || String(x._id) === String(id));
  if (!r) return;
  // v107GN: si el albarán aún no tiene id real en la BD (recién subido, sin terminar de
  // guardar), avisamos en vez de dejar editar y perder el cambio con error "uuid undefined".
  const _dbidOk = r.db_id && !['undefined', 'null', 'NaN', ''].includes(String(r.db_id).trim());
  if (!_dbidOk) {
    console.warn('[v107GN] Abriendo albarán sin db_id válido:', r.db_id, '— albarán', r.albaran);
  }
  editId = id;
  document.getElementById('mBadge').innerHTML = rowBadge(r);
  let alertHtml = '';
  if (r._dup) alertHtml = `<div class="m-alert m-alert-dup">⛔ <strong>Duplicado.</strong> TN no contabilizadas.</div>`;
  else if (r._quality === 'ilegible') alertHtml = `<div class="m-alert m-alert-warn">⚠ <strong>Posible ilegible.</strong></div>`;
  else if (r._quality === 'warn') alertHtml = `<div class="m-alert m-alert-warn">⚠ <strong>Campos incompletos.</strong></div>`;
  // v91: aviso especial cuando la matrícula es desconocida. Muestra dropdown con los 13
  // transportistas oficiales para que el admin asigne manualmente. Al cambiar, actualiza
  // el input "Transportista" del formulario. El checkbox "Aprender" controla si al
  // guardar se memoriza la matrícula en BD para que la próxima vez se reconozca sola.
  if (!r._dup && r._matDesconocida) {
    const matrShow = r.tractora ? esc(r.tractora) : '(vacía)';
    // v103b: SOLO el admin puede asignar transportista a una matrícula nueva (porque la
    // asignación se aprende y afecta a todos los albaranes futuros + a la facturación).
    // Los gestores ven un aviso informativo de solo lectura, sin select ni checkboxes.
    if (currentRole === 'admin') {
      const transActual = r.transportista || '';
      const opts = ['<option value="">— Selecciona transportista —</option>']
        .concat(TRANSPORTISTAS_OFICIALES.map(t => `<option value="${esc(t)}"${t === transActual ? ' selected' : ''}>${esc(t)}</option>`))
        .join('');
      // v91c: contar OTROS albaranes en memoria con la misma matrícula (normalizada).
      // Si hay alguno, ofrecemos al admin un segundo checkbox para actualizarlos en lote.
      const matNorm = String(r.tractora || '').trim().toUpperCase().replace(/\s+/g,'');
      const otrosConMismaMat = matNorm ? records.filter(x =>
        x !== r &&
        !x._dup &&
        x.db_id &&
        x.tractora &&
        String(x.tractora).trim().toUpperCase().replace(/\s+/g,'') === matNorm
      ) : [];
      const numOtros = otrosConMismaMat.length;
      let histHtml = '';
      if (numOtros > 0) {
        histHtml = `<label style="display:flex;align-items:center;gap:6px;font-size:11px;color:var(--mu);cursor:pointer;margin-top:6px">
          <input type="checkbox" id="mAplicarHistorico" style="cursor:pointer">
          Aplicar también a los <strong style="color:var(--wn)">${numOtros}</strong> albaranes existentes con esta matrícula
        </label>`;
      }
      alertHtml += `<div class="m-alert" style="background:rgba(255,184,0,.10);border:1px solid rgba(255,184,0,.45);color:#ffd970;padding:10px 12px">
        <div style="font-weight:600;margin-bottom:6px">🚛 Matrícula desconocida: <span style="font-family:var(--mn)">${matrShow}</span></div>
        <div style="font-size:11px;color:var(--mu);margin-bottom:8px">No está en la flota oficial ni en las aprendidas. Asigna el transportista para que la próxima vez se reconozca sola.</div>
        <select id="mAsignarTransportista" onchange="document.getElementById('mf_transportista').value=this.value" style="width:100%;background:var(--bg2);color:var(--tx);border:1px solid var(--bd);border-radius:6px;padding:7px 9px;font-size:13px;margin-bottom:6px">${opts}</select>
        <label style="display:flex;align-items:center;gap:6px;font-size:11px;color:var(--mu);cursor:pointer">
          <input type="checkbox" id="mAprenderMat" checked style="cursor:pointer">
          Aprender esta matrícula para futuros albaranes
        </label>
        ${histHtml}
      </div>`;
    } else {
      // Gestor (o cualquier otro rol no-admin): banner informativo de solo lectura.
      alertHtml += `<div class="m-alert" style="background:rgba(255,184,0,.10);border:1px solid rgba(255,184,0,.45);color:#ffd970;padding:10px 12px">
        <div style="font-weight:600;margin-bottom:6px">🚛 Matrícula desconocida: <span style="font-family:var(--mn)">${matrShow}</span></div>
        <div style="font-size:11px;color:var(--mu)">No está en la flota oficial ni en las aprendidas. Avisa al admin para que asigne el transportista.</div>
      </div>`;
    }
  }
  // v76: aviso si el albarán está marcado como editado manualmente — protegido contra reanálisis
  if (r._manual) alertHtml += `<div class="m-alert" style="background:rgba(0,232,122,.08);border:1px solid rgba(0,232,122,.3);color:var(--ac)">✏️ <strong>Editado manualmente.</strong> Protegido — Re-corregir TODO no afectará a este albarán.</div>`;
  // Info de quién subió el albarán (visible para admin/gestor)
  const subPor = userName(r.user_id);
  if (subPor && subPor !== '—') {
    alertHtml += `<div style="font-family:var(--mn);font-size:10px;color:var(--mu);padding:4px 0 12px">📤 Subido por: <strong style="color:var(--in)">${subPor}</strong>${r.created_at ? ` · ${fmtTS(r.created_at)}` : ''}</div>`;
  }
  // v107CP: si el albarán fue editado, mostrar quién lo editó. Así, aunque sea
  // un conductor abriendo SU albarán que tú (admin) editaste, ve quién lo
  // corrigió y no lo vuelve a subir.
  if (r.editado_por) {
    alertHtml += `<div style="font-family:var(--mn);font-size:10px;color:#fbbf24;padding:0 0 12px">✏️ Editado por: <strong>${userName(r.editado_por)}</strong></div>`;
  }
  document.getElementById('mAlert').innerHTML = alertHtml;
  // v107FD: recuadro de Facturación (Fase 1). Solo si el usuario tiene
  // permiso (admin / María del Mar / Marta / Logística) y el albarán ya
  // está guardado en BD (tiene db_id). Para conductores queda oculto.
  const _facBox = document.getElementById('mFacturacion');
  if (_facBox) {
    if (_puedeVerFacturacion() && r.db_id) {
      _facBox.innerHTML = _facturacionModalHtml(r);
      _facBox.style.display = 'block';
    } else {
      _facBox.innerHTML = '';
      _facBox.style.display = 'none';
    }
  }
  // Preview
  let previewHtml = '';
  if (hasValidUrl(r.file_url)) {
    const isImg = /\.(jpg|jpeg|png|gif|webp)(\?|#|$)/i.test(r.file_url);
    const isPdf = /\.pdf(\?|#|$)/i.test(r.file_url);
    if (isImg) {
      // v97i: las imágenes ahora también tienen botones de zoom igual que los PDFs.
      // Antes solo los PDFs tenían zoom; pero la mayoría de albaranes (especialmente
      // los que vienen de PDFs multi-página convertidos a JPG, o las fotos del móvil)
      // aparecen como imágenes y se quedaban sin la funcionalidad de zoom. Ahora
      // todo el mundo puede acercarse a los detalles del albarán.
      previewHtml = `
        <div id="pdfZoomWrap" class="pdf-zoom-wrap" data-is-img="1">
          <div class="pdf-zoom-controls">
            <button class="pdf-zoom-btn" onclick="zoomImgBtn('pdfZoomWrap',-1)" title="Reducir">🔍−</button>
            <button class="pdf-zoom-btn" onclick="zoomImgReset('pdfZoomWrap')" title="Tamaño original">↺</button>
            <button class="pdf-zoom-btn" onclick="zoomImgBtn('pdfZoomWrap',1)" title="Ampliar">🔍+</button>
            <button class="pdf-zoom-btn" onclick="girarImg('zoomedImg')" title="Girar 90°">🔄</button>
            <span class="pdf-zoom-info">100%</span>
          </div>
          <img src="${r.file_url}" id="zoomedImg" alt="Albarán" style="display:block;margin:0 auto;max-width:100%;height:auto;cursor:pointer;transition:transform .15s" onclick="window.open('${r.file_url}','_blank')">
        </div>
        <div style="margin-top:8px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
          <span style="font-family:var(--mn);font-size:11px;color:var(--mu)">🔍 Usa los botones <strong style="color:var(--ac)">+</strong> y <strong style="color:var(--ac)">−</strong> para hacer zoom</span>
          <a href="${r.file_url}" target="_blank" class="preview-btn">📄 Abrir documento original</a>
        </div>`;
    } else if (isPdf) {
      // v72: renderizar la página específica del PDF inline en el modal
      const pageMatch = r.file_url.match(/#page=(\d+)/);
      const pageNum = pageMatch ? parseInt(pageMatch[1]) : 1;
      const cleanUrl = r.file_url.split('#')[0];
      // v97d: zoom simplificado. Botones flotantes encima del albarán; al pulsar +/-
      // el PDF se RE-RENDERIZA a más resolución (no usa transforms CSS que daban
      // problemas en v97c). Si el albarán crece más que el contenedor, aparece scroll
      // automático y el usuario se mueve por la imagen con la rueda o arrastrando la barra.
      previewHtml = `
        <div id="pdfZoomWrap" class="pdf-zoom-wrap">
          <div class="pdf-zoom-controls">
            <button class="pdf-zoom-btn" onclick="zoomBtn('pdfZoomWrap',-1)" title="Reducir">🔍−</button>
            <button class="pdf-zoom-btn" onclick="zoomReset('pdfZoomWrap')" title="Tamaño original">↺</button>
            <button class="pdf-zoom-btn" onclick="zoomBtn('pdfZoomWrap',1)" title="Ampliar">🔍+</button>
            <button class="pdf-zoom-btn" onclick="girarImg('pdfPreviewCanvas')" title="Girar 90°">🔄</button>
            <span class="pdf-zoom-info">100%</span>
          </div>
          <canvas id="pdfPreviewCanvas"></canvas>
          <div id="pdfPreviewLoading" style="text-align:center;padding:40px;color:var(--mu);font-family:var(--mn);font-size:11px">📄 Cargando vista previa...</div>
        </div>
        <div style="margin-top:8px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
          <span style="font-family:var(--mn);font-size:11px;color:var(--mu)">🔍 Usa los botones <strong style="color:var(--ac)">+</strong> y <strong style="color:var(--ac)">−</strong> para hacer zoom</span>
          <a href="${r.file_url}" target="_blank" class="preview-btn">📄 Abrir documento original</a>
        </div>`;
    } else {
      previewHtml = `<a href="${r.file_url}" target="_blank" class="preview-btn">📄 Ver documento original</a>`;
    }
  }
  document.getElementById('mPreview').innerHTML = previewHtml;
  // v72: si hemos pintado un canvas para PDF, lanzamos el render después de inyectar el HTML
  if (hasValidUrl(r.file_url) && /\.pdf(\?|#|$)/i.test(r.file_url)) {
    const pageMatch = r.file_url.match(/#page=(\d+)/);
    const pageNum = pageMatch ? parseInt(pageMatch[1]) : 1;
    const cleanUrl = r.file_url.split('#')[0];
    // v97d: render simple — la propia función guarda los metadatos en el wrapper
    // para que después los botones de zoom puedan re-renderizar.
    setTimeout(() => {
      renderPdfPagePreview(cleanUrl, pageNum, 'pdfPreviewCanvas', 'pdfPreviewLoading');
    }, 50);
  }
  // v103: campo Transportista con tratamiento especial — ya no es un input de texto libre.
  // - admin/gestor: SELECT cerrado con los 13 TRANSPORTISTAS_OFICIALES. Si el valor histórico
  //   guardado no está en la lista oficial (ej. "ARIDFLOT, S.L." en vez de "ARIDFLOT"), se
  //   muestra arriba con un aviso ⚠ para que se migre con un clic al oficial.
  // - conductor: input bloqueado (disabled). Hoy los conductores no acceden al modal, pero
  //   se deja preparado por si en el futuro se les habilita acceso a su listado.
  // v107i: Proveedor, Origen (planta) y Destino (obra) reciben el mismo tratamiento que
  // transportista — dropdown cerrado para admin/gestor con la lista de canónicos oficiales
  // (PROVEEDORES_CANONICOS / ORIGENES_CANONICOS / DESTINOS_CANONICOS) ordenados
  // alfabéticamente. Motivo: editar a mano introducía variantes que rompían filtros y
  // exportes (mayúsculas raras, espacios, faltas OCR). Ahora el editor solo puede ELEGIR;
  // si necesita un valor nuevo, avisa a admin para añadirlo al canónico. Si el valor
  // histórico guardado no está en la lista, aparece arriba con ⚠ para canonizar con un clic.
  // Resto de campos: como siempre, input editable libre.
  document.getElementById('mFields').innerHTML = FIELDS.map(f => {
    const val = r[f.k] != null ? String(r[f.k]).replace(/"/g,'&quot;') : '';
    if (f.k === 'transportista') {
      // v103b + v107k: lógica por rol y tipo de gestor.
      // Distinguimos 4 casos:
      //  (1) ADMIN → dropdown editable con los 13 oficiales (puede cambiar el transportista).
      //  (2) GESTOR OFICINA (María del Mar, Admin... cualquier gestor NO en USUARIO_A_TRANSPORTISTA)
      //      → dropdown editable con los 13 oficiales, igual que admin. Pueden gestionar
      //      todos los transportistas porque trabajan en oficina y ven todo el flujo.
      //  (3) GESTOR SUBCONTRATADO (TRANSMARGAZ, ARIDFLOT, etc. — su nombre o email está
      //      en USUARIO_A_TRANSPORTISTA) → dropdown con SOLO su empresa, preseleccionada.
      //      Motivo: solo suben sus propios albaranes y, si la IA no detectó el transportista
      //      por matrícula ilegible u otro motivo, al editar le aparece SU empresa por defecto
      //      para asignarla con un solo clic en Guardar.
      //  (4) CONDUCTOR → input bloqueado de solo lectura (no acceden al modal hoy).
      const nombreUsuario = userMap[currentUser?.id]?.name || '';
      const transportistaSubcontratado = USUARIO_A_TRANSPORTISTA[nombreUsuario];
      const esGestorSubcontratado = currentRole === 'gestor' && transportistaSubcontratado;

      if (esGestorSubcontratado) {
        // v107k: solo ve su empresa, preseleccionada. La opción está disponible para que
        // pueda confirmar al guardar; "— Sin asignar —" sigue disponible por si el albarán
        // realmente no es suyo (caso raro pero posible, ej. error de subida).
        const suEmpresa = transportistaSubcontratado;
        const valActual = r[f.k] || '';
        // Si el valor actual coincide con su empresa, marcarlo seleccionado. Si está vacío,
        // pre-seleccionar su empresa por defecto (caso típico: matrícula ilegible que la IA
        // no pudo identificar y por eso quedó sin transportista).
        const empresaSelected = (!valActual || valActual === suEmpresa) ? ' selected' : '';
        let opts = `<option value="">— Sin asignar —</option>`;
        // Si el valor actual NO es la empresa del subcontratado (caso raro: ej. error o
        // albarán de otra empresa subido por error), mostrarlo en amarillo arriba como aviso.
        if (valActual && valActual !== suEmpresa) {
          opts += `<option value="${esc(valActual)}" selected style="color:#ffd970">⚠ ${esc(valActual)} (no es tu empresa)</option>`;
        }
        opts += `<option value="${esc(suEmpresa)}"${empresaSelected}>${esc(suEmpresa)}</option>`;
        return `<div class="fg full"><label class="fl">${f.l}</label><select class="fi" id="mf_${f.k}" title="Solo tu empresa está disponible. Si crees que es un error, avisa a oficina.">${opts}</select></div>`;
      }

      if (currentRole === 'admin' || currentRole === 'gestor') {
        // Admin y gestor oficina: dropdown con los 13 oficiales (comportamiento v103b).
        const valActual = r[f.k] || '';
        const enLista = TRANSPORTISTAS_OFICIALES.includes(valActual);
        let opts = `<option value=""${!valActual ? ' selected' : ''}>— Sin asignar —</option>`;
        if (valActual && !enLista) {
          opts += `<option value="${esc(valActual)}" selected style="color:#ffd970">⚠ ${esc(valActual)} (no oficial — elegir uno abajo)</option>`;
        }
        opts += TRANSPORTISTAS_OFICIALES.map(t => `<option value="${esc(t)}"${(enLista && t === valActual) ? ' selected' : ''}>${esc(t)}</option>`).join('');
        return `<div class="fg full"><label class="fl">${f.l}</label><select class="fi" id="mf_${f.k}">${opts}</select></div>`;
      }

      // Conductor: solo lectura
      return `<div class="fg full"><label class="fl">${f.l}</label><input class="fi" id="mf_${f.k}" value="${val}" disabled title="Solo oficina puede modificar este campo" style="background:var(--s2);color:var(--mu);cursor:not-allowed;opacity:.7"></div>`;
    }
    // v107i: Proveedor / Origen / Destino como SELECT cerrado para admin y gestor.
    // Si en el futuro hay que añadir un proveedor/origen/destino nuevo, Juan Carlos avisa
    // y se añade a la lista CANONICOS correspondiente — NO se permite escribir libre aquí.
    // v107W: añadido cliente/comprador con misma lógica (CLIENTES_CANONICOS).
    if ((f.k === 'proveedor' || f.k === 'planta' || f.k === 'obra' || f.k === 'cliente')
        && (currentRole === 'admin' || currentRole === 'gestor')) {
      const lista = f.k === 'proveedor' ? PROVEEDORES_CANONICOS
                  : f.k === 'planta'    ? ORIGENES_CANONICOS
                  : f.k === 'obra'      ? DESTINOS_CANONICOS
                  :                       CLIENTES_CANONICOS;
      // Solo los nombres canónicos (sin alias) ordenados alfabéticamente en español
      const oficiales = lista.map(x => x.canon).sort((a, b) => a.localeCompare(b, 'es'));
      const valGuardado = r[f.k] || '';
      // v107BP: el valor guardado puede ser un ALIAS de un destino/origen/etc
      // oficial (ej. "RIUDELLOTS DE LA SELVA" en vez del canónico "Riudellots
      // de la Selva"), o venir con código postal delante. matchExacto lo
      // canoniza: si encuentra el oficial, lo usamos para que el desplegable
      // muestre el oficial SELECCIONADO y NO el aviso amarillo "no oficial".
      const valCanon = valGuardado ? matchExacto(valGuardado, lista) : '';
      const valActual = (valCanon && oficiales.includes(valCanon)) ? valCanon : valGuardado;
      const enLista = oficiales.includes(valActual);
      let opts = `<option value=""${!valActual ? ' selected' : ''}>— Sin asignar —</option>`;
      if (valActual && !enLista) {
        opts += `<option value="${esc(valActual)}" selected style="color:#ffd970">⚠ ${esc(valActual)} (no oficial — elegir uno abajo)</option>`;
      }
      opts += oficiales.map(o => `<option value="${esc(o)}"${(enLista && o === valActual) ? ' selected' : ''}>${esc(o)}</option>`).join('');
      // v107BR: botón "✏️ Escribir" SOLO para admin (no gestor). Permite a
      // Juan Carlos teclear a mano cualquier destino/origen/proveedor/cliente
      // nuevo que no esté en la lista oficial, sin esperar a que se añada al
      // código. El botón cambia el desplegable por una casilla de texto libre.
      // Cuando haya muchos escritos a mano, se recogen y se añaden a la lista
      // oficial de golpe. El valor escrito a mano se guarda tal cual (si por
      // casualidad coincide con un alias oficial, matchExacto lo canoniza al
      // guardar, que es lo deseable).
      // v107GY (Juan Carlos 02/06/2026): el lápiz "✏️ Escribir" ahora también
      // para Marta y Mª del Mar (oficina nuestra, por id de usuario), para que
      // puedan editar a mano igual que el admin. El resto de gestores siguen sin él.
      const _ID_MARTA_EDIT = '6f657be7-1edd-4d5d-9895-cc6777ebbca1';
      const _ID_MARIADELMAR_EDIT = '5059731a-3e41-4578-b61e-96f20b6d8cc8';
      const _puedeEscribirLibre = (currentRole === 'admin')
        || currentUser?.id === _ID_MARTA_EDIT
        || currentUser?.id === _ID_MARIADELMAR_EDIT;
      const btnManual = _puedeEscribirLibre
        ? `<button type="button" class="bm" onclick="_modoEscribir('mf_${f.k}','${f.k}')" style="margin-left:6px;padding:4px 8px;font-size:11px;background:#1f2a1f;color:#7CFC7C;border:1px solid #2f4a2f;border-radius:6px;cursor:pointer">✏️ Escribir</button>`
        : '';
      return `<div class="fg full"><label class="fl">${f.l}${btnManual}</label><select class="fi" id="mf_${f.k}">${opts}</select></div>`;
    }
    // v107J39: el campo MATERIAL (producto) sigue siendo escribible (no rompe los
    // materiales que no son Holcim), pero añadimos DEBAJO botones pinchables con los
    // materiales Holcim habituales. Al pinchar, rellena el campo con el nombre canónico.
    if (f.k === 'producto' && (currentRole === 'admin' || currentRole === 'gestor')) {
      const chipsMat = MATERIALES_HOLCIM_CANONICOS.map(it => {
        const c = esc(it.canon);
        return `<button type="button" class="bm" onclick="document.getElementById('mf_producto').value=this.dataset.m" data-m="${c}" style="margin:2px;padding:3px 8px;font-size:11px;background:#1f2333;color:#9fc6ff;border:1px solid #2f3a5a;border-radius:6px;cursor:pointer">${c}</button>`;
      }).join('');
      return `<div class="fg full"><label class="fl">${f.l}</label>`
        + `<input class="fi" id="mf_${f.k}" value="${val}">`
        + `<div style="margin-top:6px;display:flex;flex-wrap:wrap;gap:2px">`
        + `<span style="width:100%;font-size:10px;color:var(--mu);margin-bottom:2px">Materiales Holcim (pincha para rellenar):</span>`
        + chipsMat + `</div></div>`;
    }
    return `<div class="fg${f.full?' full':''}"><label class="fl">${f.l}</label><input class="fi" id="mf_${f.k}" value="${val}"></div>`;
  }).join('');

  // v107EN6 — Sección de ANEXOS: archivos auxiliares (hoja Generalitat, copia firmada,
  // cualquier documento legal que el albarán deba conservar). NO los procesa la IA,
  // sólo los guarda en Storage y los enseña con descarga/eliminación desde el modal.
  // Datos: r.anexos = JSON array de {url, nombre, fecha}. Si no existe, vacío.
  const anexos = Array.isArray(r.anexos) ? r.anexos : [];
  const anexosHTML = anexos.length === 0
    ? `<div style="color:var(--mu);font-size:12px;padding:6px 0">(Sin anexos)</div>`
    : anexos.map((a, i) => {
        const nombre = esc(a.nombre || `anexo-${i+1}`);
        const fecha = a.fecha ? new Date(a.fecha).toLocaleDateString('es-ES') : '';
        const isAdminOGestor = (currentRole === 'admin' || currentRole === 'gestor');
        const btnDel = isAdminOGestor
          ? `<button type="button" class="bm" onclick="eliminarAnexo(${i})" title="Eliminar este anexo" style="background:#3a1f1f;color:#ff7c7c;border:1px solid #4a2f2f;border-radius:6px;padding:3px 8px;font-size:11px;cursor:pointer;margin-left:6px">✕</button>`
          : '';
        return `<div style="display:flex;align-items:center;gap:8px;padding:6px;background:var(--s2);border-radius:6px;margin-bottom:4px">
          <span style="flex:1;color:var(--fg);font-size:13px">📎 ${nombre} ${fecha ? `<span style="color:var(--mu);font-size:11px">(${fecha})</span>` : ''}</span>
          <a href="${esc(a.url)}" target="_blank" rel="noopener" class="bm" style="background:#1f2a3a;color:#7cb8fc;border:1px solid #2f3a4a;border-radius:6px;padding:3px 8px;font-size:11px;text-decoration:none">📥 Ver</a>
          ${btnDel}
        </div>`;
      }).join('');

  // Botón "+ Añadir anexo" solo para admin y gestor (no conductor)
  const btnAnexo = (currentRole === 'admin' || currentRole === 'gestor')
    ? `<div style="margin-top:8px">
        <button type="button" class="btn bs" onclick="document.getElementById('anexoFileInput').click()" style="font-size:12px;padding:6px 12px">📎 Añadir anexo</button>
        <input type="file" id="anexoFileInput" accept="application/pdf,image/*" style="display:none" onchange="subirAnexo(this.files); this.value='';">
        <span style="color:var(--mu);font-size:11px;margin-left:8px">PDF o imagen (hoja Generalitat, copia firmada, etc.)</span>
      </div>`
    : '';

  // v107EN6: inyectar sección anexos AL FINAL del contenido principal (antes del footer)
  document.getElementById('mFields').innerHTML += `<div class="fg full" style="margin-top:14px;padding-top:14px;border-top:1px solid var(--s3)">
    <label class="fl" style="font-size:13px;font-weight:600;color:var(--fg)">📎 ANEXOS <span style="color:var(--mu);font-weight:400">(${anexos.length})</span></label>
    <div id="anexosList">${anexosHTML}</div>
    ${btnAnexo}
  </div>`;
  let footer = `<button class="btn br" id="btnDel" onclick="deleteRecord()">Eliminar</button>`;
  if (r._dup) footer += `<button class="btn bw" onclick="markAsValid()">✓ Marcar válido</button>`;
  footer += `<button class="btn bs" onclick="closeModal()">Cancelar</button><button class="btn bp" onclick="saveModal()">Guardar</button>`;
  document.getElementById('mFooter').innerHTML = footer;
  document.getElementById('ov').classList.add('open');
}

function closeModal() { document.getElementById('ov').classList.remove('open'); editId = null; }

// v107BR: cambia el desplegable de destino/origen/proveedor/cliente por una
// casilla de TEXTO LIBRE para que el admin pueda escribir a mano un valor
// nuevo que no esté en la lista oficial (sin esperar a que se añada al
// código). Solo se llama desde el botón "✏️ Escribir" que solo ve el admin.
// El id del campo es el mismo (mf_XXX) así que saveModal lo lee igual.
function _modoEscribir(campoId, fk) {
  const sel = document.getElementById(campoId);
  if (!sel) return;
  // Valor actual: lo que esté seleccionado (si es un aviso "no oficial",
  // quitamos el adorno para dejar solo el nombre).
  let actual = sel.value || '';
  if (sel.selectedOptions && sel.selectedOptions[0]) {
    const txt = sel.selectedOptions[0].textContent || '';
    if (txt.indexOf('no oficial') >= 0) {
      // el value ya es el nombre limpio, lo dejamos
    }
  }
  const cont = sel.parentNode;
  const input = document.createElement('input');
  input.className = 'fi';
  input.id = campoId;            // MISMO id para que saveModal lo lea igual
  input.value = actual;
  input.placeholder = 'Escribe el valor correcto y guarda';
  input.setAttribute('autocomplete', 'off');
  sel.replaceWith(input);
  input.focus();
  input.select();
  // Oculta el botón Escribir (ya está en modo texto, no tiene sentido repetir)
  try {
    const btn = cont.querySelector('.bm');
    if (btn) btn.style.display = 'none';
  } catch (e) {}
}

// v107EN6 — Anexos: archivos auxiliares (PDFs, imágenes) que se adjuntan al
// albarán para conservar documentación legal (hoja Generalitat, copia firmada,
// etc.). NO se procesan con IA: solo se suben a Storage y se guarda la URL
// en el array JSONB `albaranes.anexos`. Visible en el modal con botones
// "Ver" (abre en pestaña nueva) y "✕" (eliminar, solo admin/gestor).
async function subirAnexo(files) {
  if (!files || !files.length) return;
  if (!editId) { toast('Primero abre el albarán', 'err'); return; }
  const r = records.find(x => String(x.db_id) === String(editId) || String(x._id) === String(editId));
  if (!r || !r.db_id) { toast('Guarda el albarán antes de añadir anexos', 'err'); return; }
  const f = files[0];
  if (!f) return;
  // Protección contra archivos vacíos
  if (!f.size || f.size < 100) {
    toast('⚠️ El archivo está vacío o no se descargó bien.', 'err');
    return;
  }
  // Tamaño máximo razonable: 10 MB (PDFs grandes pueden romper la API)
  if (f.size > 10 * 1024 * 1024) {
    toast('⚠️ Archivo demasiado grande (máx 10 MB).', 'err');
    return;
  }
  toast('📎 Subiendo anexo...');
  try {
    // Generar nombre único: anexos/{db_id}/{timestamp}-{nombre_original}
    const ts = Date.now();
    const safeName = f.name.replace(/[^a-zA-Z0-9._-]/g, '_').substring(0, 80);
    const path = `anexos/${r.db_id}/${ts}-${safeName}`;
    const { error: upErr } = await sb.storage.from('documentos').upload(path, f, {
      contentType: f.type || 'application/octet-stream',
      upsert: false
    });
    if (upErr) throw upErr;
    // URL pública
    const { data: urlData } = sb.storage.from('documentos').getPublicUrl(path);
    const url = urlData.publicUrl;
    // Añadir al array anexos del albarán
    const anexosActuales = Array.isArray(r.anexos) ? r.anexos.slice() : [];
    anexosActuales.push({
      url,
      nombre: f.name,
      fecha: new Date().toISOString(),
      path  // guardamos también el path por si hay que borrar de Storage
    });
    // Guardar en BD
    const { error: dbErr } = await sb.from('albaranes')
      .update({ anexos: anexosActuales })
      .eq('id', r.db_id);
    if (dbErr) throw dbErr;
    // Actualizar en memoria y re-renderizar la sección de anexos
    r.anexos = anexosActuales;
    _renderAnexosEnModal(r);
    toast(`✓ Anexo añadido: ${f.name}`);
    console.log('[v107EN6 subirAnexo] OK:', f.name, '→', path);
  } catch (e) {
    console.error('[v107EN6 subirAnexo] Error:', e);
    toast('Error subiendo anexo: ' + (e.message || e), 'err');
  }
}

async function eliminarAnexo(idx) {
  if (!editId) return;
  const r = records.find(x => String(x.db_id) === String(editId) || String(x._id) === String(editId));
  if (!r || !r.db_id) return;
  const anexos = Array.isArray(r.anexos) ? r.anexos : [];
  if (idx < 0 || idx >= anexos.length) return;
  const anexo = anexos[idx];
  if (!confirm(`¿Eliminar el anexo "${anexo.nombre || 'anexo'}"?\n\nSe borrará del Storage y del albarán. No se puede deshacer.`)) return;
  toast('Eliminando anexo...');
  try {
    // 1) Borrar de Storage (si tiene path)
    if (anexo.path) {
      const { error: rmErr } = await sb.storage.from('documentos').remove([anexo.path]);
      if (rmErr) console.warn('[v107EN6 eliminarAnexo] No se pudo borrar de Storage:', rmErr.message);
      // No abortar: si el archivo ya no existe en Storage, seguimos quitándolo de BD
    }
    // 2) Quitar del array en BD
    const nuevosAnexos = anexos.filter((_, i) => i !== idx);
    const { error: dbErr } = await sb.from('albaranes')
      .update({ anexos: nuevosAnexos })
      .eq('id', r.db_id);
    if (dbErr) throw dbErr;
    // 3) Actualizar memoria y re-renderizar
    r.anexos = nuevosAnexos;
    _renderAnexosEnModal(r);
    toast('✓ Anexo eliminado');
  } catch (e) {
    console.error('[v107EN6 eliminarAnexo] Error:', e);
    toast('Error eliminando anexo: ' + (e.message || e), 'err');
  }
}

// v107EN6 — Re-render de la sección de anexos dentro del modal abierto.
// Lo aislamos en función propia para reusarlo desde subirAnexo y eliminarAnexo
// sin tener que cerrar/abrir el modal entero (preserva los demás campos editados).
function _renderAnexosEnModal(r) {
  const cont = document.getElementById('anexosList');
  if (!cont) return;
  const anexos = Array.isArray(r.anexos) ? r.anexos : [];
  // Actualizar el contador del label
  try {
    const lbl = cont.parentNode.querySelector('.fl span');
    if (lbl) lbl.textContent = `(${anexos.length})`;
  } catch (e) {}
  if (anexos.length === 0) {
    cont.innerHTML = `<div style="color:var(--mu);font-size:12px;padding:6px 0">(Sin anexos)</div>`;
    return;
  }
  const isAdminOGestor = (currentRole === 'admin' || currentRole === 'gestor');
  cont.innerHTML = anexos.map((a, i) => {
    const nombre = esc(a.nombre || `anexo-${i+1}`);
    const fecha = a.fecha ? new Date(a.fecha).toLocaleDateString('es-ES') : '';
    const btnDel = isAdminOGestor
      ? `<button type="button" class="bm" onclick="eliminarAnexo(${i})" title="Eliminar este anexo" style="background:#3a1f1f;color:#ff7c7c;border:1px solid #4a2f2f;border-radius:6px;padding:3px 8px;font-size:11px;cursor:pointer;margin-left:6px">✕</button>`
      : '';
    return `<div style="display:flex;align-items:center;gap:8px;padding:6px;background:var(--s2);border-radius:6px;margin-bottom:4px">
      <span style="flex:1;color:var(--fg);font-size:13px">📎 ${nombre} ${fecha ? `<span style="color:var(--mu);font-size:11px">(${fecha})</span>` : ''}</span>
      <a href="${esc(a.url)}" target="_blank" rel="noopener" class="bm" style="background:#1f2a3a;color:#7cb8fc;border:1px solid #2f3a4a;border-radius:6px;padding:3px 8px;font-size:11px;text-decoration:none">📥 Ver</a>
      ${btnDel}
    </div>`;
  }).join('');
}

async function saveModal() {
  const r = records.find(x => String(x.db_id) === String(editId) || String(x._id) === String(editId));
  if (!r) { toast('No se encontró el albarán', 'err'); return; }

  // Capturar valores ANTES de modificar el record (para poder revertir si falla)
  const original = { ...r };
  const cambios = [];

  FIELDS.forEach(f => {
    const v = document.getElementById('mf_' + f.k)?.value?.trim();
    let newVal = v || null;
    // Normalización canónica al guardar manualmente: si lo que escribe el usuario coincide
    // EXACTAMENTE con un alias o canon, se reemplaza por la forma oficial. NO usamos match
    // por contención aquí (a diferencia del flujo automático): respetar lo que escribe el
    // usuario es prioritario para evitar sorpresas como "Montcada" → "Fábrica Montcada".
    if (newVal) {
      if (f.k === 'proveedor') newVal = matchExacto(newVal, PROVEEDORES_CANONICOS) || newVal;
      else if (f.k === 'planta') newVal = matchExacto(newVal, ORIGENES_CANONICOS) || newVal;
      else if (f.k === 'obra') newVal = matchExacto(newVal, DESTINOS_CANONICOS) || newVal;
      else if (f.k === 'cliente') newVal = matchExacto(newVal, CLIENTES_CANONICOS) || newVal;
      // v107J39: material Holcim → forma canónica (solo los de la lista Holcim).
      else if (f.k === 'producto') newVal = matchExacto(newVal, MATERIALES_HOLCIM_CANONICOS) || newVal;
      // v107U: quitada la canonización automática de matrícula al guardar manualmente.
      // El problema: fixMatricula busca variantes ortográficas (cambia W↔N, I↔1, etc.) y si
      // alguna variante coincide con una matrícula oficial, devuelve esa, pisando lo que el
      // usuario escribió. Ejemplo: usuario escribe "4210NGF" pero la flota tiene "4210WGF" →
      // fixMatricula devuelve "4210WGF" en lugar de "4210NGF". Al editar manualmente, lo que
      // escribe el usuario manda SIEMPRE. La normalización mínima (mayúsculas, sin espacios)
      // sí la mantenemos.
      else if (f.k === 'tractora') newVal = String(newVal).toUpperCase().replace(/\s+/g, '').replace(/-/g, '');
      else if (f.k === 'remolque') newVal = String(newVal).toUpperCase().replace(/\s+/g, '').replace(/-/g, '');
    }
    if (String(r[f.k] || '') !== String(newVal || '')) {
      cambios.push(`${f.l}: "${r[f.k]}" → "${newVal}"`);
    }
    r[f.k] = newVal;
  });

  // v76: marca "editado manualmente" — saveRecord lo persiste en columna BD manual_edit,
  // así queda protegido para SIEMPRE contra "Re-corregir TODO" y reanálisis automáticos,
  // incluso si recargas la página o cierras la sesión.
  r._manual = true;

  // v91: si el admin asignó manualmente un transportista a una matrícula desconocida y
  // dejó marcado el checkbox "Aprender", capturamos los valores AHORA (antes de cerrar el
  // modal o recargar) para llamar a aprenderMatricula tras guardar con éxito.
  let aprenderTras = null;
  const cbAprender = document.getElementById('mAprenderMat');
  if (cbAprender && cbAprender.checked && r.tractora && r.transportista && !getTransportista(r.tractora)) {
    aprenderTras = { matricula: r.tractora, transportista: r.transportista };
  }

  // v91c: si el admin marcó el segundo checkbox "Aplicar también a los N existentes",
  // recopilamos los IDs de los otros albaranes con la misma matrícula para hacer un
  // UPDATE masivo en BD tras guardar con éxito el albarán actual.
  let aplicarHistorico = null;
  const cbHist = document.getElementById('mAplicarHistorico');
  if (cbHist && cbHist.checked && r.tractora && r.transportista) {
    const matNorm = String(r.tractora).trim().toUpperCase().replace(/\s+/g,'');
    const ids = records.filter(x =>
      x !== r &&
      !x._dup &&
      x.db_id &&
      x.tractora &&
      String(x.tractora).trim().toUpperCase().replace(/\s+/g,'') === matNorm
    ).map(x => x.db_id);
    if (ids.length > 0) {
      aplicarHistorico = { ids, transportista: r.transportista };
    }
  }

  console.log('[saveModal] Cambios:', cambios);
  console.log('[saveModal] Datos a guardar:', r);

  // v107d: GUARDADO INSTANTÁNEO — cerramos modal y refrescamos UI ANTES de esperar
  // a Supabase. Antes esto tardaba 2-5 segundos porque hacía `await saveRecord` + `await
  // loadData()` (recargar los 2197 albaranes). Ahora:
  // 1) Modal se cierra al instante
  // 2) UI se actualiza con los cambios en memoria (ya están aplicados al record r)
  // 3) Supabase se actualiza en SEGUNDO PLANO (no bloquea al usuario)
  // 4) Si Supabase falla, revertimos el cambio en memoria y avisamos
  // Esto ahorra al admin docenas de refrescos manuales al día.

  // Cerrar modal AL INSTANTE
  closeModal();

  // Refrescar UI local con los cambios ya aplicados a r
  try {
    analyzeRecords();
    applyFilters();
    updateStats();
    renderAlerts();
  } catch (eUi) { console.error('[saveModal] Error refrescando UI local:', eUi); }

  // Mensaje optimista
  if (cambios.length === 0) {
    toast('Sin cambios');
  } else {
    toast(`✓ Guardando ${cambios.length} ${cambios.length === 1 ? 'cambio' : 'cambios'}...`);
  }

  // Guardar en BD EN SEGUNDO PLANO (sin await — el usuario ya puede seguir trabajando)
  (async () => {
    try {
      // 1) Guardar en BD. v107GL: con REINTENTOS. El guardado fallaba de forma intermitente
      // (a JC y a Aridflot) por tropiezos de conexión con Supabase: un solo fallo hacía que
      // el catch revirtiera el cambio (Object.assign(r, original)) y pareciera que "no se
      // guardaba / volvía atrás". Ahora reintenta hasta 3 veces con pausa creciente antes de
      // rendirse, así un tropiezo puntual se supera solo y el cambio NO se pierde.
      let _guardadoOK = false;
      let _ultimoErr = null;
      for (let _intento = 1; _intento <= 3; _intento++) {
        try {
          await saveRecord(r);
          _guardadoOK = true;
          break;
        } catch (eIntento) {
          _ultimoErr = eIntento;
          console.warn(`[v107GL] Guardado intento ${_intento}/3 falló (alb ${r.albaran}):`, eIntento.message || eIntento);
          if (_intento < 3) await new Promise(res => setTimeout(res, 1500 * _intento));
        }
      }
      if (!_guardadoOK) throw (_ultimoErr || new Error('No se pudo guardar tras 3 intentos'));

      // v107U: VERIFICACIÓN POST-GUARDADO. Re-leer el albarán de BD y comparar con lo que
      // mandamos. Si difiere → bug silencioso (RLS, trigger, otro proceso pisando...).
      // Esto antes no se hacía y por eso bugs como el de la matrícula pasaban desapercibidos.
      if (r.db_id) {
        try {
          const { data: verif, error: vErr } = await sb.from('albaranes').select('*').eq('id', r.db_id).single();
          if (!vErr && verif) {
            const camposVerif = ['tractora', 'proveedor', 'planta', 'obra', 'producto', 'cliente', 'albaran', 'fecha', 'transportista'];
            const discrepancias = [];
            camposVerif.forEach(k => {
              const enviado = String(r[k] || '');
              const enBd = String(verif[k] || '');
              if (enviado !== enBd) {
                discrepancias.push(`${k}: enviado="${enviado}" pero BD tiene="${enBd}"`);
              }
            });
            if (discrepancias.length > 0) {
              // v107GZ: NO revertimos el dato en memoria. El guardado con .select() de
              // saveRecord YA garantiza que la fila se actualizó de verdad (si no, habría
              // lanzado error y no llegaríamos aquí). Si la RE-LECTURA de comprobación
              // devuelve valores viejos, casi siempre es por el pooler/replica de Supabase
              // sirviendo un dato con retraso (no porque el guardado fallara). Antes
              // revertíamos a esos valores viejos y por eso "el cambio desaparecía". Ahora
              // solo lo dejamos anotado en consola y mantenemos lo que el usuario guardó.
              console.warn('[saveModal v107GZ] La relectura de comprobación devolvió valores distintos (probable retraso del pooler de Supabase). El guardado SÍ se aplicó (.select() lo confirmó). NO se revierte. Detalle:', discrepancias);
            } else {
              console.log(`[saveModal v107U] ✓ Verificación OK — todos los campos guardados correctamente (alb ${r.albaran})`);
            }
          }
        } catch (eV) {
          console.warn('[saveModal v107U] No se pudo verificar el guardado:', eV);
        }
      }

      // 2) Aprender matrícula si procede
      if (aprenderTras) {
        const nombreUsuario = userMap[currentUser?.id]?.name || currentUser?.email || 'admin';
        aprenderMatricula(aprenderTras.matricula, aprenderTras.transportista, nombreUsuario);
      }

      // 3) Aplicar a histórico si procede (UPDATE masivo)
      let histActualizados = 0;
      if (aplicarHistorico) {
        try {
          const { error: errHist } = await sb.from('albaranes')
            .update({ transportista: aplicarHistorico.transportista })
            .in('id', aplicarHistorico.ids);
          if (errHist) {
            console.error('[v91c] Error aplicando histórico:', errHist);
            toast(`✗ Error en histórico: ${errHist.message}`, 'err');
          } else {
            histActualizados = aplicarHistorico.ids.length;
            // Aplicar también en memoria a esos registros
            records.forEach(x => {
              if (aplicarHistorico.ids.includes(x.db_id)) {
                x.transportista = aplicarHistorico.transportista;
              }
            });
            try { applyFilters(); updateStats(); } catch(e) {}
            console.log(`[v91c] Histórico actualizado: ${histActualizados} albaranes con matrícula ${r.tractora} → ${aplicarHistorico.transportista}`);
          }
        } catch (e) {
          console.error('[v91c] Excepción aplicando histórico:', e);
          toast(`✗ Error en histórico: ${e.message}`, 'err');
        }
      }

      // 4) Mensaje final de éxito
      const partes = [];
      if (cambios.length > 0) partes.push(`${cambios.length} ${cambios.length === 1 ? 'cambio guardado' : 'cambios guardados'}`);
      if (histActualizados > 0) partes.push(`+${histActualizados} hist.`);
      if (partes.length > 0) toast(`✓ ${partes.join(' · ')}`);
    } catch (e) {
      // Revertir cambios en memoria y avisar. v107GL: esto solo ocurre ya tras 3 intentos
      // fallidos, así que es un fallo real de conexión/permisos, no un tropiezo puntual.
      console.error('[saveModal] Error completo tras reintentos:', e);
      Object.assign(r, original);
      try {
        analyzeRecords();
        applyFilters();
        updateStats();
        renderAlerts();
      } catch (eUi) {}
      const msg = e.message || JSON.stringify(e);
      toast(`✗ NO se pudo guardar (se intentó 3 veces). Vuelve a abrirlo y reintenta. Detalle: ${msg}`, 'err');
    }
  })();
}

function markAsValid() {
  const r = records.find(x => String(x.db_id) === String(editId) || String(x._id) === String(editId));
  if (!r) return;
  const orig = records.find(x => String(x.db_id) === String(r._dupOf) || String(x._id) === String(r._dupOf));
  if (orig) { orig._dup = true; orig._dupOf = r.db_id || r._id; }
  r._dup = false; r._dupOf = null;
  analyzeRecords(); applyFilters(); updateStats(); renderAlerts(); closeModal(); toast('✓ Marcado válido');
}

async function deleteRecord() {
  // v83c: confirmación nativa del navegador. Antes el patrón "doble clic" hacía que mucha
  // gente pinchara una vez, viera "¿Confirmar?" y pensara que no funcionaba. Ahora aparece
  // un cuadro de diálogo claro con OK/Cancelar.
  const r = records.find(x => String(x.db_id) === String(editId) || String(x._id) === String(editId));
  if (!r) { toast('No se encontró el albarán', 'err'); return; }
  const desc = r.albaran ? `albarán Nº ${r.albaran}` : 'este albarán';
  if (!confirm(`¿Eliminar ${desc}?\n\nEsta acción no se puede deshacer.`)) return;
  // Bloquear el botón para evitar doble click mientras procesa
  const btn = document.getElementById('btnDel');
  if (btn) { btn.disabled = true; btn.textContent = 'Eliminando...'; }
  try {
    if (r.db_id) await deleteRecordDB(r.db_id);
    // v83c: recargar TODO desde BD (fuente de verdad) en lugar de solo filtrar memoria.
    // Garantiza que el registro eliminado no reaparece tras un refresh ni queda inconsistencia.
    await loadData();
    closeModal();
    toast('✓ Eliminado');
  } catch (e) {
    console.error('[deleteRecord] Error:', e);
    // v100b: tolerancia a errores. A veces Supabase devuelve error en el delete pero la
    // operación SÍ se completó (típico con RLS). Recargamos y verificamos si el registro
    // sigue existiendo. Si NO existe, fue un éxito a pesar del error → silenciamos el aviso.
    try {
      await loadData();
      const stillExists = records.some(x => String(x.db_id) === String(r.db_id));
      if (!stillExists) {
        // El registro ya no está → el borrado funcionó realmente. Ignorar el error.
        closeModal();
        toast('✓ Eliminado');
        return;
      }
    } catch (e2) { /* ignorar fallo en la verificación */ }
    toast('Error eliminando: ' + (e.message || e), 'err');
    if (btn) { btn.disabled = false; btn.textContent = 'Eliminar'; }
  }
}

