// MODAL GASOIL
// ============================================================
const GAS_FIELDS = [
  {k:'fecha',l:'Fecha'},{k:'tractora',l:'Matrícula'},
  {k:'proveedor',l:'Proveedor',full:true},{k:'tipo',l:'Tipo (gasoil/adblue)'},
  {k:'litros',l:'Litros'},{k:'importe',l:'Importe (€)'},
  {k:'precio_litro',l:'€/Litro'},{k:'num_ticket',l:'Nº Ticket',full:true},
  {k:'observaciones',l:'Observaciones',full:true},
];

function openGasModal(id) {
  const r = gasoilRecords.find(x => String(x.db_id) === String(id) || String(x._id) === String(id));
  if (!r) return;
  editGasId = id;
  let previewHtml = '';
  if (hasValidUrl(r.file_url)) {
    const isImg = /\.(jpg|jpeg|png|gif|webp)(\?|#|$)/i.test(r.file_url);
    const isPdf = /\.pdf(\?|#|$)/i.test(r.file_url);
    if (isImg) {
      // v97i: imágenes en gasoil también con zoom igual que en albaranes
      previewHtml = `
        <div id="pdfZoomWrapGas" class="pdf-zoom-wrap" data-is-img="1">
          <div class="pdf-zoom-controls">
            <button class="pdf-zoom-btn" onclick="zoomImgBtn('pdfZoomWrapGas',-1)" title="Reducir">🔍−</button>
            <button class="pdf-zoom-btn" onclick="zoomImgReset('pdfZoomWrapGas')" title="Tamaño original">↺</button>
            <button class="pdf-zoom-btn" onclick="zoomImgBtn('pdfZoomWrapGas',1)" title="Ampliar">🔍+</button>
            <span class="pdf-zoom-info">100%</span>
          </div>
          <img src="${r.file_url}" alt="Ticket gasoil" style="display:block;margin:0 auto;max-width:100%;height:auto;cursor:pointer" onclick="window.open('${r.file_url}','_blank')">
        </div>
        <div style="margin-top:8px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
          <span style="font-family:var(--mn);font-size:11px;color:var(--mu)">🔍 Usa los botones <strong style="color:var(--ac)">+</strong> y <strong style="color:var(--ac)">−</strong> para hacer zoom</span>
          <a href="${r.file_url}" target="_blank" class="preview-btn">📄 Abrir ticket original</a>
        </div>`;
    } else if (isPdf) {
      previewHtml = `
        <div id="pdfZoomWrapGas" class="pdf-zoom-wrap">
          <div class="pdf-zoom-controls">
            <button class="pdf-zoom-btn" onclick="zoomBtn('pdfZoomWrapGas',-1)" title="Reducir">🔍−</button>
            <button class="pdf-zoom-btn" onclick="zoomReset('pdfZoomWrapGas')" title="Tamaño original">↺</button>
            <button class="pdf-zoom-btn" onclick="zoomBtn('pdfZoomWrapGas',1)" title="Ampliar">🔍+</button>
            <span class="pdf-zoom-info">100%</span>
          </div>
          <canvas id="pdfPreviewCanvasGas"></canvas>
          <div id="pdfPreviewLoadingGas" style="text-align:center;padding:40px;color:var(--mu);font-family:var(--mn);font-size:11px">📄 Cargando vista previa...</div>
        </div>
        <div style="margin-top:8px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
          <span style="font-family:var(--mn);font-size:11px;color:var(--mu)">🔍 Usa los botones <strong style="color:var(--ac)">+</strong> y <strong style="color:var(--ac)">−</strong> para hacer zoom</span>
          <a href="${r.file_url}" target="_blank" class="preview-btn">📄 Abrir ticket original</a>
        </div>`;
    } else {
      previewHtml = `<a href="${r.file_url}" target="_blank" class="preview-btn">📄 Ver ticket original</a>`;
    }
  }
  document.getElementById('mgPreview').innerHTML = previewHtml;
  if (hasValidUrl(r.file_url) && /\.pdf(\?|#|$)/i.test(r.file_url)) {
    const pageMatch = r.file_url.match(/#page=(\d+)/);
    const pageNum = pageMatch ? parseInt(pageMatch[1]) : 1;
    const cleanUrl = r.file_url.split('#')[0];
    setTimeout(() => {
      renderPdfPagePreview(cleanUrl, pageNum, 'pdfPreviewCanvasGas', 'pdfPreviewLoadingGas');
    }, 50);
  }
  document.getElementById('mgFields').innerHTML = GAS_FIELDS.map(f => `<div class="fg${f.full?' full':''}"><label class="fl">${f.l}</label><input class="fi" id="mgf_${f.k}" value="${r[f.k] != null ? String(r[f.k]).replace(/"/g,'&quot;') : ''}"></div>`).join('');
  document.getElementById('mgFooter').innerHTML = `<button class="btn br" id="btnDelGas" onclick="deleteGasRecord()">Eliminar</button><button class="btn bs" onclick="closeGasModal()">Cancelar</button><button class="btn bp" onclick="saveGasModal()">Guardar</button>`;
  document.getElementById('ovGas').classList.add('open');
}
function closeGasModal() { document.getElementById('ovGas').classList.remove('open'); editGasId = null; }
async function saveGasModal() {
  const r = gasoilRecords.find(x => String(x.db_id) === String(editGasId) || String(x._id) === String(editGasId));
  if (!r) return;
  // v107i: BUG ARREGLADO. El código antiguo hacía `sb.from('gasoil').update(r)` pasando
  // el objeto entero del record. Eso incluía campos LOCALES (db_id, _id, _ts, _fromPending,
  // _quality...) que NO son columnas reales de la tabla `gasoil` en Supabase. Resultado:
  // PATCH .../gasoil → 400 Bad Request, los cambios nunca llegaban a la BD, y al recargar
  // volvían a aparecer los datos originales que leyó la IA del ticket.
  // Solución: delegar en saveGasRecord (línea ~1147), que YA hace la limpieza correcta
  // (Object.keys → delete _*, delete db_id) y usa el .eq('id', db_id) para el WHERE.
  // Además añadimos snapshot + revertir si falla, igual que saveModal de albaranes (v107d).
  const original = { ...r };
  GAS_FIELDS.forEach(f => { const v = document.getElementById('mgf_' + f.k)?.value?.trim(); r[f.k] = v || null; });
  try {
    if (r.db_id) await saveGasRecord(r);
    applyGasFilters(); closeGasModal(); toast('✓ Guardado');
  } catch (e) {
    // Revertir cambios en memoria (la BD no se actualizó)
    Object.assign(r, original);
    try { applyGasFilters(); } catch (eUi) {}
    console.error('[saveGasModal] Error:', e);
    toast('Error: ' + (e.message || JSON.stringify(e)), 'err');
  }
}

// Borra ticket de gasoil con patrón doble clic (10s para confirmar)
async function deleteGasRecord() {
  const btn = document.getElementById('btnDelGas');
  if (btn && !btn.dataset.confirming) {
    btn.dataset.confirming = '1';
    const original = btn.textContent;
    btn.textContent = '¿Confirmar borrado?';
    btn.style.background = '#ff3333';
    btn.style.color = '#fff';
    setTimeout(() => {
      if (btn && btn.dataset.confirming) {
        delete btn.dataset.confirming;
        btn.textContent = original;
        btn.style.background = '';
        btn.style.color = '';
      }
    }, 10000);
    return;
  }
  if (btn) delete btn.dataset.confirming;
  const r = gasoilRecords.find(x => String(x.db_id) === String(editGasId) || String(x._id) === String(editGasId));
  try {
    if (r?.db_id) {
      const { error } = await sb.from('gasoil').delete().eq('id', r.db_id);
      if (error) throw error;
    }
    gasoilRecords = gasoilRecords.filter(x => String(x.db_id) !== String(editGasId) && String(x._id) !== String(editGasId));
    applyGasFilters();
    document.getElementById('tabGasCount').textContent = gasoilRecords.length;
    closeGasModal();
    toast('✓ Ticket eliminado');
  } catch (e) { toast('Error eliminando: ' + e.message, 'err'); }
}

// ============================================================
// EXCEL
// ============================================================
const ECOLS = ['fecha','tractora','tm','precio','albaran','proveedor','planta','obra','producto','cliente','remolque','transportista','tara_kg','bruto_kg','hora_entrada','hora_salida','observaciones'];
// v95b: Total movido al lado de Precio (columna E). Antes estaba al final como col S.
// Ahora el orden es: FECHA | MATRICULA | TN NETAS | PRECIO | TOTAL | Nº ALBARAN | ...
const EHEAD = ['FECHA','MATRICULA','TN NETAS','PRECIO (€/TN)','TOTAL (€)','Nº DE ALBARAN','NOMBRE PROVEEDOR','ORIGEN','DESTINO','MATERIAL','NOMBRE COMPRADOR','REMOLQUE','TRANSPORTISTA','TARA (KG)','BRUTO (KG)','H.ENTRADA','H.SALIDA','OBSERVACIONES','SUBIDO POR','EDITADO POR','ESTADO'];

function buildExcel(data) {
  // v84: ordenar SIEMPRE por:
  //   1) Fecha del albarán ASCENDENTE (más antiguo arriba)
  //   2) Matrícula numérica (0742 antes que 5360, gracias a localeCompare con numeric:true)
  //   3) Nº albarán
  // Esto NO afecta a la pantalla (que usa sortCol/sortDir). Solo al Excel exportado.
  const ordered = [...data].sort((a, b) => {
    // 1) Fecha ascendente
    const fa = fechaSortNum(a.fecha), fb = fechaSortNum(b.fecha);
    if (fa !== fb) return fa - fb;
    // 2) Matrícula numérica (vacías al final)
    const ma = String(a.tractora || '').toUpperCase().replace(/\s+/g, '').trim();
    const mb = String(b.tractora || '').toUpperCase().replace(/\s+/g, '').trim();
    if (ma !== mb) {
      if (!ma) return 1;
      if (!mb) return -1;
      return ma.localeCompare(mb, 'es', { numeric: true });
    }
    // 3) Nº albarán
    const aa = String(a.albaran || '').trim();
    const ab = String(b.albaran || '').trim();
    if (/^\d+$/.test(aa) && /^\d+$/.test(ab)) return parseInt(aa) - parseInt(ab);
    return aa.localeCompare(ab, 'es', { numeric: true });
  });
  const valid = ordered.filter(r => !r._dup), tmTot = valid.reduce((s, r) => s + (parseFloat(r.tm) || 0), 0);
  // v95b: Total ahora va al lado de Precio (columna E). TN=C, Precio=D, Total=E.
  // Fórmula =C*D para que al editar el precio se calcule solo.
  const rows = [EHEAD, ...ordered.map((r, idx) => {
    const tm = parseFloat(r.tm) || 0;
    // Precio siempre numérico (0 por defecto si no hay valor) — facilita edición posterior.
    const precio = r.precio != null && r.precio !== '' ? parseFloat(r.precio) : 0;
    // Total como FÓRMULA. Al editar el precio en Excel, el total se recalcula solo.
    const filaExcel = idx + 2; // +1 header, +1 base 1 Excel
    const totalFormula = { f: `C${filaExcel}*D${filaExcel}` };
    // Construimos la fila campo a campo en el orden EXACTO de EHEAD:
    // FECHA, MATRICULA, TN, PRECIO, TOTAL, Nº ALBARAN, PROV, ORIGEN, DEST, MATERIAL,
    // COMPRADOR, REMOLQUE, TRANSPORTISTA, TARA, BRUTO, H.ENT, H.SAL, OBS, SUBIDO POR, ESTADO
    return [
      r.fecha != null ? r.fecha : '',
      r.tractora != null ? r.tractora : '',
      tm,
      precio,
      totalFormula,
      r.albaran != null ? r.albaran : '',
      r.proveedor != null ? r.proveedor : '',
      r.planta != null ? r.planta : '',
      r.obra != null ? r.obra : '',
      r.producto != null ? r.producto : '',
      r.cliente != null ? r.cliente : '',
      r.remolque != null ? r.remolque : '',
      r.transportista != null ? r.transportista : '',
      r.tara_kg != null ? r.tara_kg : '',
      r.bruto_kg != null ? r.bruto_kg : '',
      r.hora_entrada != null ? r.hora_entrada : '',
      r.hora_salida != null ? r.hora_salida : '',
      r.observaciones != null ? r.observaciones : '',
      userName(r.user_id),
      r.editado_por ? userName(r.editado_por) : '',
      r._dup ? 'DUPLICADO' : r._quality === 'ilegible' ? 'REVISAR-ILEGIBLE' : r._quality === 'warn' ? 'REVISAR' : 'OK'
    ];
  })];
  // Fila TOTAL al final con SUMA de TN y de Total. TN en C, Total en E.
  const filaUltimaDato = rows.length;
  const filaSuma = ['', 'TOTAL', { f: `SUM(C2:C${filaUltimaDato})` }, '', { f: `SUM(E2:E${filaUltimaDato})` }, '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', ''];
  rows.push(filaSuma);
  const ws = XLSX.utils.aoa_to_sheet(rows);
  // v107CP: 21 anchos (añadido 18 para EDITADO POR entre SUBIDO POR y ESTADO).
  ws['!cols'] = [10,10,9,12,12,14,22,18,22,20,24,10,22,10,10,8,8,24,18,18,12].map(w => ({wch: w}));
  // Alineación centrada en TODAS las celdas + formato moneda en Precio (D) y Total (E).
  const range = XLSX.utils.decode_range(ws['!ref']);
  for (let R = range.s.r; R <= range.e.r; R++) {
    for (let C = range.s.c; C <= range.e.c; C++) {
      const addr = XLSX.utils.encode_cell({ r: R, c: C });
      if (!ws[addr]) ws[addr] = { t: 's', v: '' };
      if (!ws[addr].s) ws[addr].s = {};
      ws[addr].s.alignment = { horizontal: 'center', vertical: 'center' };
      // Precio (col 3 = D) y Total (col 4 = E): formato € con 2 decimales
      if (R > 0 && (C === 3 || C === 4)) {
        ws[addr].z = '#,##0.00 €';
      }
      // v107J14: TODAS las celdas en NEGRITA y un punto más grandes (tamaño 13, por
      // defecto Excel usa 11) para que Juan Carlos las lea mejor sin gafas. La cabecera
      // (fila 0) y la fila TOTAL (última) un poco más grandes aún (14).
      ws[addr].s.font = { bold: true, sz: 13 };
      if (R === 0 || R === range.e.r) ws[addr].s.font = { bold: true, sz: 14 };
    }
  }
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Albaranes');
  const agg = key => valid.reduce((acc, r) => { const k = r[key] || 'Sin dato'; if (!acc[k]) acc[k] = {n:0,tm:0}; acc[k].n++; acc[k].tm += parseFloat(r.tm) || 0; return acc; }, {});
  const now = new Date();
  const sum = [['RESUMEN'],[''],['Total válidos',valid.length],['Total TN',+tmTot.toFixed(3)],['Duplicados',data.filter(r=>r._dup).length],['Exportado',now.toLocaleDateString('es-ES')],
    [''],['POR PROVEEDOR','Alb','TN'],...Object.entries(agg('proveedor')).sort((a,b)=>b[1].tm-a[1].tm).map(([k,v])=>[k,v.n,+v.tm.toFixed(3)]),
    [''],['POR ORIGEN','Alb','TN'],...Object.entries(agg('planta')).sort((a,b)=>b[1].tm-a[1].tm).map(([k,v])=>[k,v.n,+v.tm.toFixed(3)]),
    [''],['POR DESTINO','Alb','TN'],...Object.entries(agg('obra')).sort((a,b)=>b[1].tm-a[1].tm).map(([k,v])=>[k,v.n,+v.tm.toFixed(3)])];
  const ws2 = XLSX.utils.aoa_to_sheet(sum); ws2['!cols'] = [{wch:30},{wch:12},{wch:12}]; XLSX.utils.book_append_sheet(wb, ws2, 'Resumen');
  return { wb, tm: tmTot };
}

function exportExcel() { if (!records.length) { toast('No hay albaranes', 'err'); return; } const {wb,tm} = buildExcel(records); XLSX.writeFile(wb, `albaranes_${new Date().toISOString().slice(0,10)}.xlsx`); toast(`✓ Excel — ${records.filter(r=>!r._dup).length} válidos · ${tm.toFixed(3)} TN`); }
function exportExcelFiltrado() { if (!filtered.length) { toast('Sin datos filtrados', 'err'); return; } const {wb,tm} = buildExcel(filtered); XLSX.writeFile(wb, `albaranes_filtrado_${new Date().toISOString().slice(0,10)}.xlsx`); toast(`✓ Excel filtrado · ${tm.toFixed(3)} TN`); }

// v83: Resumen agrupado por Origen + Destino + Material.
// Construye un array de filas { origen, destino, material, viajes, tn } a partir de los albaranes
// filtrados (respeta los filtros activos), excluyendo duplicados.
function buildResumenAgrupado(source) {
  const grupos = new Map(); // clave "origen||destino||material" -> { origen, destino, material, viajes, tn }
  source.filter(r => !r._dup).forEach(r => {
    const origen = (r.planta || '—').trim();
    const destino = (r.obra || '—').trim();
    const material = (r.producto || '—').trim();
    const key = `${origen}||${destino}||${material}`;
    const tn = parseFloat(r.tm) || 0;
    if (!grupos.has(key)) {
      grupos.set(key, { origen, destino, material, viajes: 0, tn: 0 });
    }
    const g = grupos.get(key);
    g.viajes += 1;
    g.tn += tn;
  });
  // Ordenar por origen, luego destino, luego material
  return [...grupos.values()].sort((a, b) =>
    a.origen.localeCompare(b.origen) ||
    a.destino.localeCompare(b.destino) ||
    a.material.localeCompare(b.material)
  );
}

// v83: abre el modal del resumen agrupado. Si hay filtros activos, los respeta.
function abrirResumenAgrupado() {
  const fuente = filtered.length ? filtered : records;
  const filas = buildResumenAgrupado(fuente);
  if (!filas.length) { toast('No hay datos para resumir', 'err'); return; }
  const totalViajes = filas.reduce((s, f) => s + f.viajes, 0);
  const totalTn = filas.reduce((s, f) => s + f.tn, 0);
  const hayFiltros = filtered.length > 0 && filtered.length < records.filter(r => !r._dup).length;
  const filtroLabel = hayFiltros ? `<span style="color:var(--ac);font-size:11px;font-weight:normal">· Filtros aplicados</span>` : '';
  let html = `<div class="m-bd" style="padding:0;max-width:1100px">
    <div class="m-hdr"><div class="m-tit">📊 Resumen agrupado ${filtroLabel}</div>
      <div style="display:flex;gap:8px;align-items:center">
        <button class="btn bs" onclick="exportarResumenExcel()" title="Descargar este resumen como Excel">📊 Excel resumen</button>
        <button class="m-cls" onclick="cerrarModal()">✕</button>
      </div></div>
    <div style="padding:14px;max-height:75vh;overflow:auto">
      <div style="margin-bottom:12px;font-size:12px;color:var(--mt)">
        <strong style="color:var(--ac)">${filas.length}</strong> agrupaciones ·
        <strong style="color:var(--ac)">${totalViajes}</strong> viajes ·
        <strong style="color:var(--ac)">${totalTn.toFixed(3)}</strong> TN totales
      </div>
      <table style="width:100%;border-collapse:collapse;font-size:11px">
        <thead><tr style="background:rgba(0,232,122,.08);text-align:left">
          <th style="padding:8px;border-bottom:1px solid rgba(0,232,122,.3)">ORIGEN</th>
          <th style="padding:8px;border-bottom:1px solid rgba(0,232,122,.3)">DESTINO</th>
          <th style="padding:8px;border-bottom:1px solid rgba(0,232,122,.3)">MATERIAL</th>
          <th style="padding:8px;border-bottom:1px solid rgba(0,232,122,.3);text-align:right">VIAJES</th>
          <th style="padding:8px;border-bottom:1px solid rgba(0,232,122,.3);text-align:right">TONELADAS</th>
        </tr></thead><tbody>`;
  filas.forEach(f => {
    html += `<tr style="border-bottom:1px solid rgba(255,255,255,.05)">
      <td style="padding:7px 8px">${esc(f.origen)}</td>
      <td style="padding:7px 8px">${esc(f.destino)}</td>
      <td style="padding:7px 8px;color:var(--mt)">${esc(f.material)}</td>
      <td style="padding:7px 8px;text-align:right;color:var(--ac);font-weight:600">${f.viajes}</td>
      <td style="padding:7px 8px;text-align:right;color:var(--am);font-weight:600">${f.tn.toFixed(3)}</td>
    </tr>`;
  });
  html += `</tbody><tfoot><tr style="background:rgba(0,232,122,.06);font-weight:700">
      <td colspan="3" style="padding:9px 8px;border-top:2px solid rgba(0,232,122,.3)">TOTAL</td>
      <td style="padding:9px 8px;text-align:right;border-top:2px solid rgba(0,232,122,.3);color:var(--ac)">${totalViajes}</td>
      <td style="padding:9px 8px;text-align:right;border-top:2px solid rgba(0,232,122,.3);color:var(--am)">${totalTn.toFixed(3)}</td>
    </tr></tfoot></table>
    </div></div>`;
  document.getElementById('modal').innerHTML = html;
  document.getElementById('modal').style.display = 'flex';
}

// v83: descarga el resumen como Excel
function exportarResumenExcel() {
  const fuente = filtered.length ? filtered : records;
  const filas = buildResumenAgrupado(fuente);
  if (!filas.length) { toast('No hay datos', 'err'); return; }
  const totalViajes = filas.reduce((s, f) => s + f.viajes, 0);
  const totalTn = filas.reduce((s, f) => s + f.tn, 0);
  const aoa = [
    ['ORIGEN','DESTINO','MATERIAL','VIAJES','TONELADAS'],
    ...filas.map(f => [f.origen, f.destino, f.material, f.viajes, parseFloat(f.tn.toFixed(3))]),
    ['TOTAL','','', totalViajes, parseFloat(totalTn.toFixed(3))]
  ];
  const ws = XLSX.utils.aoa_to_sheet(aoa);
  ws['!cols'] = [{wch:30},{wch:30},{wch:35},{wch:8},{wch:12}];
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Resumen');
  XLSX.writeFile(wb, `resumen_agrupado_${new Date().toISOString().slice(0,10)}.xlsx`);
  toast(`✓ Resumen exportado · ${filas.length} agrupaciones · ${totalTn.toFixed(3)} TN`);
}

// v74: descarga un ZIP con TODOS los archivos (PDFs/imágenes) de los albaranes filtrados,
// más un Excel con los datos. Útil para enviar al cliente o revisar varios a la vez.
// Deduplicación: si dos albaranes comparten el mismo PDF compartido (multipágina), descarga
// el PDF una sola vez pero lo añade al ZIP con dos nombres distintos.
async function descargarArchivosFiltrados() {
  if (!filtered.length) { toast('Sin datos filtrados', 'err'); return; }
  if (typeof JSZip === 'undefined') { toast('Librería ZIP no cargada. Recarga la página.', 'err'); return; }

  const conArchivo = filtered.filter(r => hasValidUrl(r.file_url));
  if (!conArchivo.length) {
    toast('Ninguno de los filtrados tiene archivo asociado. Sólo descargo el Excel.', 'warn');
  }

  // Confirmación si son muchos (puede tardar y consumir red)
  if (conArchivo.length > 50) {
    if (!confirm(`Se van a descargar ${conArchivo.length} archivos. Puede tardar varios minutos. ¿Continuar?`)) return;
  }

  const btn = document.getElementById('btnDlFil');
  if (btn) { btn.disabled = true; btn.textContent = '⏳ Preparando...'; }

  try {
    const zip = new JSZip();

    // 1) Excel con los datos filtrados (siempre va, aunque algunos no tengan archivo)
    try {
      const { wb } = buildExcel(filtered);
      const wbArray = XLSX.write(wb, { type: 'array', bookType: 'xlsx' });
      zip.file('00_albaranes_datos.xlsx', wbArray);
    } catch (eXls) {
      console.warn('No se pudo añadir Excel al ZIP:', eXls);
    }

    // 2) Descargar archivos con cache por URL limpia (sin #page) para no descargar el mismo
    //    PDF compartido N veces. Limitamos a 4 descargas en paralelo para no saturar la red.
    const cache = new Map();
    const total = conArchivo.length;
    let progreso = 0;
    let errores = 0;

    async function descargarUno(url) {
      if (cache.has(url)) return cache.get(url);
      const promesa = (async () => {
        const resp = await fetch(url);
        if (!resp.ok) throw new Error('HTTP ' + resp.status);
        return await resp.blob();
      })();
      cache.set(url, promesa);
      return promesa;
    }

    function nombreSafe(s, max) {
      return String(s || '').replace(/[^a-zA-Z0-9_-]+/g, '_').replace(/^_+|_+$/g, '').slice(0, max || 40) || 'sd';
    }

    function nombreArchivo(r, ext) {
      const fechaSafe = (r.fecha || 'sinfecha').replace(/\//g, '-');
      const albSafe = nombreSafe(r.albaran || 'sinNum', 20);
      const matSafe = nombreSafe(r.tractora || 'sinMat', 10);
      const provSafe = nombreSafe(r.proveedor || '', 20);
      const pageMatch = (r.file_url || '').match(/#page=(\d+)/);
      const pageSuffix = pageMatch ? `_pag${pageMatch[1]}` : '';
      return `${fechaSafe}_${albSafe}_${matSafe}${provSafe ? '_' + provSafe : ''}${pageSuffix}.${ext}`;
    }

    // Procesar en lotes de 4 paralelos
    const LOTE = 4;
    const usadosNombre = new Set();
    for (let i = 0; i < conArchivo.length; i += LOTE) {
      const lote = conArchivo.slice(i, i + LOTE);
      await Promise.all(lote.map(async (r) => {
        const cleanUrl = r.file_url.split('#')[0];
        const extRaw = (cleanUrl.split('.').pop() || 'pdf').toLowerCase().split('?')[0];
        const ext = ['pdf','jpg','jpeg','png','gif','webp'].includes(extRaw) ? extRaw : 'pdf';
        try {
          const blob = await descargarUno(cleanUrl);
          let nombre = nombreArchivo(r, ext);
          // Si el nombre ya existe (raro, pero por seguridad), añadir índice
          let idx = 2;
          while (usadosNombre.has(nombre)) {
            nombre = nombreArchivo(r, ext).replace('.' + ext, `_${idx}.${ext}`);
            idx++;
          }
          usadosNombre.add(nombre);
          zip.file(nombre, blob);
        } catch (e) {
          console.warn('[v74] Error descargando', cleanUrl, e);
          errores++;
        }
        progreso++;
        if (btn) btn.textContent = `⏳ ${progreso}/${total}...`;
      }));
    }

    // 3) Generar ZIP final
    if (btn) btn.textContent = '⏳ Generando ZIP...';
    const zipBlob = await zip.generateAsync({ type: 'blob', compression: 'DEFLATE', compressionOptions: { level: 6 } });

    // 4) Descargar
    const url = URL.createObjectURL(zipBlob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `albaranes_${new Date().toISOString().slice(0,10)}_${conArchivo.length}docs.zip`;
    document.body.appendChild(a);
    a.click();
    setTimeout(() => { URL.revokeObjectURL(url); a.remove(); }, 200);

    const okCount = total - errores;
    if (errores > 0) {
      toast(`✓ ZIP descargado: ${okCount} OK, ${errores} fallidos`, 'warn');
    } else {
      toast(`✓ ZIP descargado: ${okCount} archivos + Excel`);
    }
  } catch (err) {
    console.error('Error generando ZIP:', err);
    toast('Error generando ZIP: ' + (err.message || err), 'err');
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = '📦 Descargar archivos'; }
  }
}

// Re-aplica las reglas de corrección (destino y matrícula) a todos los albaranes ya guardados
// Útil cuando se actualizan las reglas y queremos arreglar registros antiguos sin reprocesarlos
async function reanalizarTodo() {
  // v103b: solo admin puede usar esta función (corrige también el campo transportista,
  // que es operación restringida). Doble protección: el botón está oculto para gestores,
  // pero por si alguien llama a la función desde consola, también la bloqueamos aquí.
  if (currentRole !== 'admin') {
    toast('Solo el admin puede usar Re-corregir TODO', 'err');
    return;
  }
  if (!records.length) { toast('No hay albaranes', 'err'); return; }
  const protegidos = records.filter(r => r._manual).length;
  const aprocesar = records.length - protegidos;
  let confirmMsg = `Se revisarán ${aprocesar} albaranes y se corregirán origen, destino, matrícula y proveedor mal leídos.`;
  if (protegidos > 0) confirmMsg += `\n\n⚠️ En los ${protegidos} albaranes editados manualmente SOLO se actualizará el transportista (canonización por matrícula). Origen, destino, proveedor y demás campos siguen protegidos.`;
  confirmMsg += '\n\n¿Continuar?';
  if (!confirm(confirmMsg)) return;
  let cambios = 0, errores = 0, saltados = 0, manualesCanon = 0;
  toast(`🔧 Revisando ${aprocesar} albaranes...`);
  for (const r of records) {
    // v103c: para _manual, NO procesar el resto de campos, pero SÍ canonizar el transportista
    // por matrícula (operación determinística y segura). Esto permite que el filtro por
    // transportista deje de tener variantes raras en los albaranes editados a mano.
    if (r._manual) {
      saltados++;
      if (r.tractora && r.db_id) {
        const tOficial = getTransportista(r.tractora);
        if (tOficial && tOficial !== r.transportista) {
          console.log(`[manual+canon] Transportista: "${r.transportista || '(vacío)'}" → "${tOficial}" (mat ${r.tractora}, alb ${r.albaran})`);
          const valorAnterior = r.transportista;
          r.transportista = tOficial;
          try {
            const { error } = await sb.from('albaranes').update({ transportista: tOficial }).eq('id', r.db_id);
            if (error) { errores++; r.transportista = valorAnterior; console.error('Error guardando manual+transp', r.albaran, error); }
            else manualesCanon++;
          } catch (e) { errores++; r.transportista = valorAnterior; console.error(e); }
        }
      }
      // v106: además, si el transportista actual (después del intento por matrícula) sigue
      // siendo una variante rara reconocible por nombre, canonizarlo también. Cubre el caso
      // de manual + matrícula desconocida + transportista guardado con variante rara.
      if (r.transportista && r.db_id) {
        const tFix = fixTransportista(r.transportista);
        if (tFix !== r.transportista) {
          console.log(`[manual+canon-nombre] "${r.transportista}" → "${tFix}" (alb ${r.albaran})`);
          const valorAnterior = r.transportista;
          r.transportista = tFix;
          try {
            const { error } = await sb.from('albaranes').update({ transportista: tFix }).eq('id', r.db_id);
            if (error) { errores++; r.transportista = valorAnterior; console.error('Error guardando manual+nombre', r.albaran, error); }
            else manualesCanon++;
          } catch (e) { errores++; r.transportista = valorAnterior; console.error(e); }
        }
      }
      continue;
    }
    let cambio = false;
    const update = {};
    // Corregir destino (obra)
    // v107E8: misma excepción que v107E7 — Holcim cisterna cemento NO se canoniza,
    // el destino se queda LITERAL como vino del PDF (línea 1 bajo Obra:).
    if (r.obra) {
      const _esHolcimCem2 = /Holcim/i.test(r.proveedor || '')
        && /\bECOPlanet\b|(?:^|\s)C[EF][MN]\s+[IVX/]+|Cemento\s+(?:Portland|Puzol)|CEM\s+[IVX]+\/[A-Z]/i.test(r.producto || '')
        && !/F[áa]brica\s+Montcada/i.test(String(r.obra).trim());
      if (!_esHolcimCem2) {
        const nuevoDest = fixDestino(r.obra);
        if (nuevoDest !== r.obra) {
          console.log(`Destino: "${r.obra}" → "${nuevoDest}" (alb ${r.albaran})`);
          r.obra = nuevoDest;
          update.obra = nuevoDest;
          cambio = true;
        }
      } else {
        console.log(`[v107E8 reanaliza] Holcim cisterna cemento: destino "${r.obra}" preservado literal (alb ${r.albaran})`);
      }
    }
    // Corregir origen (planta)
    if (r.planta) {
      const nuevoOri = fixOrigen(r.planta);
      if (nuevoOri !== r.planta) {
        console.log(`Origen: "${r.planta}" → "${nuevoOri}" (alb ${r.albaran})`);
        r.planta = nuevoOri;
        update.planta = nuevoOri;
        cambio = true;
      }
    }
    // Corrección retroactiva (post-v48): histórico Holcim cemento con origen "Cantera de Garraf"
    // (era alias incorrecto antes de v48). Si el material es cemento y el proveedor es Holcim,
    // el origen real es Fábrica Montcada — NO Cantera de Garraf (que es para áridos/caliza).
    // Tolera errores típicos OCR: CEM/CFM/CEN/CFN. ECOPlanet es siempre cemento Holcim.
    if (r.planta === 'Cantera de Garraf'
        && /Holcim/i.test(r.proveedor || '')
        && /\bECOPlanet\b|(?:^|\s)C[EF][MN]\s+[IVX/]+|Cemento\s+(?:Portland|Puzol)/i.test(r.producto || '')) {
      console.log(`Origen Holcim cemento: "Cantera de Garraf" → "Fábrica Montcada" (alb ${r.albaran})`);
      r.planta = 'Fábrica Montcada';
      update.planta = 'Fábrica Montcada';
      cambio = true;
    }
    // Corrección retroactiva INVERSA: histórico Holcim árido con origen "Fábrica Montcada"
    // (OCR confundió Punto expedición con Planta). Si el material es árido genérico
    // (AF-X/X-T-C, AG-X/X-T-C) y el proveedor es Holcim, el origen real es Cantera de Garraf.
    if (r.planta === 'Fábrica Montcada'
        && /Holcim/i.test(r.proveedor || '')
        && /^\s*A[FG]-\d+\/\d+-T-C/i.test(r.producto || '')) {
      console.log(`Origen Holcim árido: "Fábrica Montcada" → "Cantera de Garraf" (alb ${r.albaran})`);
      r.planta = 'Cantera de Garraf';
      update.planta = 'Cantera de Garraf';
      cambio = true;
    }
    // v107E5: Corrección retroactiva ESCOMBRO Holcim → Fábrica Montcada.
    // Albaranes de recepción Holcim cuyo material es "Hormigón [planta]"
    // (Zona Franca, La Roca, Papiol, Montcada, Celra...) son escombros
    // que entran a Fábrica Montcada. Se cobran POR VIAJE (TM=1) y el
    // ORIGEN se lee de la propia descripción del producto.
    // Mismo blindaje triple que el caso 4 de _processOne (v107E4):
    //   (a) proveedor Holcim
    //   (b) destino Fábrica Montcada
    //   (c) producto "Hormigón [planta conocida]"
    {
      const _prov3 = String(r.proveedor || '').toLowerCase();
      const _dest3 = String(r.obra || '').toLowerCase();
      const _prod3 = String(r.producto || '').toLowerCase();
      const _esHolcim3 = _prov3.indexOf('holcim') !== -1;
      const _esFabMontcada3 = /f[áa]brica\s+montcada/.test(_dest3);
      const _matchHormigon3 = _prod3.match(/^hormig[óo]n\s+(zona\s*franca|la\s*roca|papiol|montcada|celra|sant\s*just|riudellots|riudarenes|alcover|tarragona|manlleu|alaior|ciutadella)/);
      if (_esHolcim3 && _esFabMontcada3 && _matchHormigon3) {
        const _mapaOri3 = {
          'zona franca':  'Zona Franca',
          'zonafranca':   'Zona Franca',
          'la roca':      'La Roca',
          'laroca':       'La Roca',
          'papiol':       'Papiol',
          'montcada':     'Montcada',
          'celra':        'Celra',
          'sant just':    'Sant Just',
          'santjust':     'Sant Just',
          'riudellots':   'Riudellots de la Selva',
          'riudarenes':   'Riudarenes',
          'alcover':      'Alcover',
          'tarragona':    'Tarragona',
          'manlleu':      'Manlleu',
          'alaior':       'Alaior',
          'ciutadella':   'Ciutadella de Menorca'
        };
        const _keyOri3 = _matchHormigon3[1].trim().toLowerCase().replace(/\s+/g, ' ');
        const _origenLimpio3 = _mapaOri3[_keyOri3] || _mapaOri3[_keyOri3.replace(/\s+/g, '')] || _matchHormigon3[1].trim();
        // (1) Corregir ORIGEN: leer de la descripción
        if (r.planta !== _origenLimpio3) {
          console.log(`[v107E5 escombro] Origen: "${r.planta || '(vacío)'}" → "${_origenLimpio3}" (alb ${r.albaran}, prod "${r.producto}")`);
          r.planta = _origenLimpio3;
          update.planta = _origenLimpio3;
          cambio = true;
        }
        // (2) Corregir TM a 1 si no lo está (cobro por viaje, guardar TN real en obs)
        const _tnActual = parseFloat(r.tm);
        if (!isNaN(_tnActual) && _tnActual !== 1) {
          // Solo añadir nota si todavía no tiene la nota de "Cobro por viaje"
          const _obsActuales = String(r.observaciones || '');
          if (_obsActuales.indexOf('Cobro por viaje') === -1) {
            const _obsNueva = (_obsActuales ? _obsActuales + ' · ' : '')
              + 'Cobro por viaje (TN real ' + _tnActual + ')';
            r.observaciones = _obsNueva;
            update.observaciones = _obsNueva;
          }
          console.log(`[v107E5 escombro] TM: ${_tnActual} → 1 (alb ${r.albaran})`);
          r.tm = 1;
          update.tm = 1;
          cambio = true;
        }
      }
    }
    // Inferencia adicional por MATERIAL/PROVEEDOR (origen)
    const inferidoOri = inferOrigen(r);
    if (inferidoOri && inferidoOri !== r.planta) {
      console.log(`Origen inferido: → "${inferidoOri}" (alb ${r.albaran})`);
      r.planta = inferidoOri;
      update.planta = inferidoOri;
      cambio = true;
    }
    // Corregir cliente/comprador PRIMERO (variantes OCR de Planta Hormigones Zona Franca/Montcada).
    // Importante hacerlo ANTES de inferDestino para que las reglas de destino vean el cliente ya canonizado
    // y puedan inferir el destino correctamente cuando el cliente es lo que da la pista.
    if (r.cliente) {
      const nuevoCli = fixCliente(r.cliente);
      if (nuevoCli !== r.cliente) {
        console.log(`Cliente: "${r.cliente}" → "${nuevoCli}" (alb ${r.albaran})`);
        r.cliente = nuevoCli;
        update.cliente = nuevoCli;
        cambio = true;
      }
    }
    // Inferencia de destino por proveedor / combinación material / código de obra
    // v107EA: misma excepción que _processOne — Holcim cisterna cemento NO se inferencia
    const _esHolcimCem4 = /Holcim/i.test(r.proveedor || '')
      && /\bECOPlanet\b|(?:^|\s)C[EF][MN]\s+[IVX/]+|Cemento\s+(?:Portland|Puzol)|CEM\s+[IVX]+\/[A-Z]/i.test(r.producto || '')
      && !/F[áa]brica\s+Montcada/i.test(String(r.obra || '').trim());
    if (!_esHolcimCem4) {
      const inferidoDest = inferDestino(r);
      if (inferidoDest && inferidoDest !== r.obra) {
        console.log(`Destino inferido: → "${inferidoDest}" (alb ${r.albaran})`);
        r.obra = inferidoDest;
        update.obra = inferidoDest;
        cambio = true;
      }
    } else {
      console.log(`[v107EA reanaliza] inferDestino bloqueado para Holcim cisterna cemento, destino "${r.obra}" preservado (alb ${r.albaran})`);
    }
    // Corregir proveedor
    if (r.proveedor) {
      const nuevoProv = fixProveedor(r.proveedor);
      if (nuevoProv !== r.proveedor) {
        console.log(`Proveedor: "${r.proveedor}" → "${nuevoProv}" (alb ${r.albaran})`);
        r.proveedor = nuevoProv;
        update.proveedor = nuevoProv;
        cambio = true;
      }
    }
    // Corregir matrícula (y transportista derivado)
    if (r.tractora) {
      const nuevaMat = fixMatricula(r.tractora);
      if (nuevaMat !== r.tractora) {
        console.log(`Matrícula: ${r.tractora} → ${nuevaMat} (alb ${r.albaran})`);
        r.tractora = nuevaMat;
        update.tractora = nuevaMat;
        cambio = true;
      }
      // v83: aunque la matrícula no haya cambiado, comprobar si el transportista coincide con
      // el oficial del diccionario. Si no, corregirlo. Aplica a histórico de albaranes con
      // transportista mal leído por OCR.
      const tOficial = getTransportista(r.tractora);
      if (tOficial && tOficial !== r.transportista) {
        console.log(`Transportista hist: "${r.transportista || '(vacío)'}" → "${tOficial}" (mat ${r.tractora}, alb ${r.albaran})`);
        r.transportista = tOficial;
        update.transportista = tOficial;
        cambio = true;
      }
    }
    // v106: canonización adicional por NOMBRE (no por matrícula). Cubre los casos en los
    // que la matrícula es desconocida pero el transportista guardado es una variante rara
    // reconocible (ej. "ARIDFLOT, S.L." → "ARIDFLOT"). NO afecta a los que ya están canónicos.
    if (r.transportista) {
      const tFix = fixTransportista(r.transportista);
      if (tFix !== r.transportista) {
        console.log(`Transportista canonizado por nombre: "${r.transportista}" → "${tFix}" (alb ${r.albaran})`);
        r.transportista = tFix;
        update.transportista = tFix;
        cambio = true;
      }
    }
    // v107b: corrección retroactiva ROBUSTA del Nº albarán Sodira (limpia variantes mal
    // leídas como "21240001/01718/122921", "Albarán 1/01718/123026", "01718/123112",
    // "21240002" → reconstruye al formato "1/01718/XXXXXX").
    if (r.proveedor && /Sodira/i.test(r.proveedor) && r.albaran) {
      const original = String(r.albaran).trim();
      const formatoCorrecto = /^1\/01718\/\d{6}$/;
      if (!formatoCorrecto.test(original)) {
        let limpio = null;
        let m = original.match(/1\s*\/\s*01718\s*\/\s*(\d{6})/);
        if (m) {
          limpio = `1/01718/${m[1]}`;
        } else {
          m = original.match(/(?:^|[^0-9])01718\s*\/\s*(\d{6})/);
          if (m) limpio = `1/01718/${m[1]}`;
        }
        if (limpio && limpio !== original) {
          console.log(`[Sodira albaran retro] "${original}" → "${limpio}" (db_id ${r.db_id})`);
          r.albaran = limpio;
          update.albaran = limpio;
          cambio = true;
        }
      }
    }
    // Si hay cambios, actualizar en Supabase
    if (cambio && r.db_id) {
      try {
        const { error } = await sb.from('albaranes').update(update).eq('id', r.db_id);
        if (error) { errores++; console.error('Error guardando', r.albaran, error); }
        else cambios++;
      } catch (e) { errores++; console.error(e); }
    }
  }
  analyzeRecords();
  applyFilters();
  updateStats();
  renderAlerts();
  let resumen = '';
  if (cambios > 0 || manualesCanon > 0) {
    const partes = [];
    if (cambios > 0) partes.push(`${cambios} corregidos`);
    if (manualesCanon > 0) partes.push(`${manualesCanon} manuales canonizados (transp.)`);
    resumen = '✓ ' + partes.join(' · ');
  } else {
    resumen = 'No había nada que corregir';
  }
  if (saltados > 0) resumen += ` · ${saltados} protegidos`;
  if (errores > 0) resumen += ` · ${errores} errores`;
  toast(resumen);
}

// Botón "Re-corregir proveedores": pasa todos los albaranes existentes por fixProveedor
// y guarda los cambios en Supabase. Útil para limpiar grafías antiguas (FÁBRICA/FABRICA/Fábrica).
async function recorregirProveedores() {
  if (!records.length) { toast('No hay albaranes', 'err'); return; }
  if (!confirm(`Se revisarán ${records.length} albaranes y se normalizará la grafía del proveedor. ¿Continuar?`)) return;
  let cambios = 0, errores = 0;
  toast(`🏷️ Revisando ${records.length} albaranes...`);
  for (const r of records) {
    if (!r.proveedor) continue;
    const nuevoProv = fixProveedor(r.proveedor);
    if (nuevoProv === r.proveedor) continue;
    console.log(`Proveedor: "${r.proveedor}" → "${nuevoProv}" (alb ${r.albaran})`);
    r.proveedor = nuevoProv;
    if (r.db_id) {
      try {
        const { error } = await sb.from('albaranes').update({ proveedor: r.proveedor }).eq('id', r.db_id);
        if (error) { errores++; console.error('Error guardando', r.albaran, error); }
        else cambios++;
      } catch (e) { errores++; console.error(e); }
    }
  }
  analyzeRecords();
  applyFilters();
  updateStats();
  renderAlerts();
  if (cambios > 0) toast(`✓ ${cambios} proveedores normalizados${errores > 0 ? ' · ' + errores + ' errores' : ''}`);
  else toast('No había nada que normalizar');
}

function exportGasoilExcel() {
  if (!gasoilRecords.length) { toast('No hay tickets', 'err'); return; }
  const rows = [['FECHA','MATRÍCULA','PROVEEDOR','TIPO','LITROS','IMPORTE','€/LITRO','Nº TICKET','OBSERVACIONES'],
    ...gasoilRecords.map(r => [r.fecha||'',r.tractora||'',r.proveedor||'',r.tipo||'',r.litros||'',r.importe||'',r.precio_litro||'',r.num_ticket||'',r.observaciones||''])];
  const ws = XLSX.utils.aoa_to_sheet(rows); ws['!cols'] = [10,10,18,10,8,10,8,14,24].map(w=>({wch:w}));
  const wb = XLSX.utils.book_new(); XLSX.utils.book_append_sheet(wb, ws, 'Gasoil');
  XLSX.writeFile(wb, `gasoil_${new Date().toISOString().slice(0,10)}.xlsx`); toast('✓ Excel gasoil exportado');
}

function clearAll() { if (!records.length) return; if (!confirm(`¿Borrar ${records.length} albaranes?`)) return; records = []; analyzeRecords(); applyFilters(); updateStats(); renderAlerts(); toast('Eliminados'); }

// ============================================================
// TABS
// ============================================================
// Recuerda la última pestaña principal (alb o gas) para decidir qué mostrar en Subir
let _lastMainTab = 'alb';

// ============================================================
// v101 — PESTAÑA ITV (control de inspecciones técnicas)
// Solo accesible para usuarios con puede_ver_itv=TRUE en profiles.
// La fecha de caducidad se LEE del documento (no se calcula), porque la
// periodicidad varía según la edad del vehículo (anual hasta 10 años, luego
// cada 6 meses, primera ITV a 1 año desde matriculación).
// ============================================================
let itvRecords = [];
let filteredItv = [];
let editItvId = null;
const ITV_AVISO_DIAS = 15;  // umbral de aviso amarillo (15 días antes)

// v107h: estado de las CITAS ITV
let itvCitasRecords = [];
let filteredCitas = [];
let editCitaId = null;

// Estado de un registro ITV según la fecha de caducidad
function _itvEstado(rec) {
  if (!rec.fecha_caducidad) return { tipo: 'sin', dias: null, label: '?', icon: '⚪' };
  const hoy = new Date(); hoy.setHours(0,0,0,0);
  const cad = new Date(rec.fecha_caducidad + 'T00:00:00');
  const dias = Math.round((cad - hoy) / 86400000);
  if (dias < 0) return { tipo: 'caducada', dias, label: 'Caducada', icon: '🔴' };
  if (dias <= ITV_AVISO_DIAS) return { tipo: 'aviso', dias, label: 'Aviso', icon: '🟧' };
  return { tipo: 'vigente', dias, label: 'Vigente', icon: '🟢' };
}

// ============================================================
// v101b: BANNER GLOBAL DE AVISOS ITV
// Aparece en CUALQUIER pestaña para usuarios con acceso ITV.
// Niveles escalonados: caducadas (rojo intenso), 1d, 2d, 3d (rojo→naranja→amarillo),
// 4-15d (azul informativo). Botón ✕ oculta el aviso hasta el día siguiente
// (se guarda en localStorage la fecha del último ocultamiento).
// ============================================================
const ITV_BANNER_HIDE_KEY = 'itv_banner_hidden_date';
const TALLER_BANNER_HIDE_KEY = 'taller_banner_hidden_date';  // v107AL

function _itvNivelAviso(dias) {
  // Devuelve color y prioridad del aviso según los días que quedan
  if (dias < 0) return { color: '#cc0000', bg: '#3a0a0a', icon: '🚨', label: 'CADUCADA', prio: 5 };
  if (dias <= 1) return { color: '#ff3333', bg: '#3a0a0a', icon: '🔴', label: dias === 0 ? 'CADUCA HOY' : 'CADUCA MAÑANA', prio: 4 };
  if (dias === 2) return { color: '#ff8800', bg: '#3a200a', icon: '⚠️', label: '2 DÍAS', prio: 3 };
  if (dias === 3) return { color: '#ffcc00', bg: '#3a300a', icon: '📅', label: '3 DÍAS', prio: 2 };
  if (dias <= 15) return { color: '#3399ff', bg: '#0a1f3a', icon: '📋', label: `${dias} DÍAS`, prio: 1 };
  return null;  // no avisa
}

// v107AF: oculta TODOS los botones de edición de ITV y Citas para usuarios
// en modo solo-lectura (usuario TALLER). Se llama al cargar y al entrar en
// la pestaña ITV (porque las tablas se re-renderizan dinámicamente).
function _aplicarItvSoloLectura() {
  if (!window._itvSoloLectura) return;
  // Botones fijos del HTML (Subir ITV, Nueva cita, Guardar, Eliminar del modal)
  const sel = [
    'button[onclick*="itvFileInput"]',          // ➕ Subir ITV
    'button[onclick*="openCitaModalNew"]',      // ➕ Nueva cita
    '#itvSaveBtn',                              // ✓ guardar modal
    '#itvBtnDel',                               // Eliminar del modal
    'button[onclick*="saveItvModal"]',          // Guardar
    'button[onclick*="deleteItvRecord"]',       // Eliminar registro
    'button[onclick*="saveCitaModal"]',         // Guardar cita
    'button[onclick*="deleteCitaRecord"]'       // Eliminar cita
  ];
  document.querySelectorAll(sel.join(',')).forEach(b => { b.style.display = 'none'; });
  // v107H3: ocultar también la zona de arrastrar/soltar de ITV en solo-lectura
  const _dzItv = document.getElementById('dzItv');
  if (_dzItv) _dzItv.style.display = 'none';
  // v107H4: ocultar también la zona de arrastrar/soltar de CITAS en solo-lectura
  const _dzCita = document.getElementById('dzCita');
  if (_dzCita) _dzCita.style.display = 'none';
  // Quitar el onclick de las filas de ITV/citas para que no abran el modal de edición.
  // (En solo lectura, ver la tabla es suficiente; no se abre el modal editable.)
  document.querySelectorAll('#itvTableBody tr, #citasTableBody tr').forEach(tr => {
    tr.style.cursor = 'default';
    tr.onclick = null;
  });
}

function renderItvGlobalBanner() {
  // Solo renderizar si el usuario tiene acceso ITV
  if (!window._tieneITV) {
    const banner = document.getElementById('itvGlobalBanner');
    if (banner) banner.style.display = 'none';
    return;
  }
  // Comprobar si el usuario ya ocultó el aviso HOY (localStorage)
  const today = new Date().toISOString().slice(0, 10);  // 'YYYY-MM-DD'
  const hiddenOn = localStorage.getItem(ITV_BANNER_HIDE_KEY);
  const isHiddenToday = (hiddenOn === today);
  // Buscar ITVs que requieren aviso (caducadas o ≤15 días)
  const avisos = itvRecords
    .map(r => ({ rec: r, est: _itvEstado(r) }))
    .filter(x => x.est.tipo === 'caducada' || x.est.tipo === 'aviso')
    .map(x => ({ ...x, nivel: _itvNivelAviso(x.est.dias) }))
    .filter(x => x.nivel !== null)
    // Ordenar por prioridad (caducadas primero, luego más cercanas)
    .sort((a, b) => b.nivel.prio - a.nivel.prio || a.est.dias - b.est.dias);
  const banner = document.getElementById('itvGlobalBanner');
  if (!banner) return;
  if (avisos.length === 0 || isHiddenToday) {
    banner.style.display = 'none';
    return;
  }
  // Tomar el nivel más alto (el más urgente) para el color de fondo del banner
  const nivelTop = avisos[0].nivel;
  // Texto del banner: si hay 1, ponemos "matrícula 1234ABC caduca en 2 días"
  // Si hay varias, "3 ITVs requieren atención" + lista breve
  let mensajeHtml = '';
  if (avisos.length === 1) {
    const a = avisos[0];
    mensajeHtml = `<strong>${a.nivel.icon} ITV ${a.rec.matricula}</strong> · ${a.nivel.label}`;
  } else {
    // Resumen + lista corta
    const top3 = avisos.slice(0, 3).map(a => `${a.nivel.icon} <strong>${a.rec.matricula}</strong> (${a.nivel.label.toLowerCase()})`).join(' · ');
    const restoTxt = avisos.length > 3 ? ` · +${avisos.length - 3} más` : '';
    mensajeHtml = `<strong>${avisos.length} ITVs requieren atención:</strong> ${top3}${restoTxt}`;
  }
  banner.style.display = 'block';
  banner.innerHTML = `
    <div style="background:${nivelTop.bg};border:1px solid ${nivelTop.color};border-left:4px solid ${nivelTop.color};border-radius:6px;padding:10px 14px;margin:10px 0;display:flex;align-items:center;gap:12px;flex-wrap:wrap;font-family:var(--mn);font-size:12px">
      <div style="flex:1;color:#fff;line-height:1.5">${mensajeHtml}</div>
      <div style="display:flex;gap:6px">
        <button class="btn bp" style="font-size:10px;padding:6px 12px" onclick="switchTab('itv')">🛡️ Ver ITV</button>
        <button class="btn bs" style="font-size:10px;padding:6px 10px" onclick="hideItvBannerToday()" title="Ocultar hasta mañana">✕</button>
      </div>
    </div>`;
}

function hideItvBannerToday() {
  const today = new Date().toISOString().slice(0, 10);
  localStorage.setItem(ITV_BANNER_HIDE_KEY, today);
  const banner = document.getElementById('itvGlobalBanner');
  if (banner) banner.style.display = 'none';
  toast('Aviso ITV ocultado hasta mañana');
}

// v107AL: banner global de avisos de TALLER (mantenimientos vencidos o próximos).
// Mismo patrón visual que el de ITV. Solo se muestra a quien tiene acceso a Taller.
// Recorre TODAS las empresas que el usuario puede ver (no solo la subpestaña activa).
function renderTallerGlobalBanner() {
  const banner = document.getElementById('tallerGlobalBanner');
  if (!banner) return;
  if (!window._tieneTaller) { banner.style.display = 'none'; return; }
  if (!Array.isArray(tallerVehiculos) || !tallerVehiculos.length) {
    banner.style.display = 'none';
    return;
  }
  // Empresas que el usuario puede ver (igual lógica que las subpestañas)
  const permitidas = window._empresaTaller
    ? window._empresaTaller.split(',').map(s => s.trim())
    : ['TYP2014','HISPALIS','TRANSMARGAZ'];

  // Agrupar vehículos por nivel: vencido / pronto / plan
  const grupos = { vencido: [], pronto: [], plan: [] };
  tallerVehiculos
    .filter(v => permitidas.includes(v.empresa))
    .forEach(v => {
      const e = _tallerEstadoVehiculo(v);
      if (grupos[e.estado]) grupos[e.estado].push(v);
    });

  // Config visual de cada nivel. La key se usa para ocultar ese color por separado.
  const niveles = [
    { key: 'vencido', icon: '🔴', label: 'VENCIDO',  color: '#ff5050', bg: 'rgba(255,80,80,.10)', txt: 'mantenimiento VENCIDO',  txtPl: 'vehículos con mantenimiento VENCIDO' },
    { key: 'pronto',  icon: '🟠', label: 'PRÓXIMO',  color: '#ff9500', bg: 'rgba(255,149,0,.10)', txt: 'mantenimiento próximo (≤15 días o ≤5.000 km)', txtPl: 'vehículos con mantenimiento próximo' },
    { key: 'plan',    icon: '🟡', label: 'PLANIFICAR', color: '#ffd000', bg: 'rgba(255,208,0,.10)', txt: 'mantenimiento a planificar (≤1 mes o ≤10.000 km)', txtPl: 'vehículos a planificar' }
  ];

  const today = new Date().toISOString().slice(0, 10);
  let html = '';
  for (const n of niveles) {
    const lista = grupos[n.key];
    if (!lista.length) continue;
    // ¿Este color ocultado hoy? (clave separada por nivel)
    if (localStorage.getItem(TALLER_BANNER_HIDE_KEY + '_' + n.key) === today) continue;

    let mensaje;
    if (lista.length === 1) {
      mensaje = `<strong>${n.icon} ${esc(lista[0].matricula)}</strong> · ${n.txt}`;
    } else {
      const top3 = lista.slice(0, 3).map(v => `${n.icon} <strong>${esc(v.matricula)}</strong>`).join(' · ');
      const resto = lista.length > 3 ? ` · +${lista.length - 3} más` : '';
      mensaje = `<strong>${lista.length} ${n.txtPl}:</strong> ${top3}${resto}`;
    }
    html += `
      <div style="background:${n.bg};border:1px solid ${n.color};border-left:4px solid ${n.color};border-radius:6px;padding:10px 14px;margin:8px 0;display:flex;align-items:center;gap:12px;flex-wrap:wrap;font-family:var(--mn);font-size:12px">
        <div style="flex:1;color:#fff;line-height:1.5">🔧 ${mensaje}</div>
        <div style="display:flex;gap:6px">
          <button class="btn bp" style="font-size:10px;padding:6px 12px" onclick="switchTab('taller')">🔧 Ver Taller</button>
          <button class="btn bs" style="font-size:10px;padding:6px 10px" onclick="hideTallerBannerToday('${n.key}')" title="Ocultar este aviso hasta mañana">✕</button>
        </div>
      </div>`;
  }

  if (!html) { banner.style.display = 'none'; return; }
  banner.style.display = 'block';
  banner.innerHTML = html;
}

// v107AL: oculta SOLO el nivel indicado (vencido/pronto/plan) hasta mañana.
// Así el taller puede cerrar el amarillo pero seguir viendo el rojo, etc.
function hideTallerBannerToday(nivel) {
  const today = new Date().toISOString().slice(0, 10);
  if (nivel) {
    localStorage.setItem(TALLER_BANNER_HIDE_KEY + '_' + nivel, today);
  } else {
    // compatibilidad: sin argumento oculta los 3
    ['vencido','pronto','plan'].forEach(k => localStorage.setItem(TALLER_BANNER_HIDE_KEY + '_' + k, today));
  }
  renderTallerGlobalBanner();
  toast('Aviso Taller ocultado hasta mañana');
}

async function loadItvData() {
  if (!window._tieneITV) return;  // doble check de seguridad
  try {
    const { data, error } = await sb.from('itv').select('*').order('fecha_caducidad', { ascending: true, nullsFirst: false });
    if (error) throw error;
    itvRecords = (data || []).map(r => ({ ...r, db_id: r.id, _id: r.id }));
    applyItvFilters();
    updateItvStats();
    renderItvAlerts();
    document.getElementById('tabItvCount').textContent = itvRecords.filter(r => {
      const e = _itvEstado(r);
      return e.tipo === 'caducada' || e.tipo === 'aviso';
    }).length;
    // v101b: actualizar también el banner global de avisos (visible en todas las pestañas)
    renderItvGlobalBanner();
    // v107h: cargar también citas (en paralelo, sin esperar)
    loadItvCitas().catch(e => console.warn('[loadItvCitas] Error:', e));
  } catch (e) {
    console.error('[loadItvData] Error:', e);
    toast('Error cargando ITVs: ' + (e.message || e), 'err');
  }
}

// v107h: cargar citas ITV (próximas inspecciones programadas)
async function loadItvCitas() {
  if (!window._tieneITV) return;
  try {
    const { data, error } = await sb.from('itv_citas').select('*').order('fecha_cita', { ascending: true, nullsFirst: false });
    if (error) throw error;
    itvCitasRecords = (data || []).map(r => ({ ...r, db_id: r.id, _id: r.id }));
    applyCitasFilters();
  } catch (e) {
    console.error('[loadItvCitas] Error:', e);
  }
}

// v107h: estado de una cita según su fecha
function _citaEstado(rec) {
  if (!rec.fecha_cita) return { tipo: 'sin', dias: null, icon: '⚪' };
  const hoy = new Date(); hoy.setHours(0,0,0,0);
  const cita = new Date(rec.fecha_cita + 'T00:00:00');
  const dias = Math.round((cita - hoy) / (1000 * 60 * 60 * 24));
  if (dias < 0) return { tipo: 'pasada', dias, icon: '⚫' };
  if (dias === 0) return { tipo: 'hoy', dias, icon: '🔴' };
  if (dias <= 3) return { tipo: 'urgente', dias, icon: '🟠' };
  return { tipo: 'futura', dias, icon: '🟢' };
}

function applyCitasFilters() {
  const fMat = (document.getElementById('fCitaMat')?.value || '').trim().toUpperCase();
  const fCuando = document.getElementById('fCitaCuando')?.value || '';
  const hoy = new Date(); hoy.setHours(0,0,0,0);
  filteredCitas = itvCitasRecords.filter(r => {
    if (fMat && !String(r.matricula || '').toUpperCase().includes(fMat)) return false;
    if (fCuando) {
      if (!r.fecha_cita) return false;
      const cita = new Date(r.fecha_cita + 'T00:00:00');
      const dias = Math.round((cita - hoy) / (1000 * 60 * 60 * 24));
      if (fCuando === 'hoy' && dias !== 0) return false;
      if (fCuando === 'semana' && (dias < 0 || dias > 7)) return false;
      if (fCuando === 'mes' && (dias < 0 || dias > 31)) return false;
      if (fCuando === 'futuras' && dias < 0) return false;
      if (fCuando === 'pasadas' && dias >= 0) return false;
    }
    return true;
  });
  // Ordenar por fecha ascendente (más cercana primero)
  filteredCitas.sort((a, b) => {
    if (!a.fecha_cita) return 1;
    if (!b.fecha_cita) return -1;
    return a.fecha_cita.localeCompare(b.fecha_cita);
  });
  renderCitasTable();
}

function resetCitasFilters() {
  ['fCitaMat','fCitaCuando'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
  applyCitasFilters();
}

function renderCitasTable() {
  const tb = document.getElementById('citasTableBody');
  if (!tb) return;
  if (!filteredCitas.length) {
    tb.innerHTML = '<tr><td colspan="6" style="text-align:center;padding:20px;color:var(--mu)">No hay citas registradas</td></tr>';
    return;
  }
  const fmtDate = d => d ? new Date(d + 'T00:00:00').toLocaleDateString('es-ES') : '—';
  tb.innerHTML = filteredCitas.map(r => {
    const est = _citaEstado(r);
    const diasTxt = est.dias === null ? '—' :
      (est.tipo === 'pasada' ? `<span style="color:var(--mu)">${est.dias}</span>` :
       est.tipo === 'hoy' ? `<span style="color:var(--er);font-weight:700">HOY</span>` :
       est.tipo === 'urgente' ? `<span style="color:var(--wn);font-weight:700">${est.dias}</span>` :
       `<span style="color:var(--ac)">${est.dias}</span>`);
    return `<tr onclick="openCitaModal(${r.db_id})" style="cursor:pointer">
      <td style="font-size:14px">${est.icon}</td>
      <td style="font-family:var(--mn);font-weight:600;color:var(--ac)">${esc(r.matricula || '—')}</td>
      <td>${fmtDate(r.fecha_cita)}</td>
      <td style="font-family:var(--mn);font-weight:600">${esc(r.hora_cita || '—')}</td>
      <td>${diasTxt}</td>
      <td style="font-size:11px">${esc(r.centro || '—')}</td>
    </tr>`;
  }).join('');
  // v107AF: re-aplicar blindaje solo-lectura (la tabla se acaba de regenerar)
  _aplicarItvSoloLectura();
}

// v107h: abrir modal de cita (existente o nueva)
function openCitaModal(dbId) {
  const r = itvCitasRecords.find(x => String(x.db_id) === String(dbId));
  if (!r) return;
  editCitaId = dbId;
  _renderCitaModalFields(r, false);
  document.getElementById('citaBtnDel').style.display = 'inline-block';
  document.getElementById('citaOv').classList.add('open');
}

function openCitaModalNew() {
  editCitaId = null;
  _renderCitaModalFields({ matricula: '', fecha_cita: '', hora_cita: '', centro: 'Vilafranca del Penedès', direccion: '', observaciones: '' }, true);
  document.getElementById('citaBtnDel').style.display = 'none';
  document.getElementById('citaOv').classList.add('open');
}

function _renderCitaModalFields(r, esNueva) {
  const fields = document.getElementById('citaFields');
  fields.innerHTML = `
    <div class="ig"><label>Matrícula</label><input id="citaMatricula" value="${esc(r.matricula || '')}" style="font-family:var(--mn);text-transform:uppercase" placeholder="Ej: 1234ABC"></div>
    <div class="ig"><label>Fecha cita</label><input type="date" id="citaFecha" value="${r.fecha_cita || ''}"></div>
    <div class="ig"><label>Hora cita</label><input id="citaHora" value="${esc(r.hora_cita || '')}" placeholder="Ej: 14:30" style="font-family:var(--mn)"></div>
    <div class="ig"><label>Centro</label><input id="citaCentro" value="${esc(r.centro || 'Vilafranca del Penedès')}"></div>
    <div class="ig" style="grid-column:1/-1"><label>Dirección</label><input id="citaDireccion" value="${esc(r.direccion || '')}"></div>
    <div class="ig" style="grid-column:1/-1"><label>Observaciones</label><textarea id="citaObservaciones" rows="2">${esc(r.observaciones || '')}</textarea></div>
  `;
}

function closeCitaModal() {
  document.getElementById('citaOv').classList.remove('open');
  editCitaId = null;
}

async function saveCitaModal() {
  const matricula = (document.getElementById('citaMatricula').value || '').trim().toUpperCase().replace(/\s+/g,'');
  const fecha_cita = document.getElementById('citaFecha').value || null;
  const hora_cita = (document.getElementById('citaHora').value || '').trim() || null;
  const centro = (document.getElementById('citaCentro').value || '').trim() || null;
  const direccion = (document.getElementById('citaDireccion').value || '').trim() || null;
  const observaciones = (document.getElementById('citaObservaciones').value || '').trim() || null;
  if (!matricula) { toast('La matrícula es obligatoria', 'err'); return; }
  if (!fecha_cita) { toast('La fecha de la cita es obligatoria', 'err'); return; }
  const payload = { matricula, fecha_cita, hora_cita, centro, direccion, observaciones, updated_at: new Date().toISOString() };
  try {
    if (editCitaId) {
      const { error } = await sb.from('itv_citas').update(payload).eq('id', editCitaId);
      if (error) throw error;
      toast('✓ Cita actualizada');
    } else {
      payload.user_id = currentUser.id;
      const { error } = await sb.from('itv_citas').insert(payload);
      if (error) throw error;
      toast('✓ Cita creada');
    }
    closeCitaModal();
    await loadItvCitas();
  } catch (e) {
    console.error('[saveCitaModal] Error:', e);
    toast('Error guardando cita: ' + (e.message || e), 'err');
  }
}

async function deleteCitaRecord() {
  if (!editCitaId) return;
  if (!confirm('¿Eliminar esta cita?\n\nEsta acción no se puede deshacer.')) return;
  try {
    const { error } = await sb.from('itv_citas').delete().eq('id', editCitaId);
    if (error) throw error;
    closeCitaModal();
    await loadItvCitas();
    toast('✓ Cita eliminada');
  } catch (e) {
    console.error('[deleteCitaRecord] Error:', e);
    toast('Error eliminando cita: ' + (e.message || e), 'err');
  }
}

// v107EN5 — Subir foto del SMS/email del centro ITV y que la IA rellene la cita.
// Solo IMAGEN (no PDF) porque las citas suelen llegar como captura de móvil del SMS/email.
// v107EN5c (25/05/2026): GUARDA AUTOMÁTICAMENTE tras leer (sin modal previo).
// Si la cita está mal, el usuario hace click en la fila después para editarla.
// Mismo flujo que "Subir ITV" del registro: leer + guardar + listo.
async function handleCitaFiles(files) {
  if (!files || !files.length) return;
  const key = getKey();
  if (!key) { toast('Falta clave de IA — ve a "Cambiar" arriba', 'err'); return; }
  const f = files[0]; // solo procesamos la primera (las citas son 1 archivo a la vez)
  if (!/^image\//i.test(f.type)) { toast('Solo imágenes (foto del SMS/email)', 'err'); return; }
  // v107EN5b: protección contra archivos vacíos (WhatsApp/iCloud a veces no termina de descargar)
  if (!f.size || f.size < 100) {
    toast('⚠️ La imagen está vacía o no se descargó bien. Guárdala en tu PC/móvil primero y vuelve a subirla.', 'err');
    console.warn('[v107EN5 handleCitaFiles] Archivo vacío:', f.name, 'size:', f.size);
    return;
  }
  toast('🔍 Leyendo cita con IA...');
  try {
    // Convertir imagen a base64
    const b64 = await new Promise((res, rej) => {
      const r = new FileReader();
      r.onload = () => res(r.result.split(',')[1]);
      r.onerror = rej;
      r.readAsDataURL(f);
    });
    // Llamar a la IA
    const datos = await callClaudeCita(b64, f.type || 'image/jpeg', key);

    // v107EN5c: validación mínima antes de guardar — necesitamos al menos matrícula y fecha
    const matricula = (datos.matricula || '').trim().toUpperCase().replace(/\s+/g, '');
    const fecha_cita = (datos.fecha_cita || '').trim() || null;
    const hora_cita = (datos.hora_cita || '').trim() || null;
    const centro = (datos.centro || '').trim() || 'Vilafranca del Penedès';
    if (!matricula) {
      toast('⚠️ La IA no pudo leer la matrícula. Usa "+ Nueva cita" para introducirla a mano.', 'err');
      return;
    }
    if (!fecha_cita) {
      toast('⚠️ La IA no pudo leer la fecha. Usa "+ Nueva cita" para introducirla a mano.', 'err');
      return;
    }
    // v107EN5c: guardar directamente en BD (sin abrir modal)
    const payload = {
      matricula,
      fecha_cita,
      hora_cita,
      centro,
      direccion: null,
      observaciones: null,
      user_id: currentUser.id,
      updated_at: new Date().toISOString()
    };
    const { error } = await sb.from('itv_citas').insert(payload);
    if (error) throw error;
    await loadItvCitas();
    toast(`✓ Cita guardada: ${matricula} → ${fecha_cita} ${hora_cita || ''}`);
  } catch (e) {
    console.error('[handleCitaFiles] Error:', e);
    toast('Error leyendo/guardando cita: ' + (e.message || e), 'err');
  }
}

// v107EN5 — Llamar a Claude Haiku para extraer datos de una cita ITV desde foto.
// Devuelve {matricula, fecha_cita (YYYY-MM-DD), hora_cita (HH:MM), centro}.
async function callClaudeCita(b64, mediaType, key) {
  const prompt = `Esta imagen es una captura de un SMS o email de un centro de ITV (Inspección Técnica de Vehículos) en España, confirmando una CITA programada para un vehículo. Extrae los siguientes 4 datos:

1. MATRÍCULA del vehículo: formato español típico — 4 dígitos + 3 letras (ej. "1234BCD", "5360JZR") o formatos antiguos. Devuélvela en MAYÚSCULAS sin espacios.

2. FECHA de la cita: en formato ISO YYYY-MM-DD (ej. "2026-06-15"). El SMS/email puede tener formatos como "15/06/2026", "15-06-2026", "15 de junio de 2026", "15 jun 2026". Conviértelo SIEMPRE a YYYY-MM-DD.

3. HORA de la cita: en formato HH:MM 24h (ej. "14:30", "08:15"). Si pone "8:15h" → "08:15". Si solo aparece "8:15" sin contexto AM/PM, asume horario laboral (08:00-18:00).

4. CENTRO de la ITV: nombre del centro (ej. "Vilafranca del Penedès", "Granollers", "Mataró", "Sabadell", "Sant Joan Despí"). Si pone una dirección y un nombre de población, devuelve el nombre de la población. Si no se identifica claramente el centro, devuelve "Vilafranca del Penedès" (es el centro habitual por defecto).

Devuelve EXCLUSIVAMENTE un JSON con esta estructura, sin texto adicional, sin markdown:
{"matricula":"...","fecha_cita":"YYYY-MM-DD","hora_cita":"HH:MM","centro":"..."}

Si algún campo NO se ve claramente en la imagen, devuelve "" (string vacío) para ese campo, NUNCA lo inventes.`;

  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': key,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true'
    },
    body: JSON.stringify({
      model: 'claude-haiku-4-5',
      max_tokens: 500,
      messages: [{
        role: 'user',
        content: [
          { type: 'image', source: { type: 'base64', media_type: mediaType, data: b64 } },
          { type: 'text', text: prompt }
        ]
      }]
    })
  });
  if (!res.ok) {
    const e = await res.json().catch(() => ({}));
    throw new Error(e.error?.message || `HTTP ${res.status}`);
  }
  const d = await res.json();
  const text = d.content.map(x => x.text || '').join('').trim().replace(/```json|```/g, '').trim();
  console.log('[v107EN5 callClaudeCita] Respuesta IA:', text);
  try {
    const obj = JSON.parse(text);
    // Sanitizar matrícula
    if (obj.matricula) obj.matricula = String(obj.matricula).toUpperCase().replace(/\s+/g, '');
    return obj;
  } catch (e) {
    console.warn('[v107EN5 callClaudeCita] JSON inválido:', text.substring(0, 200));
    throw new Error('La IA no devolvió un JSON válido');
  }
}

function updateItvStats() {
  const cad = itvRecords.filter(r => _itvEstado(r).tipo === 'caducada').length;
  const avi = itvRecords.filter(r => _itvEstado(r).tipo === 'aviso').length;
  const vig = itvRecords.filter(r => _itvEstado(r).tipo === 'vigente').length;
  const box = document.getElementById('itvStatsBox');
  if (!box) return;
  box.innerHTML = `
    <div class="stat" style="--c:var(--er)"><div class="stat-l">Caducadas</div><div class="stat-v" style="color:var(--er)">${cad}</div><div class="stat-s">no aptas</div></div>
    <div class="stat" style="--c:var(--wn)"><div class="stat-l">Caducan en ${ITV_AVISO_DIAS} días</div><div class="stat-v" style="color:var(--wn)">${avi}</div><div class="stat-s">aviso</div></div>
    <div class="stat"><div class="stat-l">Vigentes</div><div class="stat-v">${vig}</div><div class="stat-s">en regla</div></div>
    <div class="stat"><div class="stat-l">Total ITVs</div><div class="stat-v">${itvRecords.length}</div><div class="stat-s">vehículos registrados</div></div>`;
}

function renderItvAlerts() {
  const cad = itvRecords.filter(r => _itvEstado(r).tipo === 'caducada');
  const avi = itvRecords.filter(r => _itvEstado(r).tipo === 'aviso');
  let html = '';
  if (cad.length) html += `<div class="alert-banner alert-dup"><div class="alert-txt">🔴 <strong>${cad.length} ITV(s) CADUCADA(s)</strong> — pasar inspección urgente.</div><div><button class="btn br" style="font-size:10px;padding:5px 11px" onclick="document.getElementById('fItvEstado').value='caducada';applyItvFilters()">Ver</button></div></div>`;
  if (avi.length) html += `<div class="alert-banner alert-warn"><div class="alert-txt">🟧 <strong>${avi.length} ITV(s) caducan en ${ITV_AVISO_DIAS} días o menos</strong> — preparar próxima inspección.</div><div><button class="btn bw" style="font-size:10px;padding:5px 11px" onclick="document.getElementById('fItvEstado').value='aviso';applyItvFilters()">Ver</button></div></div>`;
  document.getElementById('itvAlertsBox').innerHTML = html;
}

function applyItvFilters() {
  const fMat = (document.getElementById('fItvMat')?.value || '').trim().toUpperCase();
  const fEst = document.getElementById('fItvEstado')?.value || '';
  const fTipo = document.getElementById('fItvTipo')?.value || '';
  filteredItv = itvRecords.filter(r => {
    if (fMat && !String(r.matricula || '').toUpperCase().includes(fMat)) return false;
    if (fEst && _itvEstado(r).tipo !== fEst) return false;
    if (fTipo && r.tipo_documento !== fTipo) return false;
    return true;
  });
  // Ordenar siempre por caducidad: la más cercana primero
  filteredItv.sort((a, b) => {
    if (!a.fecha_caducidad) return 1;
    if (!b.fecha_caducidad) return -1;
    return a.fecha_caducidad.localeCompare(b.fecha_caducidad);
  });
  renderItvTable();
}

function resetItvFilters() {
  ['fItvMat','fItvEstado','fItvTipo'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
  applyItvFilters();
}

function renderItvTable() {
  const tb = document.getElementById('itvTableBody');
  if (!tb) return;
  if (!filteredItv.length) {
    tb.innerHTML = '<tr><td colspan="8" style="text-align:center;padding:20px;color:var(--mu)">No hay ITVs registradas</td></tr>';
    return;
  }
  const fmtDate = d => d ? new Date(d + 'T00:00:00').toLocaleDateString('es-ES') : '—';
  const fmtTSItv = ts => ts ? new Date(ts).toLocaleDateString('es-ES') : '—';
  tb.innerHTML = filteredItv.map(r => {
    const est = _itvEstado(r);
    const diasTxt = est.dias === null ? '—' : (est.dias < 0 ? `<span style="color:var(--er);font-weight:700">${est.dias}</span>` : (est.dias <= ITV_AVISO_DIAS ? `<span style="color:var(--wn);font-weight:700">${est.dias}</span>` : `<span style="color:var(--ac)">${est.dias}</span>`));
    const subPor = userMap[r.user_id]?.name || '—';
    const tipoLbl = r.tipo_documento === 'pegatina' ? 'Pegatina' : (r.tipo_documento === 'informe' ? 'Informe' : (r.tipo_documento === 'permiso' ? 'Permiso circ.' : '—'));
    return `<tr onclick="openItvModal(${r.db_id})" style="cursor:pointer">
      <td style="font-size:14px">${est.icon}</td>
      <td style="font-family:var(--mn);font-weight:600;color:var(--ac)">${esc(r.matricula || '—')}</td>
      <td>${fmtDate(r.fecha_itv)}</td>
      <td style="font-weight:600">${fmtDate(r.fecha_caducidad)}</td>
      <td>${diasTxt}</td>
      <td><span class="badge">${tipoLbl}</span></td>
      <td>${esc(subPor)}</td>
      <td>${fmtTSItv(r.created_at)}</td>
    </tr>`;
  }).join('');
  // v107AF: re-aplicar blindaje solo-lectura (la tabla se acaba de regenerar)
  _aplicarItvSoloLectura();
}

function openItvModal(dbId) {
  const r = itvRecords.find(x => String(x.db_id) === String(dbId));
  if (!r) return;
  editItvId = dbId;
  const fields = document.getElementById('itvFields');
  fields.innerHTML = `
    <div class="ig"><label>Matrícula</label><input id="itvMatricula" value="${esc(r.matricula || '')}" style="font-family:var(--mn);text-transform:uppercase"></div>
    <div class="ig"><label>Fecha ITV</label><input type="date" id="itvFecha" value="${r.fecha_itv || ''}"></div>
    <div class="ig"><label>Fecha caducidad</label><input type="date" id="itvCaducidad" value="${r.fecha_caducidad || ''}"></div>
    <div class="ig"><label>Tipo documento</label><select id="itvTipo"><option value="">—</option><option value="pegatina" ${r.tipo_documento==='pegatina'?'selected':''}>Pegatina</option><option value="informe" ${r.tipo_documento==='informe'?'selected':''}>Informe</option><option value="permiso" ${r.tipo_documento==='permiso'?'selected':''}>Permiso circulación</option></select></div>
    <div class="ig" style="grid-column:1/-1"><label>Observaciones</label><input id="itvObs" value="${esc(r.observaciones || '')}"></div>`;
  // Preview del archivo (foto o PDF)
  const preview = document.getElementById('itvPreview');
  if (r.file_url) {
    const isPdf = /\.pdf(\?|#|$)/i.test(r.file_url);
    if (isPdf) {
      preview.innerHTML = `<a href="${r.file_url}" target="_blank" class="preview-btn">📄 Abrir PDF</a>`;
    } else {
      preview.innerHTML = `<img src="${r.file_url}" style="max-width:100%;max-height:70vh;border-radius:8px;border:1px solid var(--bd);cursor:pointer" onclick="window.open('${r.file_url}','_blank')">`;
    }
  } else {
    preview.innerHTML = '<div style="color:var(--mu);text-align:center;padding:40px">Sin documento adjunto</div>';
  }
  // Aviso de estado
  const est = _itvEstado(r);
  document.getElementById('itvAlert').innerHTML = `<div style="margin-bottom:12px;padding:10px;border-radius:6px;background:var(--s2);font-family:var(--mn);font-size:11px">${est.icon} <strong>${est.label}</strong>${est.dias !== null ? ` · ${est.dias} días` : ''}</div>`;
  document.getElementById('itvOv').classList.add('open');
}

function closeItvModal() {
  document.getElementById('itvOv').classList.remove('open');
  editItvId = null;
}

async function saveItvModal() {
  const matricula = (document.getElementById('itvMatricula').value || '').trim().toUpperCase();
  const fecha_itv = document.getElementById('itvFecha').value || null;
  const fecha_caducidad = document.getElementById('itvCaducidad').value || null;
  const tipo_documento = document.getElementById('itvTipo').value || null;
  const observaciones = (document.getElementById('itvObs').value || '').trim() || null;
  if (!matricula) { toast('Matrícula requerida', 'err'); return; }
  try {
    const { error } = await sb.from('itv')
      .update({ matricula, fecha_itv, fecha_caducidad, tipo_documento, observaciones, updated_at: new Date().toISOString() })
      .eq('id', editItvId);
    if (error) throw error;
    closeItvModal();
    await loadItvData();
    toast('✓ ITV actualizada');
  } catch (e) {
    console.error('[saveItvModal] Error:', e);
    toast('Error guardando: ' + (e.message || e), 'err');
  }
}

async function deleteItvRecord() {
  if (!confirm('¿Eliminar este registro de ITV?\n\nEsta acción no se puede deshacer.')) return;
  try {
    const { error } = await sb.from('itv').delete().eq('id', editItvId);
    if (error) throw error;
    closeItvModal();
    await loadItvData();
    toast('✓ Eliminado');
  } catch (e) {
    console.error('[deleteItvRecord] Error:', e);
    toast('Error eliminando: ' + (e.message || e), 'err');
  }
}

// v101d: re-procesar el documento con IA. Útil cuando la primera lectura tuvo errores.
// Descarga el archivo de Storage, lo manda otra vez a Claude y actualiza los campos del modal
// (sin guardar todavía — el usuario revisa y luego pulsa Guardar).
async function reanalizarItv() {
  const r = itvRecords.find(x => String(x.db_id) === String(editItvId));
  if (!r || !r.file_url) { toast('Sin documento para reanalizar', 'err'); return; }
  const btn = document.getElementById('itvBtnReanalizar');
  if (btn) { btn.disabled = true; btn.textContent = '⏳ Analizando...'; }
  try {
    // Descargar el archivo desde Storage
    const resp = await fetch(r.file_url);
    if (!resp.ok) throw new Error('No se pudo descargar el documento');
    const blob = await resp.blob();
    const isPdf = /\.pdf(\?|#|$)/i.test(r.file_url) || blob.type === 'application/pdf';
    // Convertir a base64
    const b64 = await new Promise((res, rej) => {
      const fr = new FileReader();
      fr.onload = () => res(fr.result.split(',')[1]);
      fr.onerror = rej;
      fr.readAsDataURL(blob);
    });
    // Llamar a Claude con el prompt mejorado v101d
    const datos = await callClaudeItv(b64, isPdf ? 'application/pdf' : (blob.type || 'image/jpeg'));
    // Rellenar los campos del modal con los datos NUEVOS (sin guardar — el usuario revisa)
    if (datos.matricula) document.getElementById('itvMatricula').value = datos.matricula;
    if (datos.fecha_itv) document.getElementById('itvFecha').value = datos.fecha_itv;
    if (datos.fecha_caducidad) document.getElementById('itvCaducidad').value = datos.fecha_caducidad;
    if (datos.tipo_documento) document.getElementById('itvTipo').value = datos.tipo_documento;
    toast('✓ Reanalizado. Revisa los datos y pulsa Guardar.');
  } catch (e) {
    console.error('[reanalizarItv] Error:', e);
    toast('Error reanalizando: ' + (e.message || e), 'err');
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = '🔄 Reanalizar IA'; }
  }
}

// Subir nuevo documento ITV: sube archivo, llama a IA, guarda en BD
async function handleItvFiles(files) {
  if (!files || !files.length) return;
  if (!window._tieneITV) { toast('Sin permiso para subir ITV', 'err'); return; }
  for (const f of files) {
    try {
      toast(`📤 Subiendo ${f.name}...`);
      // 1. Subir archivo a Supabase Storage (bucket 'documentos', el mismo que albaranes/gasoil)
      const ext = (f.name.split('.').pop() || 'bin').toLowerCase();
      const path = `itv/${currentUser.id}/${Date.now()}_${Math.random().toString(36).slice(2)}.${ext}`;
      const { error: upErr } = await sb.storage.from('documentos').upload(path, f);
      if (upErr) throw upErr;
      const { data: urlData } = sb.storage.from('documentos').getPublicUrl(path);
      const file_url = urlData.publicUrl;
      // 2. Convertir a base64 para llamar a IA
      const isPdf = f.type === 'application/pdf' || f.name.toLowerCase().endsWith('.pdf');
      let b64;
      if (isPdf) {
        b64 = await new Promise((res, rej) => {
          const r = new FileReader();
          r.onload = () => res(r.result.split(',')[1]);
          r.onerror = rej;
          r.readAsDataURL(f);
        });
      } else {
        // Imagen — comprimir si hace falta
        const imgFile = f.size > 4 * 1024 * 1024 ? await comprimirImagen(f, 1400, 0.8) : f;
        b64 = await new Promise((res, rej) => {
          const r = new FileReader();
          r.onload = () => res(r.result.split(',')[1]);
          r.onerror = rej;
          r.readAsDataURL(imgFile);
        });
      }
      // 3. Llamar a IA para extraer datos
      toast(`🤖 Analizando ${f.name}...`);
      const datos = await callClaudeItv(b64, isPdf ? 'application/pdf' : (f.type || 'image/jpeg'));
      // 4. Guardar en BD (UPSERT por matrícula — si ya existe, sustituye)
      const matricula = (datos.matricula || '').trim().toUpperCase();
      if (!matricula) {
        toast(`⚠️ No se detectó matrícula en ${f.name}. Edítalo a mano.`, 'warn');
      }
      const rec = {
        matricula: matricula || `DESCONOCIDA_${Date.now()}`,
        fecha_itv: datos.fecha_itv || null,
        fecha_caducidad: datos.fecha_caducidad || null,
        tipo_documento: datos.tipo_documento || null,
        file_url,
        user_id: currentUser.id,
        updated_at: new Date().toISOString()
      };
      // UPSERT por matricula (si existe, actualiza; si no, inserta)
      const { error: upsErr } = await sb.from('itv').upsert(rec, { onConflict: 'matricula' });
      if (upsErr) throw upsErr;
      toast(`✓ ${matricula} procesada`);
    } catch (e) {
      console.error('[handleItvFiles] Error procesando', f.name, ':', e);
      toast(`✗ Error en ${f.name}: ${e.message || e}`, 'err');
    }
  }
  document.getElementById('itvFileInput').value = '';
  await loadItvData();
}

// Llamada a Claude para extraer datos de ITV
async function callClaudeItv(b64, mediaType) {
  // v101e: usar getKey() en lugar de localStorage.getItem('anthropic_key') (nombre incorrecto)
  // getKey() es la función que usan albaranes y gasoil para obtener la clave correctamente.
  const apiKey = getKey();
  if (!apiKey) throw new Error('Clave API no configurada. Configúrala en la pestaña Albaranes (botón Cambiar).');
  // v101d: prompt reforzado con los 3 formatos REALES que usa Juan Carlos:
  // 1) Pegatina circular del parabrisas (Applus Iteuve - "Fecha:" + "Caduca:")
  // 2) Informe oficial (Generalitat de Catalunya - campos numerados)
  // 3) Permiso de circulación de vehículo nuevo (DGT - "Próxima ITV" en Observaciones)
  const prompt = `Eres un experto en documentos de ITV (Inspección Técnica de Vehículos) de España y Cataluña. Analiza el documento adjunto y extrae los datos en JSON.

═══════════════════════════════════════════════════════════════
TIPOS DE DOCUMENTO Y CÓMO IDENTIFICARLOS
═══════════════════════════════════════════════════════════════

📌 TIPO 1 — "pegatina"
Pegatina circular pegada en el parabrisas (formato horizontal, fondo claro con texto APPLUS+ESPAÑA repetido en marca de agua).
Datos a extraer:
  • La matrícula aparece en grande (ej: "1968JFV")
  • "Fecha:" → fecha en que se PASÓ la ITV (DD/MM/YYYY) → fecha_itv
  • "Caduca:" → fecha de PRÓXIMA inspección (DD/MM/YYYY) → fecha_caducidad
  • Suele tener "FAVORABLE" como resultado y un código de estación (ej: "Iv: 0809")
  • Suele aparecer también los KM del vehículo (ej: "49598 km") — IGNORAR, no se guardan

📌 TIPO 2 — "informe"
Documento oficial completo de Applus Iteuve / Generalitat de Catalunya. Cabecera con logos "Generalitat de Catalunya" y "Applus Iteuve". Tabla grande con muchos campos.
Datos a extraer (campos numerados entre paréntesis):
  • "(2) Matrícula actual" → matricula (formato puede ser "4839NBF(E)" — quitar el "(E)")
  • "(3) Data d'inspecció" → fecha_itv (DD/MM/YYYY)
  • "(8) Data propera inspecció" → fecha_caducidad (DD/MM/YYYY)
  • "(7) Resultat de la inspecció: FAVORABLE" → confirmar que es válido
  • Escrito en catalán: "data" = "fecha", "propera" = "próxima", "inspecció" = "inspección"

📌 TIPO 3 — "permiso"
Permiso de circulación oficial del Reino de España (DGT/Ministerio del Interior). Cabecera con escudo de España y "PERMISO DE CIRCULACIÓN" + "COMUNIDAD EUROPEA". Tabla con campos en filas: A, B, H, I, (I.1), (I.2), C.1.1, etc.
Datos a extraer:
  • Campo "A" → matricula (ej: "3628NMW")
  • Campo "I" o "(I.1)" → fecha de matriculación (la usaremos como fecha_itv si no hay otra) (DD-MM-YYYY)
  • En el área de OBSERVACIONES (no manuscrito, está IMPRESO por la DGT) busca el texto:
    "Documento válido si acompaña ITV en vigor. Próxima ITV: DD-MM-YYYY"
    → fecha_caducidad = la fecha de "Próxima ITV"
  • Se usa para vehículos RECIÉN MATRICULADOS que aún no han pasado la primera ITV.

═══════════════════════════════════════════════════════════════
REGLAS GENERALES
═══════════════════════════════════════════════════════════════

✅ Matrícula española formato moderno: 4 dígitos + 3 letras (ej: "1234BCD"). Convertir a mayúsculas, quitar espacios y paréntesis sufijos como "(E)".
✅ TODAS las fechas en formato ISO YYYY-MM-DD (convertir desde DD/MM/YYYY o DD-MM-YYYY).
✅ Si una pegatina tiene "Caduca: 28/05/2026" → fecha_caducidad = "2026-05-28".
✅ NO inventes datos. Si no encuentras un campo claramente, ponlo a null.
✅ "tipo_documento" debe ser EXACTAMENTE uno de: "pegatina", "informe", "permiso".

═══════════════════════════════════════════════════════════════
FORMATO DE SALIDA
═══════════════════════════════════════════════════════════════

Responde SOLO con un JSON válido (sin markdown, sin explicaciones):
{
  "matricula": "1968JFV",
  "fecha_itv": "2025-11-11",
  "fecha_caducidad": "2026-05-28",
  "tipo_documento": "pegatina"
}`;

  const body = {
    model: 'claude-haiku-4-5',
    max_tokens: 500,
    messages: [{
      role: 'user',
      content: [
        { type: mediaType === 'application/pdf' ? 'document' : 'image', source: { type: 'base64', media_type: mediaType, data: b64 } },
        { type: 'text', text: prompt }
      ]
    }]
  };
  const resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true' },
    body: JSON.stringify(body)
  });
  if (!resp.ok) {
    const txt = await resp.text();
    throw new Error(`Error API: ${resp.status} - ${txt.slice(0, 200)}`);
  }
  const data = await resp.json();
  let text = data.content?.[0]?.text || '';
  // Limpiar markdown si lo hay
  text = text.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  try {
    return JSON.parse(text);
  } catch (e) {
    console.error('[callClaudeItv] No se pudo parsear:', text);
    throw new Error('Respuesta IA inválida');
  }
}

function switchTab(tab) {
  // Si entra a alb o gas, lo guardamos como última pestaña principal
  if (tab === 'alb' || tab === 'gas') _lastMainTab = tab;
  // v101: 'itv' añadido a la lista de pestañas. v105: 'produccion' añadido. v107j: 'neum' añadido. v107M: 'vac' añadido.
  ['alb','preli','gas','itv','neum','vac','taller','produccion','fichaje','subir','admin','facturacion'].forEach(t => {
    const tabEl = document.getElementById('tab' + t.charAt(0).toUpperCase() + t.slice(1));
    const content = document.getElementById('tabContent' + t.charAt(0).toUpperCase() + t.slice(1));
    if (tabEl) tabEl.classList.toggle('active', t === tab);
    if (content) content.style.display = t === tab ? 'block' : 'none';
  });
  // En la pestaña Subir, mostrar solo la zona que toca según _lastMainTab
  if (tab === 'subir') {
    const subir = document.getElementById('tabContentSubir');
    if (subir) {
      const albCard = subir.querySelectorAll('.card')[0]; // SUBIR ALBARANES
      const gasCard = subir.querySelectorAll('.card')[1]; // SUBIR TICKETS GASOIL
      if (albCard) albCard.style.display = (_lastMainTab === 'gas') ? 'none' : '';
      if (gasCard) gasCard.style.display = (_lastMainTab === 'alb') ? 'none' : '';
    }
  }
  if (tab === 'admin') loadUsers();
  if (tab === 'preli') { loadPreliquidaciones(); }
  // J24: al entrar en Facturación, pintar los meses con autofactura guardada.
  if (tab === 'facturacion') { try { factCargarMeses(); factCargarMesesHolcim(); factCargarMesesPromotora(); } catch (e) { console.warn('[J24] meses:', e); } }
  // v101: cargar ITVs al entrar en su pestaña
  if (tab === 'itv') { loadItvData(); if (window._itvSoloLectura) setTimeout(_aplicarItvSoloLectura, 200); }
  // v105: cargar tabla de producción al entrar en su pestaña
  if (tab === 'produccion') { loadProduccion(); }
  // v107j: cargar Neumáticos al entrar en su pestaña
  if (tab === 'neum') { loadNeumData(); }
  // v107M: cargar Vacaciones al entrar en su pestaña
  if (tab === 'vac') { loadVacData(); }
  // v107AE: cargar Taller al entrar en su pestaña
  if (tab === 'taller') { loadTallerData(); }
  // v107FA: cargar Fichaje al entrar en su pestaña
  if (tab === 'fichaje') { loadFichajes(); }
  // v107b: refresco automático al entrar en Albaranes. La lógica original con "5 segundos"
  // fallaba porque loadData se llama internamente durante el procesado, lo que hacía que
  // el timestamp se renovara sin que el usuario hubiera visto realmente la tabla. Ahora:
  // siempre que se entra en Albaranes, recarga (es una sola petición a Supabase, rápido).
  // El usuario nota la actualización; no se queda con datos viejos.
  if (tab === 'alb') {
    // Sin await: deja que la UI muestre la pestaña enseguida, y la tabla se actualiza
    // cuando llegan los datos. loadData() ya se encarga de re-renderizar todo.
    loadData().catch(e => console.error('[switchTab→alb] refresh falló:', e));
  }
}

// ============================================================
// v107FA: FICHAJE / REGISTRO DE JORNADA
// ------------------------------------------------------------
// Cumple RDL 8/2019: registro fiable, inmutable y exportable.
// La tabla 'fichajes' es de SOLO-AÑADIR (ni UPDATE ni DELETE en BD).
// Las correcciones son filas nuevas tipo 'correccion' que anulan a la
// original. Cada fichaje guarda hora EXACTA del servidor, trabajador,
// DNI, empresa y CIF.
//
// Tipos de evento en un día normal:
//   entrada -> salida_comida -> vuelta_comida -> salida
// El botón grande muestra solo el evento que toca según el estado.
// ============================================================

let _fichajes = [];          // todas las filas cargadas (según permisos RLS)
let _fichajeRelojTimer = null;
let _fichajeEvsHoy = [];   // v107J83: eventos de jornada de HOY (con hora) para el reloj del total

// Etiquetas legibles de cada tipo
const _FICHAJE_LABELS = {
  entrada:        '🟢 Entrada',
  salida_comida:  '🍽️ Salida a comer',
  vuelta_comida:  '↩️ Vuelta de comer',
  salida:         '🔴 Salida',
  correccion:     '✏️ Corrección',
  vacaciones:     '🏖️ Vacaciones',
  baja:           '🩺 Baja médica',
  festivo:        '🎉 Festivo',
  falta:          '⛔ Falta'
};

// Tipos que son AUSENCIA (día sin trabajo), no horas
const _FICHAJE_AUSENCIAS = ['vacaciones', 'baja', 'festivo', 'falta'];
function _fichajeEsAusencia(tipo) { return _FICHAJE_AUSENCIAS.includes(tipo); }

// Orden lógico de la jornada y qué botón ofrecer en cada punto
function _fichajeSiguienteEvento(eventosHoy) {
  // eventosHoy = lista de tipos ya fichados hoy (sin correcciones anuladas),
  // en orden cronológico.
  const tiene = (t) => eventosHoy.includes(t);
  // v107GM: si ya hay SALIDA, la jornada está completa — aunque no haya habido comida
  // (jornada continua). Esto va PRIMERO para no volver a pedir "salir a comer" tras una
  // salida directa.
  if (tiene('salida'))          return null;
  if (!tiene('entrada'))        return 'entrada';
  if (!tiene('salida_comida'))  return 'salida_comida';
  if (!tiene('vuelta_comida'))  return 'vuelta_comida';
  return 'salida';
}

// ¿Soy admin? (vista completa). Si no, soy trabajadora (mi propio fichaje).
function _fichajeEsAdmin() { return currentRole === 'admin'; }

// Datos del trabajador actual (para grabar DNI/empresa/CIF correctos)
function _fichajeMisDatos() {
  const p = userMap[currentUser?.id] || {};
  return {
    user_id: currentUser?.id,
    trabajador: p.name || currentUser?.email || 'Trabajador',
    dni: p.fichaje_dni || null,
    empresa: p.fichaje_empresa || null,
    cif: p.fichaje_cif || null
  };
}

// Carga los fichajes desde Supabase (RLS filtra: trabajadora ve lo suyo,
// admin ve todo).
async function loadFichajes() {
  try {
    const box = document.getElementById('fichajeTablaBox');
    let q = sb.from('fichajes').select('*').order('ts', { ascending: false });
    const { data, error } = await q;
    if (error) {
      if (/does not exist|relation/i.test(error.message || '')) {
        if (box) box.innerHTML = '<div style="color:var(--wn);font-family:var(--mn);font-size:12px">⚠️ Falta crear la tabla. Ejecuta el SQL <b>fichaje_setup.sql</b> en Supabase.</div>';
        return;
      }
      throw error;
    }
    _fichajes = data || [];
    renderFichaje();
  } catch (e) {
    console.error('[loadFichajes]', e);
    const box = document.getElementById('fichajeTablaBox');
    if (box) box.innerHTML = '<div style="color:var(--er);font-family:var(--mn);font-size:12px">Error cargando fichajes: ' + (e.message || e) + '</div>';
  }
}

// Devuelve los eventos VÁLIDOS CON SU HORA (aplicando correcciones) de un user
// en un día: [{tipo, ts}] ordenados por hora. Es la base; _fichajeEventosValidosDia
// devuelve solo los tipos (compatibilidad con el resto del código).
function _fichajeEventosConHoraDia(userId, fechaISO) {
  // Filas de ese usuario y día (por ts local)
  const delDia = _fichajes.filter(f => {
    if (f.user_id !== userId) return false;
    const refTs = f.tipo === 'correccion' ? (f.ts_corregido || f.ts) : f.ts;
    return _fichajeFechaLocal(refTs) === fechaISO;
  });
  // Construimos el estado: un mapa tipo -> {ts, anulado}
  const estado = {};
  // Primero los eventos directos
  delDia.filter(f => f.tipo !== 'correccion').forEach(f => {
    estado[f.tipo] = { ts: f.ts, anulado: false, id: f.id };
  });
  // Luego aplicamos correcciones en orden de creación
  delDia.filter(f => f.tipo === 'correccion')
        .sort((a, b) => new Date(a.created_at) - new Date(b.created_at))
        .forEach(f => {
    const t = f.tipo_corregido;
    if (!t) return;
    if (f.anulado) { delete estado[t]; }
    else { estado[t] = { ts: f.ts_corregido || f.ts, anulado: false, id: f.id }; }
  });
  // Devolver {tipo, ts} ordenados por hora
  return Object.keys(estado)
    .map(t => ({ tipo: t, ts: estado[t].ts }))
    .sort((a, b) => new Date(a.ts) - new Date(b.ts));
}

// Solo los TIPOS válidos del día, ordenados por hora (como antes).
function _fichajeEventosValidosDia(userId, fechaISO) {
  return _fichajeEventosConHoraDia(userId, fechaISO).map(e => e.tipo);
}

// v107J83: MINUTOS TRABAJADOS de un día (restando la comida), en vivo respecto a "ahora".
//   Mañana: entrada -> (salida a comer | salida | ahora)
//   Tarde:  vuelta de comer -> (salida | ahora)
// Si está comiendo (hay salida_comida pero aún no vuelta), el total queda CONGELADO.
function _fichajeMinutosTrabajados(evsConHora, ahora) {
  const tsDe = (t) => {
    const e = (evsConHora || []).find(x => x.tipo === t);
    return e ? new Date(e.ts).getTime() : null;
  };
  const entrada = tsDe('entrada');
  if (!entrada) return 0;
  const salComida    = tsDe('salida_comida');
  const vueltaComida = tsDe('vuelta_comida');
  const salida       = tsDe('salida');
  const now = (ahora instanceof Date ? ahora : new Date()).getTime();
  let ms = 0;
  // Segmento de la mañana
  const finManana = salComida || salida || now;
  ms += Math.max(0, finManana - entrada);
  // Segmento de la tarde (solo si volvió de comer)
  if (vueltaComida) {
    const finTarde = salida || now;
    ms += Math.max(0, finTarde - vueltaComida);
  }
  return Math.floor(ms / 60000);
}

// "H:MM" a partir de minutos (ej. 488 -> "8:08")
function _fichajeFmtMin(min) {
  min = Math.max(0, Math.round(min));
  const h = Math.floor(min / 60), m = min % 60;
  return h + ':' + String(m).padStart(2, '0');
}

// v107J85: lunes (00:00 local) de la semana que contiene la fecha d.
function _fichajeLunesSemana(d) {
  const x = new Date(d.getFullYear(), d.getMonth(), d.getDate());
  const dow = (x.getDay() + 6) % 7; // 0 = lunes
  x.setDate(x.getDate() - dow);
  return x;
}

// v107J85: resumen de la semana (L..D) de un trabajador. Para cada día con jornada
// calcula los minutos trabajados (restando comida). El SALDO suma (trabajado - 8h)
// SOLO de los días TERMINADOS (con salida), para no salir en negativo durante el día.
function _fichajeResumenSemana(userId, refDate) {
  const TOPE = 8 * 60;
  const lunes = _fichajeLunesSemana(refDate || new Date());
  const ahora = new Date();
  const hoyISO = _fichajeFechaLocal(ahora);
  const NOM = ['L', 'M', 'X', 'J', 'V', 'S', 'D'];
  const dias = [];
  let totalMin = 0, saldoMin = 0;
  for (let i = 0; i < 7; i++) {
    const d = new Date(lunes); d.setDate(lunes.getDate() + i);
    const fISO = _fichajeFechaLocal(d);
    const evs = _fichajeEventosConHoraDia(userId, fISO).filter(e => !_fichajeEsAusencia(e.tipo));
    const tieneEntrada = evs.some(e => e.tipo === 'entrada');
    const terminado = evs.some(e => e.tipo === 'salida');
    const min = tieneEntrada ? _fichajeMinutosTrabajados(evs, ahora) : 0;
    if (tieneEntrada) { totalMin += min; if (terminado) saldoMin += (min - TOPE); }
    dias.push({ nombre: NOM[i], fISO, min, tieneEntrada, terminado, esHoy: fISO === hoyISO });
  }
  return { dias, totalMin, saldoMin };
}

// v107J85: pinta el resumen de la semana en la pantalla del trabajador.
function _fichajeRenderSemana() {
  const box = document.getElementById('fichajeSemana');
  if (!box) return;
  const r = _fichajeResumenSemana(currentUser.id, new Date());
  const celdas = r.dias.map(d => {
    const val = d.tieneEntrada ? _fichajeFmtMin(d.min) : '—';
    const col = d.esHoy ? 'var(--ac)' : (d.tieneEntrada ? 'var(--tx)' : 'var(--mu)');
    return '<div style="text-align:center;min-width:36px">' +
             '<div style="font-size:10px;color:var(--mu)">' + d.nombre + '</div>' +
             '<div style="font-size:12px;font-weight:600;color:' + col + '">' + val + '</div>' +
           '</div>';
  }).join('');
  const saldoTxt = (r.saldoMin >= 0 ? '+' : '−') + _fichajeFmtMin(Math.abs(r.saldoMin));
  const saldoCol = r.saldoMin > 0 ? 'var(--wn)' : (r.saldoMin < 0 ? 'var(--in)' : 'var(--mu)');
  box.innerHTML =
    '<div style="font-family:var(--mn);font-size:10px;color:var(--mu);letter-spacing:.5px;margin-bottom:8px">ESTA SEMANA</div>' +
    '<div style="display:flex;gap:6px;justify-content:center;flex-wrap:wrap;margin-bottom:10px">' + celdas + '</div>' +
    '<div style="font-family:var(--mn);font-size:12px;color:var(--mu)">Total: <b style="color:var(--tx)">' + _fichajeFmtMin(r.totalMin) + '</b>' +
    ' · Saldo: <b style="color:' + saldoCol + '">' + saldoTxt + '</b></div>' +
    '<div style="font-family:var(--mn);font-size:10px;color:var(--mu);margin-top:4px">(saldo sobre 8h/día, solo días terminados)</div>';
}

// v107J86: RESUMEN DE HORAS POR TRABAJADOR (solo admin). El admin no ficha, así que
// no veía las horas que lleva cada uno; aquí las mostramos (hoy, semana y saldo).
function _fichajeRenderAdminResumen() {
  const box = document.getElementById('fichajeAdminResumen');
  if (!box) return;
  if (!_fichajeEsAdmin()) { box.style.display = 'none'; box.innerHTML = ''; return; }

  // Trabajadores presentes en los fichajes (user_id -> nombre)
  const nombres = {};
  _fichajes.forEach(f => { if (f.user_id) nombres[f.user_id] = f.trabajador || nombres[f.user_id] || f.user_id; });

  const ahora = new Date();
  const hoyISO = _fichajeFechaLocal(ahora);
  const filas = Object.keys(nombres).map(uid => {
    const evsHoy = _fichajeEventosConHoraDia(uid, hoyISO).filter(e => !_fichajeEsAusencia(e.tipo));
    const minHoy = evsHoy.some(e => e.tipo === 'entrada') ? _fichajeMinutosTrabajados(evsHoy, ahora) : 0;
    const sem = _fichajeResumenSemana(uid, ahora);
    return { nombre: nombres[uid], minHoy, semMin: sem.totalMin, saldoMin: sem.saldoMin };
  }).sort((a, b) => String(a.nombre).localeCompare(String(b.nombre)));

  if (!filas.length) { box.style.display = 'none'; box.innerHTML = ''; return; }
  box.style.display = '';

  const th = (t) => '<th style="text-align:left;padding:8px 10px;border-bottom:1px solid var(--bd);font-family:var(--mn);font-size:11px;color:var(--mu);white-space:nowrap">' + t + '</th>';
  const td = (t, col) => '<td style="padding:8px 10px;border-bottom:1px solid var(--bd);font-family:var(--mn);font-size:12px;white-space:nowrap;color:' + (col || 'var(--tx)') + '">' + t + '</td>';

  let html = '<table style="width:100%;border-collapse:collapse"><thead><tr>'
    + th('Trabajador') + th('Hoy') + th('Esta semana') + th('Saldo') + '</tr></thead><tbody>';
  filas.forEach(f => {
    const saldoCol = f.saldoMin > 0 ? 'var(--wn)' : (f.saldoMin < 0 ? 'var(--in)' : 'var(--mu)');
    const saldoTxt = (f.saldoMin >= 0 ? '+' : '−') + _fichajeFmtMin(Math.abs(f.saldoMin));
    html += '<tr>' + td('<b>' + _fichajeEsc(f.nombre) + '</b>') + td(_fichajeFmtMin(f.minHoy)) +
            td(_fichajeFmtMin(f.semMin)) + td(saldoTxt, saldoCol) + '</tr>';
  });
  html += '</tbody></table>';
  html += '<div style="font-family:var(--mn);font-size:10px;color:var(--mu);margin-top:8px;padding:0 10px">Saldo = horas sobre 8h/día de los días YA TERMINADOS de esta semana.</div>';

  box.innerHTML = '<div class="card-hd"><div class="st"><div class="dot" style="--c:var(--ac)"></div>HORAS POR TRABAJADOR · ESTA SEMANA</div></div>' +
                  '<div class="card-bd" style="overflow-x:auto">' + html + '</div>';
}

// Fecha local YYYY-MM-DD de un timestamp
function _fichajeFechaLocal(ts) {
  const d = new Date(ts);
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${dd}`;
}

// Hora local HH:MM:SS
function _fichajeHoraLocal(ts) {
  const d = new Date(ts);
  return d.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
}

// Fecha local DD/MM/YYYY
function _fichajeFechaBonita(fechaISO) {
  const [y, m, d] = fechaISO.split('-');
  return `${d}/${m}/${y}`;
}

// Renderiza la pestaña entera (botonera + tabla) según rol
function renderFichaje() {
  const botonera = document.getElementById('fichajeBotonera');
  const titulo = document.getElementById('fichajeTablaTitulo');
  const btnExcel = document.getElementById('fichajeBtnExcel');
  const hoyISO = _fichajeFechaLocal(new Date());

  if (_fichajeEsAdmin()) {
    // ADMIN: sin botonera (el jefe no ficha), tabla con TODAS, botón Excel
    if (botonera) botonera.style.display = 'none';
    if (titulo) titulo.textContent = 'TODOS LOS FICHAJES';
    if (btnExcel) btnExcel.style.display = '';
    const btnAusAdm = document.getElementById('fichajeBtnAusenciaAdmin');
    if (btnAusAdm) btnAusAdm.style.display = '';
  } else {
    // TRABAJADORA: botonera grande + su histórico
    if (botonera) botonera.style.display = '';
    if (titulo) titulo.textContent = 'MIS FICHAJES';
    if (btnExcel) btnExcel.style.display = 'none';
    const btnAusAdm = document.getElementById('fichajeBtnAusenciaAdmin');
    if (btnAusAdm) btnAusAdm.style.display = 'none';
    _fichajeRenderBotonera();
  }
  _fichajeRenderAdminResumen();
  renderFichajes();
}

// Botonera grande de la trabajadora (estado + botón del evento que toca)
function _fichajeRenderBotonera() {
  const hoyISO = _fichajeFechaLocal(new Date());
  const fechaEl = document.getElementById('fichajeHoy');
  if (fechaEl) fechaEl.textContent = _fichajeFechaBonita(hoyISO);

  const eventosHoy = _fichajeEventosValidosDia(currentUser.id, hoyISO);

  // v107J83: eventos de hoy CON HORA, para mostrar las horas fichadas y el total en vivo.
  const evsConHoraHoy = _fichajeEventosConHoraDia(currentUser.id, hoyISO);
  const evsJornadaHoy = evsConHoraHoy.filter(e => !_fichajeEsAusencia(e.tipo));
  _fichajeEvsHoy = evsJornadaHoy;
  const horasBox = document.getElementById('fichajeHorasHoy');
  if (horasBox) {
    horasBox.innerHTML = evsJornadaHoy.length
      ? evsJornadaHoy.map(e =>
          (_FICHAJE_LABELS[e.tipo] || e.tipo) +
          ' · <b style="color:var(--tx)">' + _fichajeHoraLocal(e.ts).slice(0, 5) + '</b>'
        ).join('<br>')
      : '';
  }
  // v107J85: resumen de la semana (días + total + saldo de extras)
  _fichajeRenderSemana();
  // ¿Hoy hay una ausencia marcada (vacaciones/baja/festivo/falta)?
  const ausenciaHoy = eventosHoy.find(t => _fichajeEsAusencia(t));
  // Para el botón de horas, solo cuentan los eventos de jornada (no ausencias)
  const eventosJornada = eventosHoy.filter(t => !_fichajeEsAusencia(t));
  const siguiente = _fichajeSiguienteEvento(eventosJornada);

  const estadoTxt = document.getElementById('fichajeEstadoTxt');
  const btn = document.getElementById('fichajeBtnGrande');

  // Si hoy está marcado como ausencia, mostrarlo y NO ofrecer fichar
  if (ausenciaHoy) {
    if (estadoTxt) estadoTxt.textContent = 'Hoy está marcado como: ' + (_FICHAJE_LABELS[ausenciaHoy] || ausenciaHoy);
    if (btn) {
      btn.textContent = (_FICHAJE_LABELS[ausenciaHoy] || ausenciaHoy).toUpperCase();
      btn.disabled = true;
      btn.style.opacity = '.55';
      btn.style.cursor = 'default';
    }
    _fichajeArrancarReloj();
    return;
  }

  // Texto de estado
  if (estadoTxt) {
    if (eventosJornada.length === 0) {
      estadoTxt.textContent = 'Aún no has fichado hoy.';
    } else {
      const ultimo = eventosJornada[eventosJornada.length - 1];
      estadoTxt.textContent = 'Último fichaje de hoy: ' + (_FICHAJE_LABELS[ultimo] || ultimo);
    }
  }

  // Botón del evento que toca
  if (btn) {
    if (siguiente === null) {
      btn.textContent = '✅ Jornada completa';
      btn.disabled = true;
      btn.style.opacity = '.55';
      btn.style.cursor = 'default';
    } else {
      const txtBtn = {
        entrada:       '🟢 FICHAR ENTRADA',
        salida_comida: '🍽️ SALIR A COMER',
        vuelta_comida: '↩️ VOLVER DE COMER',
        salida:        '🔴 FICHAR SALIDA'
      };
      btn.textContent = txtBtn[siguiente] || 'FICHAR';
      btn.disabled = false;
      btn.style.opacity = '1';
      btn.style.cursor = 'pointer';
      btn.dataset.evento = siguiente;
    }
  }

  // v107GM (Juan Carlos 01/06): JORNADA CONTINUA. Cuando lo que tocaría es "Salir a comer"
  // (ya fichó entrada, aún no comió), algunos hacen jornada CONTINUA (Mª del Mar: 3h seguidas,
  // 10-13h) y no necesitan pausa de comida. Por eso, en ese momento mostramos un SEGUNDO botón
  // "🔴 SALIR (jornada continua)" que ficha directamente la SALIDA, saltándose la comida.
  // El usuario elige: comer (botón grande) o terminar (este). En cualquier otro momento, este
  // botón extra no aparece.
  let btnCont = document.getElementById('fichajeBtnContinua');
  if (btn && btn.parentNode) {
    if (siguiente === 'salida_comida') {
      if (!btnCont) {
        btnCont = document.createElement('button');
        btnCont.id = 'fichajeBtnContinua';
        btnCont.className = 'btn bw';
        btnCont.style.cssText = 'max-width:340px;margin:0 auto 16px;font-size:13px;padding:13px;display:block;width:100%';
        btnCont.onclick = function () { _fichajeInsertar({ tipo: 'salida', metodo: 'boton' }); };
        btn.parentNode.insertBefore(btnCont, btn.nextSibling);
      }
      btnCont.textContent = '🔴 SALIR (jornada continua, sin comer)';
      btnCont.style.display = 'block';
    } else if (btnCont) {
      btnCont.style.display = 'none';
    }
  }

  // Reloj en vivo
  _fichajeArrancarReloj();
}

function _fichajeArrancarReloj() {
  const relojEl = document.getElementById('fichajeRelojVivo');
  const lblEl = document.getElementById('fichajeRelojLabel');
  if (!relojEl) return;
  const TOPE_MIN = 8 * 60; // 8 horas = norma
  const tick = () => {
    const min = _fichajeMinutosTrabajados(_fichajeEvsHoy, new Date());
    const h = Math.floor(min / 60), m = min % 60;
    relojEl.textContent = String(h).padStart(2, '0') + ':' + String(m).padStart(2, '0');
    const pasado = min >= TOPE_MIN;
    relojEl.style.color = pasado ? 'var(--er)' : 'var(--ac)'; // rojo si ya hizo 8h
    if (lblEl) {
      lblEl.style.color = pasado ? 'var(--er)' : 'var(--mu)';
      lblEl.textContent = pasado
        ? ('TRABAJADO HOY · +' + _fichajeFmtMin(min - TOPE_MIN) + ' sobre las 8h')
        : 'TRABAJADO HOY · de 8:00';
    }
  };
  tick();
  if (_fichajeRelojTimer) clearInterval(_fichajeRelojTimer);
  _fichajeRelojTimer = setInterval(tick, 1000);
}

// Pulsar el botón grande -> graba el evento que toca con la hora del servidor
async function ficharBotonGrande() {
  const btn = document.getElementById('fichajeBtnGrande');
  const evento = btn?.dataset?.evento;
  if (!evento) return;
  await _fichajeInsertar({ tipo: evento, metodo: 'boton' });
}

// Inserta un fichaje (evento directo). La hora la pone el servidor (now()).
async function _fichajeInsertar({ tipo, metodo, ts, nota }) {
  try {
    const datos = _fichajeMisDatos();
    const fila = {
      user_id: datos.user_id,
      trabajador: datos.trabajador,
      dni: datos.dni,
      empresa: datos.empresa,
      cif: datos.cif,
      tipo: tipo,
      metodo: metodo || 'boton',
      registrado_por: currentUser.id
    };
    // Si es manual con hora concreta, la mandamos; si es botón, la pone el server
    if (ts) fila.ts = ts;
    const { error } = await sb.from('fichajes').insert(fila);
    if (error) throw error;
    toast('✅ Fichaje registrado: ' + (_FICHAJE_LABELS[tipo] || tipo));
    await loadFichajes();
  } catch (e) {
    console.error('[_fichajeInsertar]', e);
    toast('Error al fichar: ' + (e.message || e), 'err');
  }
}

// ---------- FICHAJE MANUAL (trabajadora) / CORRECCIÓN (admin) ----------

let _fichajeModalModo = 'manual'; // 'manual' | 'correccion'
let _fichajeCorrigeId = null;

// Trabajadora: apuntar una hora a mano (por si se olvidó al llegar)
