// Admin: corregir un fichaje concreto (crea una fila 'correccion')
function abrirFichajeCorreccion(id) {
  const orig = _fichajes.find(f => String(f.id) === String(id));
  if (!orig) return;
  _fichajeModalModo = 'correccion';
  _fichajeCorrigeId = orig.id;
  const titulo = document.getElementById('fichajeModalTitulo');
  if (titulo) titulo.textContent = 'CORREGIR FICHAJE';
  const refTs = orig.tipo === 'correccion' ? (orig.ts_corregido || orig.ts) : orig.ts;
  const tipoRef = orig.tipo === 'correccion' ? (orig.tipo_corregido || 'entrada') : orig.tipo;
  const fechaDef = _fichajeFechaLocal(refTs);
  const horaDef = new Date(refTs).toTimeString().slice(0, 5);
  const opt = (v, lbl) => `<option value="${v}"${v === tipoRef ? ' selected' : ''}>${lbl}</option>`;
  const fields = document.getElementById('fichajeModalFields');
  if (fields) {
    fields.innerHTML = `
      <div style="font-family:var(--mn);font-size:11px;color:var(--mu);margin-bottom:10px">
        Trabajadora: <b style="color:var(--tx)">${orig.trabajador || '—'}</b><br>
        Original: ${_FICHAJE_LABELS[tipoRef] || tipoRef} · ${_fichajeFechaBonita(fechaDef)} ${horaDef}
      </div>
      <div class="login-field">
        <label class="login-label">Tipo correcto</label>
        <select class="login-input" id="fmTipo">
          ${opt('entrada','🟢 Entrada')}
          ${opt('salida_comida','🍽️ Salida a comer')}
          ${opt('vuelta_comida','↩️ Vuelta de comer')}
          ${opt('salida','🔴 Salida')}
        </select>
      </div>
      <div style="display:flex;gap:10px">
        <div class="login-field" style="flex:1">
          <label class="login-label">Fecha correcta</label>
          <input type="date" class="login-input" id="fmFecha" value="${fechaDef}">
        </div>
        <div class="login-field" style="flex:1">
          <label class="login-label">Hora correcta</label>
          <input type="time" class="login-input" id="fmHora" value="${horaDef}">
        </div>
      </div>
      <div class="login-field">
        <label class="login-label">Motivo de la corrección</label>
        <input type="text" class="login-input" id="fmNota" placeholder="Ej: el reloj iba adelantado">
      </div>
      <div style="margin-top:6px">
        <label style="font-family:var(--mn);font-size:11px;color:var(--tx);display:flex;align-items:center;gap:8px;cursor:pointer">
          <input type="checkbox" id="fmAnular"> Anular este fichaje (era un error, no debe contar)
        </label>
      </div>
      <div style="font-family:var(--mn);font-size:10px;color:var(--mu);margin-top:8px">
        La corrección NO borra el original: queda el rastro completo, como exige la Inspección.
      </div>`;
  }
  document.getElementById('ovFichaje').classList.add('open');
}

function cerrarFichajeModal() {
  document.getElementById('ovFichaje').classList.remove('open');
}

// Guardar desde el modal (manual, corrección o ausencia)
async function guardarFichajeManual() {
  // Si el modal está en modo ausencia, derivar a su propia función
  if (_fichajeModalModo === 'ausencia') { return guardarFichajeAusencia(); }
  try {
    const tipo = document.getElementById('fmTipo')?.value;
    const fecha = document.getElementById('fmFecha')?.value;
    const hora = document.getElementById('fmHora')?.value;
    const nota = (document.getElementById('fmNota')?.value || '').trim() || null;
    if (!tipo || !fecha || !hora) { toast('Rellena tipo, fecha y hora', 'warn'); return; }
    // v107J84: al APUNTAR A MANO el motivo es obligatorio (saber por qué se apunta a mano).
    // En las correcciones del admin sigue siendo opcional.
    if (_fichajeModalModo === 'manual' && !nota) { toast('Pon el motivo (por qué lo apuntas a mano)', 'warn'); return; }
    // Construir timestamp local -> ISO
    const tsLocal = new Date(`${fecha}T${hora}:00`);
    if (isNaN(tsLocal.getTime())) { toast('Fecha u hora no válidas', 'err'); return; }

    if (_fichajeModalModo === 'correccion') {
      // El admin crea una fila 'correccion' que apunta al original
      const anular = document.getElementById('fmAnular')?.checked;
      const orig = _fichajes.find(f => String(f.id) === String(_fichajeCorrigeId));
      const fila = {
        user_id: orig?.user_id || currentUser.id, // el fichaje sigue siendo de la trabajadora
        trabajador: orig?.trabajador || null,
        dni: orig?.dni || null,
        empresa: orig?.empresa || null,
        cif: orig?.cif || null,
        tipo: 'correccion',
        corrige_a: _fichajeCorrigeId,
        tipo_corregido: tipo,
        ts_corregido: tsLocal.toISOString(),
        anulado: !!anular,
        nota: nota,
        metodo: 'manual',
        registrado_por: currentUser.id
      };
      const { error } = await sb.from('fichajes').insert(fila);
      if (error) throw error;
      toast('✅ Corrección guardada (el original se conserva)');
    } else {
      // Trabajadora apunta a mano: evento directo con metodo='manual'
      await _fichajeInsertar({ tipo, metodo: 'manual', ts: tsLocal.toISOString(), nota });
    }
    cerrarFichajeModal();
    await loadFichajes();
  } catch (e) {
    console.error('[guardarFichajeManual]', e);
    toast('Error al guardar: ' + (e.message || e), 'err');
  }
}

// ---------- AUSENCIAS (vacaciones / baja / festivo / falta) ----------

// Lista de personas que pueden fichar (para que el admin elija de quién es
// la ausencia). Devuelve [{id, nombre, dni, empresa, cif}]
function _fichajeListaTrabajadores() {
  const lista = [];
  Object.keys(userMap || {}).forEach(id => {
    const p = userMap[id];
    if (p && p.puede_fichar) {
      lista.push({
        id: id,
        nombre: p.name || id,
        dni: p.fichaje_dni || null,
        empresa: p.fichaje_empresa || null,
        cif: p.fichaje_cif || null
      });
    }
  });
  lista.sort((a, b) => (a.nombre || '').localeCompare(b.nombre || ''));
  return lista;
}

// Abrir modal para marcar día(s) sin trabajo
function abrirFichajeAusencia() {
  _fichajeModalModo = 'ausencia';
  _fichajeCorrigeId = null;
  const titulo = document.getElementById('fichajeModalTitulo');
  if (titulo) titulo.textContent = 'MARCAR DÍA SIN TRABAJO';
  const hoy = _fichajeFechaLocal(new Date());
  const esAdmin = _fichajeEsAdmin();

  // Si es admin, selector de trabajadora; si no, ella misma (oculto)
  let selectorTrabajadora = '';
  if (esAdmin) {
    const lista = _fichajeListaTrabajadores();
    const opciones = lista.map(t =>
      `<option value="${t.id}">${_fichajeEsc(t.nombre)}${t.empresa ? ' · ' + _fichajeEsc(t.empresa) : ''}</option>`
    ).join('');
    selectorTrabajadora = `
      <div class="login-field">
        <label class="login-label">Trabajador/a</label>
        <select class="login-input" id="faTrabajador">${opciones}</select>
      </div>`;
  }

  const fields = document.getElementById('fichajeModalFields');
  if (fields) {
    fields.innerHTML = `
      ${selectorTrabajadora}
      <div class="login-field">
        <label class="login-label">Motivo</label>
        <select class="login-input" id="faMotivo">
          <option value="vacaciones">🏖️ Vacaciones</option>
          <option value="baja">🩺 Baja médica</option>
          <option value="festivo">🎉 Festivo</option>
          <option value="falta">⛔ Falta</option>
        </select>
      </div>
      <div style="display:flex;gap:10px">
        <div class="login-field" style="flex:1">
          <label class="login-label">Desde el día</label>
          <input type="date" class="login-input" id="faDesde" value="${hoy}">
        </div>
        <div class="login-field" style="flex:1">
          <label class="login-label">Hasta el día</label>
          <input type="date" class="login-input" id="faHasta" value="${hoy}">
        </div>
      </div>
      <div style="font-family:var(--mn);font-size:10px;color:var(--mu);margin-top:2px">
        Si es un solo día, deja la misma fecha en los dos. Para varios días seguidos
        (ej. una semana de vacaciones), pon el primero y el último.
      </div>
      <div class="login-field" style="margin-top:10px">
        <label class="login-label">Observación (opcional)</label>
        <input type="text" class="login-input" id="faNota" placeholder="Ej: vacaciones de verano">
      </div>`;
  }
  document.getElementById('ovFichaje').classList.add('open');
}

// Guardar la(s) ausencia(s): una fila por cada día del rango
async function guardarFichajeAusencia() {
  try {
    const motivo = document.getElementById('faMotivo')?.value;
    const desde = document.getElementById('faDesde')?.value;
    const hasta = document.getElementById('faHasta')?.value;
    const nota = document.getElementById('faNota')?.value || null;
    if (!motivo || !desde || !hasta) { toast('Rellena motivo y fechas', 'warn'); return; }
    if (hasta < desde) { toast('La fecha "hasta" no puede ser anterior a "desde"', 'err'); return; }

    // ¿De quién es la ausencia?
    let destino;
    if (_fichajeEsAdmin()) {
      const idSel = document.getElementById('faTrabajador')?.value;
      const lista = _fichajeListaTrabajadores();
      const t = lista.find(x => x.id === idSel);
      if (!t) { toast('Selecciona un trabajador', 'warn'); return; }
      destino = { user_id: t.id, trabajador: t.nombre, dni: t.dni, empresa: t.empresa, cif: t.cif };
    } else {
      destino = _fichajeMisDatos();
    }

    // Generar una fila por cada día del rango (mediodía, para evitar líos de zona horaria)
    const filas = [];
    let d = new Date(desde + 'T12:00:00');
    const fin = new Date(hasta + 'T12:00:00');
    let guardia = 0;
    while (d <= fin && guardia < 370) {
      filas.push({
        user_id: destino.user_id,
        trabajador: destino.trabajador,
        dni: destino.dni,
        empresa: destino.empresa,
        cif: destino.cif,
        tipo: motivo,
        ts: new Date(d).toISOString(),
        metodo: 'manual',
        nota: nota,
        registrado_por: currentUser.id
      });
      d.setDate(d.getDate() + 1);
      guardia++;
    }
    if (!filas.length) { toast('No hay días que marcar', 'warn'); return; }

    const { error } = await sb.from('fichajes').insert(filas);
    if (error) throw error;
    toast(`✅ ${filas.length} día(s) marcado(s) como ${(_FICHAJE_LABELS[motivo] || motivo)}`);
    cerrarFichajeModal();
    await loadFichajes();
  } catch (e) {
    console.error('[guardarFichajeAusencia]', e);
    toast('Error al marcar: ' + (e.message || e), 'err');
  }
}

// ---------- TABLA DE FICHAJES ----------

function renderFichajes() {
  const box = document.getElementById('fichajeTablaBox');
  if (!box) return;
  const esAdmin = _fichajeEsAdmin();

  // Filtros de fecha
  const desde = document.getElementById('fichajeFiltroDesde')?.value || null;
  const hasta = document.getElementById('fichajeFiltroHasta')?.value || null;

  // Para la tabla mostramos TODAS las filas (incluidas correcciones), porque
  // a efectos legales debe verse el rastro completo. Las correcciones salen
  // marcadas.
  let filas = _fichajes.slice();

  // Filtro por fecha (usando la fecha de referencia)
  filas = filas.filter(f => {
    const refTs = f.tipo === 'correccion' ? (f.ts_corregido || f.ts) : f.ts;
    const fISO = _fichajeFechaLocal(refTs);
    if (desde && fISO < desde) return false;
    if (hasta && fISO > hasta) return false;
    return true;
  });

  if (filas.length === 0) {
    box.innerHTML = '<div style="color:var(--mu);font-family:var(--mn);font-size:12px">No hay fichajes en este periodo.</div>';
    return;
  }

  // Ordenar por fecha/hora descendente
  filas.sort((a, b) => {
    const ta = a.tipo === 'correccion' ? (a.ts_corregido || a.ts) : a.ts;
    const tb = b.tipo === 'correccion' ? (b.ts_corregido || b.ts) : b.ts;
    return new Date(tb) - new Date(ta);
  });

  const th = (t) => `<th style="text-align:left;padding:8px 10px;font-family:var(--mn);font-size:10px;color:var(--mu);text-transform:uppercase;letter-spacing:1px;border-bottom:1px solid var(--bd);white-space:nowrap">${t}</th>`;
  const td = (t) => `<td style="padding:8px 10px;font-family:var(--mn);font-size:12px;color:var(--tx);border-bottom:1px solid var(--s2)">${t}</td>`;

  let html = '<table style="width:100%;border-collapse:collapse;min-width:640px"><thead><tr>';
  if (esAdmin) html += th('Trabajadora');
  html += th('Fecha') + th('Hora') + th('Tipo') + th('Cómo') + th('Nota');
  if (esAdmin) html += th('Acción');
  html += '</tr></thead><tbody>';

  filas.forEach(f => {
    const esCorr = f.tipo === 'correccion';
    const refTs = esCorr ? (f.ts_corregido || f.ts) : f.ts;
    const tipoMostrar = esCorr ? (f.tipo_corregido || '') : f.tipo;
    const esAus = _fichajeEsAusencia(tipoMostrar);
    let etiqueta = _FICHAJE_LABELS[tipoMostrar] || tipoMostrar;
    if (esCorr) {
      etiqueta = f.anulado
        ? '🚫 Anula ' + (_FICHAJE_LABELS[tipoMostrar] || tipoMostrar)
        : '✏️ Corrige a ' + (_FICHAJE_LABELS[tipoMostrar] || tipoMostrar);
    }
    const comoTxt = f.metodo === 'manual' ? '✍️ A mano' : '👆 Botón';
    // Fondo: corrección ámbar suave, ausencia azulado suave, normal sin fondo
    let rowStyle = '';
    if (esCorr) rowStyle = ' style="background:rgba(245,166,35,.06)"';
    else if (esAus) rowStyle = ' style="background:rgba(123,143,240,.06)"';

    html += `<tr${rowStyle}>`;
    if (esAdmin) html += td(f.trabajador || '—');
    html += td(_fichajeFechaBonita(_fichajeFechaLocal(refTs)));
    // Las ausencias no tienen hora concreta: mostramos "—"
    html += td(esAus ? '<span style="color:var(--mu)">— día completo</span>' : ('<b>' + _fichajeHoraLocal(refTs) + '</b>'));
    html += td(etiqueta);
    html += td(comoTxt);
    html += td(f.nota ? ('<span style="color:var(--mu)">' + _fichajeEsc(f.nota) + '</span>') : '—');
    if (esAdmin) {
      // El admin solo puede corregir eventos directos (no corregir una corrección)
      if (!esCorr) {
        html += td(`<button class="btn bs" style="font-size:10px;padding:4px 8px" onclick="abrirFichajeCorreccion('${f.id}')">✏️ Corregir</button>`);
      } else {
        html += td('—');
      }
    }
    html += '</tr>';
  });
  html += '</tbody></table>';
  box.innerHTML = html;
}

// Escapar texto para HTML (evitar romper la tabla con comillas/símbolos)
function _fichajeEsc(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

// ---------- EXPORTAR A EXCEL (admin) ----------

// ============================================================
// v107FG (28/05/2026): HOJA "Registro Legal" del Excel de Fichaje.
// Formato oficial Art. 10 RD-ley 8/2019 (modelo del gestor).
// Construye un array de filas (aoa) con una sección por cada
// Trabajador + Mes presente en las filas de fichaje recibidas.
// Centro de trabajo fijo para todos: Sant Vicenç dels Horts.
// ============================================================
const _FICHAJE_CENTRO_TRABAJO = 'Sant Vicenç dels Horts';

// Devuelve la hora HH:MM (sin segundos) de un timestamp, o '' si no hay.
function _fichajeHHMM(ts) {
  if (!ts) return '';
  const d = new Date(ts);
  const h = String(d.getHours()).padStart(2, '0');
  const m = String(d.getMinutes()).padStart(2, '0');
  return `${h}:${m}`;
}

function _fichajeAoaLegal(filas) {
  const MESES = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio',
                 'Agosto','Septiembre','Octubre','Noviembre','Diciembre'];

  // 1) Agrupar las filas por TRABAJADOR + AÑO-MES. Para cada día guardamos
  //    los 4 momentos (entrada/salida_comida/vuelta_comida/salida) y, si hay
  //    ausencia, su etiqueta. Las correcciones ya vienen resueltas en `filas`
  //    (usamos ts_corregido/tipo_corregido cuando es corrección no anulada).
  const grupos = {}; // clave "trabajador||YYYY-MM" -> { info, dias:{1..31} }
  filas.forEach(f => {
    if (f.tipo === 'correccion' && f.anulado) return; // anulaciones no pintan
    const esCorr = f.tipo === 'correccion';
    const refTs  = esCorr ? (f.ts_corregido || f.ts) : f.ts;
    const tipo   = esCorr ? (f.tipo_corregido || '') : f.tipo;
    if (!tipo) return;
    const fISO = _fichajeFechaLocal(refTs);       // YYYY-MM-DD
    const [yy, mm, dd] = fISO.split('-');
    const claveMes = `${f.trabajador || ''}||${yy}-${mm}`;
    if (!grupos[claveMes]) {
      grupos[claveMes] = {
        trabajador: f.trabajador || '',
        dni: f.dni || '',
        empresa: f.empresa || '',
        cif: f.cif || '',
        anio: yy,
        mesNum: parseInt(mm, 10),
        dias: {}
      };
    }
    const g = grupos[claveMes];
    const diaN = parseInt(dd, 10);
    if (!g.dias[diaN]) g.dias[diaN] = { entrada:'', salida_comida:'', vuelta_comida:'', salida:'', ausencia:'' };
    const D = g.dias[diaN];
    if (_fichajeEsAusencia(tipo)) {
      D.ausencia = (_FICHAJE_LABELS[tipo] || tipo).replace(/^[^\sA-Za-zÁÉÍÓÚáéíóúÑñ]+\s*/, '');
    } else if (tipo === 'entrada' || tipo === 'salida_comida' || tipo === 'vuelta_comida' || tipo === 'salida') {
      D[tipo] = _fichajeHHMM(refTs);
    }
  });

  // 2) Construir UNA hoja (aoa) por cada Trabajador+Mes -> [{nombre, anio, mesNum, aoa}].
  //    Así el admin puede imprimir cada parte por separado (una pestaña por trabajador).
  const claves = Object.keys(grupos).sort(); // orden por trabajador y mes
  const secciones = [];
  if (!claves.length) return secciones;

  const TOPE = 8 * 60; // 8 horas = jornada normal
  const fmtm = (m) => { m = Math.max(0, Math.round(m)); return `${Math.floor(m/60)}:${String(m%60).padStart(2,'0')}`; };

  claves.forEach((clave) => {
    const g = grupos[clave];
    const aoa = [];

    aoa.push(['REGISTRO DIARIO JORNADA DE TRABAJO']);
    aoa.push(['Registro elaborado de acuerdo a lo establecido en el Art. 10 del Real Decreto-ley 8/2019, de 8 de marzo']);
    aoa.push(['Empresa:', g.empresa, '', 'CIF:', g.cif]);
    aoa.push(['Trabajador:', g.trabajador, '', 'DNI/NIE:', g.dni]);
    aoa.push(['Nº horas según contrato:', '', 'Mes:', `${MESES[g.mesNum-1]} ${g.anio}`, 'Centro Trabajo:', _FICHAJE_CENTRO_TRABAJO]);
    aoa.push([]);
    aoa.push(['Día', 'Entrada', 'Salida comer', 'Vuelta comer', 'Salida', 'Horas día', 'H. ordinarias', 'H. extras', 'Observaciones']);

    // Días del mes (1..número de días reales del mes)
    const numDias = new Date(parseInt(g.anio,10), g.mesNum, 0).getDate();
    let totalMin = 0, totalOrd = 0, totalExt = 0, saldoMin = 0;
    for (let d = 1; d <= numDias; d++) {
      const D = g.dias[d];
      if (!D) { aoa.push([d, '', '', '', '', '', '', '', '']); continue; }
      if (D.ausencia) { aoa.push([d, '', '', '', '', '', '', '', D.ausencia]); continue; }
      // Calcular horas del día: (salida_comida - entrada) + (salida - vuelta_comida).
      // Si faltan tramos, sumamos lo que haya de forma sensata.
      const min = (hhmm) => { if(!hhmm) return null; const [h,m]=hhmm.split(':').map(Number); return h*60+m; };
      const e=min(D.entrada), sc=min(D.salida_comida), vc=min(D.vuelta_comida), s=min(D.salida);
      let dm = 0;
      if (e!=null && sc!=null) dm += Math.max(0, sc-e);
      if (vc!=null && s!=null)  dm += Math.max(0, s-vc);
      // Si solo hay entrada y salida (sin pausa de comida), contar entrada→salida.
      if (dm===0 && e!=null && s!=null && sc==null && vc==null) dm = Math.max(0, s-e);
      const ord = Math.min(dm, TOPE);          // ordinarias: hasta 8h
      const ext = Math.max(0, dm - TOPE);      // extras: lo que pase de 8h
      totalMin += dm; totalOrd += ord; totalExt += ext;
      if (dm > 0) saldoMin += (dm - TOPE);     // saldo neto (compensa días cortos con largos)
      aoa.push([d, D.entrada, D.salida_comida, D.vuelta_comida, D.salida,
                dm>0 ? fmtm(dm) : '', dm>0 ? fmtm(ord) : '', ext>0 ? fmtm(ext) : '', '']);
    }
    aoa.push(['TOTAL', '', '', '', '', fmtm(totalMin), fmtm(totalOrd), fmtm(totalExt), '']);
    const saldoTxt = (saldoMin >= 0 ? '+' : '-') + fmtm(Math.abs(saldoMin));
    aoa.push(['Saldo (sobre 8h/día):', '', '', '', '', saldoTxt, '', '', '']);
    aoa.push(['Firma trabajador:', '', '', '', 'Firma empresa:', '', '', '', '']);

    secciones.push({ nombre: g.trabajador || 'Trabajador', anio: g.anio, mesNum: g.mesNum, aoa });
  });

  return secciones;
}

function exportFichajesExcel() {
  try {
    if (!_fichajes.length) { toast('No hay fichajes para exportar', 'warn'); return; }
    const desde = document.getElementById('fichajeFiltroDesde')?.value || null;
    const hasta = document.getElementById('fichajeFiltroHasta')?.value || null;
    let filas = _fichajes.filter(f => {
      const refTs = f.tipo === 'correccion' ? (f.ts_corregido || f.ts) : f.ts;
      const fISO = _fichajeFechaLocal(refTs);
      if (desde && fISO < desde) return false;
      if (hasta && fISO > hasta) return false;
      return true;
    });
    filas.sort((a, b) => {
      const ta = a.tipo === 'correccion' ? (a.ts_corregido || a.ts) : a.ts;
      const tb = b.tipo === 'correccion' ? (b.ts_corregido || b.ts) : b.ts;
      return new Date(ta) - new Date(tb);
    });
    const datos = filas.map(f => {
      const esCorr = f.tipo === 'correccion';
      const refTs = esCorr ? (f.ts_corregido || f.ts) : f.ts;
      const tipoMostrar = esCorr ? (f.tipo_corregido || '') : f.tipo;
      const esAus = _fichajeEsAusencia(tipoMostrar);
      let tipoTxt = (_FICHAJE_LABELS[tipoMostrar] || tipoMostrar).replace(/^[^\sA-Za-zÁÉÍÓÚáéíóúÑñ]+\s*/, '');
      if (esCorr) tipoTxt = (f.anulado ? 'ANULA ' : 'CORRIGE ') + tipoTxt;
      return {
        'Trabajadora': f.trabajador || '',
        'DNI': f.dni || '',
        'Empresa': f.empresa || '',
        'CIF': f.cif || '',
        'Fecha': _fichajeFechaBonita(_fichajeFechaLocal(refTs)),
        'Hora': esAus ? 'Día completo' : _fichajeHoraLocal(refTs),
        'Tipo': tipoTxt,
        'Método': f.metodo === 'manual' ? 'A mano' : 'Botón',
        'Nota': f.nota || '',
        'ID': f.id,
        'Corrige al ID': f.corrige_a || ''
      };
    });
    const ws = XLSX.utils.json_to_sheet(datos);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Fichajes');

    // v107FG (28/05/2026): SEGUNDA HOJA "Registro Legal" con el formato
    // oficial del Art. 10 RD-ley 8/2019 (modelo del gestor). Una sección
    // por cada Trabajador + Mes presente en los datos filtrados:
    //   · Cabecera: Empresa, CIF, Trabajador, DNI, Nº horas según contrato,
    //     Mes, Centro de Trabajo (Sant Vicenç dels Horts).
    //   · Tabla días 1..31: Entrada · Salida a comer · Vuelta de comer ·
    //     Salida · Horas del día. Si fue ausencia (vacaciones/baja/festivo/
    //     falta) → texto en la fila, sin horas.
    //   · Fila de totales (suma de horas del mes).
    // La hoja "Fichajes" (lista cronológica) se mantiene intacta arriba.
    try {
      const secciones = _fichajeAoaLegal(filas);
      if (!secciones.length) {
        const wsE = XLSX.utils.aoa_to_sheet([['No hay fichajes en el rango seleccionado.']]);
        XLSX.utils.book_append_sheet(wb, wsE, 'Registro Legal');
      } else {
        const MESN = ['01','02','03','04','05','06','07','08','09','10','11','12'];
        const usados = {};
        // Nombre de pestaña: "Nombre Apellido MM-AAAA", limpio, único y <=31 caracteres
        // (Excel no admite \ / ? * [ ] : en el nombre de la hoja).
        const nombreHoja = (s) => {
          let base = String(s.nombre || 'Trab').replace(/[\\\/\?\*\[\]:]/g, ' ').replace(/\s+/g, ' ').trim();
          const sufijo = ' ' + MESN[s.mesNum - 1] + '-' + s.anio;        // " MM-AAAA"
          base = base.slice(0, 31 - sufijo.length).trim();               // recorta el nombre solo si no cabe
          let nom = (base + sufijo).slice(0, 31).trim();
          let n = nom, i = 2;
          while (usados[n.toLowerCase()]) { n = (nom.slice(0, 27) + ' (' + i + ')').slice(0, 31); i++; }
          usados[n.toLowerCase()] = true;
          return n;
        };
        secciones.forEach(s => {
          const wsL = XLSX.utils.aoa_to_sheet(s.aoa);
          wsL['!cols'] = [{wch:6},{wch:11},{wch:13},{wch:13},{wch:13},{wch:11},{wch:13},{wch:11},{wch:18}];
          XLSX.utils.book_append_sheet(wb, wsL, nombreHoja(s));
        });
      }
    } catch (eL) {
      console.warn('[v107FG] no pude construir la hoja Registro Legal:', eL);
    }

    const hoy = _fichajeFechaLocal(new Date());
    XLSX.writeFile(wb, `fichajes_${hoy}.xlsx`);
    toast('✅ Excel descargado');
  } catch (e) {
    console.error('[exportFichajesExcel]', e);
    toast('Error al exportar: ' + (e.message || e), 'err');
  }
}

// ============================================================
// ADMIN — USERS
// ============================================================
function showNewUserModal() { document.getElementById('ovNewUser').classList.add('open'); }

async function createUser() {
  const email = document.getElementById('nuEmail').value.trim();
  const pass = document.getElementById('nuPass').value.trim();
  const name = document.getElementById('nuName').value.trim();
  const role = document.getElementById('nuRole').value;
  if (!email || !pass) { toast('Email y contraseña requeridos', 'err'); return; }
  if (pass.length < 6) { toast('La contraseña debe tener al menos 6 caracteres', 'err'); return; }

  // Cliente Supabase temporal: hace el signUp sin afectar la sesión del admin actual
  // (signUp crea una sesión, pero al hacerlo en un cliente aparte, la sesión del admin se mantiene intacta)
  const tempClient = createClient(SUPA_URL, SUPA_KEY);
  const { data, error } = await tempClient.auth.signUp({
    email,
    password: pass,
    options: { data: { name, role } }
  });

  if (error) {
    // Mensajes más amigables según el error
    let msg = error.message;
    if (/already.*registered|user.*exists/i.test(msg)) msg = 'Ese email ya está registrado';
    else if (/invalid.*email/i.test(msg)) msg = 'El formato del email no es válido';
    else if (/password/i.test(msg)) msg = 'Problema con la contraseña: ' + msg;
    toast('Error: ' + msg, 'err');
    return;
  }

  if (data?.user) {
    // Pequeña espera (500ms) para que el trigger automático del backend
    // termine de crear la fila básica en profiles. Si no esperamos, la
    // operación de actualizar el rol puede correr antes y perderse.
    await new Promise(r => setTimeout(r, 500));
    // Ahora actualizamos rol y nombre con UPDATE (más fiable que upsert en este caso)
    const { error: profErr } = await sb.from('profiles')
      .update({ role, name: name || email })
      .eq('id', data.user.id);
    if (profErr) {
      toast('Usuario creado pero error en perfil: ' + profErr.message, 'warn');
    } else {
      toast(`✓ Usuario "${name || email}" creado como ${role}`);
    }
    // Limpiar formulario y cerrar modal
    document.getElementById('nuEmail').value = '';
    document.getElementById('nuPass').value = '';
    document.getElementById('nuName').value = '';
    document.getElementById('ovNewUser').classList.remove('open');
    loadUsers();
  }
}

async function loadUsers() {
  const box = document.getElementById('usersListBox');
  if (!box) return;
  box.innerHTML = '<div style="font-family:var(--mn);font-size:11px;color:var(--mu)">Cargando...</div>';
  const { data, error } = await sb.from('profiles').select('*');
  if (error) { box.innerHTML = `<p style="color:var(--er);font-family:var(--mn);font-size:11px">${error.message}</p>`; return; }
  if (!data?.length) { box.innerHTML = '<div style="font-family:var(--mn);font-size:11px;color:var(--mu)">No hay usuarios en la tabla profiles todavía.</div>'; return; }
  box.innerHTML = data.map(u => {
    // Protección: el admin actual NO puede borrarse a sí mismo
    const isMe = u.id === currentUser?.id;
    const delBtn = isMe
      ? `<button class="btn bs" disabled style="font-size:10px;padding:6px 10px;opacity:.4;cursor:not-allowed" title="No puedes borrarte a ti mismo">🗑</button>`
      : `<button class="btn br" id="delU_${u.id}" onclick="deleteUser('${u.id}','${(u.name || u.id).replace(/'/g, "\\'")}')" style="font-size:10px;padding:6px 10px" title="Eliminar usuario">🗑</button>`;
    // v101: checkbox para gestionar acceso a ITV. Los conductores normalmente no lo necesitan.
    // El propio admin actual no puede quitarse el permiso a sí mismo (para evitar bloqueos).
    const itvCheck = `<label style="display:inline-flex;align-items:center;gap:4px;font-family:var(--mn);font-size:10px;color:var(--mu);cursor:${isMe?'not-allowed':'pointer'};opacity:${isMe?'.6':'1'}" title="Permite ver/editar la pestaña ITV">
      <input type="checkbox" ${u.puede_ver_itv ? 'checked' : ''} ${isMe ? 'disabled' : ''} onchange="toggleItvAccess('${u.id}', this.checked)" style="cursor:${isMe?'not-allowed':'pointer'}">🛡️ ITV
    </label>`;
    return `
    <div class="user-row">
      <div class="user-info">
        <div class="user-email">${u.name || u.id}</div>
        <div class="user-meta">${u.id}</div>
      </div>
      <div style="display:flex;gap:10px;align-items:center;flex-wrap:wrap">
        <select class="role-sel" onchange="updateRole('${u.id}',this.value)" ${isMe ? 'disabled title="No puedes cambiar tu propio rol"' : ''}>
          <option value="conductor" ${u.role==='conductor'?'selected':''}>🚛 Conductor</option>
          <option value="gestor" ${u.role==='gestor'?'selected':''}>📋 Gestor</option>
          <option value="admin" ${u.role==='admin'?'selected':''}>👑 Admin</option>
        </select>
        ${itvCheck}
        ${delBtn}
      </div>
    </div>`;
  }).join('');
}

// v101: actualizar el flag puede_ver_itv en BD desde el checkbox de la pestaña Usuarios
async function toggleItvAccess(userId, checked) {
  try {
    const { error } = await sb.from('profiles').update({ puede_ver_itv: checked }).eq('id', userId);
    if (error) throw error;
    // Actualizar userMap en memoria también para que se refleje sin recargar
    if (userMap[userId]) userMap[userId].puede_ver_itv = checked;
    toast(checked ? '✓ Acceso ITV concedido' : '✓ Acceso ITV retirado');
  } catch (e) {
    console.error('[toggleItvAccess] Error:', e);
    toast('Error: ' + (e.message || e), 'err');
    // Revertir el checkbox visualmente si falló
    loadUsers();
  }
}

// Borrar usuario (de la tabla profiles). El usuario en auth.users queda huérfano:
// no podrá iniciar sesión porque no tiene perfil, pero el email seguirá "registrado".
// Para reciclar el mismo email habría que ir a Supabase → Authentication → Users.
async function deleteUser(uid, displayName) {
  const btn = document.getElementById('delU_' + uid);
  // Patrón de doble clic igual que deleteRecord (10 segundos para confirmar)
  if (btn && !btn.dataset.confirming) {
    btn.dataset.confirming = '1';
    const original = btn.textContent;
    btn.textContent = '¿Confirmar?';
    btn.style.background = '#ff3333';
    btn.style.color = '#fff';
    btn.style.padding = '6px 12px';
    setTimeout(() => {
      if (btn && btn.dataset.confirming) {
        delete btn.dataset.confirming;
        btn.textContent = original;
        btn.style.background = '';
        btn.style.color = '';
        btn.style.padding = '';
      }
    }, 10000);
    return;
  }
  // Segundo clic: borrar de verdad
  if (btn) delete btn.dataset.confirming;
  // .select() añadido para verificar que el DELETE realmente afectó alguna fila.
  // Sin esto, las RLS de Supabase pueden hacer que el delete devuelva éxito en silencio sin borrar nada.
  const { data, error } = await sb.from('profiles').delete().eq('id', uid).select();
  if (error) {
    toast('Error eliminando: ' + error.message, 'err');
    return;
  }
  if (!data || data.length === 0) {
    toast('No se eliminó. Faltan permisos en Supabase (RLS). Te paso el SQL para arreglarlo.', 'err');
    return;
  }
  toast(`✓ "${displayName}" eliminado del sistema`);
  loadUsers();
}

async function updateRole(uid, role) {
  const { error } = await sb.from('profiles').update({ role }).eq('id', uid);
  if (error) toast('Error: ' + error.message, 'err');
  else toast('✓ Rol actualizado');
}

