// v83: lista oficial de transportistas para validar y filtrar (13 empresas).
// El filtro Transportista solo mostrará estos, evitando que la IA cree variantes raras.
const TRANSPORTISTAS_OFICIALES = [
  'TYP2014','TTES HISPALIS 2016','TRANSMARGAZ 2018','JOSE MIGUEL VALLDEPEREZ','FRANCISCO OCAÑA',
  'CIPRIAN IOAN BUSILA','ANTONIO MARTIN','JOAQUIN CAÑAS','MIGUEL A. GARCIA','ARIDFLOT',
  'T. REFRIGERADOS DOMINGUEZ','T. SATIG 79','OP TRANS V.'
];

// v106: red de seguridad agresiva para canonizar transportistas guardados con variantes
// raras (OCR antiguo, matrículas aprendidas mal antes de v103, denominaciones legales con
// "S.L." al final, etc.). Devuelve uno de los 13 oficiales si reconoce el nombre por
// palabras clave; si no reconoce, devuelve el valor tal cual (no inventa). El orden de
// las reglas importa: de más específico a más general.
function fixTransportista(t) {
  if (!t || typeof t !== 'string') return t;
  const u = String(t).trim().toUpperCase().replace(/\s+/g, ' ');
  if (!u) return t;
  // Si ya está exacto en la lista oficial, devolver tal cual
  const exacto = TRANSPORTISTAS_OFICIALES.find(o => o.toUpperCase() === u);
  if (exacto) return exacto;
  // Reglas por palabras clave (orden: más específico primero)
  if (/\bTYP\s*2014\b|\bY\s*PORTES\s*2014\b|\bPORTES\s*2014\b/.test(u)) return 'TYP2014';
  if (/\bHISPALIS\b/.test(u)) return 'TTES HISPALIS 2016';
  if (/\bTRANSMARGAZ\b/.test(u)) return 'TRANSMARGAZ 2018';
  if (/\bARIDFLOT\b/.test(u)) return 'ARIDFLOT';
  if (/\bVALLDEPEREZ\b|JOSE\s*MIGUEL.*SEGURA/.test(u)) return 'JOSE MIGUEL VALLDEPEREZ';
  if (/\bFCO\.?\s*OCA[NÑ]A\b|\bFRANCISCO\s*OCA[NÑ]A\b|\bOCA[NÑ]A\s*COSTALAGO\b/.test(u)) return 'FRANCISCO OCAÑA';
  if (/\bCIPRIAN\b|\bBUSILA\b|\bGIURGIU\b/.test(u)) return 'CIPRIAN IOAN BUSILA';
  if (/\bANTONIO\s*MARTIN\b/.test(u)) return 'ANTONIO MARTIN';
  if (/\bJOAQUIN\s*CA[NÑ]AS\b/.test(u)) return 'JOAQUIN CAÑAS';
  if (/\bMIGUEL\s*A\.?\s*GARCIA\b|\bMIGUEL\s*ANGEL\s*GARCIA\b/.test(u)) return 'MIGUEL A. GARCIA';
  if (/\bREFRIGERADOS\s*DOMI[NG]+UEZ\b|\bT\.\s*REFRIGERADOS\b/.test(u)) return 'T. REFRIGERADOS DOMINGUEZ';
  if (/\bSATIG\b/.test(u)) return 'T. SATIG 79';
  if (/\bOP\s*TRANS\b/.test(u)) return 'OP TRANS V.';
  // No se reconoce → devolver tal cual (quedará marcado como "no oficial" en el modal)
  return t;
}

