// v83: normaliza la matrícula (espacios al final, mayúsculas) antes de consultar.
// Resuelve casos como '6102LSR ' (con espacio) o '6102lsr' que antes no encontraban transportista.
// v87: ahora consulta TANTO el diccionario fijo TRANSPORTISTAS como las matrículas aprendidas
// dinámicamente desde Supabase (MATRICULAS_APRENDIDAS).
// v91d: respeta el convenio interno de matrícula doble "XXXXLLL/XXXXLLL" (la primera es la
// que aparece en el albarán del cliente y se usa para preliquidación; la segunda es apunte
// interno del camión real subcontratado). Para todas las consultas de transportista,
// validación y cruces, se usa SIEMPRE la primera parte.
function matriculaPrincipal(mat) {
  if (!mat) return mat;
  const clean = String(mat).trim().toUpperCase().replace(/\s+/g,'');
  if (clean.includes('/')) return clean.split('/')[0];
  return clean;
}

function getTransportista(mat) {
  if (!mat) return null;
  const clean = matriculaPrincipal(mat);
  // v106: aplicamos fixTransportista al resultado para canonizar valores que pudieron
  // aprenderse con variantes raras (TYP2014 vs "TRANSPORTES Y PORTES 2014, S.L.", etc.)
  // antes de tener todo este blindaje.
  const raw = TRANSPORTISTAS[clean] || MATRICULAS_APRENDIDAS[clean] || null;
  return raw ? fixTransportista(raw) : null;
}

// RED DE SEGURIDAD: corrige automáticamente destinos mal extraídos por la IA
// Mapea códigos internos / nombres genéricos al pueblo real
function fixDestino(d) {
  if (!d) return d;
  const u = String(d).toUpperCase().trim();
  // Códigos cortos sospechosos (3-6 caracteres alfanuméricos sin espacios) → marcar como destino sin verificar
  // Patrones conocidos de Holcim → pueblo real
  if (/MONTMEL[OÓ]|NUEVO ALMACEN MONTM/.test(u)) return 'Montornès del Vallès';
  if (/HS25|HORMIGON ENSACADO/.test(u)) return 'Montornès del Vallès';
  if (/^PLANTA FERRAN/.test(u)) return 'Planta Ferran-Riera';
  if (/^FABRICA ALCOVER/.test(u)) return 'Alcover';
  // NOTA: NO tocamos "Fábrica Montcada" aquí — es un destino legítimo (la fábrica de cemento Holcim)
  // donde se descargan materias primas. La canonización a "Montcada" la hace _matchDestino.
  if (/^MOLIENDA TARRAGONA/.test(u)) return 'Tarragona';
  if (/^GURREA DE GALLEGO/i.test(u.normalize('NFD').replace(/[\u0300-\u036f]/g,''))) return 'Gurrea de Gállego';
  // Códigos huérfanos (CE44I, CE44D...) → log pero no podemos saber el pueblo automáticamente
  if (/^CE\d{2}[A-Z]?$/.test(u)) {
    console.warn(`[fixDestino] Código sospechoso "${d}" sin pueblo. Revisar manualmente.`);
    // Mapeo conocido de algunos códigos a pueblos
    const map = { 'CE44I': 'Celra', 'CE44D': 'Barcelona', 'CE44K': 'Montcada', 'CE44E': 'La Roca', 'CES17': 'Riudellots de la Selva' };
    if (map[u]) return map[u];
  }
  // Paso final: normalizar contra lista de destinos canónicos (gestiona variantes como
  // "El Prat de Llobregat" → "El Prat" o "Fábrica Montcada" → "Montcada")
  return _matchDestino(d);
}

