// fixCliente: canoniza variantes OCR de plantas conocidas en el campo COMPRADOR/CLIENTE.
// Pilla "Planta Horígenes Zona Franca", "Planta Hormagones Zona Franca", "Planta Hormoigones..."
// y similares OCR-mal-leídos, y los unifica al nombre oficial.
// También detecta el caso donde Haiku confundió "Operador logístico" (Transportes y Portes 2014
// = la propia transportista) con el cliente real → devuelve null.
function fixCliente(c) {
  if (!c) return c;
  const u = String(c).toUpperCase().trim();
  // Caso especial: el cliente NUNCA es la propia transportista. Si vemos "Transportes y Portes 2014"
  // o variantes, lo borramos (era confusión OCR del campo "Operador logístico").
  if (/TRANSPORTES?\s+Y\s+PORTES\s+2014/i.test(u) || /PORTES\s+2014\s+IMPORT/i.test(u)) {
    return null;
  }
  // v107W: intentar canonizar contra CLIENTES_CANONICOS (match contra canon o alias normalizado)
  const norm = (s) => String(s||'').toUpperCase().replace(/[.,]/g, '').replace(/\s+/g, ' ').trim();
  const cn = norm(c);
  for (const cli of CLIENTES_CANONICOS) {
    if (norm(cli.canon) === cn) return cli.canon;
    for (const al of (cli.alias || [])) {
      if (norm(al) === cn) return cli.canon;
    }
  }
  // Patrón flexible: "PLANTA HOR<cualquier cosa> ZONA FRANCA" → forma canónica
  if (/^PLANTA\s+HOR\S*\s*ZONA\s+FRANCA/i.test(u)) return 'Planta Hormigones Zona Franca';
  // Patrón flexible: "PLANTA HOR<cualquier cosa> MONTCADA" → forma canónica
  if (/^PLANTA\s+HOR\S*\s+MONTCADA/i.test(u)) return 'Planta Hormigones Montcada';
  return c; // si no coincide ningún patrón, devolver tal cual
}

