// Helper para edición MANUAL: solo aplica match exacto (no contención) para que lo que el
// usuario escribe se respete tal cual. Si coincide exactamente con un alias o canon, devuelve
// la forma oficial. Si no, devuelve el input sin cambios.
// v76: además del match estricto, prueba un match "permisivo" que ignora palabras vacías
// como "de", "la", "el", "del" — así "Cantera Garraf" matchea con "Cantera de Garraf",
// "Planta Montcada" con "Planta de Montcada", etc. Esto es lo que el usuario espera.
function matchExacto(input, canonicalList) {
  if (!input) return input;
  const norm = s => String(s || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^A-Z0-9]/g,'');
  // Variante permisiva: además de quitar tildes/símbolos, elimina palabras vacías cortas
  const normLoose = s => {
    const cleanedTokens = String(s || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'')
      .split(/[^A-ZÑ0-9]+/).filter(t => t && !['DE','LA','EL','LAS','LOS','DEL','Y','I'].includes(t));
    return cleanedTokens.join('');
  };
  const key = norm(input);
  const keyLoose = normLoose(input);
  if (!key) return input;
  // Pasada 1: match estricto
  for (const item of canonicalList) {
    if (norm(item.canon) === key) return item.canon;
    for (const a of (item.alias || [])) {
      if (norm(a) === key) return item.canon;
    }
  }
  // Pasada 2: match permisivo (sin palabras vacías)
  if (keyLoose) {
    for (const item of canonicalList) {
      if (normLoose(item.canon) === keyLoose) return item.canon;
      for (const a of (item.alias || [])) {
        if (normLoose(a) === keyLoose) return item.canon;
      }
    }
  }
  return input;
}

// Helper genérico: crea un "matcher" que dado un input devuelve el canónico (o el input si no encuentra)
// Hace 2 tipos de match: (1) exacto normalizado, (2) por contención si el canon/alias normalizado
// (de al menos 6 caracteres) está contenido dentro del input. Esto pilla cosas tipo
// "LA ROCA-P 5500116119 FONT PARERA" → "La Roca" porque "LAROCA" está dentro del texto largo.
function makeCanonMatcher(canonicalList) {
  const norm = s => String(s || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^A-Z0-9]/g,'');
  const exactMap = new Map();
  const containEntries = [];
  for (const item of canonicalList) {
    const canonStr = item.canon;
    const cn = norm(canonStr);
    exactMap.set(cn, canonStr);
    containEntries.push({ key: cn, canon: canonStr, len: cn.length });
    for (const a of (item.alias || [])) {
      const an = norm(a);
      exactMap.set(an, canonStr);
      containEntries.push({ key: an, canon: canonStr, len: an.length });
    }
  }
  // Más largos primero para que ganen los matches más específicos
  containEntries.sort((a, b) => b.len - a.len);

  return (input) => {
    if (!input) return input;
    const key = norm(input);
    if (!key) return input;
    // 1) Match exacto
    let canonical = exactMap.get(key);
    if (canonical) {
      if (canonical !== input) console.log(`[match exacto] "${input}" → "${canonical}"`);
      return canonical;
    }
    // 2) Match por contención (umbral mínimo 6 chars normalizados para evitar falsos positivos)
    for (const e of containEntries) {
      if (e.len >= 6 && key.includes(e.key)) {
        console.log(`[match contención] "${input}" → "${e.canon}"`);
        return e.canon;
      }
    }
    return input;
  };
}

const _matchProveedor = makeCanonMatcher(PROVEEDORES_CANONICOS);

// RED DE SEGURIDAD: normaliza el nombre del proveedor según la lista canónica.
// Si la versión normalizada coincide (con canon o alias), devuelve el nombre oficial.
// Si no, devuelve el original tal cual (no rompe nada para proveedores nuevos).
function fixProveedor(p) {
  return _matchProveedor(p);
}

