// Auto-corrige matrículas con errores típicos OCR (I↔L, 0↔O, 1↔I)
// v91d: si la matrícula viene con formato dual XXXXLLL/XXXXLLL (convenio interno del admin),
// devuélvela tal cual sin tocar — el admin la escribió a mano deliberadamente.
function fixMatricula(mat) {
  if (!mat) return mat;
  const m = String(mat).toUpperCase().trim();
  if (m.includes('/')) return m;
  if (TRANSPORTISTAS[m]) return m;
  // v107BO: ampliada la lista de caracteres que el OCR confunde. Caso real
  // detectado: Molins albarán "9295JJZ" leído como "9295IJZ" (I por J), que
  // antes NO se corregía porque I↔J no estaba aquí. Añadidos: I↔J, J↔1, U↔V
  // (todos confusiones OCR típicas en matrículas escaneadas). SEGURO: esta
  // función SOLO devuelve la variante si EXISTE en la flota (TRANSPORTISTAS);
  // si ninguna variante coincide con un camión real, devuelve la original
  // sin tocar — nunca inventa una matrícula.
  const swaps = { 'I':'L', 'L':'I', 'O':'0', '0':'O', '1':'I', '8':'B', 'B':'8', 'S':'5', '5':'S', 'Z':'2', '2':'Z', 'J':'I', 'U':'V', 'V':'U' };
  const tried = new Set([m]);
  const queue = [m];
  while (queue.length) {
    const cur = queue.shift();
    for (let i = 0; i < cur.length; i++) {
      const ch = cur[i];
      const candidates = [];
      if (swaps[ch]) candidates.push(swaps[ch]);
      if (ch === 'I') candidates.push('1', 'J');   // I → 1, J
      if (ch === '1') candidates.push('I', 'J');   // 1 → I, J
      if (ch === 'J') candidates.push('1');        // J → 1 (además del J→I del mapa swaps)
      for (const c of candidates) {
        const variant = cur.substring(0, i) + c + cur.substring(i + 1);
        if (tried.has(variant)) continue;
        tried.add(variant);
        if (TRANSPORTISTAS[variant]) return variant;
        if (tried.size < 50) queue.push(variant);
      }
    }
  }
  return m;
}

// v89: comprueba si una matrícula tiene formato español válido (4 dígitos + 3 letras consonantes,
// sin vocales ni Q, ej: 9295JJZ, 1748JGL). Devuelve true/false.
// Las matrículas españolas modernas excluyen vocales y Q en las letras, pero algunos OCR pueden
// leer mal. Aquí seamos algo permisivos: aceptamos 4 dígitos + 3 letras cualesquiera.
// v91d: aceptar también el formato dual XXXXLLL/XXXXLLL (convenio interno: primera matrícula =
// la del cliente que aparece en el albarán y se preliquida; segunda matrícula = la del camión
// subcontratado que realmente hizo el viaje). Solo se considera válido si AMBAS partes son 4D+3L.
function esMatriculaValida(mat) {
  if (!mat) return false;
  const m = String(mat).toUpperCase().replace(/\s+/g, '').replace(/-/g, '').trim();
  return /^\d{4}[A-Z]{3}$/.test(m) || /^\d{4}[A-Z]{3}\/\d{4}[A-Z]{3}$/.test(m);
}

// v89: si lo que lee la IA NO tiene formato matrícula válido, intenta extraer una de cualquier
// texto/objeto que tengamos disponible. Como red de seguridad final cuando la IA falla en Cemex.
// Recibe el texto bruto del documento (si lo tenemos) y devuelve la primera matrícula que
// encuentre con formato 4D+3L que NO empiece por R (que sería remolque).
function rescatarMatriculaDeTexto(texto) {
  if (!texto) return null;
  // Buscar todas las apariciones de patrón 4D+3L en el texto
  const matches = String(texto).toUpperCase().match(/\b\d{4}[A-Z]{3}\b/g) || [];
  // Filtrar las que parecen remolque (empiezan por R en el contexto cercano)
  // En Cemex el remolque viene como R5640BDJ (5 dígitos+3 letras precedido de R).
  // Si encontramos un match 4D+3L sin R delante, es la tractora.
  for (const m of matches) {
    // Verificar que no esté precedido por R en el texto original (sería remolque)
    const idx = String(texto).toUpperCase().indexOf(m);
    if (idx > 0 && String(texto).toUpperCase()[idx - 1] === 'R') continue;
    return m;
  }
  return null;
}

// ============================================================
// UTILS
// ============================================================
function parseDate(s) { if (!s) return 0; const p = s.split('/'); return p.length === 3 ? new Date(p[2], p[1]-1, p[0]).getTime() : new Date(s).getTime() || 0; }
function sortBy(col) { sortCol === col ? sortDir *= -1 : (sortCol = col, sortDir = -1); applyFilters(); }
function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
function esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
let toastT;
function toast(msg, type='ok') { const el = document.getElementById('toast'); el.textContent = msg; el.className = 'toast show' + (type==='err'?' err':type==='warn'?' warn':''); clearTimeout(toastT); toastT = setTimeout(() => el.classList.remove('show'), 4000); }

// ============================================================
// PRELIQUIDACIONES
// ============================================================
let preliquidaciones = []; // lista de cabeceras (un PDF subido = una preliquidación)
let preliFilas = [];       // todas las filas de TODAS las preliquidaciones
let preliActiva = null;    // id de la preliquidación que se está viendo en detalle
let preliFiltroEstado = 'all';
let _processingPreli = false;

async function loadPreliquidaciones() {
  // Cargar cabeceras (group by id_preliquidacion)
  let q = sb.from('preliquidaciones').select('*').order('created_at', { ascending: false });
  if (currentRole === 'gestor') q = q.eq('user_id', currentUser.id);
  const { data, error } = await q;
  if (error) {
    if (error.message && /does not exist|relation/i.test(error.message)) {
      document.getElementById('preliList').innerHTML = `
        <div style="background:rgba(255,170,0,0.1);border:1px solid var(--wn);padding:14px;border-radius:8px;font-family:var(--mn);font-size:12px;color:var(--wn);line-height:1.6">
          ⚠️ <strong>La tabla "preliquidaciones" aún no existe en Supabase</strong>.<br>
          Pídele al administrador que ejecute el SQL de creación de tablas (ver instrucciones).
        </div>`;
      return;
    }
    toast('Error: ' + error.message, 'err');
    return;
  }
  preliFilas = data || [];
  // Agrupar por id_preliquidacion para construir la lista de cabeceras
  const grupos = {};
  preliFilas.forEach(r => {
    const k = r.id_preliquidacion;
    if (!grupos[k]) grupos[k] = { id: k, cliente: r.cliente, filename: r.filename, file_url: r.file_url, created_at: r.created_at, filas: [] };
    grupos[k].filas.push(r);
  });
  preliquidaciones = Object.values(grupos).sort((a,b) => (b.created_at||'').localeCompare(a.created_at||''));
  renderPreliList();
  document.getElementById('tabPreliCount').textContent = preliquidaciones.length;
}

function renderPreliList() {
  const cont = document.getElementById('preliList');
  const empty = document.getElementById('emptyPreli');
  if (!preliquidaciones.length) {
    cont.innerHTML = '';
    empty.style.display = 'block';
    return;
  }
  empty.style.display = 'none';
  cont.innerHTML = preliquidaciones.map(p => {
    const total = p.filas.length;
    const ok = p.filas.filter(f => f.estado_comparacion === 'COINCIDE').length;
    const falta = p.filas.filter(f => f.estado_comparacion === 'FALTA_BD').length;
    const dif = p.filas.filter(f => f.estado_comparacion === 'DIFERENCIA_TM').length;
    const pct = total > 0 ? Math.round(ok/total*100) : 0;
    const fecha = p.created_at ? new Date(p.created_at).toLocaleDateString('es-ES') : '';
    return `<div class="preli-item" onclick="openPreliDetail('${esc(p.id)}')" style="background:var(--bg-2);border:1px solid var(--bd);border-radius:8px;padding:14px;margin-bottom:8px;cursor:pointer;display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap">
      <div>
        <div style="font-family:var(--mn);font-size:13px;color:var(--fg)">📋 <strong>${esc(p.cliente || 'Sin cliente')}</strong> · ${esc(p.filename || '')}</div>
        <div style="font-family:var(--mn);font-size:10px;color:var(--mu);margin-top:4px">Subida ${fecha} · ${total} filas</div>
      </div>
      <div style="display:flex;gap:14px;align-items:center;font-family:var(--mn);font-size:11px">
        <span style="color:var(--ok)">✅ ${ok}</span>
        <span style="color:var(--er)">⛔ ${falta}</span>
        <span style="color:var(--wn)">🔴 ${dif}</span>
        <span style="color:var(--mu)">${pct}% OK</span>
      </div>
    </div>`;
  }).join('');
}

// SUBIDA Y PROCESAMIENTO
async function addPreliFile(files) {
  if (!files || !files.length) return;
  const f = files[0];
  if (!f.name.toLowerCase().endsWith('.pdf')) { toast('Solo se aceptan PDFs', 'err'); return; }
  if (!getKey()) { toast('Configura tu API Key primero', 'err'); return; }

  // Mostrar el archivo en cola
  const queueDiv = document.getElementById('preliQueue');
  queueDiv.innerHTML = `<div id="preliProgress" style="background:var(--bg-2);border:1px solid var(--bd);border-radius:8px;padding:14px;font-family:var(--mn);font-size:12px">
    📤 <strong>${esc(f.name)}</strong><br><span id="preliProgTxt" style="color:var(--mu)">Preparando...</span>
    <div style="background:var(--bd);height:4px;border-radius:2px;margin-top:8px;overflow:hidden"><div id="preliProgBar" style="background:var(--ok);height:100%;width:0%;transition:width 0.3s"></div></div>
  </div>`;

  if (_processingPreli) { toast('Ya se está procesando una preliquidación', 'warn'); return; }
  _processingPreli = true;

  try {
    await procesarPreliquidacion(f);
  } catch (e) {
    console.error(e);
    toast('Error: ' + e.message, 'err');
  } finally {
    _processingPreli = false;
    document.getElementById('preliFileInput').value = '';
  }
}

function setPreliProgress(txt, pct) {
  const t = document.getElementById('preliProgTxt');
  const b = document.getElementById('preliProgBar');
  if (t) t.textContent = txt;
  if (b) b.style.width = (pct || 0) + '%';
}

async function procesarPreliquidacion(file) {
  const idPreli = (crypto.randomUUID ? crypto.randomUUID() : 'preli_' + Date.now() + '_' + Math.random());

  // Subir el PDF a Storage UNA vez
  setPreliProgress('Subiendo PDF a Storage...', 5);
  let fileUrl = null;
  try { fileUrl = await uploadFile(file, 'preli'); } catch (e) { console.warn('Upload falló:', e); }

  // Cargar PDF y leer texto de TODAS las páginas (para detectar cliente y filtrar páginas sin datos)
  setPreliProgress('Leyendo páginas del PDF...', 8);
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const numPages = pdf.numPages;

  setPreliProgress(`Analizando contenido (${numPages} páginas)...`, 10);
  const paginasInfo = [];
  let textoPrimera = '';
  for (let p = 1; p <= numPages; p++) {
    const page = await pdf.getPage(p);
    let texto = '';
    try {
      const tc = await page.getTextContent();
      texto = tc.items.map(it => it.str).join(' ');
    } catch (e) { /* PDF escaneado sin capa de texto */ }
    if (p === 1) textoPrimera = texto;
    paginasInfo.push({ pagina: p, page, texto });
  }

  // Detectar el cliente combinando nombre de archivo + texto de la primera página
  const clienteDetectado = detectarCliente(file.name, textoPrimera) || 'Desconocido';

  // Filtrar las páginas que tienen datos (en Holcim hay 8-12 páginas de cabecera/subtotales que no aportan filas)
  let paginasConDatos = paginasInfo.filter(pi => paginaTieneDatos(pi.texto, clienteDetectado));
  // Fallback: si la heurística filtra TODAS las páginas (ej. PDF escaneado sin texto), procesar todas
  if (!paginasConDatos.length) paginasConDatos = paginasInfo;

  setPreliProgress(`Cliente: ${clienteDetectado} · ${paginasConDatos.length}/${numPages} páginas con datos`, 14);
  await sleep(600); // pausa para que el usuario vea el mensaje

  // Concurrencia 2, con pausa entre lotes para respetar rate limit
  const todasLasFilas = [];
  const scale = numPages > 30 ? 1.5 : 1.8;
  const quality = numPages > 30 ? 0.75 : 0.85;

  // Generar imágenes solo de las páginas que tienen datos
  const tareas = [];
  for (const pi of paginasConDatos) {
    setPreliProgress(`Generando imagen página ${pi.pagina}/${numPages}...`, 14 + (tareas.length / paginasConDatos.length) * 26);
    const viewport = pi.page.getViewport({ scale });
    const canvas = document.createElement('canvas');
    canvas.width = viewport.width;
    canvas.height = viewport.height;
    const ctx = canvas.getContext('2d');
    await pi.page.render({ canvasContext: ctx, viewport }).promise;
    const dataUrl = canvas.toDataURL('image/jpeg', quality);
    tareas.push({ pagina: pi.pagina, b64: dataUrl.split(',')[1] });
    canvas.width = 0; canvas.height = 0;
  }

  // Procesar páginas en paralelo de a 2
  const CONCURRENCY = 2;
  let procesadas = 0;
  for (let i = 0; i < tareas.length; i += CONCURRENCY) {
    const batch = tareas.slice(i, i + CONCURRENCY);
    const results = await Promise.all(batch.map(async t => {
      try {
        const filas = await callClaudePreli(t.b64, getKey(), t.pagina, clienteDetectado);
        return { pagina: t.pagina, filas, error: null };
      } catch (e) {
        // Reintento en rate limit
        if (e.status === 429 || /rate.?limit/i.test(e.message)) {
          await sleep(30000);
          try {
            const filas = await callClaudePreli(t.b64, getKey(), t.pagina, clienteDetectado);
            return { pagina: t.pagina, filas, error: null };
          } catch (e2) { return { pagina: t.pagina, filas: [], error: e2.message }; }
        }
        return { pagina: t.pagina, filas: [], error: e.message };
      }
    }));
    for (const r of results) {
      if (r.error) console.warn(`Página ${r.pagina}: ${r.error}`);
      todasLasFilas.push(...r.filas);
    }
    procesadas += batch.length;
    setPreliProgress(`Extrayendo filas: ${todasLasFilas.length} encontradas (${procesadas}/${tareas.length} páginas procesadas)...`, 40 + (procesadas/tareas.length)*40);
    if (i + CONCURRENCY < tareas.length) await sleep(1500);
  }

  if (!todasLasFilas.length) {
    toast('No se extrajeron filas. Revisa el formato del PDF.', 'err');
    document.getElementById('preliQueue').innerHTML = '';
    return;
  }

  // Comparar cada fila con la BD de albaranes (en cascada: por nº albarán, luego por fecha+mat+tm)
  // Compartimos un Set "usados" entre todas las filas para evitar que un mismo albarán BD
  // haga match con dos filas distintas de la misma preliquidación.
  setPreliProgress('Comparando con albaranes en BD...', 85);
  const usados = new Set();
  const filasConEstado = todasLasFilas.map(f => compararFilaConBD(f, usados));

  // Guardar en Supabase
  setPreliProgress(`Guardando ${filasConEstado.length} filas en BD...`, 92);
  const filasParaInsertar = filasConEstado.map(f => ({
    id_preliquidacion: idPreli,
    cliente: clienteDetectado,
    filename: file.name,
    file_url: fileUrl,
    albaran: f.albaran || null,
    fecha: f.fecha || null,
    tractora: f.tractora || null,
    remolque: f.remolque || null,
    proveedor_cliente: f.proveedor_cliente || null,
    direccion: f.direccion || null,
    zona: f.zona || null,
    material: f.material || null,
    tm: f.tm != null ? parseFloat(f.tm) : null,
    unidad: f.unidad || 'TN',
    estado_comparacion: f.estado_comparacion,
    db_albaran_id: f.db_albaran_id || null,
    user_id: currentUser.id
  }));

  // Insertar por lotes de 100 (Supabase tiene límite)
  for (let i = 0; i < filasParaInsertar.length; i += 100) {
    const lote = filasParaInsertar.slice(i, i + 100);
    const { error } = await sb.from('preliquidaciones').insert(lote);
    if (error) { toast('Error guardando: ' + error.message, 'err'); console.error(error); throw error; }
  }

  setPreliProgress(`✓ ${filasConEstado.length} filas guardadas`, 100);
  await sleep(800);
  document.getElementById('preliQueue').innerHTML = '';
  toast(`✓ Preliquidación procesada: ${filasConEstado.length} filas`);
  await loadPreliquidaciones();
  // Abrir el detalle automáticamente
  openPreliDetail(idPreli);
}

function detectarCliente(filename, textoPdf) {
  const f = (filename || '').toLowerCase();
  const t = (textoPdf || '').toLowerCase();
  // 1. Por nombre de archivo (palabras clave directas)
  if (/holcim/.test(f)) return 'Holcim';
  if (/cemex/.test(f)) return 'Cemex';
  if (/elite|élite/.test(f)) return 'Elite Cementos';
  // 2. Por contenido textual de la primera página del PDF
  if (/holcim/.test(t)) return 'Holcim';
  if (/cemex españa|cemex/.test(t)) return 'Cemex';
  if (/élite cementos|elite cementos/.test(t)) return 'Elite Cementos';
  // 3. Patrones típicos en el nombre del archivo
  if (/^invoic_\d/.test(f)) return 'Holcim'; // formato Holcim típico: INVOIC_<ref>_...
  return null;
}

// ¿Esta página del PDF contiene filas de datos reales? (para no enviar a la IA páginas de cabecera/subtotales)
function paginaTieneDatos(texto, cliente) {
  if (!texto) return false;
  if (cliente === 'Holcim') {
    // Página de datos Holcim: tiene >=3 fechas DD.MM.YYYY y >=3 números de albarán de 10-12 dígitos.
    // Las páginas de cabecera factura, "Total PO", "Subtotal por vehiculo" o resumen final no cumplen estos umbrales.
    const fechas = (texto.match(/\d{2}\.\d{2}\.\d{4}/g) || []).length;
    const albs = (texto.match(/\b\d{10,12}\b/g) || []).length;
    return fechas >= 3 && albs >= 3;
  }
  // Por defecto: cualquier página con al menos 3 fechas en formato común
  const fechas = (texto.match(/\d{2}[./-]\d{2}[./-]\d{4}/g) || []).length;
  return fechas >= 3;
}

// Llamada a la IA con prompt específico para preliquidaciones
async function callClaudePreli(b64, key, paginaNum, cliente) {
  let prompt;
  if (cliente === 'Holcim') {
    prompt = `Eres un OCR experto extrayendo datos de facturas/preliquidaciones de Holcim España. Esta es UNA PÁGINA del documento.

La página puede contener: (a) tabla con filas de datos de albaranes, (b) cabecera de factura/totales/subtotales SIN datos, (c) ambos mezclados.

EXTRAE SOLO las filas que cumplan TODAS estas condiciones:
- Tienen una fecha en formato DD.MM.YYYY (NO la fecha de la factura del encabezado superior)
- Tienen un "Num. Entrega" (número de albarán) de 10-12 dígitos
- Tienen una matrícula de camión española (formato 4 dígitos + 3 letras, ej "1968JFV")
- Tienen una cantidad numérica > 0 en la columna "Cta."

DESCARTA SIEMPRE estas líneas (NO las extraigas):
- Línea de cabecera de columnas: "Fecha de entrega | Num. Entrega | Matrícula | Nombre Proveedor | ..."
- "Subtotal por vehiculo XXXXXXX" / "Subtotal por PO" / "Subtotal por destino" / "Total" cualquier cosa
- "Total transporte" / "Total Transportista" / "Total Cantidad" / "Total Importe" / "Total con IVA" / "Total Neto" / "IVA"
- "Condiciones de pago" / "Página #" / "Material Coste Imp" / "Servicios / Extra costes" / "AFR Transporte"
- Cabeceras de bloques: "Fábrica Montcada", "Lafarge CEM", "Logistica", "Pedido de compras", "Periodo:", "Referencia"
- Cualquier fila con cantidad 0 o vacía o sin Num. Entrega

Por cada fila VÁLIDA devuelve un objeto JSON con esta estructura exacta:
{
  "fecha": "DD/MM/YYYY",
  "albaran": "0941343096",
  "tractora": "1968JFV",
  "remolque": "R3542BBV",
  "proveedor_cliente": "PROMOTORA MEDITERRANEA 2 S A",
  "direccion": "CR NACIONAL 340 KM 1242,3, 08620 SAN VICENÇ DELS HORTS",
  "zona": "Origen",
  "material": "Caliza Promsa",
  "tm": 26.900,
  "unidad": "T",
  "transportista_real": "TRANSPORTES Y PORTES 2014, S.L"
}

Notas importantes:
- "fecha": convierte "02.03.2026" a "02/03/2026"
- "albaran": copia EXACTO, conservando ceros iniciales (ej "0941343096", "31048146095")
- "tractora" y "remolque": cuando la celda contiene "1968JFV / R3542BBV" o "1968JFV/R3542BBV", separa por el "/" — la primera es la tractora, la segunda (suele empezar por R) es el remolque
- "tm": NÚMERO con punto decimal (convierte "27,820" → 27.820, "30 T" → 30.0)
- "transportista_real": el nombre que aparece en la cabecera "Transportista : XXX" justo encima del bloque de la tabla (ej "TRANSPORTES Y PORTES 2014, S.L", "TRANSPORTES HISPALIS 2016, S.L", "ARIDFLOT, S.L.", "TRANSMARGAZ 2018, S.L.", "Bogdan Sebastian Giurgiu", "FCO. OCAÑA COSTALAGO", "JOSE MIGUEL VALLDEPEREZ SEGURA", "TRANS REFIGERADOS DOMIGUEZ"). Repite ese mismo valor en cada fila del bloque, hasta encontrar una nueva cabecera "Transportista :".

Devuelve SOLO un ARRAY JSON con las filas válidas. Si la página NO tiene filas de datos, devuelve [].
SOLO JSON válido, sin markdown, sin texto antes ni después.`;
  } else {
    // Prompt genérico para cualquier otro cliente (Cemex, Élite u otros)
    prompt = `Eres un OCR experto en preliquidaciones de transporte de áridos y cemento en España. Esta es UNA PÁGINA de una preliquidación enviada por un cliente (Holcim, Cemex, Élite Cementos, etc.) a su transportista. La página contiene una TABLA con MÚLTIPLES albaranes (entregas) listados por filas.

EXTRAE TODAS LAS FILAS de la tabla. Cada fila representa una entrega/albarán independiente.

Por cada fila devuelve un objeto JSON con estos campos (todos opcionales si no aparece):
- albaran: número de entrega/albarán (string, ej "31048146095")
- fecha: fecha de entrega en formato DD/MM/YYYY (convierte de "02.03.2026" a "02/03/2026")
- tractora: matrícula del camión (formato "1234ABC", ignora la del remolque)
- remolque: matrícula del remolque si aparece después de la tractora separada por "/" (ej "R3542BBV")
- proveedor_cliente: nombre del proveedor o cliente al que se entrega (ej "Montcada (Hormig)", "La Roca", "Planta Hormigones Zona Franca")
- direccion: dirección completa del punto de entrega
- zona: zona logística (ej "Montcada I Reixac Ba", "La Roca Valles Bar", "Provincia de Barcelona")
- material: tipo de material/servicio (ej "AF-0/4-T-C", "AG-4/11-T-C", "AG-11/22-T-C")
- tm: cantidad en toneladas (NÚMERO, convierte "27,820" a 27.82). El cliente puede usar coma decimal.
- unidad: unidad de medida (ej "TN", "T")
- cliente_emisor: nombre del cliente que emite la preliquidación (ej "HOLCIM", "CEMEX", "ÉLITE"). Solo en la primera fila o cabecera del PDF.

IGNORA totales, subtotales, líneas de cabecera, y filas vacías. Solo extrae filas de DATOS.

Devuelve SOLO un ARRAY JSON con todos los objetos. Si la página no tiene filas de datos, devuelve [].
SOLO JSON válido, sin markdown, sin explicaciones.`;
  }

  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), 180000);
  try {
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-api-key': key, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true' },
      body: JSON.stringify({
        model: 'claude-haiku-4-5',
        max_tokens: 16000,
        messages: [{ role: 'user', content: [
          { type: 'image', source: { type: 'base64', media_type: 'image/jpeg', data: b64 } },
          { type: 'text', text: prompt }
        ]}]
      }),
      signal: ctrl.signal
    });
    clearTimeout(timer);
    if (!res.ok) {
      const e = await res.json().catch(() => ({}));
      const err = new Error(e.error?.message || `HTTP ${res.status}`);
      err.status = res.status;
      throw err;
    }
    const d = await res.json();
    const text = d.content.map(x => x.text || '').join('').trim().replace(/```json|```/g, '').trim();
    const parsed = JSON.parse(text);
    return Array.isArray(parsed) ? parsed : [parsed];
  } catch (e) {
    clearTimeout(timer);
    throw e;
  }
}

// Comparar una fila de preliquidación con los albaranes guardados en BD.
// Cruce en cascada:
// 1) Por número de albarán (Lafarge CEM, áridos Garraf, cisternas — funciona el "Num. Entrega")
// 2) Si no encuentra, por fecha + matrícula + TN (Holcim yeso y similares — el Num. Entrega
//    es un código de pedido semanal tipo "12W2026-0000128" que no coincide con nuestro albaran)
// 3) Marca matches como usados para que un mismo albarán de BD no haga match con dos filas.
//
// El parámetro `usados` es un Set de db_id ya emparejados en esta misma preliquidación.
function compararFilaConBD(filaPreli, usados) {
  if (!usados) usados = new Set(); // si no se pasa, hacemos uno vacío (compatibilidad)
  const albPreli = String(filaPreli.albaran || '').trim().replace(/^0+/, '');
  const tmPreli = parseFloat(filaPreli.tm) || 0;
  const matPreli = String(filaPreli.tractora || '').trim().toUpperCase();
  const fechaPreli = String(filaPreli.fecha || '').trim(); // formato DD/MM/YYYY

  // Helper: normaliza TN a número con 3 decimales
  const tmEq = (a, b) => Math.abs((parseFloat(a)||0) - (parseFloat(b)||0)) <= 0.05;

  // ---------- Estrategia 1: match por número de albarán ----------
  // Funciona en Lafarge CEM (áridos Garraf) y cisternas, donde Num. Entrega = nuestro nº albarán
  if (albPreli && /^\d{8,}$/.test(albPreli)) {
    const matchAlb = records.find(r => {
      if (usados.has(r.db_id)) return false;
      const albBd = String(r.albaran || '').trim().replace(/^0+/, '');
      return albBd === albPreli;
    });
    if (matchAlb) {
      usados.add(matchAlb.db_id);
      const tmBd = parseFloat(matchAlb.tm) || 0;
      const estado = tmEq(tmBd, tmPreli) ? 'COINCIDE' : 'DIFERENCIA_TM';
      return { ...filaPreli, estado_comparacion: estado, db_albaran_id: matchAlb.db_id, metodo_match: 'albaran' };
    }
  }

  // ---------- Estrategia 2: match por fecha + matrícula + TN ----------
  // Para preliquidaciones donde Num. Entrega es un código de pedido (Holcim yeso)
  // v86: normalizamos matrículas quitando ceros al inicio para tolerar variantes OCR.
  // Ejemplo: la preliquidación trae "846NGHN" y la BD tiene "0846NGHN" → se considera misma matrícula.
  // v91d: si la BD guarda la matrícula en formato dual "XXXXLLL/XXXXLLL" (convenio interno
  // del admin), usamos solo la PRIMERA parte para cruzar con la preliquidación, ya que el
  // cliente factura/preliquida por esa primera matrícula.
  if (fechaPreli && matPreli && tmPreli > 0) {
    const matPreliNorm = matPreli.replace(/^0+/, '');
    const matchFMT = records.find(r => {
      if (usados.has(r.db_id)) return false;
      const matBd = matriculaPrincipal(r.tractora || '').replace(/^0+/, '');
      const fechaBd = String(r.fecha || '').trim();
      if (matBd !== matPreliNorm) return false;
      if (fechaBd !== fechaPreli) return false;
      return tmEq(r.tm, tmPreli);
    });
    if (matchFMT) {
      usados.add(matchFMT.db_id);
      return { ...filaPreli, estado_comparacion: 'COINCIDE', db_albaran_id: matchFMT.db_id, metodo_match: 'fecha+mat+tm' };
    }
  }

  // ---------- No hay match ----------
  return { ...filaPreli, estado_comparacion: 'FALTA_BD', db_albaran_id: null, metodo_match: null };
}

// VISTA DETALLE DE UNA PRELIQUIDACIÓN
function openPreliDetail(idPreli) {
  preliActiva = idPreli;
  const preli = preliquidaciones.find(p => p.id === idPreli);
  if (!preli) { toast('Preliquidación no encontrada', 'err'); return; }
  preliFiltroEstado = 'all';
  document.getElementById('preliDetail').style.display = 'block';
  document.getElementById('preliDetailTitle').textContent = `${preli.cliente} · ${preli.filename}`;
  renderPreliDetail();
  // Scroll al detalle
  setTimeout(() => document.getElementById('preliDetail').scrollIntoView({ behavior: 'smooth', block: 'start' }), 100);
}

function closePreliDetail() {
  preliActiva = null;
  document.getElementById('preliDetail').style.display = 'none';
}

function filterPreli(filtro) { preliFiltroEstado = filtro; renderPreliDetail(); }

function renderPreliDetail() {
  if (!preliActiva) return;
  const preli = preliquidaciones.find(p => p.id === preliActiva);
  if (!preli) return;
  const todas = preli.filas;
  const ok = todas.filter(f => f.estado_comparacion === 'COINCIDE').length;
  const falta = todas.filter(f => f.estado_comparacion === 'FALTA_BD').length;
  const dif = todas.filter(f => f.estado_comparacion === 'DIFERENCIA_TM').length;
  const sin = todas.filter(f => f.estado_comparacion === 'SIN_ALBARAN').length;
  // Sobra: albaranes en BD que NO están en esta preliquidación, del mismo cliente
  const albsPreli = new Set(todas.map(f => String(f.albaran || '').trim().replace(/^0+/, '')));
  const sobra = records.filter(r => {
    const albBd = String(r.albaran || '').trim().replace(/^0+/, '');
    return albBd && !albsPreli.has(albBd);
  });
  const tmPreli = todas.reduce((s,f) => s + (parseFloat(f.tm) || 0), 0);
  document.getElementById('preliStats').innerHTML = `
    <div>Total: <strong>${todas.length}</strong></div>
    <div style="color:var(--ok)">✅ Coinciden: <strong>${ok}</strong></div>
    <div style="color:var(--er)">⛔ Faltan en mi BD: <strong>${falta}</strong></div>
    <div style="color:var(--wn)">🔴 Diferencia TM: <strong>${dif}</strong></div>
    <div style="color:var(--mu)">🟡 Sobra en mi BD: <strong>${sobra.length}</strong></div>
    ${sin?'<div style="color:var(--mu)">⚠️ Sin nº albarán: <strong>'+sin+'</strong></div>':''}
    <div>TN total: <strong>${tmPreli.toFixed(2)}</strong></div>
  `;

  // Filtrar
  let visibles;
  if (preliFiltroEstado === 'problema') visibles = todas.filter(f => f.estado_comparacion !== 'COINCIDE');
  else if (preliFiltroEstado === 'falta') visibles = todas.filter(f => f.estado_comparacion === 'FALTA_BD');
  else if (preliFiltroEstado === 'dif') visibles = todas.filter(f => f.estado_comparacion === 'DIFERENCIA_TM');
  else if (preliFiltroEstado === 'ok') visibles = todas.filter(f => f.estado_comparacion === 'COINCIDE');
  else if (preliFiltroEstado === 'sobra') visibles = sobra.map(r => ({
    fecha: r.fecha, tractora: r.tractora, albaran: r.albaran, material: r.producto,
    proveedor_cliente: r.proveedor, direccion: r.planta + ' → ' + r.obra, tm: r.tm,
    estado_comparacion: 'SOBRA_BD', _es_albaran_bd: true
  }));
  else visibles = todas;

  // Ordenar por matrícula → fecha → albarán
  visibles = [...visibles].sort(compareRecords);

  const ESTADO_LABEL = {
    'COINCIDE': '<span style="color:var(--ok)">✅ OK</span>',
    'FALTA_BD': '<span style="color:var(--er)">⛔ Falta en BD</span>',
    'DIFERENCIA_TM': '<span style="color:var(--wn)">🔴 Dif. TM</span>',
    'SIN_ALBARAN': '<span style="color:var(--mu)">⚠️ Sin alb.</span>',
    'SOBRA_BD': '<span style="color:var(--mu)">🟡 Sobra en BD</span>'
  };

  const tbody = document.getElementById('tbodyPreli');
  if (!visibles.length) {
    tbody.innerHTML = '<tr><td colspan="8" style="text-align:center;padding:30px;color:var(--mu);font-family:var(--mn);font-size:11px">No hay filas con este filtro.</td></tr>';
    return;
  }
  tbody.innerHTML = visibles.map(f => {
    let detalleDif = '';
    if (f.estado_comparacion === 'DIFERENCIA_TM' && f.db_albaran_id) {
      const bd = records.find(r => (r.db_id || r.id) === f.db_albaran_id);
      if (bd) detalleDif = ` <span style="color:var(--mu);font-size:10px">(BD: ${bd.tm} TN)</span>`;
    }
    const origen = f._es_albaran_bd ? (f.direccion || '') : (f.proveedor_cliente || '');
    const destino = f._es_albaran_bd ? '' : (f.direccion || f.zona || '');
    return `<tr>
      <td>${esc(f.fecha || '')}</td>
      <td>${esc(f.tractora || '')}${f.remolque?' / '+esc(f.remolque):''}</td>
      <td>${esc(f.albaran || '')}</td>
      <td>${esc(f.material || '')}</td>
      <td>${esc(origen)}</td>
      <td>${esc(destino)}</td>
      <td>${f.tm != null ? parseFloat(f.tm).toFixed(2) : ''}${detalleDif}</td>
      <td>${ESTADO_LABEL[f.estado_comparacion] || esc(f.estado_comparacion || '')}</td>
    </tr>`;
  }).join('');
}

async function recompararPreli() {
  if (!preliActiva) return;
  if (!confirm('Se volverán a comparar todas las filas con tus albaranes guardados. ¿Continuar?')) return;
  const preli = preliquidaciones.find(p => p.id === preliActiva);
  if (!preli) return;
  toast('🔄 Recomparando...');
  let cambios = 0;
  // Set compartido para que un mismo albarán BD no haga match con dos filas distintas
  const usadosRecompara = new Set();
  for (const f of preli.filas) {
    const nuevo = compararFilaConBD(f, usadosRecompara);
    if (nuevo.estado_comparacion !== f.estado_comparacion || nuevo.db_albaran_id !== f.db_albaran_id) {
      const { error } = await sb.from('preliquidaciones').update({
        estado_comparacion: nuevo.estado_comparacion,
        db_albaran_id: nuevo.db_albaran_id
      }).eq('id', f.id);
      if (!error) {
        f.estado_comparacion = nuevo.estado_comparacion;
        f.db_albaran_id = nuevo.db_albaran_id;
        cambios++;
      }
    }
  }
  toast(`✓ ${cambios} filas actualizadas`);
  renderPreliDetail();
  renderPreliList();
}

function exportPreliExcel() {
  if (!preliActiva) return;
  const preli = preliquidaciones.find(p => p.id === preliActiva);
  if (!preli) return;
  const albsPreli = new Set(preli.filas.map(f => String(f.albaran || '').trim().replace(/^0+/, '')));
  const sobran = records.filter(r => {
    const albBd = String(r.albaran || '').trim().replace(/^0+/, '');
    return albBd && !albsPreli.has(albBd);
  });

  const HEAD = ['FECHA','MATRICULA','REMOLQUE','Nº ALBARAN','PROVEEDOR/CLIENTE','DIRECCION','ZONA','MATERIAL','TN','UNIDAD','ESTADO','TN BD','DIFERENCIA TN'];
  const rows = [HEAD];
  // Filas de la preliquidación
  [...preli.filas].sort(compareRecords).forEach(f => {
    let tmBd = '', dif = '';
    if (f.db_albaran_id) {
      const bd = records.find(r => (r.db_id || r.id) === f.db_albaran_id);
      if (bd) {
        tmBd = parseFloat(bd.tm) || 0;
        dif = ((parseFloat(f.tm) || 0) - tmBd).toFixed(2);
      }
    }
    const estLabel = {
      'COINCIDE':'OK','FALTA_BD':'FALTA EN BD','DIFERENCIA_TM':'DIFERENCIA TM',
      'SIN_ALBARAN':'SIN ALBARAN'
    }[f.estado_comparacion] || f.estado_comparacion;
    rows.push([
      f.fecha||'', f.tractora||'', f.remolque||'', f.albaran||'',
      f.proveedor_cliente||'', f.direccion||'', f.zona||'',
      f.material||'', f.tm != null ? parseFloat(f.tm) : '',
      f.unidad||'TN', estLabel, tmBd, dif
    ]);
  });
  // Sección "SOBRAN EN BD"
  if (sobran.length) {
    rows.push([]);
    rows.push(['ALBARANES EN BD QUE NO ESTÁN EN ESTA PRELIQUIDACIÓN']);
    rows.push(HEAD);
    [...sobran].sort(compareRecords).forEach(r => {
      rows.push([
        r.fecha||'', r.tractora||'', r.remolque||'', r.albaran||'',
        r.proveedor||'', (r.planta||'') + ' → ' + (r.obra||''), '',
        r.producto||'', parseFloat(r.tm)||0,
        'TN', 'SOBRA EN BD', '', ''
      ]);
    });
  }
  // Resumen
  rows.push([]);
  rows.push(['RESUMEN']);
  rows.push(['Cliente', preli.cliente]);
  rows.push(['Archivo', preli.filename]);
  rows.push(['Total filas en preliquidación', preli.filas.length]);
  rows.push(['Coinciden', preli.filas.filter(f => f.estado_comparacion === 'COINCIDE').length]);
  rows.push(['Faltan en BD', preli.filas.filter(f => f.estado_comparacion === 'FALTA_BD').length]);
  rows.push(['Diferencia TM', preli.filas.filter(f => f.estado_comparacion === 'DIFERENCIA_TM').length]);
  rows.push(['Sobran en BD (no en preli)', sobran.length]);
  rows.push(['TN total preliquidación', preli.filas.reduce((s,f) => s + (parseFloat(f.tm) || 0), 0).toFixed(3)]);

  const ws = XLSX.utils.aoa_to_sheet(rows);
  ws['!cols'] = [10,10,10,14,28,30,18,18,8,6,18,8,10].map(w => ({wch: w}));
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Comparación');
  const fname = `preliquidacion_${(preli.cliente||'').replace(/\s+/g,'_')}_${new Date().toISOString().slice(0,10)}.xlsx`;
  XLSX.writeFile(wb, fname);
  toast(`✓ Excel descargado`);
}

// ============================================================
// v107j — NEUMÁTICOS (stock y consumo)
// Tablas: neumaticos_movimientos, neumaticos_modelos, neumaticos_alertas_config
// 3 empresas: TYP2014 / HISPALIS / TRANSMARGAZ
// Movimientos: inventario_inicial, compra, montaje, baja, ajuste
// ============================================================
let neumMovimientos = [];      // todos los movimientos cargados de BD
let neumModelos = [];          // catálogo de modelos (marca+modelo+medida → uso)
let neumAlertasConfig = [];    // umbrales configurables
let neumEmpresaActiva = 'TYP2014';   // qué subpestaña se ve
let editNeumMovId = null;      // ID del movimiento que se está editando

// Cargar TODO de Neumáticos desde Supabase. Llamado al inicio (si tiene permiso)
// y al entrar en la pestaña. También expone la cuenta para la badge.
async function loadNeumData() {
  if (!window._tieneNeum) return;
  try {
    // Si el usuario está limitado a una empresa concreta, forzar esa subpestaña.
    if (window._empresaNeum && neumEmpresaActiva !== window._empresaNeum) {
      neumEmpresaActiva = window._empresaNeum;
    }
    // Ocultar subpestañas que no puede ver
    if (window._empresaNeum) {
      ['TYP2014','HISPALIS','TRANSMARGAZ'].forEach(emp => {
        const btn = document.getElementById('neumSub' + emp);
        if (btn) btn.style.display = (emp === window._empresaNeum) ? '' : 'none';
      });
    }
    // 1) Catálogo de modelos
    const { data: dM, error: eM } = await sb.from('neumaticos_modelos').select('*');
    if (eM) throw eM;
    neumModelos = dM || [];
    // 2) Config de alertas
    const { data: dA, error: eA } = await sb.from('neumaticos_alertas_config').select('*');
    if (eA) throw eA;
    neumAlertasConfig = dA || [];
    // 3) Movimientos
    const { data: dMov, error: eMov } = await sb.from('neumaticos_movimientos').select('*').order('fecha', { ascending: false });
    if (eMov) throw eMov;
    neumMovimientos = dMov || [];
    // Badge: nº de avisos activos (stock bajo) de la empresa actual
    const avisos = _neumCalcularAvisos(neumEmpresaActiva).length;
    const badge = document.getElementById('tabNeumCount');
    if (badge) badge.textContent = avisos;
    // Pintar
    renderNeum();
  } catch (e) {
    console.error('[loadNeumData] Error:', e);
    toast('Error cargando neumáticos: ' + (e.message || e), 'err');
  }
}

// Cambia la subpestaña de empresa activa
function switchNeumEmpresa(emp) {
  if (window._empresaNeum && emp !== window._empresaNeum) {
    toast('No tienes permiso para esa empresa', 'err');
    return;
  }
  neumEmpresaActiva = emp;
  // Actualizar botones (visualmente el activo en verde)
  ['TYP2014','HISPALIS','TRANSMARGAZ'].forEach(e => {
    const btn = document.getElementById('neumSub' + e);
    if (!btn) return;
    btn.classList.remove('bp','bs');
    btn.classList.add(e === emp ? 'bp' : 'bs');
  });
  renderNeum();
}

// Devuelve el stock actual para una empresa, agrupado por (medida + modelo).
// Suma cantidad de todos los movimientos: positivos suman (inventario, compra),
// negativos restan (montaje, baja). Devuelve array de {medida, marca, modelo, uso, stock, precio_neto_unitario_ultimo}.
function _neumCalcularStock(empresa) {
  const map = {};   // clave = "medida|marca|modelo"
  neumMovimientos.filter(m => m.empresa === empresa).forEach(m => {
    const key = `${m.medida || '?'}|${m.marca || '?'}|${m.modelo || '?'}`;
    if (!map[key]) {
      map[key] = {
        medida: m.medida, marca: m.marca, modelo: m.modelo, uso: m.uso,
        stock: 0, precio_neto_unitario_ultimo: null, fecha_ultimo: null
      };
    }
    map[key].stock += (m.cantidad || 0);
    // Guardar precio neto de la última compra (para mostrarlo en la tarjeta)
    if (m.tipo === 'compra' && m.precio_neto_unitario) {
      if (!map[key].fecha_ultimo || m.fecha > map[key].fecha_ultimo) {
        map[key].fecha_ultimo = m.fecha;
        map[key].precio_neto_unitario_ultimo = m.precio_neto_unitario;
      }
    }
  });
  // Ordenar por medida, luego por uso (motriz / dirección / remolque)
  return Object.values(map).sort((a, b) => {
    if (a.medida !== b.medida) return (a.medida || '').localeCompare(b.medida || '');
    return (a.uso || '').localeCompare(b.uso || '');
  });
}

// Obtiene el umbral aplicable a una combinación (lo más específico que encaje).
// Por ahora solo usamos el GLOBAL; en el futuro se pueden añadir por medida/modelo.
function _neumUmbral(empresa, marca, modelo, medida) {
  const cfg = neumAlertasConfig.filter(c => c.activo !== false);
  // Específico por empresa+medida+modelo > empresa+medida > empresa > global
  const score = c => (c.empresa === empresa ? 100 : (c.empresa === 'GLOBAL' ? 1 : 0))
                  + (c.medida === medida ? 10 : 0)
                  + (c.modelo === modelo ? 5 : 0)
                  + (c.marca === marca ? 2 : 0);
  const best = cfg.sort((a, b) => score(b) - score(a))[0];
  return best ? best.umbral : 4;
}

// Devuelve la lista de combinaciones con stock por debajo del umbral
function _neumCalcularAvisos(empresa) {
  return _neumCalcularStock(empresa).filter(s => {
    const u = _neumUmbral(empresa, s.marca, s.modelo, s.medida);
    return s.stock <= u && s.stock > 0;   // si stock=0 no avisamos (ya no hay nada que gestionar)
  });
}

// Pinta la pestaña: stock + histórico
function renderNeum() {
  document.getElementById('neumEmpresaTitulo').textContent = neumEmpresaActiva;
  const stock = _neumCalcularStock(neumEmpresaActiva);
  const box = document.getElementById('neumStockBox');
  if (!stock.length) {
    box.innerHTML = `<div style="color:var(--mu);font-family:var(--mn);font-size:11px;padding:14px;text-align:center">Sin movimientos para <strong>${esc(neumEmpresaActiva)}</strong>. Pulsa <strong>📥 Inventario inicial</strong> para empezar.</div>`;
  } else {
    box.innerHTML = stock.map(s => {
      const umbral = _neumUmbral(neumEmpresaActiva, s.marca, s.modelo, s.medida);
      const alerta = s.stock <= umbral;
      const color = alerta ? 'var(--er)' : (s.stock <= umbral * 2 ? '#ffb84d' : 'var(--ok)');
      const icon = alerta ? '⚠️' : '✅';
      const precio = s.precio_neto_unitario_ultimo
        ? `<div style="font-family:var(--mn);font-size:10px;color:var(--mu);margin-top:4px">~${parseFloat(s.precio_neto_unitario_ultimo).toFixed(2)} €/ud</div>` : '';
      const usoLabel = s.uso ? `<span style="font-family:var(--mn);font-size:9px;color:var(--mu);text-transform:uppercase">${esc(s.uso)}</span>` : '';
      return `
        <div style="border:1px solid ${color};border-radius:8px;padding:12px;background:rgba(0,0,0,.15)">
          <div style="font-family:var(--mn);font-size:11px;color:var(--mu)">${esc(s.medida || '—')} · ${usoLabel}</div>
          <div style="font-family:var(--mn);font-size:11px;color:var(--ac);margin-top:2px">${esc(s.marca || '')} ${esc(s.modelo || '')}</div>
          <div style="font-size:28px;font-weight:bold;color:${color};margin-top:6px">${icon} ${s.stock} ud</div>
          ${precio}
        </div>`;
    }).join('');
  }
  // Histórico
  const hist = neumMovimientos.filter(m => m.empresa === neumEmpresaActiva);
  const histBox = document.getElementById('neumHistBox');
  if (!hist.length) {
    histBox.innerHTML = `<div style="color:var(--mu);font-family:var(--mn);font-size:11px;padding:14px;text-align:center">Sin histórico.</div>`;
  } else {
    histBox.innerHTML = `
      <table style="width:100%;border-collapse:collapse;font-family:var(--mn);font-size:11px">
        <thead>
          <tr style="text-align:left;border-bottom:1px solid var(--bd);color:var(--mu)">
            <th style="padding:6px">FECHA</th>
            <th style="padding:6px">TIPO</th>
            <th style="padding:6px">MEDIDA · MODELO</th>
            <th style="padding:6px;text-align:right">UDS</th>
            <th style="padding:6px">TRACTORA</th>
            <th style="padding:6px">FACTURA / OBS</th>
            <th style="padding:6px"></th>
          </tr>
        </thead>
        <tbody>
        ${hist.map(m => {
          const tipoIcon = {
            'inventario_inicial':'📥', 'compra':'➕', 'montaje':'🔧', 'baja':'🗑️', 'ajuste':'✏️'
          }[m.tipo] || '·';
          const tipoLbl = {
            'inventario_inicial':'Inv.inicial', 'compra':'Compra', 'montaje':'Montaje', 'baja':'Baja', 'ajuste':'Ajuste'
          }[m.tipo] || m.tipo;
          const sign = m.cantidad > 0 ? '+' : '';
          const cantColor = m.cantidad > 0 ? 'var(--ok)' : 'var(--er)';
          const extra = m.tipo === 'compra' ? esc(m.num_factura || m.proveedor || '') : esc(m.observaciones || m.conductor || '');
          return `<tr style="border-bottom:1px solid var(--bd)">
            <td style="padding:6px;white-space:nowrap">${esc((m.fecha || '').split('T')[0].split('-').reverse().join('/'))}</td>
            <td style="padding:6px;white-space:nowrap">${tipoIcon} ${tipoLbl}</td>
            <td style="padding:6px">${esc(m.medida || '')} · ${esc(m.marca || '')} ${esc(m.modelo || '')}</td>
            <td style="padding:6px;text-align:right;color:${cantColor};font-weight:bold">${sign}${m.cantidad}</td>
            <td style="padding:6px">${esc(m.tractora || m.remolque || '')}</td>
            <td style="padding:6px;color:var(--mu)">${m.file_url ? `<a href="${esc(m.file_url)}" target="_blank" style="color:var(--ac);margin-right:6px" title="Ver archivo adjunto">📎</a>` : ''}${extra}</td>
            <td style="padding:6px"><button class="btn bs" style="font-size:9px;padding:4px 8px" onclick="openNeumMovimientoModal(null, '${m.id}')">Editar</button></td>
          </tr>`;
        }).join('')}
        </tbody>
      </table>`;
  }
}

// Abre el modal. Si se pasa un id, edita ese movimiento. Si se pasa un tipo, crea nuevo.
function openNeumMovimientoModal(tipo, id) {
  editNeumMovId = id || null;
  const m = id ? neumMovimientos.find(x => x.id === id) : null;
  const tipoFinal = m ? m.tipo : tipo;
  // Título según tipo
  const titulos = {
    'inventario_inicial': '📥 INVENTARIO INICIAL',
    'compra': '➕ NUEVA COMPRA',
    'montaje': '🔧 REGISTRAR MONTAJE',
    'baja': '🗑️ BAJA (rotura/desecho)',
    'ajuste': '✏️ AJUSTE MANUAL'
  };
  document.getElementById('neumModalTitulo').textContent = titulos[tipoFinal] || 'MOVIMIENTO';
  // Construir formulario según tipo
  const hoy = new Date().toISOString().slice(0, 10);
  const v = (k) => m ? esc(m[k] != null ? String(m[k]) : '') : '';
  const empresaActual = m ? m.empresa : neumEmpresaActiva;
  // Opciones del select de modelos (catálogo)
  const modeloOpts = neumModelos.map(mo => {
    const sel = (m && m.marca === mo.marca && m.modelo === mo.modelo && m.medida === mo.medida) ? ' selected' : '';
    return `<option value="${esc(mo.marca + '|' + mo.modelo + '|' + mo.medida + '|' + (mo.uso || ''))}"${sel}>${esc(mo.marca)} · ${esc(mo.modelo)} · ${esc(mo.medida)} (${esc(mo.uso || '?')})</option>`;
  }).join('');
  // Sección común: empresa + fecha + producto
  let camposComunes = `
    <div class="fg" style="margin-bottom:10px"><label class="fl">Empresa</label>
      <select class="fi" id="neumF_empresa">
        <option value="TYP2014"${empresaActual==='TYP2014'?' selected':''}>🏢 TYP2014</option>
        <option value="HISPALIS"${empresaActual==='HISPALIS'?' selected':''}>🚚 HISPALIS</option>
        <option value="TRANSMARGAZ"${empresaActual==='TRANSMARGAZ'?' selected':''}>🚛 TRANSMARGAZ</option>
      </select>
    </div>
    <div class="fg" style="margin-bottom:10px"><label class="fl">Fecha</label>
      <input class="fi" type="date" id="neumF_fecha" value="${m ? esc(m.fecha) : hoy}">
    </div>
    <div class="fg full" style="margin-bottom:10px"><label class="fl">Modelo (del catálogo)</label>
      <select class="fi" id="neumF_modelo" onchange="_neumOnModeloChange()">
        <option value="">— Elige un modelo o pon Marca/Modelo/Medida manualmente —</option>
        ${modeloOpts}
      </select>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:10px">
      <div class="fg"><label class="fl">Marca</label><input class="fi" id="neumF_marca" value="${v('marca')}" placeholder="Continental"></div>
      <div class="fg"><label class="fl">Modelo</label><input class="fi" id="neumF_modelo_txt" value="${v('modelo')}" placeholder="Hybrid HD5"></div>
      <div class="fg"><label class="fl">Medida</label><input class="fi" id="neumF_medida" value="${v('medida')}" placeholder="315/80R22.5"></div>
    </div>
    <div class="fg" style="margin-bottom:10px"><label class="fl">Uso (motriz / dirección / remolque)</label>
      <input class="fi" id="neumF_uso" value="${v('uso')}" placeholder="se rellena solo del catálogo">
    </div>`;
  // Sección variable por tipo
  let camposVariables = '';
  if (tipoFinal === 'compra') {
    const cant = m ? Math.abs(m.cantidad) : '';
    camposVariables = `
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">
        <div class="fg"><label class="fl">Cantidad (uds)</label><input class="fi" type="number" id="neumF_cantidad" value="${cant}" min="1" step="1"></div>
        <div class="fg"><label class="fl">Precio bruto unitario (€)</label><input class="fi" type="number" id="neumF_precio_unitario" value="${v('precio_unitario')}" step="0.01"></div>
      </div>
      <div class="fg" style="margin-bottom:10px"><label class="fl">Precio NETO unitario con descuentos+tasa NFU (€)</label>
        <input class="fi" type="number" id="neumF_precio_neto" value="${v('precio_neto_unitario')}" step="0.01" placeholder="opcional, para cuentas reales">
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">
        <div class="fg"><label class="fl">Proveedor</label><input class="fi" id="neumF_proveedor" value="${v('proveedor')}" placeholder="Neumáticos Soledad"></div>
        <div class="fg"><label class="fl">Nº factura</label><input class="fi" id="neumF_num_factura" value="${v('num_factura')}" placeholder="N0000046886"></div>
      </div>
      <div class="fg full" style="margin-bottom:10px"><label class="fl">Observaciones</label>
        <input class="fi" id="neumF_observaciones" value="${v('observaciones')}" placeholder="opcional">
      </div>
      ${_neumCampoArchivo(m, 'factura de compra (opcional)')}`;
  } else if (tipoFinal === 'montaje' || tipoFinal === 'baja') {
    const cant = m ? Math.abs(m.cantidad) : '';
    const labelCant = tipoFinal === 'montaje' ? 'Cantidad montada (uds)' : 'Cantidad dada de baja (uds)';
    camposVariables = `
      <div class="fg" style="margin-bottom:10px"><label class="fl">${labelCant}</label>
        <input class="fi" type="number" id="neumF_cantidad" value="${cant}" min="1" step="1">
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">
        <div class="fg"><label class="fl">Tractora (matrícula)</label><input class="fi" id="neumF_tractora" value="${v('tractora')}" placeholder="5360JZR" style="text-transform:uppercase"></div>
        <div class="fg"><label class="fl">Remolque (matrícula)</label><input class="fi" id="neumF_remolque" value="${v('remolque')}" placeholder="opcional" style="text-transform:uppercase"></div>
      </div>
      <div class="fg full" style="margin-bottom:10px"><label class="fl">Conductor / Observaciones</label>
        <input class="fi" id="neumF_observaciones" value="${v('observaciones')}" placeholder="${tipoFinal==='baja'?'motivo de la baja: rotura, desgaste...':'datos extra'}">
      </div>
      ${_neumCampoArchivo(m, tipoFinal === 'baja' ? 'foto de la rueda (opcional)' : 'albarán del taller (opcional)')}`;
  } else {
    // inventario_inicial o ajuste
    const cant = m ? m.cantidad : '';
    const ayuda = tipoFinal === 'inventario_inicial'
      ? 'Cantidad que tenéis HOY físicamente en almacén.'
      : 'Positivo para sumar, negativo para restar (corrección manual).';
    camposVariables = `
      <div class="fg" style="margin-bottom:10px"><label class="fl">Cantidad (uds) <span style="color:var(--mu);font-size:9px">${ayuda}</span></label>
        <input class="fi" type="number" id="neumF_cantidad" value="${cant}" step="1">
      </div>
      <div class="fg full" style="margin-bottom:10px"><label class="fl">Observaciones</label>
        <input class="fi" id="neumF_observaciones" value="${v('observaciones')}" placeholder="opcional">
      </div>`;
  }
  // Pintar
  document.getElementById('neumModalFields').innerHTML = camposComunes + camposVariables
    + `<input type="hidden" id="neumF_tipo" value="${esc(tipoFinal)}">`;
  // Botón eliminar: visible solo al editar
  document.getElementById('btnDelNeum').style.display = m ? '' : 'none';
  document.getElementById('ovNeum').classList.add('open');
}

// Cuando se elige un modelo del catálogo, autorrellenar marca/modelo/medida/uso
function _neumOnModeloChange() {
  const sel = document.getElementById('neumF_modelo').value;
  if (!sel) return;
  const [marca, modelo, medida, uso] = sel.split('|');
  document.getElementById('neumF_marca').value = marca || '';
  document.getElementById('neumF_modelo_txt').value = modelo || '';
  document.getElementById('neumF_medida').value = medida || '';
  document.getElementById('neumF_uso').value = uso || '';
}

// v107L: helper para el campo de "Adjuntar archivo". Si el movimiento ya tiene un archivo,
// muestra un enlace para verlo y opción de reemplazarlo. Si no, solo el selector de archivo.
function _neumCampoArchivo(m, etiqueta) {
  const tieneArchivo = m && m.file_url;
  const verActual = tieneArchivo
    ? `<div style="margin-bottom:6px;font-family:var(--mn);font-size:10px">
         📎 <a href="${esc(m.file_url)}" target="_blank" style="color:var(--ac)">Ver archivo actual</a>
         <span style="color:var(--mu)"> · sube otro para reemplazarlo</span>
       </div>` : '';
  return `
    <div class="fg full" style="margin-bottom:10px">
      <label class="fl">📎 Adjuntar ${etiqueta}</label>
      ${verActual}
      <input class="fi" type="file" id="neumF_archivo" accept="image/*,.pdf" style="padding:6px">
      <div id="neumF_archivoStatus" style="font-family:var(--mn);font-size:10px;color:var(--mu);margin-top:4px"></div>
    </div>`;
}

function closeNeumModal() {
  document.getElementById('ovNeum').classList.remove('open');
  editNeumMovId = null;
}

// ============================================================
// v107I2 (02/06/2026): PROCESADO DE ALBARANES SOLEDAD (Flujo 1)
// ============================================================
// Mapa CIF → empresa (las 3 que llevan stock de neumáticos).
// v107I4 (02/06/2026): Portes 2014 Import (B02657435) comparte stock con TYP2014
// (las facturas/albaranes de Soledad de TYP2014 + Portes Import vienen juntas por la
// Holding). Hispalis y Transmargaz, cada uno al suyo.
const _NEUM_CIF_EMPRESA = {
  'B90172735': 'TYP2014',         // TYP2014
  'B02657435': 'TYP2014',         // Portes 2014 Import → mismo stock que TYP2014 (Holding)
  'B90286337': 'HISPALIS',
  'B67316752': 'TRANSMARGAZ'
};

// v107I3 (02/06/2026): convierte una fecha a formato BD AAAA-MM-DD (el que usa la
// columna fecha de neumaticos_movimientos, igual que el input type=date del formulario
// manual). Antes el lector guardaba "02/06/2026" (DD/MM/AAAA) y la BD lo interpretaba
// al revés (2026-02-06). Acepta DD/MM/AAAA, DD-MM-AAAA o ya-AAAA-MM-DD. Si no la
// entiende, usa la fecha de hoy en formato ISO.
function _neumFechaISO(s) {
  const t = String(s || '').trim();
  // Ya viene en AAAA-MM-DD
  let m = t.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
  if (m) return `${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}`;
  // DD/MM/AAAA o DD-MM-AAAA
  m = t.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})$/);
  if (m) {
    let y = m[3]; if (y.length === 2) y = '20' + y;
    return `${y}-${m[2].padStart(2,'0')}-${m[1].padStart(2,'0')}`;
  }
  // No reconocida → hoy en ISO
  return new Date().toISOString().slice(0, 10);
}

// Maneja los archivos soltados/elegidos en la zona de albaranes Soledad.
// Procesa cada archivo de uno en uno y muestra un resumen al final.
async function handleNeumAlbFiles(fileList) {
  const files = Array.from(fileList || []);
  if (!files.length) return;
  const key = getKey();
  if (!key) { toast('Falta la clave de IA (arriba, botón Cambiar)', 'err'); return; }
  toast(`📤 Procesando ${files.length} albarán(es) de neumáticos...`, 'ok');
  let okCount = 0, movCount = 0, sinStock = 0, errores = 0;
  for (const file of files) {
    try {
      const r = await _neumProcesarAlbaranSoledad(file, key);
      if (r && r.ok) { okCount++; movCount += r.movimientos; sinStock += r.sinStock; }
      else errores++;
    } catch (e) {
      console.error('[v107I2] Error procesando albarán neumático:', e);
      errores++;
    }
  }
  await loadNeumData();
  let msg = `✓ ${okCount} albarán(es) leídos · ${movCount} movimiento(s) de stock`;
  if (sinStock) msg += ` · ${sinStock} compra(s) registrada(s) (stock neutro, pendiente de factura)`;
  if (errores) msg += ` · ⚠️ ${errores} con error`;
  toast(msg, errores ? 'err' : 'ok');
}

// Procesa UN albarán Soledad: lee con IA, detecta empresa por CIF, sube el
// archivo a Storage y crea los movimientos de stock (montaje) para las líneas
// SU_PROPIEDAD. Devuelve {ok, movimientos, sinStock}.
async function _neumProcesarAlbaranSoledad(file, key) {
  // 1) Convertir a base64
  const isPdf = (file.type === 'application/pdf') || /\.pdf$/i.test(file.name);
  const mediaType = file.type || (isPdf ? 'application/pdf' : 'image/jpeg');
  const b64 = await new Promise((res, rej) => {
    const fr = new FileReader();
    fr.onload = () => res(String(fr.result).split(',')[1]);
    fr.onerror = () => rej(new Error('No se pudo leer el archivo'));
    fr.readAsDataURL(file);
  });

  // 2) Leer con la IA
  const lineas = await callClaudeNeumAlb(b64, mediaType, key, isPdf, null);
  if (!lineas || !lineas.length) {
    toast(`⚠️ ${file.name}: no se detectaron neumáticos en el albarán`, 'err');
    return { ok: false, movimientos: 0, sinStock: 0 };
  }

  // 3) Avisos de 19,5 (no se procesan)
  const avisos195 = lineas.filter(l => l && l.avisa19_5);
  const lineasNeum = lineas.filter(l => l && !l.avisa19_5 && l.medida);
  if (avisos195.length) {
    toast(`⚠️ ${file.name}: ${avisos195.length} línea(s) de 19,5" (no se lleva stock, revísalo a mano)`, 'err');
  }
  if (!lineasNeum.length) {
    return { ok: true, movimientos: 0, sinStock: 0 };
  }

  // 4) Detectar empresa por CIF (todas las líneas comparten el mismo albarán/CIF)
  const cif = String(lineasNeum[0].cif_cliente || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
  let empresa = _NEUM_CIF_EMPRESA[cif] || null;
  if (!empresa) {
    // Seguro: si el CIF no se lee o no coincide, preguntar a mano.
    const elegida = prompt(`No he podido identificar la empresa por el CIF "${cif || '(vacío)'}" del albarán ${lineasNeum[0].num_albaran || ''}.\n\nEscribe a qué empresa va:\n- TYP2014\n- HISPALIS\n- TRANSMARGAZ`, neumEmpresaActiva || 'TYP2014');
    if (!elegida) { toast('Albarán cancelado (sin empresa)', 'err'); return { ok: false, movimientos: 0, sinStock: 0 }; }
    empresa = elegida.trim().toUpperCase();
    if (!['TYP2014', 'HISPALIS', 'TRANSMARGAZ'].includes(empresa)) {
      toast('Empresa no válida: ' + empresa, 'err'); return { ok: false, movimientos: 0, sinStock: 0 };
    }
  }

  // 4b) v107I6 ANTI-DUPLICADO: como varios usuarios comparten correo, es fácil subir
  // el mismo albarán dos veces. Si ya hay movimientos de ESTE nº de albarán en ESTA
  // empresa, avisamos antes de volver a descontar/registrar. Buscamos el nº albarán en
  // las observaciones (donde lo guardamos: "Albarán Soledad D700004618 ...").
  const numAlbDup = String(lineasNeum[0].num_albaran || '').trim();
  if (numAlbDup) {
    try {
      const { data: yaExisteAlb } = await sb.from('neumaticos_movimientos')
        .select('id').eq('empresa', empresa).ilike('observaciones', `%${numAlbDup}%`).limit(1);
      if (yaExisteAlb && yaExisteAlb.length) {
        if (!confirm(`El albarán ${numAlbDup} ya parece estar cargado en ${empresa}.\n\n(Puede que lo haya subido otro compañero.)\n\n¿Volver a procesarlo igualmente? — CUIDADO: descontaría/registraría el stock OTRA VEZ.`)) {
          toast(`Albarán ${numAlbDup} omitido (ya estaba cargado)`, 'warn');
          return { ok: false, movimientos: 0, sinStock: 0 };
        }
      }
    } catch (e) { /* si falla la comprobación, seguimos */ }
  }

  // 5) Subir el archivo a Storage (no crítico: si falla, seguimos)
  let fileUrl = null;
  try {
    const ext = (file.name.split('.').pop() || 'bin').toLowerCase();
    const ts = Date.now();
    const filename = `neumaticos/${empresa}/albaran-soledad_${ts}.${ext}`;
    const { error: upErr } = await sb.storage.from('documentos').upload(filename, file, { upsert: false, contentType: file.type || 'application/octet-stream' });
    if (!upErr) {
      const { data: urlData } = sb.storage.from('documentos').getPublicUrl(filename);
      if (urlData && urlData.publicUrl) fileUrl = urlData.publicUrl;
    }
  } catch (e) { console.warn('[v107I2] No se pudo subir el archivo (no crítico):', e.message); }

  // 6) Crear movimientos según propiedad:
  //    · SU_PROPIEDAD (S/PROP / DE SU STOCK) → 1 montaje (-N): descuenta stock (eran tuyos).
  //    · COMPRA_VENTA (sin S/PROP) → v107I4: se compran Y se montan en el acto, así que
  //      registramos 2 movimientos: compra (+N) y montaje (-N) → stock NEUTRO, pero queda
  //      el registro de la compra para verla y para cuadrarla luego con la factura.
  let movimientos = 0, compras = 0;
  for (const l of lineasNeum) {
    const cant = Math.abs(parseInt(l.cantidad) || 0);
    if (!cant) continue;
    const medida = String(l.medida || '').trim();
    const marca = String(l.marca || '').trim().toUpperCase() || null;
    const modelo = String(l.modelo || '').trim() || null;
    const fecha = _neumFechaISO(l.fecha);
    const matricula = String(l.matricula || '').toUpperCase().replace(/\s+/g, '') || null;
    const esPropiedad = String(l.propiedad || '') === 'SU_PROPIEDAD';
    const numAlb = l.num_albaran || '';
    const base = { empresa, fecha, marca, modelo, medida, uso: null, tractora: matricula, remolque: null, user_id: currentUser.id, updated_at: new Date().toISOString() };
    if (fileUrl) base.file_url = fileUrl;

    if (esPropiedad) {
      // Eran del cliente → solo montaje (resta stock)
      const pMontaje = Object.assign({}, base, { tipo: 'montaje', cantidad: -cant, observaciones: `Albarán Soledad ${numAlb} (leído por IA, S/PROP)`.trim() });
      const { error } = await sb.from('neumaticos_movimientos').insert(pMontaje);
      if (error) { console.error('[v107I4] Error guardando montaje:', error); toast('Error guardando montaje: ' + error.message, 'err'); }
      else movimientos++;
    } else {
      // Compra-y-monta: compra (+) y montaje (-) → stock neutro, queda el registro de compra
      const pCompra = Object.assign({}, base, { tipo: 'compra', cantidad: cant, proveedor: 'Neumáticos Soledad', num_factura: null, observaciones: `Compra-montaje · Albarán Soledad ${numAlb} (leído por IA, pendiente de factura)`.trim() });
      const r1 = await sb.from('neumaticos_movimientos').insert(pCompra);
      if (r1.error) { console.error('[v107I4] Error guardando compra:', r1.error); toast('Error guardando compra: ' + r1.error.message, 'err'); }
      else compras++;
      const pMontaje = Object.assign({}, base, { tipo: 'montaje', cantidad: -cant, observaciones: `Montaje (compra-montaje) · Albarán Soledad ${numAlb} (leído por IA)`.trim() });
      const r2 = await sb.from('neumaticos_movimientos').insert(pMontaje);
      if (r2.error) { console.error('[v107I4] Error guardando montaje:', r2.error); }
      else movimientos++;
    }
  }
  return { ok: true, movimientos, sinStock: compras };
}

// Drag&drop para la zona de albaranes Soledad (verde).
function dropNeumAlb(e) {
  e.preventDefault();
  const target = e.currentTarget;
  _dragCounters.set(target, 0);
  target.classList.remove('ov');
  handleNeumAlbFiles(e.dataTransfer.files);
}

// ============================================================
// v107I5 (02/06/2026): PROCESADO DE FACTURAS SOLEDAD (Flujo 2 Parte B)
// ============================================================
// CIF de la Holding (POR.2014 CAPITAL HOLDINGS) → stock de TYP2014.
const _NEUM_CIF_FACTURA = Object.assign({}, _NEUM_CIF_EMPRESA, {
  'B75555037': 'TYP2014'   // POR.2014 CAPITAL HOLDINGS → stock TYP2014
});

async function handleNeumFacturaFiles(fileList) {
  const files = Array.from(fileList || []);
  if (!files.length) return;
  const key = getKey();
  if (!key) { toast('Falta la clave de IA (arriba, botón Cambiar)', 'err'); return; }
  toast(`📄 Leyendo ${files.length} factura(s) de neumáticos (puede tardar un poco)...`, 'ok');
  let okCount = 0, sumadas = 0, unidades = 0, errores = 0;
  for (const file of files) {
    try {
      const r = await _neumProcesarFacturaSoledad(file, key);
      if (r && r.ok) { okCount++; sumadas += r.lineas; unidades += r.unidades; }
      else errores++;
    } catch (e) {
      console.error('[v107I5] Error procesando factura neumático:', e);
      errores++;
    }
  }
  await loadNeumData();
  let msg = `✓ ${okCount} factura(s) leídas · ${sumadas} línea(s) · +${unidades} neumático(s) sumados al stock`;
  if (errores) msg += ` · ⚠️ ${errores} con error`;
  toast(msg, errores ? 'err' : 'ok');
}

// Procesa UNA factura Soledad: lee con IA, detecta empresa por CIF, sube el
// archivo a Storage y crea un movimiento de COMPRA (+N) por cada línea → SUMA stock.
async function _neumProcesarFacturaSoledad(file, key) {
  const isPdf = (file.type === 'application/pdf') || /\.pdf$/i.test(file.name);
  const mediaType = file.type || (isPdf ? 'application/pdf' : 'image/jpeg');
  const b64 = await new Promise((res, rej) => {
    const fr = new FileReader();
    fr.onload = () => res(String(fr.result).split(',')[1]);
    fr.onerror = () => rej(new Error('No se pudo leer el archivo'));
    fr.readAsDataURL(file);
  });

  const lineas = await callClaudeNeumFactura(b64, mediaType, key, isPdf, null);
  if (!lineas || !lineas.length) {
    toast(`⚠️ ${file.name}: no se detectaron neumáticos comprados en la factura`, 'err');
    return { ok: false, lineas: 0, unidades: 0 };
  }

  // Empresa por CIF (Holding B75555037 / TYP2014 / Portes Import → TYP2014; Hispalis / Transmargaz a lo suyo)
  const cif = String(lineas[0].cif_cliente || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
  let empresa = _NEUM_CIF_FACTURA[cif] || null;
  if (!empresa) {
    const elegida = prompt(`No he podido identificar la empresa por el CIF "${cif || '(vacío)'}" de la factura ${lineas[0].num_factura || ''}.\n\nEscribe a qué empresa va el stock:\n- TYP2014\n- HISPALIS\n- TRANSMARGAZ`, neumEmpresaActiva || 'TYP2014');
    if (!elegida) { toast('Factura cancelada (sin empresa)', 'err'); return { ok: false, lineas: 0, unidades: 0 }; }
    empresa = elegida.trim().toUpperCase();
    if (!['TYP2014', 'HISPALIS', 'TRANSMARGAZ'].includes(empresa)) { toast('Empresa no válida: ' + empresa, 'err'); return { ok: false, lineas: 0, unidades: 0 }; }
  }

  const numFactura = lineas[0].num_factura || '';

  // Anti-duplicado: si ya hay movimientos de compra con esta misma factura, avisar.
  try {
    const { data: yaExiste } = await sb.from('neumaticos_movimientos').select('id').eq('empresa', empresa).eq('tipo', 'compra').ilike('num_factura', numFactura).limit(1);
    if (yaExiste && yaExiste.length) {
      if (!confirm(`La factura ${numFactura} ya parece estar cargada en ${empresa}.\n\n¿Volver a sumarla igualmente? (cuidado: duplicaría stock)`)) {
        return { ok: false, lineas: 0, unidades: 0 };
      }
    }
  } catch (e) { /* si falla la comprobación, seguimos */ }

  // Subir el archivo a Storage (no crítico)
  let fileUrl = null;
  try {
    const ext = (file.name.split('.').pop() || 'bin').toLowerCase();
    const ts = Date.now();
    const filename = `neumaticos/${empresa}/factura-soledad_${ts}.${ext}`;
    const { error: upErr } = await sb.storage.from('documentos').upload(filename, file, { upsert: false, contentType: file.type || 'application/octet-stream' });
    if (!upErr) {
      const { data: urlData } = sb.storage.from('documentos').getPublicUrl(filename);
      if (urlData && urlData.publicUrl) fileUrl = urlData.publicUrl;
    }
  } catch (e) { console.warn('[v107I5] No se pudo subir la factura (no crítico):', e.message); }

  // Crear un movimiento de COMPRA (+N) por cada línea → SUMA stock
  const fecha = _neumFechaISO(lineas[0].fecha);
  let nLineas = 0, nUnidades = 0;
  for (const l of lineas) {
    const cant = Math.abs(parseInt(l.cantidad) || 0);
    if (!cant) continue;
    const medida = String(l.medida || '').trim();
    if (!medida) continue;
    const payload = {
      empresa, tipo: 'compra', fecha,
      marca: String(l.marca || '').trim().toUpperCase() || null,
      modelo: String(l.modelo || '').trim() || null,
      medida, uso: null,
      cantidad: cant,  // compra = entrada (suma)
      proveedor: 'Neumáticos Soledad',
      num_factura: numFactura || null,
      observaciones: `Compra almacén · Factura Soledad ${numFactura} (leída por IA)`.trim(),
      user_id: currentUser.id,
      updated_at: new Date().toISOString()
    };
    if (fileUrl) payload.file_url = fileUrl;
    const { error } = await sb.from('neumaticos_movimientos').insert(payload);
    if (error) { console.error('[v107I5] Error guardando compra:', error); toast('Error guardando compra: ' + error.message, 'err'); }
    else { nLineas++; nUnidades += cant; }
  }
  return { ok: true, lineas: nLineas, unidades: nUnidades };
}

function dropNeumFactura(e) {
  e.preventDefault();
  const target = e.currentTarget;
  _dragCounters.set(target, 0);
  target.classList.remove('ov');
  handleNeumFacturaFiles(e.dataTransfer.files);
}

async function saveNeumModal() {
  // Leer todos los campos
  const tipo = document.getElementById('neumF_tipo').value;
  const empresa = document.getElementById('neumF_empresa').value;
  const fecha = document.getElementById('neumF_fecha').value;
  const marca = (document.getElementById('neumF_marca').value || '').trim();
  const modelo = (document.getElementById('neumF_modelo_txt').value || '').trim();
  const medida = (document.getElementById('neumF_medida').value || '').trim();
  const uso = (document.getElementById('neumF_uso').value || '').trim() || null;
  const cantInput = document.getElementById('neumF_cantidad').value;
  if (!medida) { toast('La medida es obligatoria', 'err'); return; }
  if (!fecha) { toast('La fecha es obligatoria', 'err'); return; }
  if (cantInput === '' || isNaN(parseInt(cantInput))) { toast('La cantidad es obligatoria', 'err'); return; }
  let cantidad = parseInt(cantInput);
  // Convertir el signo según el tipo:
  // - inventario_inicial / compra: SIEMPRE positivo (entrada)
  // - montaje / baja: SIEMPRE negativo (salida)
  // - ajuste: respeta el signo que ponga el usuario
  if (tipo === 'inventario_inicial' || tipo === 'compra') cantidad = Math.abs(cantidad);
  else if (tipo === 'montaje' || tipo === 'baja') cantidad = -Math.abs(cantidad);
  // Campos opcionales según tipo
  const payload = { empresa, tipo, fecha, marca: marca || null, modelo: modelo || null, medida, uso, cantidad };
  if (tipo === 'compra') {
    payload.proveedor = (document.getElementById('neumF_proveedor').value || '').trim() || null;
    payload.num_factura = (document.getElementById('neumF_num_factura').value || '').trim() || null;
    const pu = parseFloat(document.getElementById('neumF_precio_unitario').value);
    const pn = parseFloat(document.getElementById('neumF_precio_neto').value);
    payload.precio_unitario = isNaN(pu) ? null : pu;
    payload.precio_neto_unitario = isNaN(pn) ? null : pn;
    if (!isNaN(pu)) payload.precio_total = pu * Math.abs(cantidad);
  }
  if (tipo === 'montaje' || tipo === 'baja') {
    payload.tractora = (document.getElementById('neumF_tractora').value || '').trim().toUpperCase().replace(/\s+/g,'') || null;
    payload.remolque = (document.getElementById('neumF_remolque').value || '').trim().toUpperCase().replace(/\s+/g,'') || null;
  }
  const obs = document.getElementById('neumF_observaciones');
  if (obs) payload.observaciones = (obs.value || '').trim() || null;
  payload.updated_at = new Date().toISOString();
  // Validación de stock: si es salida, comprobar que hay suficiente
  if (cantidad < 0) {
    const stock = _neumCalcularStock(empresa).find(s => s.medida === medida && s.marca === marca && s.modelo === modelo);
    const stockActual = stock ? stock.stock : 0;
    if (stockActual + cantidad < 0) {
      if (!confirm(`⚠️ Stock insuficiente: solo hay ${stockActual} ud de ${medida} ${modelo}. ¿Guardar de todas formas?`)) return;
    }
  }
  // v107L: subir archivo si el usuario lo seleccionó. Si falla la subida, avisamos
  // PERO guardamos igual el movimiento (no perder dato por un fallo de Storage).
  const fileInput = document.getElementById('neumF_archivo');
  const file = fileInput && fileInput.files && fileInput.files[0];
  let archivoSubido = false;
  if (file) {
    const statusBox = document.getElementById('neumF_archivoStatus');
    if (statusBox) statusBox.textContent = '📤 Subiendo archivo...';
    try {
      const ext = (file.name.split('.').pop() || 'bin').toLowerCase();
      const ts = Date.now();
      const safeTipo = tipo.replace(/_/g, '-');
      const filename = `neumaticos/${empresa}/${safeTipo}_${ts}.${ext}`;
      const { error: upErr } = await sb.storage.from('documentos').upload(filename, file, {
        upsert: false, contentType: file.type || 'application/octet-stream'
      });
      if (upErr) throw upErr;
      const { data: urlData } = sb.storage.from('documentos').getPublicUrl(filename);
      if (urlData && urlData.publicUrl) {
        payload.file_url = urlData.publicUrl;
        archivoSubido = true;
        if (statusBox) statusBox.textContent = '✓ Archivo subido';
      }
    } catch (e) {
      console.error('[saveNeumModal] Error subiendo archivo:', e);
      toast('⚠️ Archivo no subido: ' + (e.message || e) + '. El movimiento sí se guardará.', 'err');
      if (statusBox) statusBox.textContent = '✗ Error: ' + (e.message || e);
    }
  }
  try {
    if (editNeumMovId) {
      // Al editar: solo sobrescribir file_url si el usuario subió un nuevo archivo
      if (!archivoSubido) delete payload.file_url;
      const { error } = await sb.from('neumaticos_movimientos').update(payload).eq('id', editNeumMovId);
      if (error) throw error;
      toast('✓ Movimiento actualizado');
    } else {
      payload.user_id = currentUser.id;
      const { error } = await sb.from('neumaticos_movimientos').insert(payload);
      if (error) throw error;
      toast('✓ Movimiento guardado');
    }
    closeNeumModal();
    await loadNeumData();
  } catch (e) {
    console.error('[saveNeumModal] Error:', e);
    toast('Error guardando: ' + (e.message || JSON.stringify(e)), 'err');
  }
}

async function deleteNeumMov() {
  if (!editNeumMovId) return;
  if (!confirm('¿Eliminar este movimiento?\n\nEsta acción no se puede deshacer.')) return;
  try {
    const { error } = await sb.from('neumaticos_movimientos').delete().eq('id', editNeumMovId);
    if (error) throw error;
    closeNeumModal();
    await loadNeumData();
    toast('✓ Eliminado');
  } catch (e) {
    console.error('[deleteNeumMov] Error:', e);
    toast('Error: ' + (e.message || e), 'err');
  }
}

// ============================================================
// v107M — VACACIONES Y ASUNTOS PROPIOS
// Tablas: trabajadores, vacaciones_periodos, vacaciones_festivos
// 30 días vacaciones + 2 días asuntos propios por trabajador/año
// Cómputo elegible periodo a periodo: naturales o laborables
// ============================================================
const VAC_DIAS_VACACIONES = 30;       // por trabajador y año
const VAC_DIAS_ASUNTOS_PROPIOS = 2;

let vacTrabajadores = [];     // todos los trabajadores (activos + archivados)
let vacPeriodos = [];          // todos los periodos
let vacFestivos = [];          // calendario de festivos
let vacMostrarArchivados = false;
let vacAnioActivo = new Date().getFullYear();
let vacMesCalendario = new Date();    // mes mostrado en el calendario visual
let vacVistaCalendario = 'mes';        // v107X: 'mes' o 'anio'
let vacEmpresaActiva = 'TYP2014';     // v107N: subpestaña activa (TYP2014/HISPALIS/TRANSMARGAZ)
let editTrabId = null;
let editVacPerId = null;

async function loadVacData() {
  if (!window._tieneVac) return;
  try {
    // v107N: ajustar subpestañas visibles según permisos del usuario.
    // window._empresaVac contiene la lista de empresas permitidas separada por comas.
    // NULL = ve las 3. 'TYP2014,HISPALIS' = ve 2. 'TRANSMARGAZ' = ve solo Transmargaz.
    const empresasPermitidas = window._empresaVac
      ? window._empresaVac.split(',').map(s => s.trim())
      : ['TYP2014','HISPALIS','TRANSMARGAZ'];
    ['TYP2014','HISPALIS','TRANSMARGAZ'].forEach(emp => {
      const btn = document.getElementById('vacSub' + emp);
      if (btn) btn.style.display = empresasPermitidas.includes(emp) ? '' : 'none';
    });
    // Si la empresa activa no está permitida, cambiar a la primera permitida
    if (!empresasPermitidas.includes(vacEmpresaActiva)) {
      vacEmpresaActiva = empresasPermitidas[0] || 'TYP2014';
    }
    // Actualizar botón activo visualmente
    empresasPermitidas.forEach(emp => {
      const btn = document.getElementById('vacSub' + emp);
      if (btn) {
        btn.classList.remove('bp','bs');
        btn.classList.add(emp === vacEmpresaActiva ? 'bp' : 'bs');
      }
    });
    const [r1, r2, r3] = await Promise.all([
      sb.from('trabajadores').select('*').order('nombre'),
      sb.from('vacaciones_periodos').select('*').order('fecha_inicio', { ascending: false }),
      sb.from('vacaciones_festivos').select('*').order('fecha')
    ]);
    if (r1.error) throw r1.error;
    if (r2.error) throw r2.error;
    if (r3.error) throw r3.error;
    vacTrabajadores = r1.data || [];
    vacPeriodos = r2.data || [];
    vacFestivos = r3.data || [];
    // Badge: nº de trabajadores activos
    const badge = document.getElementById('tabVacCount');
    if (badge) badge.textContent = vacTrabajadores.filter(t => !t.archivado).length;
    // Inicializar año seleccionado (si no hay selector aún cargado)
    const sel = document.getElementById('vacAnio');
    if (sel) {
      vacAnioActivo = parseInt(sel.value) || new Date().getFullYear();
    }
    renderVac();
  } catch (e) {
    console.error('[loadVacData] Error:', e);
    toast('Error cargando vacaciones: ' + (e.message || e), 'err');
  }
}

// v107N: cambiar de subpestaña de empresa
function switchVacEmpresa(emp) {
  const empresasPermitidas = window._empresaVac
    ? window._empresaVac.split(',').map(s => s.trim())
    : ['TYP2014','HISPALIS','TRANSMARGAZ'];
  if (!empresasPermitidas.includes(emp)) {
    toast('No tienes permiso para esa empresa', 'err');
    return;
  }
  vacEmpresaActiva = emp;
  empresasPermitidas.forEach(e => {
    const btn = document.getElementById('vacSub' + e);
    if (!btn) return;
    btn.classList.remove('bp','bs');
    btn.classList.add(e === emp ? 'bp' : 'bs');
  });
  renderVac();
}

// Helper: comprueba si una fecha (YYYY-MM-DD) es festivo
function _vacEsFestivo(fechaStr) {
  return vacFestivos.some(f => f.fecha === fechaStr);
}

// Helper: cuenta días entre 2 fechas según cómputo (incluye los dos extremos)
function _vacContarDias(inicio, fin, computo) {
  if (!inicio || !fin) return 0;
  const ini = new Date(inicio + 'T00:00:00');
  const en = new Date(fin + 'T00:00:00');
  if (en < ini) return 0;
  let dias = 0;
  const cursor = new Date(ini);
  while (cursor <= en) {
    if (computo === 'naturales') {
      dias++;
    } else {
      // laborables: lunes a viernes y no festivo
      const dia = cursor.getDay();   // 0=domingo, 6=sábado
      const fechaStr = cursor.toISOString().slice(0, 10);
      if (dia !== 0 && dia !== 6 && !_vacEsFestivo(fechaStr)) dias++;
    }
    cursor.setDate(cursor.getDate() + 1);
  }
  return dias;
}

// Helper: calcula los saldos de un trabajador en un año dado
function _vacSaldoTrabajador(trabajadorId, anio) {
  const periodos = vacPeriodos.filter(p => p.trabajador_id === trabajadorId && p.anio === anio);
  // v107Z: solo se cuentan vacaciones / asuntos propios para los saldos del trabajador.
  // Bajas médicas, permisos retribuidos y faltas injustificadas se MUESTRAN en el calendario
  // pero NO consumen días de vacaciones (son categorías informativas, no descuento).
  const usadasVac = periodos.filter(p => p.tipo === 'vacaciones').reduce((s, p) => s + (p.dias_contados || 0), 0);
  const usadasAP = periodos.filter(p => p.tipo === 'asuntos_propios').reduce((s, p) => s + (p.dias_contados || 0), 0);
  return {
    vac_disfrutadas: usadasVac,
    vac_restantes: VAC_DIAS_VACACIONES - usadasVac,
    ap_disfrutados: usadasAP,
    ap_restantes: VAC_DIAS_ASUNTOS_PROPIOS - usadasAP,
    periodos
  };
}

function renderVac() {
  // Actualizar año en título
  vacAnioActivo = parseInt(document.getElementById('vacAnio')?.value) || new Date().getFullYear();
  const tit = document.getElementById('vacAnioTitulo');
  if (tit) tit.textContent = '· ' + vacAnioActivo;
  // v107N: actualizar título de empresa activa
  const titEmp = document.getElementById('vacEmpresaTitulo');
  if (titEmp) titEmp.textContent = vacEmpresaActiva;
  // v107N: filtrar trabajadores por empresa activa + toggle de archivados
  // - Si empresa del trabajador coincide → se ve
  // - Si trabajador tiene empresa NULL → solo se ve en TYP2014 (default para legacy)
  const trabs = vacTrabajadores.filter(t => {
    const empMatch = t.empresa === vacEmpresaActiva || (!t.empresa && vacEmpresaActiva === 'TYP2014');
    if (!empMatch) return false;
    return vacMostrarArchivados ? t.archivado : !t.archivado;
  });
  const box = document.getElementById('vacTablaBox');
  if (!trabs.length) {
    const msg = vacMostrarArchivados
      ? `No hay trabajadores archivados en ${vacEmpresaActiva}.`
      : `No hay trabajadores activos en <strong>${vacEmpresaActiva}</strong>. Pulsa <strong>➕ Añadir trabajador</strong> para empezar.`;
    box.innerHTML = `<div style="color:var(--mu);font-family:var(--mn);font-size:11px;padding:18px;text-align:center">${msg}</div>`;
  } else {
    box.innerHTML = `
      <table style="width:100%;border-collapse:collapse;font-family:var(--mn);font-size:11px">
        <thead>
          <tr style="text-align:left;border-bottom:1px solid var(--bd);color:var(--mu)">
            <th style="padding:8px">NOMBRE</th>
            <th style="padding:8px">EMPRESA</th>
            <th style="padding:8px">🏖️ VACACIONES (uso / total)</th>
            <th style="padding:8px">🎯 ASUNTOS PROPIOS</th>
            <th style="padding:8px">PERIODOS</th>
            <th style="padding:8px"></th>
          </tr>
        </thead>
        <tbody>
        ${trabs.map(t => {
          const s = _vacSaldoTrabajador(t.id, vacAnioActivo);
          const pctVac = Math.min(100, (s.vac_disfrutadas / VAC_DIAS_VACACIONES) * 100);
          const colorVac = s.vac_restantes <= 5 ? 'var(--er)' : (s.vac_restantes <= 10 ? '#ffb84d' : 'var(--ok)');
          const archivadoBadge = t.archivado ? `<span style="background:#888;color:#000;font-size:9px;padding:2px 6px;border-radius:3px;margin-left:6px">ARCHIVADO</span>` : '';
          return `<tr style="border-bottom:1px solid var(--bd)">
            <td style="padding:8px;color:var(--ac)">${esc(t.nombre)}${archivadoBadge}</td>
            <td style="padding:8px;color:var(--mu)">${esc(t.empresa || '—')}</td>
            <td style="padding:8px">
              <div style="display:flex;align-items:center;gap:8px">
                <div style="flex:1;height:8px;background:rgba(255,255,255,.08);border-radius:4px;overflow:hidden;min-width:80px">
                  <div style="width:${pctVac}%;height:100%;background:${colorVac};transition:width .3s"></div>
                </div>
                <span style="color:${colorVac};font-weight:bold;white-space:nowrap">${s.vac_disfrutadas}/${VAC_DIAS_VACACIONES}</span>
                <span style="color:var(--mu);white-space:nowrap">(${s.vac_restantes} rest.)</span>
              </div>
            </td>
            <td style="padding:8px">${s.ap_disfrutados}/${VAC_DIAS_ASUNTOS_PROPIOS} <span style="color:var(--mu)">(${s.ap_restantes} rest.)</span></td>
            <td style="padding:8px">${s.periodos.length}</td>
            <td style="padding:8px;text-align:right">
              <button class="btn bs" style="font-size:9px;padding:4px 8px;margin-right:4px" onclick="openVacTrabajadorDetalle('${t.id}')">Ver periodos</button>
              <button class="btn bs" style="font-size:9px;padding:4px 8px" onclick="openTrabajadorModal('${t.id}')">Editar</button>
            </td>
          </tr>`;
        }).join('')}
        </tbody>
      </table>`;
  }
  // Calendario
  _vacRenderCalendario();
}

// === Calendario visual de vacaciones ===
function vacCambiarMes(delta) {
  vacMesCalendario.setMonth(vacMesCalendario.getMonth() + delta);
  _vacRenderCalendario();
}

// v107X: alternar entre vista mensual y anual (12 mini-calendarios)
// v107AA: añadida vista 3 meses (anterior + actual + siguiente)
function vacCambiarVista(vista) {
  vacVistaCalendario = vista;
  const btnMes = document.getElementById('vacBtnVistaMes');
  const btn3m = document.getElementById('vacBtnVista3m');
  const btnAnio = document.getElementById('vacBtnVistaAnio');
  const nav = document.getElementById('vacNavMes');
  const tit = document.getElementById('vacCalTit');
  if (btnMes && btnAnio) {
    btnMes.classList.toggle('bp', vista === 'mes');
    btnMes.classList.toggle('bs', vista !== 'mes');
    if (btn3m) {
      btn3m.classList.toggle('bp', vista === '3meses');
      btn3m.classList.toggle('bs', vista !== '3meses');
    }
    btnAnio.classList.toggle('bp', vista === 'anio');
    btnAnio.classList.toggle('bs', vista !== 'anio');
  }
  // Navegación de mes visible en vistas Mes y 3 meses (no en Año)
  if (nav) nav.style.display = vista === 'anio' ? 'none' : 'flex';
  // Título adaptado a cada vista
  if (tit) {
    const titulos = { 'mes': 'CALENDARIO MENSUAL', '3meses': 'CALENDARIO 3 MESES', 'anio': 'CALENDARIO ANUAL' };
    tit.textContent = titulos[vista] || 'CALENDARIO';
  }
  _vacRenderCalendario();
}

function _vacRenderCalendario() {
  if (vacVistaCalendario === 'anio') {
    _vacRenderCalendarioAnio();
  } else if (vacVistaCalendario === '3meses') {
    _vacRenderCalendario3Meses();
  } else {
    _vacRenderCalendarioMes();
  }
}

function _vacRenderCalendarioMes() {
  const mes = vacMesCalendario.getMonth();
  const anio = vacMesCalendario.getFullYear();
  const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
  const titulo = document.getElementById('vacMesTitulo');
  if (titulo) titulo.textContent = `${meses[mes]} ${anio}`;
  // Días del mes
  const diasMes = new Date(anio, mes + 1, 0).getDate();
  // Primer día de la semana (lunes=1, domingo=0). Ajustar para empezar en lunes.
  const primerDia = new Date(anio, mes, 1).getDay();
  const offset = primerDia === 0 ? 6 : primerDia - 1;
  // Construir array de días con info
  const dias = [];
  for (let i = 0; i < offset; i++) dias.push(null);
  for (let d = 1; d <= diasMes; d++) {
    const fechaStr = `${anio}-${String(mes+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
    const fechaObj = new Date(fechaStr + 'T00:00:00');
    const dow = fechaObj.getDay();
    const esFinde = dow === 0 || dow === 6;
    const esFestivo = _vacEsFestivo(fechaStr);
    // Periodos activos este día (v107N: filtrados por empresa activa también)
    const periodosDia = vacPeriodos.filter(p => {
      if (p.fecha_inicio > fechaStr || p.fecha_fin < fechaStr) return false;
      // Solo periodos cuyo trabajador pertenece a la empresa activa
      const t = vacTrabajadores.find(x => x.id === p.trabajador_id);
      if (!t) return false;
      return t.empresa === vacEmpresaActiva || (!t.empresa && vacEmpresaActiva === 'TYP2014');
    });
    dias.push({ d, fechaStr, esFinde, esFestivo, periodosDia });
  }
  // Render
  const box = document.getElementById('vacCalendarioBox');
  if (!box) return;
  const cabecera = ['L','M','X','J','V','S','D'].map(d =>
    `<div style="text-align:center;font-family:var(--mn);font-size:10px;color:var(--mu);padding:6px">${d}</div>`
  ).join('');
  const celdas = dias.map(c => {
    if (!c) return `<div style="min-height:60px"></div>`;
    const bg = c.esFestivo ? 'rgba(255,80,80,.08)' : (c.esFinde ? 'rgba(255,255,255,.03)' : 'rgba(255,255,255,.02)');
    const colorDia = c.esFestivo ? 'var(--er)' : (c.esFinde ? 'var(--mu)' : 'var(--fg)');
    const trabajadoresHoy = c.periodosDia.slice(0, 3).map(p => {
      const t = vacTrabajadores.find(x => x.id === p.trabajador_id);
      const nombreCorto = (t?.nombre || '?').split(' ')[0];
      // v107Z: cada tipo tiene su color
      const colorMap = {
        'vacaciones': '#34d399',           // verde
        'asuntos_propios': '#a78bfa',      // morado
        'baja_medica': '#fbbf24',          // amarillo
        'permiso_retribuido': '#60a5fa',   // azul
        'falta_injustificada': '#ef4444'   // rojo
      };
      const labelMap = {
        'vacaciones': 'Vac', 'asuntos_propios': 'AP',
        'baja_medica': 'Baja', 'permiso_retribuido': 'Permiso', 'falta_injustificada': 'Falta'
      };
      const color = colorMap[p.tipo] || '#34d399';
      return `<div style="font-size:9px;background:${color};color:#000;padding:1px 4px;border-radius:3px;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;cursor:pointer" onclick="openVacPeriodoModal('${p.id}')" title="${esc(t?.nombre || '')} — ${labelMap[p.tipo] || p.tipo}">${esc(nombreCorto)}</div>`;
    }).join('');
    const masTexto = c.periodosDia.length > 3
      ? `<div style="font-size:9px;color:var(--mu);margin-top:2px">+${c.periodosDia.length - 3} más</div>` : '';
    return `<div style="min-height:60px;border:1px solid var(--bd);border-radius:4px;padding:4px;background:${bg}">
      <div style="font-family:var(--mn);font-size:11px;color:${colorDia}">${c.d}</div>
      ${trabajadoresHoy}${masTexto}
    </div>`;
  }).join('');
  box.innerHTML = `
    <div style="display:grid;grid-template-columns:repeat(7,1fr);gap:4px;margin-bottom:4px">${cabecera}</div>
    <div style="display:grid;grid-template-columns:repeat(7,1fr);gap:4px">${celdas}</div>
    <div style="margin-top:10px;display:flex;gap:14px;flex-wrap:wrap;font-family:var(--mn);font-size:10px;color:var(--mu)">
      <span><span style="display:inline-block;width:10px;height:10px;background:#34d399;border-radius:2px;vertical-align:middle"></span> Vacaciones</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#a78bfa;border-radius:2px;vertical-align:middle"></span> Asuntos propios</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#fbbf24;border-radius:2px;vertical-align:middle"></span> Baja médica</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#60a5fa;border-radius:2px;vertical-align:middle"></span> Permiso retribuido</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#ef4444;border-radius:2px;vertical-align:middle"></span> Falta injustificada</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:rgba(255,80,80,.5);border-radius:2px;vertical-align:middle"></span> Festivo</span>
    </div>`;
}

// v107AA: vista 3 MESES. Muestra el mes anterior + el actual + el siguiente lado a lado.
// Tamaño intermedio entre vista Mes (1 grande) y vista Año (12 mini). Ideal para
// planificar verano (jun-jul-ago) o Navidad (dic-ene-feb) con detalle medio.
// Usa el botón ◀▶ para navegar moviendo el "centro" del trío de meses.
function _vacRenderCalendario3Meses() {
  const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
  const hoy = new Date();
  const hoyStr = `${hoy.getFullYear()}-${String(hoy.getMonth()+1).padStart(2,'0')}-${String(hoy.getDate()).padStart(2,'0')}`;
  // Centro = vacMesCalendario; lados = mes anterior y siguiente
  const centroMes = vacMesCalendario.getMonth();
  const centroAnio = vacMesCalendario.getFullYear();
  const titulo = document.getElementById('vacMesTitulo');
  if (titulo) {
    const antMes = new Date(centroAnio, centroMes - 1, 1);
    const sigMes = new Date(centroAnio, centroMes + 1, 1);
    titulo.textContent = `${meses[antMes.getMonth()].slice(0,3)} · ${meses[centroMes]} ${centroAnio} · ${meses[sigMes.getMonth()].slice(0,3)}`;
  }
  // Pre-filtrar periodos por empresa activa
  const periodosEmpresa = vacPeriodos.filter(p => {
    const t = vacTrabajadores.find(x => x.id === p.trabajador_id);
    if (!t) return false;
    return t.empresa === vacEmpresaActiva || (!t.empresa && vacEmpresaActiva === 'TYP2014');
  });
  // Colores por tipo (mismo esquema que en mes y año)
  const tipoColor = {
    'vacaciones': '#34d399',
    'asuntos_propios': '#a78bfa',
    'baja_medica': '#fbbf24',
    'permiso_retribuido': '#60a5fa',
    'falta_injustificada': '#ef4444'
  };
  const tipoLabel = {
    'vacaciones': 'Vac', 'asuntos_propios': 'AP',
    'baja_medica': 'Baja', 'permiso_retribuido': 'Permiso', 'falta_injustificada': 'Falta'
  };
  // Renderizar cada uno de los 3 meses (offset: -1, 0, +1)
  const mesesHTML = [];
  for (let off = -1; off <= 1; off++) {
    const fecha = new Date(centroAnio, centroMes + off, 1);
    const m = fecha.getMonth();
    const a = fecha.getFullYear();
    const diasMes = new Date(a, m + 1, 0).getDate();
    const primerDia = fecha.getDay();
    const offset = primerDia === 0 ? 6 : primerDia - 1;
    const cabecera = ['L','M','X','J','V','S','D'].map(d =>
      `<div style="text-align:center;font-family:var(--mn);font-size:10px;color:var(--mu);padding:3px 0">${d}</div>`
    ).join('');
    const celdas = [];
    for (let i = 0; i < offset; i++) celdas.push('<div></div>');
    for (let d = 1; d <= diasMes; d++) {
      const fechaStr = `${a}-${String(m+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
      const fechaObj = new Date(fechaStr + 'T00:00:00');
      const dow = fechaObj.getDay();
      const esFinde = dow === 0 || dow === 6;
      const esFestivo = _vacEsFestivo(fechaStr);
      const esHoy = fechaStr === hoyStr;
      const periodosDia = periodosEmpresa.filter(p => p.fecha_inicio <= fechaStr && p.fecha_fin >= fechaStr);
      // Color de fondo según periodo(s)
      let bg = 'transparent';
      if (periodosDia.length === 1) bg = tipoColor[periodosDia[0].tipo] || '#34d399';
      else if (periodosDia.length > 1) {
        const c1 = tipoColor[periodosDia[0].tipo] || '#34d399';
        const c2 = tipoColor[periodosDia[1].tipo] || '#a78bfa';
        bg = `linear-gradient(135deg,${c1} 50%,${c2} 50%)`;
      } else if (esFestivo) bg = 'rgba(255,80,80,.18)';
      else if (esFinde) bg = 'rgba(255,255,255,.04)';
      const color = periodosDia.length ? '#000' : (esFestivo ? 'var(--er)' : (esFinde ? 'var(--mu)' : 'var(--fg)'));
      const borde = esHoy ? 'border:1.5px solid var(--ac)' : '';
      // En vista 3 meses, mostramos nombre corto del trabajador en pequeño debajo del día
      const nombreCorto = periodosDia.length === 1
        ? (vacTrabajadores.find(x => x.id === periodosDia[0].trabajador_id)?.nombre || '').split(' ')[0]
        : (periodosDia.length > 1 ? `+${periodosDia.length}` : '');
      const tooltip = periodosDia.length
        ? periodosDia.map(p => {
            const t = vacTrabajadores.find(x => x.id === p.trabajador_id);
            return `${t?.nombre || '?'} (${tipoLabel[p.tipo] || p.tipo})`;
          }).join(', ')
        : (esFestivo ? 'Festivo' : '');
      const onclick = periodosDia.length === 1
        ? `onclick="openVacPeriodoModal('${periodosDia[0].id}')" style="cursor:pointer;${borde ? borde+';' : ''}background:${bg}"`
        : `style="${borde ? borde+';' : ''}background:${bg}"`;
      celdas.push(`<div title="${esc(tooltip)}" ${onclick} style="min-height:38px;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:2px;border-radius:3px;color:${color}">
        <div style="font-family:var(--mn);font-size:11px;line-height:1">${d}</div>
        ${nombreCorto ? `<div style="font-size:8px;line-height:1;margin-top:1px;max-width:100%;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(nombreCorto)}</div>` : ''}
      </div>`);
    }
    mesesHTML.push(`
      <div style="border:1px solid var(--bd);border-radius:6px;padding:10px;background:rgba(255,255,255,.01)">
        <div style="font-family:var(--mn);font-size:13px;color:var(--ac);text-align:center;margin-bottom:8px">${meses[m]} ${a}</div>
        <div style="display:grid;grid-template-columns:repeat(7,1fr);gap:3px;margin-bottom:3px">${cabecera}</div>
        <div style="display:grid;grid-template-columns:repeat(7,1fr);gap:3px">${celdas.join('')}</div>
      </div>
    `);
  }
  const box = document.getElementById('vacCalendarioBox');
  if (!box) return;
  box.innerHTML = `
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:14px">
      ${mesesHTML.join('')}
    </div>
    <div style="margin-top:14px;display:flex;gap:14px;flex-wrap:wrap;font-family:var(--mn);font-size:10px;color:var(--mu)">
      <span><span style="display:inline-block;width:10px;height:10px;background:#34d399;border-radius:2px;vertical-align:middle"></span> Vacaciones</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#a78bfa;border-radius:2px;vertical-align:middle"></span> Asuntos propios</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#fbbf24;border-radius:2px;vertical-align:middle"></span> Baja médica</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#60a5fa;border-radius:2px;vertical-align:middle"></span> Permiso retribuido</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#ef4444;border-radius:2px;vertical-align:middle"></span> Falta injustificada</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:rgba(255,80,80,.18);border-radius:2px;vertical-align:middle"></span> Festivo</span>
      <span><span style="display:inline-block;width:10px;height:10px;border:1.5px solid var(--ac);border-radius:2px;vertical-align:middle"></span> Hoy</span>
    </div>`;
}

// v107X: vista AÑO COMPLETO. 12 mini-calendarios para previsión visual rápida.
// Cada día tiene un fondo coloreado según haya vacaciones/asuntos propios/festivo.
// Solo muestra los datos del año seleccionado en vacAnioActivo y de la empresa activa.
function _vacRenderCalendarioAnio() {
  const anio = vacAnioActivo || new Date().getFullYear();
  const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
  const hoy = new Date();
  const hoyStr = `${hoy.getFullYear()}-${String(hoy.getMonth()+1).padStart(2,'0')}-${String(hoy.getDate()).padStart(2,'0')}`;
  // Pre-calcular periodos válidos para esta empresa
  const periodosEmpresa = vacPeriodos.filter(p => {
    const t = vacTrabajadores.find(x => x.id === p.trabajador_id);
    if (!t) return false;
    return t.empresa === vacEmpresaActiva || (!t.empresa && vacEmpresaActiva === 'TYP2014');
  });
  // Renderizar cada mes como mini-card
  const mesesHTML = [];
  for (let m = 0; m < 12; m++) {
    const diasMes = new Date(anio, m + 1, 0).getDate();
    const primerDia = new Date(anio, m, 1).getDay();
    const offset = primerDia === 0 ? 6 : primerDia - 1;
    const cabeceraMini = ['L','M','X','J','V','S','D'].map(d =>
      `<div style="text-align:center;font-family:var(--mn);font-size:8px;color:var(--mu);padding:1px 0">${d}</div>`
    ).join('');
    const celdasMini = [];
    for (let i = 0; i < offset; i++) celdasMini.push('<div></div>');
    for (let d = 1; d <= diasMes; d++) {
      const fechaStr = `${anio}-${String(m+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
      const fechaObj = new Date(fechaStr + 'T00:00:00');
      const dow = fechaObj.getDay();
      const esFinde = dow === 0 || dow === 6;
      const esFestivo = _vacEsFestivo(fechaStr);
      const esHoy = fechaStr === hoyStr;
      // ¿Hay periodos activos este día?
      const periodosDia = periodosEmpresa.filter(p => p.fecha_inicio <= fechaStr && p.fecha_fin >= fechaStr);
      // v107Z: colores por tipo (todos los nuevos)
      const tipoColor = {
        'vacaciones': '#34d399',
        'asuntos_propios': '#a78bfa',
        'baja_medica': '#fbbf24',
        'permiso_retribuido': '#60a5fa',
        'falta_injustificada': '#ef4444'
      };
      let bg = 'transparent';
      if (periodosDia.length === 1) {
        bg = tipoColor[periodosDia[0].tipo] || '#34d399';
      } else if (periodosDia.length > 1) {
        // Múltiples tipos: gradiente con los 2 primeros
        const c1 = tipoColor[periodosDia[0].tipo] || '#34d399';
        const c2 = tipoColor[periodosDia[1].tipo] || '#a78bfa';
        bg = `linear-gradient(135deg,${c1} 50%,${c2} 50%)`;
      } else if (esFestivo) bg = 'rgba(255,80,80,.3)';
      else if (esFinde) bg = 'rgba(255,255,255,.04)';
      let color = periodosDia.length ? '#000' : (esFestivo ? 'var(--er)' : (esFinde ? 'var(--mu)' : 'var(--fg)'));
      const borde = esHoy ? 'border:1.5px solid var(--ac)' : '';
      const tooltip = periodosDia.length
        ? periodosDia.map(p => {
            const t = vacTrabajadores.find(x => x.id === p.trabajador_id);
            const labels = {'vacaciones':'Vac','asuntos_propios':'AP','baja_medica':'Baja','permiso_retribuido':'Permiso','falta_injustificada':'Falta'};
            return `${t?.nombre || '?'} (${labels[p.tipo] || p.tipo})`;
          }).join(', ')
        : (esFestivo ? 'Festivo' : '');
      // Click para abrir periodo si hay uno
      const onclick = periodosDia.length === 1
        ? `onclick="openVacPeriodoModal('${periodosDia[0].id}')" style="cursor:pointer"` : '';
      celdasMini.push(`<div title="${esc(tooltip)}" ${onclick} style="aspect-ratio:1;display:flex;align-items:center;justify-content:center;font-family:var(--mn);font-size:9px;color:${color};background:${bg};border-radius:2px;${borde}">${d}</div>`);
    }
    mesesHTML.push(`
      <div style="border:1px solid var(--bd);border-radius:6px;padding:8px;background:rgba(255,255,255,.01)">
        <div style="font-family:var(--mn);font-size:11px;color:var(--ac);text-align:center;margin-bottom:6px">${meses[m]} ${anio}</div>
        <div style="display:grid;grid-template-columns:repeat(7,1fr);gap:2px;margin-bottom:2px">${cabeceraMini}</div>
        <div style="display:grid;grid-template-columns:repeat(7,1fr);gap:2px">${celdasMini.join('')}</div>
      </div>
    `);
  }
  const box = document.getElementById('vacCalendarioBox');
  if (!box) return;
  box.innerHTML = `
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px">
      ${mesesHTML.join('')}
    </div>
    <div style="margin-top:14px;display:flex;gap:14px;flex-wrap:wrap;font-family:var(--mn);font-size:10px;color:var(--mu)">
      <span><span style="display:inline-block;width:10px;height:10px;background:#34d399;border-radius:2px;vertical-align:middle"></span> Vacaciones</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#a78bfa;border-radius:2px;vertical-align:middle"></span> Asuntos propios</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#fbbf24;border-radius:2px;vertical-align:middle"></span> Baja médica</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#60a5fa;border-radius:2px;vertical-align:middle"></span> Permiso retribuido</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:#ef4444;border-radius:2px;vertical-align:middle"></span> Falta injustificada</span>
      <span><span style="display:inline-block;width:10px;height:10px;background:rgba(255,80,80,.3);border-radius:2px;vertical-align:middle"></span> Festivo</span>
      <span><span style="display:inline-block;width:10px;height:10px;border:1.5px solid var(--ac);border-radius:2px;vertical-align:middle"></span> Hoy</span>
    </div>`;
}

function vacToggleArchivados() {
  vacMostrarArchivados = !vacMostrarArchivados;
  const btn = document.getElementById('vacBtnArchivados');
  if (btn) btn.textContent = vacMostrarArchivados ? '👤 Ver activos' : '👁️ Ver archivados';
  renderVac();
}

// === Modal trabajador ===
function openTrabajadorModal(id) {
  editTrabId = id || null;
  const t = id ? vacTrabajadores.find(x => x.id === id) : null;
  document.getElementById('trabModalTitulo').textContent = t ? 'EDITAR TRABAJADOR' : 'NUEVO TRABAJADOR';
  const v = (k) => t ? esc(t[k] != null ? String(t[k]) : '') : '';
  document.getElementById('trabModalFields').innerHTML = `
    <div class="fg full" style="margin-bottom:10px"><label class="fl">Nombre completo</label>
      <input class="fi" id="trabF_nombre" value="${v('nombre')}" placeholder="Carlos Calderón">
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">
      <div class="fg"><label class="fl">DNI/NIE</label><input class="fi" id="trabF_dni" value="${v('dni')}" placeholder="12345678X"></div>
      <div class="fg"><label class="fl">Empresa</label>
        <select class="fi" id="trabF_empresa">
          <option value="">—</option>
          <option value="TYP2014"${(t?.empresa==='TYP2014') || (!t && vacEmpresaActiva==='TYP2014')?' selected':''}>TYP2014</option>
          <option value="HISPALIS"${(t?.empresa==='HISPALIS') || (!t && vacEmpresaActiva==='HISPALIS')?' selected':''}>HISPALIS</option>
          <option value="TRANSMARGAZ"${(t?.empresa==='TRANSMARGAZ') || (!t && vacEmpresaActiva==='TRANSMARGAZ')?' selected':''}>TRANSMARGAZ</option>
        </select>
      </div>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">
      <div class="fg"><label class="fl">Rol/Puesto</label><input class="fi" id="trabF_rol" value="${v('rol')}" placeholder="Conductor"></div>
      <div class="fg"><label class="fl">Fecha alta</label><input class="fi" type="date" id="trabF_alta" value="${t?.fecha_alta || ''}"></div>
    </div>
    <div class="fg full" style="margin-bottom:10px"><label class="fl">Notas</label>
      <input class="fi" id="trabF_notas" value="${v('notas')}" placeholder="opcional">
    </div>`;
  document.getElementById('btnDelTrab').style.display = (t && !t.archivado) ? '' : 'none';
  document.getElementById('btnReactTrab').style.display = (t && t.archivado) ? '' : 'none';
  document.getElementById('ovTrab').classList.add('open');
}

function closeTrabModal() {
  document.getElementById('ovTrab').classList.remove('open');
  editTrabId = null;
}

async function saveTrabModal() {
  const nombre = (document.getElementById('trabF_nombre').value || '').trim();
  if (!nombre) { toast('El nombre es obligatorio', 'err'); return; }
  const payload = {
    nombre,
    dni: (document.getElementById('trabF_dni').value || '').trim() || null,
    empresa: document.getElementById('trabF_empresa').value || null,
    rol: (document.getElementById('trabF_rol').value || '').trim() || null,
    fecha_alta: document.getElementById('trabF_alta').value || null,
    notas: (document.getElementById('trabF_notas').value || '').trim() || null,
    updated_at: new Date().toISOString()
  };
  try {
    if (editTrabId) {
      const { error } = await sb.from('trabajadores').update(payload).eq('id', editTrabId);
      if (error) throw error;
      toast('✓ Trabajador actualizado');
    } else {
      const { error } = await sb.from('trabajadores').insert(payload);
      if (error) throw error;
      toast('✓ Trabajador creado');
    }
    closeTrabModal();
    await loadVacData();
  } catch (e) {
    console.error('[saveTrabModal] Error:', e);
    toast('Error: ' + (e.message || JSON.stringify(e)), 'err');
  }
}

async function archivarTrabajador() {
  if (!editTrabId) return;
  const t = vacTrabajadores.find(x => x.id === editTrabId);
  const motivo = prompt(`¿Motivo de baja para ${t?.nombre}?\n(voluntaria / despido / jubilacion / otro)`, 'voluntaria');
  if (motivo === null) return;
  try {
    const { error } = await sb.from('trabajadores').update({
      archivado: true,
      fecha_baja: new Date().toISOString().slice(0, 10),
      motivo_baja: motivo || null,
      updated_at: new Date().toISOString()
    }).eq('id', editTrabId);
    if (error) throw error;
    closeTrabModal();
    await loadVacData();
    toast('✓ Trabajador archivado (su historial se conserva)');
  } catch (e) {
    console.error('[archivarTrabajador] Error:', e);
    toast('Error: ' + (e.message || e), 'err');
  }
}

async function reactivarTrabajador() {
  if (!editTrabId) return;
  if (!confirm('¿Reactivar este trabajador?')) return;
  try {
    const { error } = await sb.from('trabajadores').update({
      archivado: false,
      fecha_baja: null,
      motivo_baja: null,
      updated_at: new Date().toISOString()
    }).eq('id', editTrabId);
    if (error) throw error;
    closeTrabModal();
    await loadVacData();
    toast('✓ Trabajador reactivado');
  } catch (e) {
    console.error('[reactivarTrabajador] Error:', e);
    toast('Error: ' + (e.message || e), 'err');
  }
}

// === Modal periodo de vacaciones ===
function openVacPeriodoModal(periodoId, trabajadorIdPrefill) {
  editVacPerId = periodoId || null;
  const p = periodoId ? vacPeriodos.find(x => x.id === periodoId) : null;
  document.getElementById('vacPerModalTitulo').textContent = p ? 'EDITAR PERIODO' : 'NUEVO PERIODO';
  // Trabajadores para el dropdown (v107N: solo de la empresa activa)
  // Si editamos, incluir el trabajador del periodo aunque no sea de la empresa activa.
  // Si está archivado, incluirlo solo si es el del periodo editado.
  const trabsOpciones = vacTrabajadores
    .filter(t => {
      // En edición: siempre incluir el trabajador del periodo
      if (p && t.id === p.trabajador_id) return true;
      // Excluir archivados
      if (t.archivado) return false;
      // Filtrar por empresa activa (con fallback a TYP2014 para trabajadores sin empresa)
      return t.empresa === vacEmpresaActiva || (!t.empresa && vacEmpresaActiva === 'TYP2014');
    })
    .map(t => {
      const sel = (p && p.trabajador_id === t.id) || (trabajadorIdPrefill === t.id) ? ' selected' : '';
      return `<option value="${t.id}"${sel}>${esc(t.nombre)}${t.archivado ? ' (archivado)' : ''}</option>`;
    }).join('');
  const v = (k) => p ? esc(p[k] != null ? String(p[k]) : '') : '';
  const hoy = new Date().toISOString().slice(0, 10);
  document.getElementById('vacPerModalFields').innerHTML = `
    <div class="fg full" style="margin-bottom:10px"><label class="fl">Trabajador</label>
      <select class="fi" id="vacPerF_trab" ${p ? 'disabled' : ''}>
        <option value="">— Elige trabajador —</option>
        ${trabsOpciones}
      </select>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">
      <div class="fg"><label class="fl">Tipo</label>
        <select class="fi" id="vacPerF_tipo" onchange="_vacPerRecalcular()">
          <option value="vacaciones"${p?.tipo==='vacaciones'?' selected':''}>🏖️ Vacaciones</option>
          <option value="asuntos_propios"${p?.tipo==='asuntos_propios'?' selected':''}>🎯 Asuntos propios</option>
          <option value="baja_medica"${p?.tipo==='baja_medica'?' selected':''}>🏥 Baja médica</option>
          <option value="permiso_retribuido"${p?.tipo==='permiso_retribuido'?' selected':''}>📋 Permiso retribuido</option>
          <option value="falta_injustificada"${p?.tipo==='falta_injustificada'?' selected':''}>❌ Falta injustificada</option>
        </select>
      </div>
      <div class="fg"><label class="fl">Cómputo</label>
        <select class="fi" id="vacPerF_computo" onchange="_vacPerRecalcular()">
          <option value="naturales"${p?.computo==='naturales'?' selected':''}>⚖️ Días naturales</option>
          <option value="laborables"${p?.computo==='laborables'?' selected':''}>💼 Días laborables</option>
        </select>
      </div>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">
      <div class="fg"><label class="fl">Fecha inicio</label>
        <input class="fi" type="date" id="vacPerF_inicio" value="${p?.fecha_inicio || hoy}" onchange="_vacPerRecalcular()">
      </div>
      <div class="fg"><label class="fl">Fecha fin</label>
        <input class="fi" type="date" id="vacPerF_fin" value="${p?.fecha_fin || hoy}" onchange="_vacPerRecalcular()">
      </div>
    </div>
    <div class="fg full" style="margin-bottom:10px;padding:10px;border:1px dashed var(--bd);border-radius:6px;background:rgba(255,255,255,.02)">
      <div style="font-family:var(--mn);font-size:11px;color:var(--mu)">Días que descuenta:</div>
      <div style="font-family:var(--mn);font-size:18px;color:var(--ac);font-weight:bold;margin-top:4px" id="vacPerF_calculo">—</div>
    </div>
    <div class="fg full" style="margin-bottom:10px"><label class="fl">Observaciones</label>
      <input class="fi" id="vacPerF_observaciones" value="${v('observaciones')}" placeholder="opcional">
    </div>`;
  document.getElementById('btnDelVacPer').style.display = p ? '' : 'none';
  document.getElementById('ovVacPer').classList.add('open');
  _vacPerRecalcular();
}

// Recalcula los días contados en el modal en tiempo real
function _vacPerRecalcular() {
  const inicio = document.getElementById('vacPerF_inicio')?.value;
  const fin = document.getElementById('vacPerF_fin')?.value;
  const computo = document.getElementById('vacPerF_computo')?.value;
  const calc = document.getElementById('vacPerF_calculo');
  if (!inicio || !fin || !calc) { if (calc) calc.textContent = '—'; return; }
  if (new Date(fin) < new Date(inicio)) {
    calc.textContent = '⚠️ La fecha fin no puede ser anterior';
    calc.style.color = 'var(--er)';
    return;
  }
  const dias = _vacContarDias(inicio, fin, computo);
  calc.textContent = `${dias} día${dias===1?'':'s'} (${computo})`;
  calc.style.color = 'var(--ac)';
}

function closeVacPerModal() {
  document.getElementById('ovVacPer').classList.remove('open');
  editVacPerId = null;
}

async function saveVacPerModal() {
  const trabajador_id = document.getElementById('vacPerF_trab').value;
  if (!trabajador_id) { toast('Elige un trabajador', 'err'); return; }
  const tipo = document.getElementById('vacPerF_tipo').value;
  const computo = document.getElementById('vacPerF_computo').value;
  const fecha_inicio = document.getElementById('vacPerF_inicio').value;
  const fecha_fin = document.getElementById('vacPerF_fin').value;
  if (!fecha_inicio || !fecha_fin) { toast('Fechas obligatorias', 'err'); return; }
  if (new Date(fecha_fin) < new Date(fecha_inicio)) { toast('La fecha fin no puede ser anterior', 'err'); return; }
  const dias_contados = _vacContarDias(fecha_inicio, fecha_fin, computo);
  if (dias_contados <= 0) { toast('El periodo cuenta 0 días — revisa fechas/cómputo', 'err'); return; }
  const anio = parseInt(fecha_inicio.slice(0, 4));
  const observaciones = (document.getElementById('vacPerF_observaciones').value || '').trim() || null;
  // Validar saldo disponible (avisar pero no bloquear).
  // v107AB: solo validar contra saldo si el tipo es vacaciones o asuntos_propios.
  // Los tipos informativos (baja médica, permiso retribuido, falta injustificada) NO
  // consumen saldo de los 30+2 días, así que no tiene sentido avisar de saldo agotado.
  if (tipo === 'vacaciones' || tipo === 'asuntos_propios') {
    const saldo = _vacSaldoTrabajador(trabajador_id, anio);
    const yaEnEste = editVacPerId
      ? (vacPeriodos.find(p => p.id === editVacPerId)?.dias_contados || 0)
      : 0;
    const restantes = tipo === 'vacaciones'
      ? saldo.vac_restantes + yaEnEste
      : saldo.ap_restantes + yaEnEste;
    if (dias_contados > restantes) {
      const t = vacTrabajadores.find(x => x.id === trabajador_id);
      if (!confirm(`⚠️ ${t?.nombre || ''} solo tiene ${restantes} día(s) ${tipo === 'vacaciones' ? 'de vacaciones' : 'de asuntos propios'} restantes en ${anio}. Vas a registrar ${dias_contados}. ¿Continuar?`)) return;
    }
  }
  const payload = { trabajador_id, tipo, computo, fecha_inicio, fecha_fin, dias_contados, anio, observaciones, updated_at: new Date().toISOString() };
  try {
    if (editVacPerId) {
      const { error } = await sb.from('vacaciones_periodos').update(payload).eq('id', editVacPerId);
      if (error) throw error;
      toast('✓ Periodo actualizado');
    } else {
      payload.user_id = currentUser.id;
      const { error } = await sb.from('vacaciones_periodos').insert(payload);
      if (error) throw error;
      toast('✓ Periodo registrado');
    }
    closeVacPerModal();
    await loadVacData();
  } catch (e) {
    console.error('[saveVacPerModal] Error:', e);
    toast('Error: ' + (e.message || JSON.stringify(e)), 'err');
  }
}

async function deleteVacPer() {
  if (!editVacPerId) return;
  if (!confirm('¿Eliminar este periodo?\n\nEsta acción no se puede deshacer.')) return;
  try {
    const { error } = await sb.from('vacaciones_periodos').delete().eq('id', editVacPerId);
    if (error) throw error;
    closeVacPerModal();
    await loadVacData();
    toast('✓ Eliminado');
  } catch (e) {
    console.error('[deleteVacPer] Error:', e);
    toast('Error: ' + (e.message || e), 'err');
  }
}

// Vista de detalle de un trabajador: lista sus periodos del año
function openVacTrabajadorDetalle(trabajadorId) {
  const t = vacTrabajadores.find(x => x.id === trabajadorId);
  if (!t) return;
  const s = _vacSaldoTrabajador(trabajadorId, vacAnioActivo);
  if (!s.periodos.length) {
    if (confirm(`${t.nombre} no tiene periodos en ${vacAnioActivo}.\n\n¿Registrar uno nuevo?`)) {
      openVacPeriodoModal(null, trabajadorId);
    }
    return;
  }
  const lines = s.periodos.map(p => {
    const icon = p.tipo === 'vacaciones' ? '🏖️' : '🎯';
    const computoIcon = p.computo === 'naturales' ? '⚖️' : '💼';
    const fIni = p.fecha_inicio.split('-').reverse().join('/');
    const fFin = p.fecha_fin.split('-').reverse().join('/');
    return `${icon} ${computoIcon} ${fIni} → ${fFin} · ${p.dias_contados}d${p.observaciones ? ' · ' + p.observaciones : ''}`;
  }).join('\n');
  alert(`${t.nombre} · ${vacAnioActivo}\n\n🏖️ Vacaciones: ${s.vac_disfrutadas}/${VAC_DIAS_VACACIONES} (${s.vac_restantes} rest.)\n🎯 Asuntos propios: ${s.ap_disfrutados}/${VAC_DIAS_ASUNTOS_PROPIOS} (${s.ap_restantes} rest.)\n\nPERIODOS:\n${lines}\n\nPulsa los días en el calendario o "Registrar vacaciones" para añadir/editar.`);
}

// ============================================================
// MÓDULO TALLER (v107AE) — control de mantenimientos de flota
// ============================================================
let tallerVehiculos = [];      // filas de taller_vehiculos
let tallerMantenimientos = []; // filas de taller_mantenimientos
let tallerEmpresaActiva = 'TYP2014';

async function loadTallerData() {
  try {
    // Ajustar subpestañas según permisos (igual que Gasoil/Vacaciones)
    const permitidas = window._empresaTaller
      ? window._empresaTaller.split(',').map(s => s.trim())
      : ['TYP2014','HISPALIS','TRANSMARGAZ'];
    ['TYP2014','HISPALIS','TRANSMARGAZ'].forEach(emp => {
      const btn = document.getElementById('tallerSub' + emp);
      if (btn) btn.style.display = permitidas.includes(emp) ? '' : 'none';
    });
    if (!permitidas.includes(tallerEmpresaActiva)) tallerEmpresaActiva = permitidas[0] || 'TYP2014';

    const [vehRes, manRes] = await Promise.all([
      sb.from('taller_vehiculos').select('*').eq('activo', true),
      sb.from('taller_mantenimientos').select('*').order('fecha', { ascending: false })
    ]);
    if (vehRes.error) throw vehRes.error;
    if (manRes.error) throw manRes.error;
    // v107AO: filtrar por empresas permitidas (window._empresaTaller).
    // Admin pasa a ver solo TYP2014+HISPALIS → Transmargaz queda fuera de
    // TODO el Taller (mantenimientos, recambios, banner). Caja cerrada.
    tallerVehiculos = (vehRes.data || []).filter(v => permitidas.includes(v.empresa));
    tallerMantenimientos = (manRes.data || []).filter(m => permitidas.includes(m.empresa));

    // Badge con total de vehículos de la empresa activa
    const cnt = document.getElementById('tabTallerCount');
    if (cnt) cnt.textContent = tallerVehiculos.length;

    _tallerActualizarSubtabs();
    renderTallerTabla();
    renderTallerAvisos();
    renderTallerGlobalBanner();  // v107AL: banner global visible en todas las pestañas
  } catch (e) {
    console.error('[loadTallerData] Error:', e);
    const body = document.getElementById('tallerTablaBody');
    if (body) body.innerHTML = `<tr><td colspan="8" style="text-align:center;color:var(--er);font-family:var(--mn);font-size:11px;padding:20px">Error cargando taller: ${esc(e.message || e)}</td></tr>`;
  }
}

function _tallerActualizarSubtabs() {
  ['TYP2014','HISPALIS','TRANSMARGAZ'].forEach(e => {
    const btn = document.getElementById('tallerSub' + e);
    if (!btn) return;
    btn.classList.remove('bp','bs');
    btn.classList.add(e === tallerEmpresaActiva ? 'bp' : 'bs');
  });
  const tit = document.getElementById('tallerEmpresaTitulo');
  if (tit) {
    const labels = {'TYP2014':'TYP2014','HISPALIS':'T. HISPALIS 2016','TRANSMARGAZ':'TRANSMARGAZ 2018'};
    tit.textContent = labels[tallerEmpresaActiva] || tallerEmpresaActiva;
  }
}

function switchTallerEmpresa(emp) {
  const permitidas = window._empresaTaller
    ? window._empresaTaller.split(',').map(s => s.trim())
    : ['TYP2014','HISPALIS','TRANSMARGAZ'];
  if (!permitidas.includes(emp)) { toast('No tienes permiso para esa empresa', 'err'); return; }
  tallerEmpresaActiva = emp;
  _tallerActualizarSubtabs();
  renderTallerTabla();
  renderTallerAvisos();
  // v107AL: si está activa la vista Recambios, recargar los de la nueva empresa
  if (tallerVistaActiva === 'recambios') loadRecambiosData();
}

// Calcula el estado de mantenimiento de un vehículo: devuelve
// { estado:'ok'|'plan'|'pronto'|'vencido', ultimaFecha, ultimoKm, proxFecha, motivo }
function _tallerEstadoVehiculo(v) {
  const mants = tallerMantenimientos
    .filter(m => m.matricula === v.matricula)
    .sort((a, b) => (b.fecha || '').localeCompare(a.fecha || ''));
  const ultimo = mants[0] || null;
  const intMeses = v.intervalo_meses || 12;
  const intKm = v.intervalo_km || 60000;
  const hoy = new Date();

  let estadoTiempo = 'ok', proxFechaStr = '—';
  if (ultimo && ultimo.fecha) {
    const fUlt = new Date(ultimo.fecha + 'T00:00:00');
    const fProx = new Date(fUlt); fProx.setMonth(fProx.getMonth() + intMeses);
    proxFechaStr = `${String(fProx.getDate()).padStart(2,'0')}/${String(fProx.getMonth()+1).padStart(2,'0')}/${fProx.getFullYear()}`;
    const diasRest = Math.floor((fProx - hoy) / 86400000);
    if (diasRest < 0) estadoTiempo = 'vencido';
    else if (diasRest <= 15) estadoTiempo = 'pronto';
    else if (diasRest <= 31) estadoTiempo = 'plan';
  } else {
    estadoTiempo = 'sinmant';
  }

  let estadoKm = 'ok', proxKmStr = '—';
  const kmActual = v.km_actual || 0;
  if (ultimo && ultimo.km != null && kmActual > 0) {
    const kmProx = ultimo.km + intKm;
    proxKmStr = kmProx.toLocaleString('es-ES') + ' km';
    const kmRest = kmProx - kmActual;
    // v107AL: umbrales km según Juan Carlos: 10.000 (plan) / 5.000 (pronto) / 0 (vencido)
    if (kmRest <= 0) estadoKm = 'vencido';
    else if (kmRest <= 5000) estadoKm = 'pronto';
    else if (kmRest <= 10000) estadoKm = 'plan';
  }

  // El estado peor manda (vencido > pronto > plan > ok)
  const orden = { vencido: 4, pronto: 3, plan: 2, sinmant: 2, ok: 1 };
  const peor = orden[estadoTiempo] >= orden[estadoKm] ? estadoTiempo : estadoKm;
  return {
    estado: peor,
    ultimaFecha: ultimo?.fecha ? ultimo.fecha.split('-').reverse().join('/') : '—',
    ultimoKm: ultimo?.km != null ? ultimo.km.toLocaleString('es-ES') : '—',
    proxFecha: proxFechaStr,
    proxKm: proxKmStr,
    numMants: mants.length
  };
}

// v107AL: genera <option> de tiempo marcando el valor actual. Si el valor
// guardado no está en la lista, lo añade para no perderlo.
function _tallerOpcsMeses(actual) {
  const vals = [6, 12, 18, 24];
  if (!vals.includes(actual)) vals.push(actual);
  vals.sort((a, b) => a - b);
  return vals.map(m => `<option value="${m}"${m === actual ? ' selected' : ''}>${m} meses</option>`).join('');
}
function _tallerOpcsKm(actual) {
  const vals = [20000, 30000, 40000, 50000, 60000, 80000, 100000, 120000];
  if (!vals.includes(actual)) vals.push(actual);
  vals.sort((a, b) => a - b);
  return vals.map(k => `<option value="${k}"${k === actual ? ' selected' : ''}>${k.toLocaleString('es-ES')} km</option>`).join('');
}

function _tallerSemaforo(estado) {
  if (estado === 'vencido') return '<span title="Vencido" style="font-size:14px">🔴</span>';
  if (estado === 'pronto')  return '<span title="Pronto (≤15 días o ≤5.000 km)" style="font-size:14px">🟠</span>';
  if (estado === 'plan')    return '<span title="Planificar (≤1 mes o ≤10.000 km)" style="font-size:14px">🟡</span>';
  if (estado === 'sinmant') return '<span title="Sin mantenimientos registrados" style="font-size:14px">⚪</span>';
  return '<span title="Al día" style="font-size:14px">🟢</span>';
}

function renderTallerTabla() {
  const body = document.getElementById('tallerTablaBody');
  if (!body) return;
  const vs = tallerVehiculos
    .filter(v => v.empresa === tallerEmpresaActiva)
    .sort((a, b) => {
      // Ordenar por estado (peor primero) y luego matrícula
      const ea = _tallerEstadoVehiculo(a).estado, eb = _tallerEstadoVehiculo(b).estado;
      const ord = { vencido: 0, pronto: 1, plan: 2, sinmant: 3, ok: 4 };
      if (ord[ea] !== ord[eb]) return ord[ea] - ord[eb];
      return (a.matricula || '').localeCompare(b.matricula || '');
    });
  if (!vs.length) {
    body.innerHTML = `<tr><td colspan="8" style="text-align:center;color:var(--mu);font-family:var(--mn);font-size:11px;padding:20px">No hay vehículos en ${tallerEmpresaActiva}</td></tr>`;
    return;
  }
  body.innerHTML = vs.map(v => {
    const e = _tallerEstadoVehiculo(v);
    const tipoIcon = v.tipo_vehiculo === 'semirremolque' ? '🚛' : '🚚';
    return `<tr style="cursor:pointer" onclick="tallerAbrirModal('${v.id}')">
      <td style="text-align:center">${_tallerSemaforo(e.estado)}</td>
      <td style="font-family:var(--mn);color:var(--ac)">${esc(v.matricula)}${v.notas ? `<div style="font-size:9px;color:var(--mu)">${esc(v.notas)}</div>` : ''}</td>
      <td style="font-size:11px">${tipoIcon} ${v.tipo_vehiculo === 'semirremolque' ? 'Remolque' : 'Tractora'}</td>
      <td style="font-family:var(--mn);font-size:11px">${v.km_actual ? v.km_actual.toLocaleString('es-ES') + ' km' : '—'}</td>
      <td style="font-size:11px">${e.ultimaFecha}</td>
      <td style="font-size:11px">${e.proxFecha}</td>
      <td style="font-size:11px">${e.proxKm}</td>
      <td><button class="btn bs" style="font-size:10px;padding:3px 8px" onclick="event.stopPropagation();tallerAbrirModal('${v.id}')">Ver / ${e.numMants}</button></td>
    </tr>`;
  }).join('');
}

function renderTallerAvisos() {
  const box = document.getElementById('tallerAvisos');
  if (!box) return;
  const vs = tallerVehiculos.filter(v => v.empresa === tallerEmpresaActiva);
  const alertas = [];
  vs.forEach(v => {
    const e = _tallerEstadoVehiculo(v);
    if (e.estado === 'vencido') alertas.push(`🔴 ${v.matricula} VENCIDO`);
    else if (e.estado === 'pronto') alertas.push(`🟠 ${v.matricula} pronto`);
  });
  if (!alertas.length) { box.style.display = 'none'; return; }
  box.style.display = 'block';
  box.innerHTML = `<div style="background:rgba(255,140,0,.08);border:1px solid rgba(255,140,0,.3);border-radius:8px;padding:10px 14px;font-family:var(--mn);font-size:12px;color:var(--fg)">
    🔧 <b>${alertas.length}</b> vehículo(s) requieren mantenimiento: ${alertas.slice(0, 8).map(esc).join(' · ')}${alertas.length > 8 ? ` · +${alertas.length - 8} más` : ''}
  </div>`;
}

// Modal de un vehículo: historial de mantenimientos editable (mín. 15 líneas)
let _tallerVehIdActual = null;
function tallerAbrirModal(vehId) {
  const v = tallerVehiculos.find(x => x.id === vehId);
  if (!v) return;
  _tallerVehIdActual = vehId;
  const mants = tallerMantenimientos
    .filter(m => m.matricula === v.matricula)
    .sort((a, b) => (b.fecha || '').localeCompare(a.fecha || ''));
  const filas = [...mants];
  while (filas.length < 15) filas.push(null);

  const rowsHtml = filas.map((m, i) => `
    <tr data-idx="${i}" data-id="${m?.id || ''}">
      <td><input type="date" class="fi tallerMF" value="${m?.fecha || ''}" style="font-size:11px;padding:4px"></td>
      <td><input type="number" class="fi tallerMK" value="${m?.km != null ? m.km : ''}" placeholder="km" style="font-size:11px;padding:4px;width:90px"></td>
      <td><input type="text" class="fi tallerMT" value="${m ? esc(m.tipo || '') : ''}" placeholder="Ej: Cambio aceite + filtro" style="font-size:11px;padding:4px"></td>
      <td><input type="text" class="fi tallerMN" value="${m ? esc(m.notas || '') : ''}" placeholder="notas" style="font-size:11px;padding:4px"></td>
      <td><input type="text" class="fi tallerMR" value="${m ? esc(m.realizado_por || '') : ''}" placeholder="Taller propio / Casa oficial" style="font-size:11px;padding:4px"></td>
      <td style="text-align:center">${m?.id ? `<button class="btn bs" style="font-size:10px;padding:2px 6px;color:var(--er)" onclick="tallerBorrarLinea('${m.id}','${vehId}')">🗑</button>` : ''}</td>
    </tr>`).join('');

  document.getElementById('tallerMantTitulo').textContent = `🔧 MANTENIMIENTOS · ${v.matricula}`;
  document.getElementById('tallerMantBody').innerHTML = `
    <div style="display:flex;gap:14px;flex-wrap:wrap;margin-bottom:14px;font-family:var(--mn);font-size:12px;color:var(--mu)">
      <span>Empresa: <b style="color:var(--fg)">${esc(v.empresa)}</b></span>
      <span>Tipo: <b style="color:var(--fg)">${v.tipo_vehiculo === 'semirremolque' ? 'Semirremolque' : 'Tractora'}</b></span>
      <span>KM actual: <b style="color:var(--fg)">${v.km_actual ? v.km_actual.toLocaleString('es-ES') : '—'}</b></span>
      ${v.notas ? `<span>Nota: <b style="color:var(--fg)">${esc(v.notas)}</b></span>` : ''}
    </div>
    <div style="display:flex;gap:10px;align-items:end;margin-bottom:12px;flex-wrap:wrap;background:rgba(255,255,255,.02);padding:10px;border-radius:6px">
      <div><label style="font-size:10px;color:var(--mu);font-family:var(--mn)">Intervalo tiempo</label><br>
        <select class="fi" id="tallerVintMeses" style="font-size:11px;padding:4px">${_tallerOpcsMeses(v.intervalo_meses || 12)}</select></div>
      <div><label style="font-size:10px;color:var(--mu);font-family:var(--mn)">Intervalo km</label><br>
        <select class="fi" id="tallerVintKm" style="font-size:11px;padding:4px">${_tallerOpcsKm(v.intervalo_km || 60000)}</select></div>
      <div><label style="font-size:10px;color:var(--mu);font-family:var(--mn)">KM actual</label><br><input type="number" class="fi" id="tallerVkmActual" value="${v.km_actual || ''}" style="width:100px;font-size:11px;padding:4px"></div>
      <button class="btn bs" style="font-size:11px" onclick="tallerGuardarVehiculo('${vehId}')">💾 Guardar config</button>
    </div>
    <div style="overflow-x:auto">
      <table class="tbl" id="tallerModalTabla">
        <thead><tr>
          <th style="font-size:10px">Fecha</th><th style="font-size:10px">KM</th>
          <th style="font-size:10px">Tipo (libre)</th><th style="font-size:10px">Notas</th>
          <th style="font-size:10px">Realizado por</th><th style="font-size:10px"></th>
        </tr></thead>
        <tbody id="tallerModalBody">${rowsHtml}</tbody>
      </table>
    </div>
    <button class="btn bs" style="font-size:11px;margin-top:10px" onclick="tallerAddLinea()">➕ Añadir línea</button>`;
  const saveBtn = document.getElementById('tallerMantSaveBtn');
  if (saveBtn) saveBtn.onclick = () => tallerGuardarMantenimientos(vehId);
  document.getElementById('ovTallerMant').classList.add('open');
}

function closeTallerMant() { document.getElementById('ovTallerMant').classList.remove('open'); }
function closeTallerNuevo() { document.getElementById('ovTallerNuevo').classList.remove('open'); }

function tallerAddLinea() {
  const body = document.getElementById('tallerModalBody');
  if (!body) return;
  const i = body.children.length;
  const tr = document.createElement('tr');
  tr.setAttribute('data-idx', i);
  tr.setAttribute('data-id', '');
  tr.innerHTML = `
    <td><input type="date" class="fi tallerMF" style="font-size:11px;padding:4px"></td>
    <td><input type="number" class="fi tallerMK" placeholder="km" style="font-size:11px;padding:4px;width:90px"></td>
    <td><input type="text" class="fi tallerMT" placeholder="Ej: Cambio aceite + filtro" style="font-size:11px;padding:4px"></td>
    <td><input type="text" class="fi tallerMN" placeholder="notas" style="font-size:11px;padding:4px"></td>
    <td><input type="text" class="fi tallerMR" placeholder="Taller propio / Casa oficial" style="font-size:11px;padding:4px"></td>
    <td></td>`;
  body.appendChild(tr);
}

async function tallerGuardarMantenimientos(vehId) {
  const v = tallerVehiculos.find(x => x.id === vehId);
  if (!v) return;
  const filas = [...document.querySelectorAll('#tallerModalBody tr')];
  const aInsertar = [], aActualizar = [];
  for (const tr of filas) {
    const id = tr.getAttribute('data-id');
    const fecha = tr.querySelector('.tallerMF')?.value || '';
    const kmRaw = tr.querySelector('.tallerMK')?.value || '';
    const tipo = (tr.querySelector('.tallerMT')?.value || '').trim();
    const notas = (tr.querySelector('.tallerMN')?.value || '').trim();
    const realizado = (tr.querySelector('.tallerMR')?.value || '').trim();
    // Línea vacía → ignorar. Línea con datos → necesita fecha y tipo
    if (!fecha && !tipo && !kmRaw && !notas && !realizado) continue;
    if (!fecha || !tipo) { toast('Cada línea con datos necesita Fecha y Tipo', 'err'); return; }
    const reg = {
      empresa: v.empresa, matricula: v.matricula, fecha,
      km: kmRaw ? parseInt(kmRaw, 10) : null,
      tipo, notas: notas || null, realizado_por: realizado || null,
      user_id: currentUser?.id || null
    };
    if (id) aActualizar.push({ id, ...reg });
    else aInsertar.push(reg);
  }
  try {
    if (aInsertar.length) {
      const { error } = await sb.from('taller_mantenimientos').insert(aInsertar);
      if (error) throw error;
    }
    for (const r of aActualizar) {
      const { id, ...rest } = r;
      rest.updated_at = new Date().toISOString();
      const { error } = await sb.from('taller_mantenimientos').update(rest).eq('id', id);
      if (error) throw error;
    }
    toast(`Guardado: ${aInsertar.length} nuevos, ${aActualizar.length} actualizados`, 'ok');
    closeTallerMant();
    await loadTallerData();
  } catch (e) {
    console.error('[tallerGuardarMantenimientos]', e);
    toast('Error guardando: ' + (e.message || e), 'err');
  }
}

async function tallerBorrarLinea(manId, vehId) {
  if (!confirm('¿Borrar esta línea de mantenimiento?')) return;
  try {
    const { error } = await sb.from('taller_mantenimientos').delete().eq('id', manId);
    if (error) throw error;
    toast('Línea borrada', 'ok');
    closeTallerMant();
    await loadTallerData();
    tallerAbrirModal(vehId);
  } catch (e) { toast('Error: ' + (e.message || e), 'err'); }
}

async function tallerGuardarVehiculo(vehId) {
  const v = tallerVehiculos.find(x => x.id === vehId);
  if (!v) return;
  const intMeses = parseInt(document.getElementById('tallerVintMeses')?.value || '12', 10);
  const intKm = parseInt(document.getElementById('tallerVintKm')?.value || '60000', 10);
  const kmActualRaw = document.getElementById('tallerVkmActual')?.value || '';
  const upd = { intervalo_meses: intMeses, intervalo_km: intKm, updated_at: new Date().toISOString() };
  if (kmActualRaw) { upd.km_actual = parseInt(kmActualRaw, 10); upd.km_actual_fecha = new Date().toISOString().slice(0, 10); }
  try {
    const { error } = await sb.from('taller_vehiculos').update(upd).eq('id', vehId);
    if (error) throw error;
    toast('Configuración guardada', 'ok');
    await loadTallerData();
  } catch (e) { toast('Error: ' + (e.message || e), 'err'); }
}

// Añadir vehículo nuevo manualmente (compra de camión, etc.)
function tallerAddVehiculoModal() {
  // Limpiar campos
  document.getElementById('tallerAddMat').value = '';
  document.getElementById('tallerAddTipo').value = 'tractora';
  document.getElementById('tallerAddMeses').value = 12;
  document.getElementById('tallerAddKm').value = 60000;
  document.getElementById('tallerAddNota').value = '';
  const sel = document.getElementById('tallerAddEmp');
  if (sel) sel.value = tallerEmpresaActiva;
  document.getElementById('ovTallerNuevo').classList.add('open');
}

async function tallerCrearVehiculo() {
  const mat = (document.getElementById('tallerAddMat')?.value || '').toUpperCase().replace(/[\s-]/g, '').trim();
  const emp = document.getElementById('tallerAddEmp')?.value;
  const tipo = document.getElementById('tallerAddTipo')?.value;
  const meses = parseInt(document.getElementById('tallerAddMeses')?.value || '12', 10);
  const km = parseInt(document.getElementById('tallerAddKm')?.value || '60000', 10);
  const nota = (document.getElementById('tallerAddNota')?.value || '').trim();
  if (!mat) { toast('Pon una matrícula', 'err'); return; }
  try {
    const { error } = await sb.from('taller_vehiculos').insert({
      empresa: emp, matricula: mat, tipo_vehiculo: tipo,
      intervalo_meses: meses, intervalo_km: km, notas: nota || null, activo: true
    });
    if (error) throw error;
    toast('Vehículo creado: ' + mat, 'ok');
    closeTallerNuevo();
    await loadTallerData();
  } catch (e) {
    if (/duplicate|unique/i.test(e.message || '')) toast('Esa matrícula ya existe', 'err');
    else toast('Error: ' + (e.message || e), 'err');
  }
}

// Importar km del Excel de ASG Trans (formato "Gasóleo Profesional": todos los
// vehículos juntos con Matrícula + Cuentakilómetros fin) o el formato de 1 vehículo.
async function tallerImportarKmExcel(file) {
  if (!file) return;
  try {
    const buf = await file.arrayBuffer();
    const wb = XLSX.read(buf, { type: 'array' });
    const ws = wb.Sheets[wb.SheetNames[0]];
    const rows = XLSX.utils.sheet_to_json(ws, { header: 1, raw: false });
    // Buscar la fila de cabecera (contiene "Matrícula" y "Cuentakilómetros")
    let headerIdx = -1, colMat = -1, colKmFin = -1;
    for (let i = 0; i < rows.length; i++) {
      const fila = (rows[i] || []).map(c => String(c || '').toLowerCase());
      const jMat = fila.findIndex(c => c.includes('matr'));
      const jKm = fila.findIndex(c => c.includes('cuentakil') && c.includes('fin'));
      const jKm2 = fila.findIndex(c => c.includes('cuentakil'));
      if (jMat >= 0 && (jKm >= 0 || jKm2 >= 0)) {
        headerIdx = i; colMat = jMat; colKmFin = jKm >= 0 ? jKm : jKm2; break;
      }
    }
    if (headerIdx < 0) { toast('No reconozco el formato del Excel (falta Matrícula/Cuentakilómetros)', 'err'); return; }

    let actualizados = 0, noEncontrados = [], saltadosCero = 0;
    const fechaImport = new Date().toISOString().slice(0, 10);
    for (let i = headerIdx + 1; i < rows.length; i++) {
      const fila = rows[i] || [];
      const matRaw = String(fila[colMat] || '').toUpperCase().replace(/[\s-]/g, '').trim();
      if (!matRaw || !/^R?\d/.test(matRaw)) continue; // fila no válida
      const kmVal = parseInt(String(fila[colKmFin] || '0').replace(/[^\d]/g, ''), 10);
      if (!kmVal || kmVal <= 0) { saltadosCero++; continue; } // no machacar km bueno con 0
      const v = tallerVehiculos.find(x => x.matricula === matRaw);
      if (!v) { noEncontrados.push(matRaw); continue; }
      // Solo actualizar si el km nuevo es mayor o igual al guardado (el cuentakm no baja)
      if (v.km_actual && kmVal < v.km_actual) continue;
      const { error } = await sb.from('taller_vehiculos')
        .update({ km_actual: kmVal, km_actual_fecha: fechaImport, updated_at: new Date().toISOString() })
        .eq('id', v.id);
      if (!error) actualizados++;
    }
    let msg = `✅ ${actualizados} vehículos actualizados`;
    if (saltadosCero) msg += ` · ${saltadosCero} sin datos (km 0, ignorados)`;
    if (noEncontrados.length) msg += ` · ${noEncontrados.length} no encontrados: ${noEncontrados.slice(0, 5).join(', ')}${noEncontrados.length > 5 ? '...' : ''}`;
    toast(msg, actualizados ? 'ok' : 'err');
    await loadTallerData();
  } catch (e) {
    console.error('[tallerImportarKmExcel]', e);
    toast('Error leyendo Excel: ' + (e.message || e), 'err');
  }
  // Limpiar el input para poder re-subir el mismo archivo
  const inp = document.getElementById('tallerExcelInput'); if (inp) inp.value = '';
}

// FASE 4a: leer el Excel de KM del tacógrafo ("Gasóleo Profesional") y
// guardarlo en la tabla km_periodos. Formato fijo (lectura directa, sin
// IA): arriba DATOS EMPRESA + CIF + Período (2 fechas); luego filas con
// Matrícula / Fecha inicio / Km inicio / Fecha fin / Km fin / Diferencia.
// Detecta la empresa por el CIF. Anti-duplicados: mismo matrícula +
// fecha_inicio + fecha_fin no se vuelve a guardar.
async function gasImportarKmExcel(file) {
  if (!file) return;
  try {
    const buf = await file.arrayBuffer();
    const wb = XLSX.read(buf, { type: 'array' });
    const ws = wb.Sheets[wb.SheetNames[0]];
    const rows = XLSX.utils.sheet_to_json(ws, { header: 1, raw: false });

    // 1) Empresa por CIF (mismo mapeo que las facturas). J19: Portes 2014 Import
    // (B02657435) se trata como TYP2014 (sus 2 tractoras operan en TYP2014), para que
    // sus km caigan en TYP2014 igual que sus litros y el consumo salga junto.
    const CIF_EMP = {
      'B90172735': 'TYP2014',
      'B90286337': 'HISPALIS',
      'B67316752': 'TRANSMARGAZ',
      'B02657435': 'TYP2014'
    };
    let cifDoc = '', empresaDoc = '';
    for (let i = 0; i < Math.min(rows.length, 8); i++) {
      const _raw = rows[i] || [];
      for (let k = 0; k < _raw.length; k++) {
        const cel = String(_raw[k] == null ? '' : _raw[k]).toUpperCase().replace(/[\s.\-]/g, '');
        const m = cel.match(/B\d{8}/);
        if (m && CIF_EMP[m[0]]) { cifDoc = m[0]; empresaDoc = CIF_EMP[m[0]]; break; }
      }
      if (cifDoc) break;
    }

    // 2) Periodo global (fila "Período  dd/mm/aaaa  dd/mm/aaaa").
    let perIni = '', perFin = '';
    for (let i = 0; i < Math.min(rows.length, 10); i++) {
      const _raw = rows[i] || [];
      const fila = Array.from({ length: _raw.length }, (_, k) => String(_raw[k] == null ? '' : _raw[k]));
      if (fila.some(c => c.toLowerCase().includes('per') && c.toLowerCase().includes('odo'))) {
        const fechas = fila.filter(c => /\d{1,2}\/\d{1,2}\/\d{2,4}/.test(c));
        if (fechas.length >= 2) { perIni = fechas[0]; perFin = fechas[1]; }
        break;
      }
    }

    // 3) Cabecera de la tabla (Matrícula + Cuentakilómetros inicio/fin).
    let hIdx = -1, cMat = -1, cFIni = -1, cKIni = -1, cFFin = -1, cKFin = -1, cDif = -1;
    for (let i = 0; i < rows.length; i++) {
      const _raw = rows[i] || [];
      const f = Array.from({ length: _raw.length }, (_, k) => String(_raw[k] == null ? '' : _raw[k]).toLowerCase());
      const jM = f.findIndex(c => c.includes('matr'));
      const jKI = f.findIndex(c => c.includes('cuentakil') && c.includes('inicio'));
      const jKF = f.findIndex(c => c.includes('cuentakil') && c.includes('fin'));
      if (jM >= 0 && jKI >= 0 && jKF >= 0) {
        hIdx = i; cMat = jM; cKIni = jKI; cKFin = jKF;
        cFIni = f.findIndex(c => c.includes('fecha') && c.includes('inicio'));
        cFFin = f.findIndex(c => c.includes('fecha') && c.includes('fin'));
        cDif = f.findIndex(c => c.includes('diferencia'));
        break;
      }
    }
    if (hIdx < 0) { toast('No reconozco el Excel de km (falta Matrícula/Cuentakilómetros inicio/fin)', 'err'); return; }

    // 4) Cargar lo ya existente para anti-duplicados.
    const { data: yaBd } = await sb.from('km_periodos').select('matricula,fecha_inicio,fecha_fin');
    const claveExiste = new Set((yaBd || []).map(r =>
      String(r.matricula || '').toUpperCase() + '|' + (r.fecha_inicio || '') + '|' + (r.fecha_fin || '')));

    const toISO = (s) => {
      const m = String(s || '').match(/(\d{1,2})\/(\d{1,2})\/(\d{2,4})/);
      if (!m) return null;
      let [_, d, mes, y] = m; if (y.length === 2) y = '20' + y;
      return y + '-' + mes.padStart(2, '0') + '-' + d.padStart(2, '0');
    };
    const fIniISO = toISO(perIni), fFinISO = toISO(perFin);

    let guardados = 0, dupOmitidos = 0, sinDatos = 0;
    for (let i = hIdx + 1; i < rows.length; i++) {
      const fila = rows[i] || [];
      const mat = String(fila[cMat] || '').toUpperCase().replace(/[\s\-]/g, '').trim();
      if (!mat || !/^R?\d/.test(mat)) continue;
      const kIni = parseInt(String(fila[cKIni] || '0').replace(/[^\d]/g, ''), 10) || 0;
      const kFin = parseInt(String(fila[cKFin] || '0').replace(/[^\d]/g, ''), 10) || 0;
      let dif = cDif >= 0 ? (parseInt(String(fila[cDif] || '0').replace(/[^\d]/g, ''), 10) || 0) : 0;
      if (!dif && kFin && kIni) dif = kFin - kIni;
      // fecha inicio/fin: de la fila si existe, si no la del periodo global
      const fIni = (cFIni >= 0 ? toISO(fila[cFIni]) : null) || fIniISO;
      const fFin = (cFFin >= 0 ? toISO(fila[cFFin]) : null) || fFinISO;
      if (!dif || dif <= 0) { sinDatos++; continue; }
      const clave = mat + '|' + (fIni || '') + '|' + (fFin || '');
      if (claveExiste.has(clave)) { dupOmitidos++; continue; }
      const { error } = await sb.from('km_periodos').insert({
        matricula: mat, empresa: empresaDoc || null,
        fecha_inicio: fIni, fecha_fin: fFin,
        km_inicio: kIni || null, km_fin: kFin || null, km_diferencia: dif,
        cif: cifDoc || null,
        user_id: currentUser ? currentUser.id : null
      });
      if (!error) { guardados++; claveExiste.add(clave); }
      else console.warn('[gasImportarKmExcel] error guardando ' + mat + ':', error.message);
    }

    let msg = '✅ Km tacógrafo: ' + guardados + ' camiones guardados';
    if (empresaDoc) msg += ' (' + empresaDoc + ')';
    if (perIni && perFin) msg += ' · periodo ' + perIni + ' a ' + perFin;
    if (dupOmitidos) msg += ' · ' + dupOmitidos + ' ya estaban (omitidos)';
    if (sinDatos) msg += ' · ' + sinDatos + ' sin km (ignorados)';
    console.log('[gasImportarKmExcel] ' + msg);
    toast(msg, guardados ? 'ok' : 'warn');
    // v107BK: invalidar la cache de km para que la vista de Consumo
    // recargue los datos nuevos la proxima vez que se abra.
    if (guardados) {
      _kmPeriodos = null;
      const vCon = document.getElementById('gasVistaConsumo');
      if (vCon && vCon.style.display !== 'none' && typeof gasRenderConsumo === 'function') {
        gasRenderConsumo();
      }
    }
    if (dupOmitidos && !guardados) {
      setTimeout(() => { try { alert('⚠️ ESTE EXCEL DE KM YA ESTABA SUBIDO\n\nLos ' + dupOmitidos + ' camiones de este periodo ya estaban.\nNo se ha duplicado nada.'); } catch (e) {} }, 300);
    }
  } catch (e) {
    console.error('[gasImportarKmExcel]', e);
    toast('Error leyendo Excel de km: ' + (e.message || e), 'err');
  }
}

// ============================================================
// MÓDULO RECAMBIOS (v107AL · Fase 1) — albaranes/facturas taller
// Privacidad:
//  - TALLER (no admin): sube y ve SOLO albaranes de las 3 empresas. NO facturas.
//  - Admin (Juan Carlos): ve todo (albaranes + facturas), sube ambos, concilia (Fase 2).
//  - Transmargaz: ve SOLO sus albaranes + sus facturas. No concilia.
// ============================================================
let recambiosDocs = [];          // filas de recambios_albaranes
let tallerVistaActiva = 'mant';  // 'mant' | 'recambios'

function switchTallerVista(v) {
  tallerVistaActiva = v;
  const mb = document.getElementById('tallerVistaMantBox');
  const rb = document.getElementById('tallerVistaRecambiosBox');
  const bm = document.getElementById('tallerVistaMant');
  const br = document.getElementById('tallerVistaRecambios');
  if (v === 'recambios') {
    if (mb) mb.style.display = 'none';
    if (rb) rb.style.display = '';
    if (bm) { bm.classList.remove('bp'); bm.classList.add('bs'); }
    if (br) { br.classList.remove('bs'); br.classList.add('bp'); }
    loadRecambiosData();
  } else {
    if (mb) mb.style.display = '';
    if (rb) rb.style.display = 'none';
    if (bm) { bm.classList.remove('bs'); bm.classList.add('bp'); }
    if (br) { br.classList.remove('bp'); br.classList.add('bs'); }
  }
}

// ¿Es el usuario TALLER (rol no admin con permiso taller)? → no ve facturas, no concilia
function _recambiosEsTaller() {
  return !!window._tieneTaller && (userMap[currentUser?.id]?.role || '').toLowerCase() !== 'admin';
}
function _recambiosEsAdmin() {
  return (userMap[currentUser?.id]?.role || '').toLowerCase() === 'admin';
}
// v107AO: ¿es el usuario Transmargaz? (su empresa_taller es solo TRANSMARGAZ).
// Transmargaz puede conciliar SUS facturas (las de empresa TRANSMARGAZ).
function _recambiosEsTransmargaz() {
  const emp = (window._empresaTaller || '').split(',').map(s => s.trim());
  return !_recambiosEsAdmin() && emp.length === 1 && emp[0] === 'TRANSMARGAZ';
}

async function loadRecambiosData() {
  try {
    // Empresa activa = la subpestaña de Taller seleccionada
    const emp = tallerEmpresaActiva || 'TYP2014';
    // v107AO: ordenar por created_at (cuándo se subió) para que el último
    // subido aparezca SIEMPRE arriba, no mezclado por la fecha del documento.
    let q = sb.from('recambios_albaranes').select('*').eq('empresa', emp).order('created_at', { ascending: false });
    const { data, error } = await q;
    if (error) throw error;
    let docs = data || [];

    // Filtrado por privacidad:
    if (_recambiosEsTaller()) {
      // TALLER: solo albaranes (nunca facturas ni abonos)
      docs = docs.filter(d => d.tipo_doc === 'albaran');
    }
    // (Admin y Transmargaz ven todo lo de su empresa; Transmargaz ya está
    //  limitado porque solo puede entrar a su subpestaña TRANSMARGAZ.)
    recambiosDocs = docs;

    // Botones según rol: el botón de factura solo lo ve admin o Transmargaz (no TALLER)
    const btnFac = document.getElementById('recambiosBtnSubirFac');
    if (btnFac) btnFac.style.display = _recambiosEsTaller() ? 'none' : '';

    // Título empresa
    const tit = document.getElementById('recambiosEmpresaTitulo');
    if (tit) {
      const labels = {'TYP2014':'TYP2014','HISPALIS':'T. HISPALIS 2016','TRANSMARGAZ':'TRANSMARGAZ 2018'};
      tit.textContent = labels[emp] || emp;
    }
    // Rellenar filtro de proveedores
    const provSel = document.getElementById('recambiosFiltroProv');
    if (provSel) {
      const provs = [...new Set(recambiosDocs.map(d => d.proveedor).filter(Boolean))].sort();
      const actual = provSel.value;
      provSel.innerHTML = '<option value="">Todos los proveedores</option>' +
        provs.map(p => `<option value="${esc(p)}">${esc(p)}</option>`).join('');
      provSel.value = actual;
    }
    renderRecambios();
  } catch (e) {
    console.error('[loadRecambiosData]', e);
    const body = document.getElementById('recambiosTablaBody');
    if (body) body.innerHTML = `<tr><td colspan="9" style="text-align:center;color:var(--er);font-family:var(--mn);font-size:11px;padding:20px">Error: ${esc(e.message || e)}</td></tr>`;
  }
}

function renderRecambios() {
  const body = document.getElementById('recambiosTablaBody');
  if (!body) return;
  const fTipo = document.getElementById('recambiosFiltroTipo')?.value || '';
  const fProv = document.getElementById('recambiosFiltroProv')?.value || '';
  const fBuscar = (document.getElementById('recambiosFiltroBuscar')?.value || '').toLowerCase().trim();

  let docs = [...recambiosDocs];
  if (fTipo) docs = docs.filter(d => d.tipo_doc === fTipo);
  if (fProv) docs = docs.filter(d => d.proveedor === fProv);
  if (fBuscar) docs = docs.filter(d => {
    const enCab = `${d.num_documento || ''} ${d.proveedor || ''}`.toLowerCase().includes(fBuscar);
    const enLin = (d.lineas || []).some(l => `${l.codigo || ''} ${l.descripcion || ''}`.toLowerCase().includes(fBuscar));
    return enCab || enLin;
  });

  const resumen = document.getElementById('recambiosResumen');
  if (resumen) {
    const nAlb = docs.filter(d => d.tipo_doc === 'albaran').length;
    const nFac = docs.filter(d => d.tipo_doc === 'factura').length;
    resumen.textContent = `${docs.length} doc · ${nAlb} albaranes · ${nFac} facturas`;
  }

  if (!docs.length) {
    body.innerHTML = `<tr><td colspan="9" style="text-align:center;color:var(--mu);font-family:var(--mn);font-size:11px;padding:20px">Sin documentos. Sube un albarán con el botón de arriba.</td></tr>`;
    return;
  }
  // v107AL: detectar duplicados (mismo tipo+empresa+proveedor+nº doc).
  // Se marca en rojo cualquier documento que aparezca 2+ veces.
  const _claveDup = x => `${x.tipo_doc}|${x.empresa}|${_recambNorm(x.proveedor)}|${_recambNorm(x.num_documento)}`;
  const _conteo = {};
  recambiosDocs.forEach(x => {
    if (!x.num_documento || !x.proveedor) return;
    const k = _claveDup(x);
    _conteo[k] = (_conteo[k] || 0) + 1;
  });
  const esDuplicado = d => d.num_documento && d.proveedor && _conteo[_claveDup(d)] > 1;
  const nDup = docs.filter(esDuplicado).length;

  const resumenDup = document.getElementById('recambiosResumen');
  if (resumenDup && nDup) {
    resumenDup.innerHTML += ` · <span style="color:#ff5050">⚠️ ${nDup} duplicado(s)</span>`;
  }

  const tipoBadge = t => t === 'factura'
    ? '<span style="background:rgba(255,180,0,.15);color:#ffb400;padding:2px 7px;border-radius:4px;font-size:10px">🧾 Factura</span>'
    : t === 'abono'
    ? '<span style="background:rgba(255,80,80,.15);color:#ff5050;padding:2px 7px;border-radius:4px;font-size:10px">↩️ Abono</span>'
    : '<span style="background:rgba(0,232,122,.12);color:var(--ac);padding:2px 7px;border-radius:4px;font-size:10px">📦 Albarán</span>';
  body.innerHTML = docs.map(d => {
    const est = d.conciliado
      ? '<span style="color:var(--ac);font-size:11px">🟢 Conciliado</span>'
      : '<span style="color:var(--mu);font-size:11px">⚪ Pendiente</span>';
    const fecha = d.fecha ? d.fecha.split('-').reverse().join('/') : '—';
    const nLin = (d.lineas || []).length;
    // v107AO: botón Conciliar en facturas. Admin concilia TYP2014+Hispalis;
    // Transmargaz concilia SOLO sus facturas (empresa TRANSMARGAZ). TALLER nunca.
    const puedeConciliar = d.tipo_doc === 'factura' && (
      _recambiosEsAdmin() ||
      (_recambiosEsTransmargaz() && d.empresa === 'TRANSMARGAZ')
    );
    const btnConciliar = puedeConciliar
      ? `<button class="btn bp" style="font-size:10px;padding:3px 8px;margin-right:4px" onclick="event.stopPropagation();recambiosConciliar('${d.id}')">🔍 Conciliar</button>`
      : '';
    // v107AL: marca de duplicado
    const dup = esDuplicado(d);
    const trStyle = dup
      ? 'cursor:pointer;background:rgba(255,80,80,.08);border-left:3px solid #ff5050'
      : 'cursor:pointer';
    const dupTag = dup
      ? ' <span style="background:rgba(255,80,80,.2);color:#ff5050;padding:1px 6px;border-radius:4px;font-size:9px;font-weight:bold" title="Este documento está duplicado (mismo proveedor y nº)">⚠️ DUPLICADO</span>'
      : '';
    return `<tr style="${trStyle}" onclick="recambiosVerDetalle('${d.id}')">
      <td>${tipoBadge(d.tipo_doc)}</td>
      <td style="font-size:11px">${esc(d.proveedor || '—')}</td>
      <td style="font-family:var(--mn);font-size:11px;color:var(--ac)">${esc(d.num_documento || '—')}${dupTag}</td>
      <td style="font-size:11px">${fecha}</td>
      <td style="font-family:var(--mn);font-size:11px">${d.base_imponible != null ? d.base_imponible.toFixed(2) + '€' : '—'}</td>
      <td style="font-family:var(--mn);font-size:11px">${d.iva != null ? d.iva.toFixed(2) + '€' : '—'}</td>
      <td style="font-family:var(--mn);font-size:12px;color:var(--fg)"><b>${d.total != null ? d.total.toFixed(2) + '€' : '—'}</b></td>
      <td>${est}</td>
      <td style="white-space:nowrap">${btnConciliar}<button class="btn bs" style="font-size:10px;padding:3px 8px" onclick="event.stopPropagation();recambiosVerDetalle('${d.id}')">Ver / ${nLin}</button></td>
    </tr>`;
  }).join('');
}

// Sube uno o varios documentos (albarán o factura) y los lee con IA
async function recambiosSubir(files, tipoForzado) {
  if (!files || !files.length) return;
  const key = getKey();
  if (!key) { toast('Falta la API key de Anthropic (config)', 'err'); return; }
  const emp = tallerEmpresaActiva || 'TYP2014';
  const colaBox = document.getElementById('recambiosColaBox');
  const arr = [...files];
  let ok = 0, err = 0;
  if (colaBox) { colaBox.style.display = 'block'; }

  for (let i = 0; i < arr.length; i++) {
    const f = arr[i];
    if (colaBox) colaBox.innerHTML = `<div style="background:rgba(0,232,122,.06);border:1px solid rgba(0,232,122,.25);border-radius:8px;padding:10px 14px;font-family:var(--mn);font-size:12px;color:var(--fg)">⏳ Procesando ${i + 1}/${arr.length}: ${esc(f.name)}...</div>`;
    try {
      const isPdf = /pdf$/i.test(f.type) || /\.pdf$/i.test(f.name);
      const b64 = await _fileToB64(f);
      // v107BA: guardar el PDF/foto en Storage para poder verlo/descargarlo
      // luego en el modal (igual que albaranes de transporte). Si falla la
      // subida del archivo, seguimos igualmente (no perdemos los datos leídos).
      let _recFileUrl = null;
      try {
        _recFileUrl = await uploadFile(f, 'recambios');
      } catch (e) {
        console.warn('[v107BA recambios] no pude subir el archivo a Storage (seguimos sin él):', e);
      }
      const parsed = await callClaudeRecambio(b64, f.type || (isPdf ? 'application/pdf' : 'image/jpeg'), key, isPdf);
      const docs = Array.isArray(parsed) ? parsed : [parsed];
      for (const doc of docs) {
        // tipoForzado viene del botón pulsado; si la IA detecta factura y se subió como
        // albarán (o viceversa) respetamos lo que diga la IA salvo que no esté claro.
        let tipo = tipoForzado;
        if (doc.tipo_detectado === 'factura' || doc.tipo_detectado === 'albaran' || doc.tipo_detectado === 'abono') {
          tipo = doc.tipo_detectado;
        }
        const reg = {
          tipo_doc: tipo,
          empresa: emp,
          proveedor: doc.proveedor || null,
          proveedor_nif: doc.proveedor_nif || null,
          num_documento: doc.num_documento || null,
          fecha: _recambiosFecha(doc.fecha),
          base_imponible: _num(doc.base_imponible),
          iva: _num(doc.iva),
          total: _num(doc.total),
          lineas: doc.lineas || [],
          observaciones: doc.observaciones || null,
          file_url: _recFileUrl,
          user_id: currentUser?.id || null
        };
        // v107AZ: RED DE SEGURIDAD del proveedor. Si la IA puso una de NUESTRAS
        // empresas como proveedor (error real: confunde el destinatario con el
        // emisor), lo marcamos para revisar — el proveedor real es otro (el del
        // logo de la marca de recambios). NO lo borramos (perderíamos el dato),
        // pero avisamos claramente para que Juan Carlos lo corrija a mano.
        {
          const _p = String(reg.proveedor || '').toLowerCase();
          const _nuestras = /transportes\s*y\s*portes\s*2014|transportes\s*hispalis\s*2016|transmargaz|^typ\s*2014$/i;
          const _nifNuestro = /b\s*90172735|b\s*90286337|b\s*67316752/i.test(String(reg.proveedor_nif || ''));
          if (_p && (_nuestras.test(_p) || _nifNuestro)) {
            console.warn('[v107AZ recambios] proveedor mal leído como NUESTRA empresa ("' + reg.proveedor + '") → marcado para revisar');
            reg.observaciones = (reg.observaciones ? reg.observaciones + ' · ' : '')
              + '⚠️ REVISAR PROVEEDOR: la IA leyó "' + reg.proveedor + '" (somos nosotros, el cliente). El proveedor real es la marca del logo.';
          }
        }
        // v107AL: detectar duplicado (mismo proveedor + nº documento + empresa + tipo).
        // Avisa y deja decidir; si el usuario cancela, se salta este documento.
        if (reg.num_documento && reg.proveedor) {
          const dupNum = _recambNorm(reg.num_documento);
          const dupProv = _recambNorm(reg.proveedor);
          const yaExiste = recambiosDocs.some(x =>
            x.tipo_doc === reg.tipo_doc &&
            x.empresa === reg.empresa &&
            _recambNorm(x.num_documento) === dupNum &&
            _recambNorm(x.proveedor) === dupProv
          );
          if (yaExiste) {
            const segir = confirm(`⚠️ Ya existe un ${reg.tipo_doc} con nº "${reg.num_documento}" de "${reg.proveedor}" en ${reg.empresa}.\n\n¿Subirlo igualmente? (Cancelar = saltar este documento)`);
            if (!segir) { continue; }
          }
        }
        const { error } = await sb.from('recambios_albaranes').insert(reg);
        if (error) throw error;
        ok++;
      }
    } catch (e) {
      console.error('[recambiosSubir]', f.name, e);
      err++;
    }
  }
  if (colaBox) {
    colaBox.innerHTML = `<div style="background:${err ? 'rgba(255,140,0,.08)' : 'rgba(0,232,122,.06)'};border:1px solid ${err ? 'rgba(255,140,0,.3)' : 'rgba(0,232,122,.25)'};border-radius:8px;padding:10px 14px;font-family:var(--mn);font-size:12px;color:var(--fg)">✅ ${ok} guardados${err ? ` · ⚠️ ${err} con error (revisar consola)` : ''}</div>`;
    setTimeout(() => { colaBox.style.display = 'none'; }, 6000);
  }
  toast(`Recambios: ${ok} guardados${err ? `, ${err} con error` : ''}`, err ? 'warn' : 'ok');
  // Limpiar inputs
  ['recambiosFileAlb','recambiosFileFac'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
  await loadRecambiosData();
}

function _fileToB64(file) {
  return new Promise((res, rej) => {
    const r = new FileReader();
    r.onload = () => res(String(r.result).split(',')[1]);
    r.onerror = () => rej(new Error('No se pudo leer el archivo'));
    r.readAsDataURL(file);
  });
}
function _num(v) {
  if (v == null || v === '') return null;
  // v107AL: si la IA ya devuelve un número JSON (ej. 320.37), usarlo TAL CUAL.
  // El bug anterior quitaba el punto decimal y convertía 320.37 en 32037.
  if (typeof v === 'number') return isNaN(v) ? null : v;
  let s = String(v).trim().replace(/[€\s]/g, '');
  // Detectar formato: si tiene coma Y punto, el último separador es el decimal.
  const tieneComa = s.includes(','), tienePunto = s.includes('.');
  if (tieneComa && tienePunto) {
    // Formato español "1.234,56" → el punto es miles, la coma decimal
    if (s.lastIndexOf(',') > s.lastIndexOf('.')) s = s.replace(/\./g, '').replace(',', '.');
    // Formato inglés "1,234.56" → la coma es miles, el punto decimal
    else s = s.replace(/,/g, '');
  } else if (tieneComa) {
    // Solo coma → decimal español "320,37"
    s = s.replace(',', '.');
  }
  // Solo punto o sin separadores → ya está en formato parseable
  s = s.replace(/[^\d.-]/g, '');
  const n = parseFloat(s);
  return isNaN(n) ? null : n;
}
function _recambiosFecha(f) {
  if (!f) return null;
  // admite DD/MM/YYYY o DD/MM/YY o YYYY-MM-DD
  const s = String(f).trim();
  let m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/);
  if (m) {
    let y = m[3]; if (y.length === 2) y = '20' + y;
    return `${y}-${m[2].padStart(2,'0')}-${m[1].padStart(2,'0')}`;
  }
  m = s.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (m) return `${m[1]}-${m[2]}-${m[3]}`;
  return null;
}

// IA: lee un albarán o factura de recambios y devuelve estructura JSON
async function callClaudeRecambio(b64, mediaType, key, isPdf) {
  if (!b64 || typeof b64 !== 'string' || b64.length < 100) {
    throw new Error('Archivo vacío o corrupto — vuelve a subirlo');
  }
  const prompt = `Eres un OCR experto en albaranes y facturas de RECAMBIOS de automoción/camión en España (proveedores como Zona Franca Alari Sepauto/IVECO, Autosur de Levante, IVECO Auto Distribución, LARAUTO, RS TURIA, y otros).

${isPdf ? 'El PDF puede tener VARIAS PÁGINAS. Si es UN único documento de varias páginas (una factura larga), devuelve UN SOLO objeto JSON juntando TODAS las líneas de todas las páginas. Si hay documentos DISTINTOS, devuelve un ARRAY con un objeto por documento.' : 'Devuelve UN objeto JSON (no array).'}

Determina primero el TIPO de documento:
- "factura": pone la palabra FACTURA, tiene Nº Factura, base imponible, IVA y TOTAL FACTURA. Suele agrupar varios albaranes dentro.
- "albaran": es un albarán/nota de entrega individual (puede o no traer precios), no tiene IVA desglosado.
- "abono": es un abono/nota de crédito/devolución (importes en negativo o pone ABONO).

Campos a extraer (JSON):
{
  "tipo_detectado": "albaran" | "factura" | "abono",
  "proveedor": "nombre del proveedor que EMITE el documento (ej: LARAUTO S.A., RS TURIA, Zona Franca Alari Sepauto S.A., Autosur de Levante S.A., IVECO Auto Distribución)",
  "proveedor_nif": "CIF del proveedor emisor (ej: A58685892). NO el del cliente B90172735/B90286337",
  "num_documento": "nº de la factura o del albarán (ej: F/000603, R12600399, FB01224, 2026006075)",
  "fecha": "DD/MM/YYYY del documento",
  "base_imponible": número (base imponible / suma sin IVA). Punto decimal con coma española.,
  "iva": número (cuota de IVA en euros, NO el porcentaje),
  "total": número (TOTAL del documento con IVA),
  "observaciones": "texto corto si hay algo relevante escrito (ej: nombre a mano, 'POR RUTA'), o null",
  "lineas": [
    {
      "albaran": "nº de albarán al que pertenece esta línea, SI el documento es una factura que agrupa albaranes y lo indica (ej: C12603354, AR 445865, 2026/004197). Si es un albarán suelto, repite su propio número. Si no hay, null",
      "codigo": "referencia/código del artículo (ej: 5801269683, AS40253131, N908613). Si no hay, null",
      "descripcion": "descripción del artículo (ej: RADIADOR/CALEFA, FILTRO ACEITE, JUNTA)",
      "cantidad": número (unidades),
      "precio": número (precio unitario sin IVA),
      "dto": número (porcentaje de descuento, 0 si no hay),
      "importe": número (importe de la línea = total de esa línea)
    }
  ]
}

IMPORTANTE:
- ⚠️ PROVEEDOR (CRÍTICO, error real detectado): el proveedor es SIEMPRE quien EMITE y FACTURA el documento — es el del LOGO/CABECERA de arriba (ej. "RS TURIA", "LARAUTO", "Autosur de Levante", "IVECO Auto Distribución", "Zona Franca Alari Sepauto"). NUNCA es "TRANSPORTES Y PORTES 2014, S.L." ni "TRANSPORTES HISPALIS 2016" ni "TRANSMARGAZ" — esas SOMOS NOSOTROS, el CLIENTE que recibe el recambio, aunque aparezcan en un recuadro grande en la zona del destinatario. Señal infalible: si el CIF junto a ese nombre es B90172735, B90286337 o B67316752, ESE es el cliente (nosotros), NO el proveedor. El proveedor es el OTRO nombre, el del logo de la marca de recambios. Ejemplo real: en un albarán onde el logo pone "RS TURIA - RECAMBIOS Y ACCESORIOS" y a la derecha hay un recuadro con "TRANSPORTES Y PORTES 2014, S.L. ... CIF B90172735", el proveedor es "RS TURIA" (NUNCA "Transportes y Portes 2014").
- Lee CADA línea con su cantidad, precio y descuento. La cantidad es CRÍTICA (es lo que el usuario quiere verificar).
- Para facturas que agrupan albaranes (como Zona Franca/IVECO o IVECO Auto Distribución): asocia cada línea a su nº de albarán (campo "albaran" de cada línea). El nº de albarán aparece como "Nº Albaran C12603354" o "ALBARÁN Nº. 01141" o "Albarán AR 445865" antes de su grupo de líneas.
- Números en formato español: "1.126,47" = 1126.47. "33,900" = 33.90. DEVUELVE los números como NÚMERO JSON con punto decimal (ej: 320.37, 1126.47, 33.90), NUNCA como texto con coma ni con separador de miles. El total de "320,37 €" debe devolverse como 320.37 (NO 32037).
- Si un dato no aparece, pon null. NO inventes.
- Devuelve SOLO el JSON, sin texto adicional ni markdown.`;

  const contentBlock = isPdf
    ? { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: b64 } }
    : { type: 'image', source: { type: 'base64', media_type: mediaType, data: b64 } };

  const res = await fetchAnthropicConReintento(
    { model: 'claude-haiku-4-5', max_tokens: 8000, messages: [{ role: 'user', content: [contentBlock, { type: 'text', text: prompt }] }] },
    key, null, 'callClaudeRecambio'
  );
  if (!res.ok) {
    const e = await res.json().catch(() => ({}));
    const err = new Error(e.error?.message || `HTTP ${res.status}`);
    err.status = res.status;
    throw err;
  }
  const d = await res.json();
  const text = d.content.map(x => x.text || '').join('').trim().replace(/```json|```/g, '').trim();
  return JSON.parse(text);
}

// Modal de detalle de un documento de recambios
function recambiosVerDetalle(id) {
  const d = recambiosDocs.find(x => x.id === id);
  if (!d) return;
  const lineas = d.lineas || [];
  const fecha = d.fecha ? d.fecha.split('-').reverse().join('/') : '—';
  const tipoTxt = d.tipo_doc === 'factura' ? '🧾 FACTURA' : d.tipo_doc === 'abono' ? '↩️ ABONO' : '📦 ALBARÁN';
  const lineasHtml = lineas.length ? lineas.map(l => `
    <tr>
      <td style="font-size:10px;font-family:var(--mn)">${esc(l.albaran || '—')}</td>
      <td style="font-size:10px;font-family:var(--mn)">${esc(l.codigo || '—')}</td>
      <td style="font-size:11px">${esc(l.descripcion || '—')}</td>
      <td style="font-size:11px;text-align:right">${l.cantidad != null ? l.cantidad : '—'}</td>
      <td style="font-size:11px;text-align:right">${l.precio != null ? Number(l.precio).toFixed(2) : '—'}</td>
      <td style="font-size:11px;text-align:right">${l.dto ? l.dto + '%' : '—'}</td>
      <td style="font-size:11px;text-align:right">${l.importe != null ? Number(l.importe).toFixed(2) : '—'}</td>
    </tr>`).join('') : '<tr><td colspan="7" style="text-align:center;color:var(--mu);font-size:11px;padding:14px">Sin líneas leídas</td></tr>';

  document.getElementById('recambiosDetTitulo').textContent = `${tipoTxt} · ${d.proveedor || ''} · ${d.num_documento || ''}`;
  document.getElementById('recambiosDetBody').innerHTML = `
    <div style="display:flex;gap:14px;flex-wrap:wrap;margin-bottom:14px;font-family:var(--mn);font-size:12px;color:var(--mu)">
      <span>Proveedor: <b style="color:var(--fg)">${esc(d.proveedor || '—')}</b></span>
      <span>NIF: <b style="color:var(--fg)">${esc(d.proveedor_nif || '—')}</b></span>
      <span>Nº: <b style="color:var(--fg)">${esc(d.num_documento || '—')}</b></span>
      <span>Fecha: <b style="color:var(--fg)">${fecha}</b></span>
      <span>Empresa: <b style="color:var(--fg)">${esc(d.empresa || '—')}</b></span>
    </div>
    <div style="display:flex;gap:18px;flex-wrap:wrap;margin-bottom:14px;font-family:var(--mn);font-size:12px">
      <span>Base: <b>${d.base_imponible != null ? d.base_imponible.toFixed(2) + '€' : '—'}</b></span>
      <span>IVA: <b>${d.iva != null ? d.iva.toFixed(2) + '€' : '—'}</b></span>
      <span>Total: <b style="color:var(--ac)">${d.total != null ? d.total.toFixed(2) + '€' : '—'}</b></span>
    </div>
    ${d.observaciones ? `<div style="font-size:11px;color:var(--mu);margin-bottom:10px">📝 ${esc(d.observaciones)}</div>` : ''}
    ${d.file_url ? `<div style="margin-bottom:14px">
      <a href="${esc(d.file_url)}" target="_blank" rel="noopener" class="btn bp" style="padding:7px 14px;font-size:11px;text-decoration:none;display:inline-block">📄 Ver / descargar albarán</a>
    </div>` : `<div style="font-size:11px;color:var(--mu);margin-bottom:14px">📄 (Sin archivo guardado — documento subido antes de la v107BA)</div>`}
    <div style="overflow-x:auto">
      <table class="tbl">
        <thead><tr>
          <th style="font-size:10px">Albarán</th><th style="font-size:10px">Código</th>
          <th style="font-size:10px">Descripción</th><th style="font-size:10px;text-align:right">Cant</th>
          <th style="font-size:10px;text-align:right">Precio</th><th style="font-size:10px;text-align:right">Dto</th>
          <th style="font-size:10px;text-align:right">Importe</th>
        </tr></thead>
        <tbody>${lineasHtml}</tbody>
      </table>
    </div>`;
  // Botón eliminar: admin siempre; TALLER solo sus albaranes; Transmargaz sus docs
  const btnDel = document.getElementById('recambiosDetBtnDel');
  if (btnDel) btnDel.onclick = () => recambiosEliminar(d.id);
  document.getElementById('ovRecambiosDet').classList.add('open');
}
function closeRecambiosDet() { document.getElementById('ovRecambiosDet').classList.remove('open'); }

async function recambiosEliminar(id) {
  if (!confirm('¿Eliminar este documento de recambios?')) return;
  try {
    const { error } = await sb.from('recambios_albaranes').delete().eq('id', id);
    if (error) throw error;
    toast('Documento eliminado', 'ok');
    closeRecambiosDet();
    await loadRecambiosData();
  } catch (e) { toast('Error: ' + (e.message || e), 'err'); }
}

// ============================================================
// RECAMBIOS Fase 2 (v107AL) — conciliación factura ↔ albaranes
// Solo admin. Cruza una factura con los albaranes del mismo
// proveedor (por nº de albarán; si no hay, por proveedor+fecha)
// y compara línea a línea (referencia o descripción; cantidad y
// precio; margen ±0,02€ para ignorar redondeos).
// ============================================================
const RECAMB_MARGEN = 0.02;

function _recambNorm(s) {
  return String(s || '').toUpperCase().replace(/[\s.\-_/]/g, '').trim();
}

async function recambiosConciliar(facturaId) {
  const factura = recambiosDocs.find(d => d.id === facturaId);
  if (!factura) { toast('Factura no encontrada', 'err'); return; }
  if (factura.tipo_doc !== 'factura') { toast('Solo se concilian facturas', 'err'); return; }

  // Traer TODOS los albaranes de la misma empresa (no filtrados por privacidad,
  // admin los ve todos) para cruzarlos con la factura.
  let albaranes = [];
  try {
    const { data, error } = await sb.from('recambios_albaranes')
      .select('*')
      .eq('empresa', factura.empresa)
      .eq('tipo_doc', 'albaran');
    if (error) throw error;
    albaranes = data || [];
  } catch (e) {
    toast('Error cargando albaranes: ' + (e.message || e), 'err');
    return;
  }

  // Filtrar albaranes del MISMO proveedor (comparación flexible)
  const provFac = _recambNorm(factura.proveedor);
  const albProv = albaranes.filter(a => {
    const p = _recambNorm(a.proveedor);
    return p && provFac && (p.includes(provFac) || provFac.includes(p) || p === provFac);
  });

  // Construir índice de líneas de la factura agrupadas por nº de albarán
  const lineasFac = (factura.lineas || []).map(l => ({ ...l, _alb: _recambNorm(l.albaran) }));
  const numsAlbEnFactura = [...new Set(lineasFac.map(l => l._alb).filter(Boolean))];

  const informe = { ok: [], avisos: [], albNoEnFactura: [], albNoSubidos: [] };

  // Para cada albarán que tengo subido, buscar su correspondencia en la factura
  const albCruzados = new Set();
  for (const alb of albProv) {
    const numAlb = _recambNorm(alb.num_documento);
    // Líneas de la factura que pertenecen a este albarán (por nº)
    let lineasDeEste = numAlb ? lineasFac.filter(l => l._alb && (l._alb === numAlb || l._alb.includes(numAlb) || numAlb.includes(l._alb))) : [];
    // Si la factura no trae nº de albarán, cruzar por proveedor+fecha
    let modoCruce = 'nº albarán';
    if (!lineasDeEste.length && !numsAlbEnFactura.length) {
      lineasDeEste = lineasFac;  // factura sin desglose por albarán → comparar todo
      modoCruce = 'proveedor+fecha';
    }
    if (!lineasDeEste.length) {
      informe.albNoEnFactura.push({ alb, motivo: `Albarán ${alb.num_documento || '?'} no aparece en la factura` });
      continue;
    }
    albCruzados.add(numAlb);

    // Comparar cada línea del albarán con las de la factura
    for (const lAlb of (alb.lineas || [])) {
      const refA = _recambNorm(lAlb.codigo);
      const descA = _recambNorm(lAlb.descripcion);
      // Emparejar: primero por referencia, si no por descripción
      let match = lineasDeEste.find(lF => refA && _recambNorm(lF.codigo) === refA);
      if (!match) match = lineasDeEste.find(lF => descA && _recambNorm(lF.descripcion) === descA);
      if (!match) {
        informe.avisos.push(`⚠️ ${alb.num_documento || ''}: "${lAlb.descripcion || lAlb.codigo || '?'}" del albarán NO aparece en la factura`);
        continue;
      }
      // Comparar cantidad
      const cantA = Number(lAlb.cantidad) || 0;
      const cantF = Number(match.cantidad) || 0;
      if (Math.abs(cantA - cantF) > 0.001) {
        informe.avisos.push(`⚠️ ${alb.num_documento || ''} · ${lAlb.descripcion || lAlb.codigo}: cantidad albarán ${cantA} vs factura ${cantF}`);
      }
      // Comparar precio unitario (con margen ±0,02€)
      const pA = Number(lAlb.precio);
      const pF = Number(match.precio);
      if (!isNaN(pA) && !isNaN(pF) && Math.abs(pA - pF) > RECAMB_MARGEN) {
        informe.avisos.push(`⚠️ ${alb.num_documento || ''} · ${lAlb.descripcion || lAlb.codigo}: precio albarán ${pA.toFixed(2)}€ vs factura ${pF.toFixed(2)}€`);
      }
    }
    if (!informe.avisos.some(a => a.includes(alb.num_documento || '\u0000'))) {
      informe.ok.push(`✅ ${alb.num_documento || '?'} (${(alb.lineas || []).length} líneas) cuadra`);
    }
  }

  // Albaranes que están en la factura pero NO los subí
  for (const numF of numsAlbEnFactura) {
    const subido = albProv.some(a => {
      const n = _recambNorm(a.num_documento);
      return n && (n === numF || n.includes(numF) || numF.includes(n));
    });
    if (!subido) {
      informe.albNoSubidos.push(numF);
    }
  }

  // v107AL: CARGOS FANTASMA — líneas de la factura que NO casan con ninguna
  // línea de ningún albarán subido (ni por referencia ni por descripción).
  informe.fantasma = [];
  // Reunir todas las líneas de todos los albaranes del proveedor
  const todasLineasAlb = [];
  albProv.forEach(a => (a.lineas || []).forEach(l => todasLineasAlb.push(l)));
  for (const lF of lineasFac) {
    const refF = _recambNorm(lF.codigo);
    const descF = _recambNorm(lF.descripcion);
    const casa = todasLineasAlb.some(lA =>
      (refF && _recambNorm(lA.codigo) === refF) ||
      (descF && _recambNorm(lA.descripcion) === descF)
    );
    if (!casa && (refF || descF)) {
      const imp = lF.importe != null ? ` (${Number(lF.importe).toFixed(2)}€)` : '';
      informe.fantasma.push(`💸 "${lF.descripcion || lF.codigo || '?'}"${imp} está en la factura pero NO viene de ningún albarán subido`);
    }
  }

  // v107AL: verificar que el TOTAL de la factura cuadra (base + IVA = total)
  informe.totalCuadra = null;
  if (factura.base_imponible != null && factura.iva != null && factura.total != null) {
    const calc = factura.base_imponible + factura.iva;
    informe.totalCuadra = Math.abs(calc - factura.total) <= 0.05;
    if (!informe.totalCuadra) {
      informe.avisos.push(`⚠️ El total de la factura no cuadra: base ${factura.base_imponible.toFixed(2)}€ + IVA ${factura.iva.toFixed(2)}€ = ${calc.toFixed(2)}€, pero la factura pone ${factura.total.toFixed(2)}€`);
    }
  }

  _recambiosMostrarInforme(factura, informe, albProv.length);

  // Marcar la factura como conciliada (revisada)
  try {
    await sb.from('recambios_albaranes')
      .update({ conciliado: true, updated_at: new Date().toISOString() })
      .eq('id', facturaId);
    await loadRecambiosData();
  } catch (e) { console.warn('[recambiosConciliar] no se pudo marcar conciliado:', e); }
}

function _recambiosMostrarInforme(factura, inf, totalAlbProv) {
  const fantasma = inf.fantasma || [];
  const hayProblemas = inf.avisos.length || inf.albNoEnFactura.length || inf.albNoSubidos.length || fantasma.length;
  const cab = hayProblemas
    ? `<div style="background:rgba(255,140,0,.10);border:1px solid #ff9500;border-radius:6px;padding:12px;margin-bottom:14px;font-size:13px;color:#fff">⚠️ <b>Hay diferencias que revisar</b> entre la factura y tus albaranes.</div>`
    : `<div style="background:rgba(0,232,122,.10);border:1px solid var(--ac);border-radius:6px;padding:12px;margin-bottom:14px;font-size:13px;color:#fff">✅ <b>Todo cuadra.</b> La factura coincide con los albaranes subidos.</div>`;

  const seccion = (titulo, items, color) => items.length ? `
    <div style="margin-bottom:14px">
      <div style="font-family:var(--mn);font-size:12px;color:${color};margin-bottom:6px;font-weight:bold">${titulo} (${items.length})</div>
      <div style="display:flex;flex-direction:column;gap:4px">
        ${items.map(t => `<div style="font-size:12px;color:var(--fg);line-height:1.4;padding:4px 8px;background:rgba(255,255,255,.02);border-radius:4px">${esc(typeof t === 'string' ? t : t.motivo)}</div>`).join('')}
      </div>
    </div>` : '';

  document.getElementById('recambiosInfTitulo').textContent = `🔍 Conciliación · ${factura.proveedor || ''} · ${factura.num_documento || ''}`;
  document.getElementById('recambiosInfBody').innerHTML = `
    ${cab}
    <div style="display:flex;gap:18px;flex-wrap:wrap;margin-bottom:14px;font-family:var(--mn);font-size:12px;color:var(--mu)">
      <span>Factura total: <b style="color:var(--ac)">${factura.total != null ? factura.total.toFixed(2) + '€' : '—'}</b></span>
      <span>Albaranes del proveedor cruzados: <b style="color:var(--fg)">${totalAlbProv}</b></span>
      ${inf.totalCuadra === true ? '<span style="color:var(--ac)">✅ Total factura cuadra</span>' : inf.totalCuadra === false ? '<span style="color:#ff5050">⚠️ Total factura NO cuadra</span>' : ''}
    </div>
    ${seccion('✅ Albaranes que cuadran', inf.ok, 'var(--ac)')}
    ${seccion('💸 Cargos en la factura SIN albarán (revisar bien)', fantasma, '#ff5050')}
    ${seccion('⚠️ Diferencias detectadas', inf.avisos, '#ff9500')}
    ${seccion('⚠️ Albaranes en la factura que NO subiste', inf.albNoSubidos.map(n => `Falta subir el albarán ${n} (está en la factura)`), '#ff9500')}
    ${seccion('⚠️ Albaranes subidos que NO están en la factura', inf.albNoEnFactura, '#ff9500')}
    ${!inf.ok.length && !hayProblemas ? '<div style="font-size:12px;color:var(--mu)">No se encontraron albaranes de este proveedor para cruzar. Sube primero los albaranes del mes.</div>' : ''}
    <div style="margin-top:14px;font-size:11px;color:var(--mu);line-height:1.5;border-top:1px solid var(--bd);padding-top:10px">
      ℹ️ La IA señala posibles diferencias para que las revises tú. Margen de ±0,02€ aplicado (ignora redondeos). Verifica siempre el documento original antes de reclamar.
    </div>`;
  document.getElementById('ovRecambiosInf').classList.add('open');
}
function closeRecambiosInf() { document.getElementById('ovRecambiosInf').classList.remove('open'); }

// ============================================================
// v107FI (28/05/2026): LECTOR DE AUTOFACTURAS CEMEX
// ------------------------------------------------------------
// Sube el PDF de la preliquidación CEMEX, la IA lee cada línea y
// la cruza con los albaranes que el usuario ve (records → respeta
// privacidad RLS). Resultado en 3 grupos:
//   🟢 ABONADOS        → albarán en app Y en autofactura (se marca facturado)
//   ⚠️ NO ABONADOS     → albarán en app pero NO en la autofactura
//   📋 ABONADOS S/ALB. → línea pagada sin albarán nuestro (solo Excel)
// Si cuadra el nº pero baila un dato → 🟢 + nota "coincide todo menos X".
// CEMEX cruza por: nº albarán (principal) + fecha/TN/matrícula de apoyo.
// ============================================================

// Estado del último cruce (para el botón Excel del modal).
let _factAutoUltimo = null;

// J21: ACUMULADOR de líneas de autofactura. Como hay varias autofacturas por mes
// (Hispalis, TYP2014, Portes…), las vamos juntando aquí según se suben, deduplicadas
// por nº de albarán. Así el informe muestra SIEMPRE el cuadro completo (todos los
// abonados, todos los "que no tenemos", todos los no abonados), no solo la última.
// Se vacía al refrescar la página (para empezar un mes nuevo, refresca y vuelve a subir).
let _factAutoLineasAcum = [];   // portes acumulados
let _factAutoFicheros = [];     // nombres de los PDF subidos esta sesión
let _factAutoArchivos = [];     // J28: [{fichero, n}] cargados del mes (para mostrar la lista)
let _factAutoAjustesAcum = [];  // J23: ajustes acumulados (sábados, repercusión gasoil…)

// J23: clave para no duplicar ajustes (misma matrícula + scd + importe).
function _factAjusteKey(L) {
  return _factNormMat(L && L.matricula) + '|' + String((L && L.scd) || '') + '|' + (L ? _factNum(L.importe) : '');
}

// J24: ===== AUTOFACTURAS GUARDADAS POR MES (tabla autofacturas_lineas) =====
let _factMesActual = '';   // mes que se está viendo, ej "2026-05"

// J26: convertir bytes (Uint8Array) a base64, por trozos para no petar la pila.
function _uint8ToBase64(u8) {
  let bin = '';
  const chunk = 0x8000;
  for (let i = 0; i < u8.length; i += chunk) {
    bin += String.fromCharCode.apply(null, u8.subarray(i, i + chunk));
  }
  return btoa(bin);
}

// J26: leer una autofactura. Si tiene muchas páginas, la parte en TROZOS de pocas
// páginas, lee cada trozo con la IA y junta el resultado. Así no se corta nunca,
// por muy extensa que sea (Holcim: 7 autofacturas, alguna de 40+ páginas).
async function _leerAutofacturaGrande(file, key, lector, setEstado) {
  const PAG = 4;            // v107J36: páginas por trozo (antes 8). Trozos más pequeños = respuesta IA más corta = no se corta nunca.
  const UMBRAL = 6;         // v107J36: a partir de aquí, partir (antes 10). Las liquidaciones densas de arena (cientos de líneas) saturaban el trozo de 8 págs.
  window._factPartesFallidas = [];
  // 1) Intentar abrir el PDF para partirlo.
  let src = null, total = 0;
  try {
    if (window.PDFLib && file) {
      const buf = await file.arrayBuffer();
      src = await window.PDFLib.PDFDocument.load(buf, { ignoreEncryption: true });
      total = src.getPageCount();
    }
  } catch (e) {
    console.warn('[J34] no pude abrir el PDF para partirlo, lo leo entero:', e);
    src = null;
  }
  // 2) Si es largo, leer POR TROZOS. Cada trozo es independiente: si uno falla,
  //    se reintenta y, si aun así no se puede, se SIGUE con los demás (no se pierde el resto).
  if (src && total > UMBRAL) {
    const nTrozos = Math.ceil(total / PAG);
    let todas = [];
    const fallidos = [];
    for (let i = 0, parte = 1; i < total; i += PAG, parte++) {
      if (setEstado) setEstado('⏳ Leyendo parte ' + parte + ' de ' + nTrozos + ' (PDF de ' + total + ' páginas)…');
      // 2a) preparar el trozo (PDF de pocas páginas)
      let b64trozo = null;
      try {
        const out = await window.PDFLib.PDFDocument.create();
        const idx = [];
        for (let p = i; p < Math.min(i + PAG, total); p++) idx.push(p);
        const pgs = await out.copyPages(src, idx);
        pgs.forEach(pg => out.addPage(pg));
        const bytes = await out.save();
        b64trozo = _uint8ToBase64(bytes);
      } catch (e) {
        console.warn('[J34] no pude preparar la parte ' + parte + ':', e);
        fallidos.push(parte);
        continue;
      }
      // 2b) leer el trozo con hasta 3 intentos; si todos fallan, anotar y seguir.
      let leido = null;
      for (let intento = 1; intento <= 3 && leido === null; intento++) {
        try {
          leido = await lector(b64trozo, key);
        } catch (e) {
          console.warn('[J34] fallo leyendo la parte ' + parte + ' (intento ' + intento + '):', e);
          if (intento < 3) {
            if (setEstado) setEstado('⏳ Reintentando parte ' + parte + ' de ' + nTrozos + '… (intento ' + (intento + 1) + ')');
            await new Promise(r => setTimeout(r, 1500));
          }
        }
      }
      if (leido === null) fallidos.push(parte);
      else todas = todas.concat(leido);
    }
    window._factPartesFallidas = fallidos;
    // v107J37: separar el objeto de control (_control) de las líneas reales.
    window._factControl = null;
    const limpias = [];
    for (const x of todas) {
      if (x && x._control === true) { window._factControl = x; }
      else { limpias.push(x); }
    }
    return limpias;
  }
  // 3) PDF pequeño (o pdf-lib no disponible) → leer entero, como siempre.
  window._factControl = null;
  const b64 = await new Promise((res, rej) => {
    const r = new FileReader();
    r.onload = () => res(((r.result || '') + '').split(',')[1] || '');
    r.onerror = () => rej(new Error('No se pudo leer el PDF'));
    r.readAsDataURL(file);
  });
  const leidoEntero = await lector(b64, key);
  const limpiasEntero = [];
  for (const x of (leidoEntero || [])) {
    if (x && x._control === true) { window._factControl = x; }
    else { limpiasEntero.push(x); }
  }
  return limpiasEntero;
}

// Mes a partir de las fechas de las líneas (el más repetido) → "YYYY-MM".
function _factMesDeLineas(lineas) {
  const cuenta = {};
  (lineas || []).forEach(L => {
    const f = normFecha(L.fecha); // DD/MM/YYYY
    const m = f.match(/^\d{1,2}\/(\d{2})\/(\d{4})$/);
    if (m) { const k = m[2] + '-' + m[1]; cuenta[k] = (cuenta[k] || 0) + 1; }
  });
  let best = '', n = -1;
  for (const k in cuenta) if (cuenta[k] > n) { n = cuenta[k]; best = k; }
  return best;
}

// Mes a partir del nombre del PDF (ej "...2026 May_Preliquidación...") → "YYYY-MM".
function _factMesDeFichero(nombre) {
  if (!nombre) return '';
  const t = String(nombre).toLowerCase();
  const anio = (t.match(/20\d{2}/) || [])[0];
  const meses = { ene: '01', enero: '01', feb: '02', febrero: '02', mar: '03', marzo: '03', abr: '04', abril: '04', may: '05', mayo: '05', jun: '06', junio: '06', jul: '07', julio: '07', ago: '08', agosto: '08', sep: '09', sept: '09', septiembre: '09', oct: '10', octubre: '10', nov: '11', noviembre: '11', dic: '12', diciembre: '12' };
  let mm = '';
  for (const k in meses) { if (new RegExp('\\b' + k).test(t)) { mm = meses[k]; break; } }
  return (anio && mm) ? (anio + '-' + mm) : '';
}

// "2026-05" → "Mayo 2026".
function _factMesBonito(m) {
  if (!m || m === 'sin-mes') return 'Sin mes';
  const p = String(m).split('-');
  const nom = ['', 'Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'];
  return (nom[parseInt(p[1], 10)] || p[1]) + ' ' + p[0];
}

// J31: ¿ya hay una autofactura subida con ESTE nombre de fichero y proveedor?
// Devuelve cuántas líneas tiene (0 = no está). Rápido: solo cuenta, no trae filas.
async function _factYaSubida(fichero, proveedor) {
  try {
    const r = await sb.from('autofacturas_lineas')
      .select('fichero', { count: 'exact', head: true })
      .eq('fichero', fichero).eq('proveedor', proveedor);
    if (r.error) { console.warn('[J31] comprobar duplicado:', r.error); return 0; }
    return r.count || 0;
  } catch (e) { console.warn('[J31] comprobar duplicado (exc):', e); return 0; }
}

// J30/J32: sube el PDF original de la autofactura al almacén y devuelve su enlace público.
// J32: reusa uploadFile() (la misma que ya funciona para albaranes/recambios), porque guarda
// la ruta con el id de usuario que pide la regla de seguridad de Supabase. Si falla, null.
async function _factSubirPdf(file, proveedor, mes) {
  try {
    if (!file) return null;
    return await uploadFile(file, 'autofacturas');
  } catch (e) { console.warn('[J32] subir PDF autofactura:', e); return null; }
}

// J33: trae TODAS las líneas de un mes/proveedor. Supabase devuelve máx. 1000 por consulta,
// así que pedimos por tandas de 1000 hasta traerlas todas (Holcim pasa de 2000/mes). Si no
// hiciéramos esto, faltarían archivos en la lista Y el cruce sería incompleto.
async function _factTraerLineas(mes, proveedor, cols) {
  async function tanda(orderCol) {
    let todas = [], desde = 0; const LOTE = 1000;
    for (let i = 0; i < 80; i++) { // tope de seguridad: 80.000 líneas
      const r = await sb.from('autofacturas_lineas').select(cols)
        .eq('mes', mes).eq('proveedor', proveedor)
        .order(orderCol, { ascending: true }).range(desde, desde + LOTE - 1);
      if (r.error) throw r.error;
      const lote = r.data || [];
      todas = todas.concat(lote);
      if (lote.length < LOTE) break;
      desde += LOTE;
    }
    return todas;
  }
  try { return await tanda('id'); }
  catch (e) { console.warn('[J33] sin columna id, ordeno por fichero:', e); return await tanda('fichero'); }
}

// J28: cuenta cuántas líneas tiene cada PDF cargado del mes → [{fichero, n}] ordenado.
function _factContarArchivos(data) {
  const c = {}, url = {};
  (data || []).forEach(L => {
    if (!L.fichero) return;
    c[L.fichero] = (c[L.fichero] || 0) + 1;
    if (L.fichero_url && !url[L.fichero]) url[L.fichero] = L.fichero_url;
  });
  return Object.keys(c).sort().map(f => ({ fichero: f, n: c[f], url: url[f] || null }));
}

// J29: VER SUBIDAS — lista los PDF cargados de un mes SIN cruzar nada (rápido).
// Pensado para cuando solo estás subiendo y quieres comprobar cuáles llevas / cuáles faltan.
async function factVerSubidas(mes, proveedor) {
  const esHolcim = (proveedor === 'HOLCIM');
  const estado = document.getElementById(esHolcim ? 'factHolcimEstado' : 'factAutoEstado');
  const setEstado = (h) => { if (estado) { estado.style.display = 'block'; estado.innerHTML = h; } };
  setEstado('⏳ Cargando la lista de subidas…');
  let data;
  try {
    data = await _factTraerLineas(mes, proveedor, 'fichero, fichero_url');
  } catch (e) { setEstado('❌ No pude cargar la lista: ' + (e.message || e)); return; }
  const arr = _factContarArchivos(data);
  if (!arr.length) { setEstado('No hay autofacturas guardadas de ' + _factMesBonito(mes) + '.'); return; }
  const esc = (s) => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  let h = '<div style="font-family:var(--mn);font-size:12px;line-height:1.7;margin-top:4px">';
  h += '<div style="font-weight:700;color:var(--mu);margin-bottom:4px">📎 ' + _factMesBonito(mes) + ' — ' + arr.length + ' autofacturas cargadas (sin revisar):</div>';
  arr.forEach(a => {
    const nom = a.url
      ? '<a href="' + a.url + '" target="_blank" rel="noopener" style="color:#7cc4ff;text-decoration:underline">' + esc(a.fichero) + '</a> 🔗'
      : esc(a.fichero);
    h += '<div>• ' + nom + ' <span style="color:var(--mu)">(' + a.n + ' líneas)</span></div>';
  });
  h += '</div>';
  setEstado(h);
}

// J28: bloque HTML con la lista de PDF cargados del mes (para el informe).
function _factBloqueArchivos(arr, esc) {
  if (!arr || !arr.length) return '';
  let h = '<div style="margin-bottom:16px;padding:10px 12px;background:var(--bg2,#1a1a1a);border:1px solid var(--bd);border-radius:8px">';
  h += '<div style="font-weight:700;color:var(--mu);font-size:11px;margin-bottom:6px">📎 AUTOFACTURAS CARGADAS ESTE MES (' + arr.length + ')</div>';
  h += '<div style="font-size:11px;line-height:1.7;font-family:var(--mn)">';
  arr.forEach(a => {
    const nom = a.url
      ? '<a href="' + a.url + '" target="_blank" rel="noopener" style="color:#7cc4ff;text-decoration:underline">' + esc(a.fichero) + '</a> 🔗'
      : esc(a.fichero);
    h += '<div>• ' + nom + ' <span style="color:var(--mu)">(' + a.n + ' líneas)</span></div>';
  });
  h += '</div></div>';
  return h;
}

// Guardar las líneas de UNA autofactura en la tabla. Re-subir el mismo PDF (mismo
// fichero) reemplaza sus líneas, para no duplicar.
async function _factGuardarEnTabla(lineas, mes, fichero, proveedor, ficheroUrl) {
  // v107J67 — HOLCIM: VARIOS PDF por mes y los nº de servicio semanales ("19W2026-…") los comparten
  // MUCHAS líneas distintas, así que NO se puede borrar por número ni por nombre de archivo. Solución
  // SIN RIESGO (no se borra nada): se traen las líneas ya guardadas del mes y solo se insertan las que
  // NO existan ya (misma CLAVE DE CONTENIDO: nº+fecha+matrícula+TN+concepto). Re-subir un PDF deja de
  // crear copias y nunca se pierde una línea buena. CEMEX se queda EXACTAMENTE igual (borra por archivo).
  const _claveLinea = (numero, fecha, mat, tn, concepto) =>
    [String(numero || ''), String(fecha || ''), String(mat || ''),
     (isNaN(_factNum(tn)) ? '' : _factNum(tn).toFixed(2)), String(concepto || '')].join('|');
  if ((proveedor || '') === 'HOLCIM') {
    const existentes = new Set();
    try {
      const { data } = await sb.from('autofacturas_lineas')
        .select('numero_albaran,fecha,matricula,tn,concepto').eq('proveedor', 'HOLCIM').eq('mes', mes);
      (data || []).forEach(r => existentes.add(_claveLinea(r.numero_albaran, r.fecha, r.matricula, r.tn, r.concepto)));
    } catch (e) { console.warn('[J67] no pude leer existentes:', e); }
    lineas = (lineas || []).filter(L => !existentes.has(_claveLinea(L.numero_albaran, L.fecha, L.matricula, L.tn, L.concepto)));
  } else {
    await sb.from('autofacturas_lineas').delete().eq('fichero', fichero);
  }
  const filas = (lineas || []).map(L => {
    const n = _factNormAlb(L.numero_albaran);
    const imp = _factNum(L.importe);
    const tn = _factNum(L.tn);
    return {
      mes: mes, fichero: fichero, proveedor: proveedor || 'CEMEX', fichero_url: ficheroUrl || null,
      numero_albaran: L.numero_albaran || null,
      fecha: L.fecha || null,
      // v107J76 — corrige matrícula mal leída SOLO en Holcim (encaja la inválida con la conocida por 4 dígitos)
      matricula: (proveedor === 'HOLCIM' ? _corregirMatAutof(L.matricula) : L.matricula) || null,
      origen: L.origen || null,
      destino: L.destino || null,
      tn: isNaN(tn) ? null : tn,
      importe: isNaN(imp) ? null : imp,
      scd: L.scd != null ? String(L.scd) : null,
      es_ajuste: (L.es_ajuste === true) || (!n && !isNaN(imp)),
      concepto: L.concepto || null
    };
  });
  for (let i = 0; i < filas.length; i += 200) {
    const { error } = await sb.from('autofacturas_lineas').insert(filas.slice(i, i + 200));
    if (error) throw error;
  }
}

// Pintar los botones de meses que tienen autofactura guardada.
async function factCargarMeses() {
  const cont = document.getElementById('factMesesBar');
  if (!cont) return;
  let data;
  try {
    const r = await sb.from('autofacturas_lineas').select('mes').eq('proveedor', 'CEMEX');
    if (r.error) throw r.error;
    data = r.data || [];
  } catch (e) { cont.innerHTML = '<span style="font-family:var(--mn);font-size:11px;color:var(--er)">No se pudieron cargar los meses: ' + (e.message || e) + '</span>'; return; }
  const meses = [...new Set(data.map(r => r.mes).filter(Boolean))].sort().reverse();
  if (!meses.length) {
    cont.innerHTML = '<span style="font-family:var(--mn);font-size:11px;color:var(--mu)">Aún no hay autofacturas guardadas. Sube una y aparecerá su mes aquí para revisarlo cuando quieras.</span>';
    return;
  }
  cont.innerHTML = '<span style="font-family:var(--mn);font-size:11px;color:var(--mu);margin-right:4px">Revisar mes:</span>'
    + meses.map(m => '<button class="btn bs" style="font-size:11px" onclick="factConciliarMes(\'' + m + '\')">📅 ' + _factMesBonito(m) + '</button> <button class="btn bs" style="font-size:11px;opacity:.85" onclick="factVerSubidas(\'' + m + '\',\'CEMEX\')">📎 Ver subidas</button>').join(' ');
}

// Revisar un mes: carga de la tabla TODO lo guardado de ese mes y lo cruza con tus
// albaranes del momento. NO hace falta volver a subir la autofactura.
async function factConciliarMes(mes) {
  const estado = document.getElementById('factAutoEstado');
  const setEstado = (h) => { if (estado) { estado.style.display = 'block'; estado.innerHTML = h; } };
  setEstado('⏳ Cargando autofacturas de ' + _factMesBonito(mes) + '…');
  let data;
  try {
    data = await _factTraerLineas(mes, 'CEMEX', '*');
  } catch (e) { setEstado('❌ No pude cargar el mes: ' + (e.message || e)); return; }
  if (!data.length) { setEstado('No hay autofacturas guardadas de ' + _factMesBonito(mes) + '. Sube una.'); return; }
  _factMesActual = mes;
  _factAutoLineasAcum = data.filter(L => !L.es_ajuste && _factNormAlb(L.numero_albaran));
  _factAutoAjustesAcum = data.filter(L => L.es_ajuste);
  _factAutoFicheros = [...new Set(data.map(L => L.fichero).filter(Boolean))];
  _factAutoArchivos = _factContarArchivos(data);
  _factProcesarYMostrar(setEstado);
}

// J27: ===== lo mismo pero para HOLCIM (tabla compartida, columna proveedor='HOLCIM') =====
let _factHolcimLineasAcum = [];
let _factHolcimMesActual = '';
let _factHolcimFicheros = [];
let _factHolcimArchivos = [];   // J28: [{fichero, n}] de Holcim del mes

// Pintar los botones de meses que tienen autofactura HOLCIM guardada.
async function factCargarMesesHolcim() {
  const cont = document.getElementById('factMesesBarHolcim');
  if (!cont) return;
  let data;
  try {
    const r = await sb.from('autofacturas_lineas').select('mes').eq('proveedor', 'HOLCIM');
    if (r.error) throw r.error;
    data = r.data || [];
  } catch (e) { cont.innerHTML = '<span style="font-family:var(--mn);font-size:11px;color:var(--er)">No se pudieron cargar los meses: ' + (e.message || e) + '</span>'; return; }
  const meses = [...new Set(data.map(r => r.mes).filter(Boolean))].sort().reverse();
  if (!meses.length) {
    cont.innerHTML = '<span style="font-family:var(--mn);font-size:11px;color:var(--mu)">Aún no hay liquidaciones de Holcim guardadas. Sube una y aparecerá su mes aquí para revisarlo cuando quieras.</span>';
    return;
  }
  cont.innerHTML = '<span style="font-family:var(--mn);font-size:11px;color:var(--mu);margin-right:4px">Revisar mes:</span>'
    + meses.map(m => '<button class="btn bs" style="font-size:11px" onclick="factConciliarMesHolcim(\'' + m + '\')">📅 ' + _factMesBonito(m) + '</button> <button class="btn bs" style="font-size:11px;opacity:.85" onclick="factVerSubidas(\'' + m + '\',\'HOLCIM\')">📎 Ver subidas</button>').join(' ');
}

// v107J59 — APARTADO PROMOTORA (lista para facturar; NO cruza nada). Recoge tus albaranes de áridos
// de Promsa (proveedor Promotora/Promsa/Molins + AF-/AG-, o destino "Zona Franca II"), agrupa botones
// por mes y, al pulsar uno, descarga el Excel de ese mes (transportista → matrícula → fecha).
function _esAlbPromsaArido(r) {
  const _provU = String(r.proveedor || '').toUpperCase();
  const _matU = String(r.producto || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const _destU = String(r.obra || r.destino || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const _esPromsa = /PROMOTORA\s+MEDITERR|PROMSA|MOLINS/.test(_provU);
  const _esArido = /^AF[-\s]|^AG[-\s]|ARIDO/.test(_matU) || /^A[FG]\d/.test(_matU);
  return (_esPromsa && _esArido) || /ZONA\s*FRANCA\s*II/.test(_destU);
}
function _mesDeFechaAlb(f) { const m = String(f || '').match(/^(\d{1,2})\/(\d{2})\/(\d{4})$/); return m ? (m[3] + '-' + m[2]) : ''; }
function factCargarMesesPromotora() {
  const cont = document.getElementById('factMesesBarPromotora');
  if (!cont) return;
  const proms = (records || []).filter(_esAlbPromsaArido);
  const meses = [...new Set(proms.map(r => _mesDeFechaAlb(r.fecha)).filter(Boolean))].sort().reverse();
  if (!meses.length) { cont.innerHTML = '<span style="font-family:var(--mn);font-size:11px;color:var(--mu)">Aún no hay albaranes de áridos de Promsa.</span>'; return; }
  cont.innerHTML = '<span style="font-family:var(--mn);font-size:11px;color:var(--mu);margin-right:4px">Descargar Excel del mes:</span>'
    + meses.map(m => '<button class="btn bs" style="font-size:11px" onclick="exportPromotoraExcelMes(\'' + m + '\')">📊 ' + _factMesBonito(m) + '</button>').join(' ');
}
function exportPromotoraExcelMes(mes) {
  const estado = document.getElementById('factPromotoraEstado');
  const setE = (h) => { if (estado) { estado.style.display = 'block'; estado.innerHTML = h; } };
  if (typeof XLSX === 'undefined') { setE('❌ No se pudo cargar el generador de Excel'); return; }
  const lista = (records || []).filter(r => _esAlbPromsaArido(r) && _mesDeFechaAlb(r.fecha) === mes);
  if (!lista.length) { setE('No hay áridos de Promsa en ' + _factMesBonito(mes) + '.'); return; }
  const _matKey = (s) => String(s || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
  const _fKey = (f) => { const m = String(f || '').match(/(\d{1,2})\/(\d{1,2})\/(\d{2,4})/); if (!m) return '9999-99-99'; const y = m[3].length === 2 ? ('20' + m[3]) : m[3]; return y + '-' + m[2].padStart(2, '0') + '-' + m[1].padStart(2, '0'); };
  const _tKey = (t) => String(t || '').toUpperCase().replace(/[^A-Z0-9]/g, '') || 'ZZZZ';
  const _tr = (r) => r.transportista || (typeof getTransportista === 'function' ? getTransportista(r.tractora) : '') || '';
  lista.sort((a, b) => {
    const TA = _tKey(_tr(a)), TB = _tKey(_tr(b)); if (TA < TB) return -1; if (TA > TB) return 1;
    const MA = _matKey(a.tractora), MB = _matKey(b.tractora); if (MA < MB) return -1; if (MA > MB) return 1;
    const FA = _fKey(a.fecha), FB = _fKey(b.fecha); return FA < FB ? -1 : (FA > FB ? 1 : 0);
  });
  const aoa = [];
  aoa.push(['PROMOTORA MEDITERRÁNEA — ' + _factMesBonito(mes) + ' (los facturas tú)']);
  aoa.push([]);
  aoa.push(['📋 ALBARANES (' + lista.length + ')']);
  aoa.push(['Transportista', 'Albarán', 'Matrícula', 'Fecha', 'TN', 'Material', 'Destino']);
  lista.forEach(r => aoa.push([_tr(r), r.albaran || '', r.tractora || '', r.fecha || '', r.tm || '', r.producto || '', r.obra || r.destino || '']));
  const ws = XLSX.utils.aoa_to_sheet(aoa);
  ws['!cols'] = [{ wch: 22 }, { wch: 16 }, { wch: 12 }, { wch: 12 }, { wch: 10 }, { wch: 28 }, { wch: 22 }];
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, ('Promotora ' + _factMesBonito(mes)).slice(0, 31));
  XLSX.writeFile(wb, 'Promotora_' + mes + '.xlsx');
  setE('✅ Excel de Promotora ' + _factMesBonito(mes) + ' descargado (' + lista.length + ' albaranes).');
}

// Revisar un mes de Holcim: carga lo guardado de ese mes y lo cruza con tus albaranes.
async function factConciliarMesHolcim(mes) {
  const estado = document.getElementById('factHolcimEstado');
  const setEstado = (h) => { if (estado) { estado.style.display = 'block'; estado.innerHTML = h; } };
  setEstado('⏳ Cargando liquidaciones de Holcim de ' + _factMesBonito(mes) + '…');
  let data;
  try {
    data = await _factTraerLineas(mes, 'HOLCIM', '*');
  } catch (e) { setEstado('❌ No pude cargar el mes: ' + (e.message || e)); return; }
  if (!data.length) { setEstado('No hay liquidaciones de Holcim guardadas de ' + _factMesBonito(mes) + '. Sube una.'); return; }
  _factHolcimMesActual = mes;
  _factHolcimFicheros = [...new Set(data.map(L => L.fichero).filter(Boolean))];
  _factHolcimArchivos = _factContarArchivos(data);
  // Restaurar los nombres de campo que usa el cruce/informe de Holcim.
  _factHolcimLineasAcum = data.map(r => ({
    num_entrega: r.numero_albaran, fecha: r.fecha, matricula: r.matricula,
    material: r.concepto, tn: r.tn, valor_neto: r.importe, transportista: r.destino,
    destino: r.origen || null // v107J42: destino/cliente de la línea (La Roca, Zona Franca, Montcada, Molienda Tarragona, Grao Castellón…)
  }));
  _factProcesarYMostrarHolcim(setEstado);
}

// J21: ¿son el MISMO destino aunque esté escrito distinto? CEMEX escribe la planta
// (ej "HORMIGON SANT JUST", "HORMIGON MONTCADA") y nosotros el pueblo ("Sant Just
// Desvern", "Montcada"). Quitamos palabras de relleno y comparamos el núcleo.
function _factDestinoIgual(a, b) {
  const limpia = (s) => String(s || '')
    .toUpperCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')        // quitar acentos
    .replace(/\b(HORMIGON|HORMIGO|PLANTA|FABRICA|OBRA|CANTERA|ARIDOS?|CEMENTO|DESVERN|DEL|DE|LA|EL|LOS|LAS|SILO|ES)\b/g, ' ')
    .replace(/[^A-Z0-9]/g, ' ')
    .replace(/\s+/g, ' ').trim();
  const x = limpia(a), y = limpia(b);
  if (!x || !y) return true;            // si uno está vacío, no avisamos
  if (x === y) return true;
  // coincide si comparten al menos una palabra fuerte (3+ letras)
  const px = x.split(' ').filter(w => w.length >= 3);
  const py = y.split(' ').filter(w => w.length >= 3);
  return px.some(w => py.includes(w));
}

// --- Lector IA de la autofactura CEMEX (PDF multipágina) ---
async function callClaudeAutofacturaCemex(b64, key, signal) {
  const prompt = 'Eres un OCR experto en "Reporte de Preliquidación" de CEMEX ESPAÑA OPERACIONES para transportistas en España. Es un PDF de varias páginas. CEMEX paga al transportista por cada porte.\n\n'
    + 'Devuelve SIEMPRE un ARRAY JSON. Incluye DOS tipos de objeto: (A) PORTES = líneas con Número Albarán (los viajes normales). (B) AJUSTES = líneas SIN número de albarán o con Cantidad 0 pero CON un importe (columna "Ajustes" o "Importe Total"): son cobros extra a favor del transportista (mínimos de facturación por día, repercusión del gasoil, trabajo en sábados/festivos, peajes…). Marca cada AJUSTE con "es_ajuste": true; los PORTES con "es_ajuste": false.\n\n'
    + 'Cada línea tiene estas columnas en este orden: Matrícula | Planta(origen) | Fecha Albarán | Número Albarán | Obra(destino) | Grupo Porte | Cantidad(TN) | Unidad | Importe Total | Moneda | Importe Base | ... | SCD.\n\n'
    + 'De cada línea saca:\n'
    + '- numero_albaran: el "Número Albarán", que empieza por M y tiene muchos dígitos (ej "M4690000242019" áridos, "M8480000008858" cemento). SIN espacios. Es el dato MÁS importante.\n'
    + '- fecha: la "Fecha Albarán" en formato DD/MM/YYYY (en el PDF viene como DD.MM.YYYY, conviértela con barras).\n'
    + '- matricula: la matrícula española (4 dígitos + 3 letras, ej "1437LDV"). Quita espacios.\n'
    + '- origen: el texto de "Planta" (ej "CANTERA BEGUES", "ES - Silo Portcement Alcanar").\n'
    + '- destino: el texto de "Obra" (ej "HORMIGON MONTCADA", "IN BCN ZONA FRANCA", "HORMIGON SANT JUST").\n'
    + '- tn: la Cantidad en toneladas, con punto decimal (ej 28.340).\n'
    + '- importe: el "Importe Total" en euros, con punto decimal (ej 212.55). En los AJUSTES, el importe es el número de la columna "Ajustes" (o el "Importe Total" si ese trae el valor del ajuste).\n'
    + '- scd: el código largo de la columna SCD (ej "28260687"), solo como referencia.\n'
    + '- es_ajuste: true SOLO si la línea es un ajuste (sin nº de albarán, o Cantidad 0, con importe). false en los portes normales.\n'
    + '- concepto: SOLO para los ajustes, el texto que describe el ajuste (lo que ponga en Obra/Planta/Grupo Porte de esa línea, ej "ES - Silo Portcement Alcanar"). En los portes, null.\n\n'
    + 'REGLAS IMPORTANTES:\n'
    + '- Recorre TODAS las páginas y TODAS las líneas. Puede haber decenas o cientos. No te dejes ninguna.\n'
    + '- Una misma matrícula encabeza un bloque y debajo van varias líneas: cada línea es un objeto, todas con esa matrícula hasta que cambie.\n'
    + '- AJUSTES: las líneas SIN número de albarán (o con Cantidad 0) que tengan un IMPORTE en "Ajustes" o "Importe Total" SÍ debes incluirlas, marcadas con es_ajuste:true (con su matricula, fecha si la hay, concepto, importe y scd). NO las ignores.\n'
    + '- IGNORA SIEMPRE (ni como porte ni como ajuste): las filas de totales ("Total Matrícula", "Total Cantidad", "Total Importe", "Total Ajuste"), cabeceras, pies de página y logos. Y NO incluyas como ajuste una línea cuyo único dato sea un SCD sin importe.\n'
    + '- NO te inventes números ni matrículas. Si un dato no se ve, ponlo null. En los PORTES, numero_albaran y matricula deben verse; en los AJUSTES puede no haber numero_albaran (déjalo null) pero debe haber importe.\n\n'
    + 'SOLO JSON válido (array), sin markdown ni explicaciones.';

  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'x-api-key': key, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true' },
    body: JSON.stringify({
      model: 'claude-haiku-4-5',
      max_tokens: 32000,
      messages: [{ role: 'user', content: [
        { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: b64 } },
        { type: 'text', text: prompt }
      ] }]
    }),
    signal: signal
  });
  if (!res.ok) {
    let e = {}; try { e = await res.json(); } catch (_) {}
    const err = new Error(e.error?.message || `HTTP ${res.status}`);
    err.status = res.status;
    throw err;
  }
  const d = await res.json();
  const text = d.content.map(x => x.text || '').join('').trim().replace(/```json|```/g, '').trim();
  // J25: marcar si la respuesta se cortó por tamaño (autofactura muy larga).
  window._factAutoCortada = (d.stop_reason === 'max_tokens');
  let parsed;
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    // Si el PDF es muy largo y la respuesta vino cortada, recuperar hasta el último
    // objeto completo en vez de fallar del todo (igual que en Holcim).
    const lastObj = text.lastIndexOf('}');
    if (lastObj > -1) {
      let t2 = text.slice(0, lastObj + 1);
      if (!t2.trim().startsWith('[')) t2 = '[' + t2;
      parsed = JSON.parse(t2 + ']');
      window._factAutoCortada = true;
      console.warn('[J25] respuesta CEMEX recuperada parcialmente (PDF largo).');
    } else { throw e; }
  }
  return Array.isArray(parsed) ? parsed : [parsed];
}

// Normaliza un número de albarán para comparar (mayúsculas, sin espacios ni signos).
function _factNormAlb(s) {
  return String(s || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
}
// Normaliza matrícula (sin espacios/guiones, mayúsculas).
function _factNormMat(s) {
  return String(s || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
}
// v107J76 — Corrige una matrícula MAL LEÍDA de una autofactura de Holcim. Las matrículas españolas son
// 4 dígitos + 3 CONSONANTES (sin vocales A E I O U, ni Ñ ni Q). Si la IA lee algo inválido (ej. "9295LIZ":
// la "I" es vocal → imposible), la encaja con la matrícula CONOCIDA que tenga esos MISMOS 4 dígitos, y SOLO
// si hay UNA única coincidencia. Si la matrícula leída ya es válida, se respeta tal cual. NUNCA inventa:
// si no hay una única conocida con esos dígitos, deja lo leído como está.
function _corregirMatAutof(mat) {
  const m = String(mat || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
  if (!m) return m;
  const FORMATO = /^[0-9]{4}[BCDFGHJKLMNPRSTVWXYZ]{3}$/;
  if (FORMATO.test(m)) return m;                 // ya es válida → respetar, no tocar
  const dig = m.slice(0, 4);
  if (/^[0-9]{4}$/.test(dig) && typeof TRANSPORTISTAS === 'object' && TRANSPORTISTAS) {
    const cands = Object.keys(TRANSPORTISTAS).filter(k => k.slice(0, 4) === dig && FORMATO.test(k));
    if (cands.length === 1) return cands[0];     // única conocida con esos 4 dígitos → corregir
  }
  return m;                                      // no se puede corregir con seguridad → dejar lo leído
}
// Convierte TN a número (admite coma o punto decimal).
function _factNum(s) {
  if (s === null || s === undefined) return NaN;
  let t = String(s).trim().replace(/\s/g, '');
  // si tiene coma decimal española, cambiarla a punto (y quitar separador de miles)
  if (t.indexOf(',') > -1) t = t.replace(/\./g, '').replace(',', '.');
  return parseFloat(t);
}

// --- Subir y procesar la autofactura CEMEX ---
async function factSubirAutofactura(files) {
  const file = files && files[0];
  // Limpiamos el input para poder volver a subir el mismo PDF si hace falta.
  const inp = document.getElementById('factAutoFileInput');
  if (inp) inp.value = '';
  if (!file) return;
  if (!_puedeVerFacturacion()) { toast('No tienes permiso para facturación', 'err'); return; }

  const key = getKey();
  if (!key) { toast('Falta la clave de IA (API key)', 'err'); return; }

  const estado = document.getElementById('factAutoEstado');
  const setEstado = (html) => { if (estado) { estado.style.display = 'block'; estado.innerHTML = html; } };

  // J31: si esta autofactura YA está subida (mismo nombre de fichero), no la leas otra vez
  // (ahorra tiempo e IA). Pregunta por si la quieres re-subir a propósito.
  const _fich = (file && file.name) || '';
  if (_fich) {
    const ya = await _factYaSubida(_fich, 'CEMEX');
    if (ya > 0 && !confirm('Esta autofactura ya la tienes subida:\n"' + _fich + '" (' + ya + ' líneas).\n\n¿Volver a leerla de todas formas?')) {
      setEstado('✅ No la he vuelto a leer: ya estaba subida (' + ya + ' líneas). Pulsa 📅 para revisar el mes.');
      return;
    }
  }

  setEstado('⏳ Leyendo la autofactura CEMEX… (puede tardar un poco si tiene muchas páginas)');

  // J26: leer el PDF. Si es largo, _leerAutofacturaGrande lo parte en trozos para
  // que no se corte (Holcim grandes). Si es corto, lo lee entero como siempre.
  let lineas;
  try {
    lineas = await _leerAutofacturaGrande(file, key, callClaudeAutofacturaCemex, setEstado);
  } catch (e) {
    setEstado('❌ No se pudo leer la autofactura: ' + (e.message || e));
    return;
  }
  if (!lineas || !lineas.length) {
    setEstado('⚠️ No he encontrado líneas de porte en este PDF. ¿Seguro que es una preliquidación CEMEX?');
    return;
  }
  // J34: si alguna parte del PDF no se pudo leer (tras reintentos), avisar para re-subir.
  if (window._factPartesFallidas && window._factPartesFallidas.length) {
    toast('⚠️ No pude leer la(s) parte(s) ' + window._factPartesFallidas.join(', ') + ' de este PDF. Vuelve a subirlo para completarlo.', 'err');
  }
  // J25: si la autofactura era tan larga que la lectura se cortó, avisar (se guarda lo leído).
  if (window._factAutoCortada) {
    toast('⚠️ Autofactura muy larga: leídas ' + lineas.length + ' líneas, pero puede faltar alguna del final. Si ves que falta, divide el PDF en 2 y súbelos (se acumulan en el mes).', 'err');
  }

  // J24: separar portes y ajustes de ESTA autofactura.
  const portesDoc = [], ajustesDoc = [];
  lineas.forEach(L => {
    const n = _factNormAlb(L.numero_albaran);
    const tieneImporte = (L.importe != null && String(L.importe) !== '');
    const esAjuste = (L.es_ajuste === true) || (!n && tieneImporte);
    if (esAjuste) { L.es_ajuste = true; ajustesDoc.push(L); }
    else if (n) portesDoc.push(L);
  });

  // J24: de qué MES es esta autofactura (por las fechas; si no, por el nombre del PDF).
  const mesDoc = _factMesDeLineas(lineas) || _factMesDeFichero(file && file.name) || 'sin-mes';

  // Guardar PERMANENTE en la tabla (por mes). Re-subir el mismo PDF reemplaza sus líneas.
  setEstado('⏳ Guardando la autofactura de ' + _factMesBonito(mesDoc) + '…');
  const urlPdf = await _factSubirPdf(file, 'CEMEX', mesDoc);
  try {
    await _factGuardarEnTabla(portesDoc.concat(ajustesDoc), mesDoc, (file && file.name) || ('autofactura_' + Date.now()), 'CEMEX', urlPdf);
  } catch (e) { setEstado('❌ No se pudo guardar: ' + (e.message || e)); return; }

  factCargarMeses();
  // Conciliar el MES ENTERO (carga de la tabla TODO lo de ese mes y lo cruza con tus albaranes).
  await factConciliarMes(mesDoc);
}

// J24: cruza las líneas acumuladas (cargadas de la tabla, por mes) con tus albaranes y
// muestra el informe. Lo usan la subida de una autofactura Y el botón "Revisar mes".
function _factProcesarYMostrar(setEstado) {
  setEstado = setEstado || function () {};
  const lineasTodas = _factAutoLineasAcum;

  // --- CRUCE ---
  // Índice de albaranes del usuario por número (normalizado).
  const porNum = new Map();
  records.forEach(r => {
    const n = _factNormAlb(r.albaran);
    if (n) {
      if (!porNum.has(n)) porNum.set(n, []);
      porNum.get(n).push(r);
    }
  });

  // v107FP — PASO 2: cruzar también los albaranes CEMEX VIEJOS guardados con el formato
  // antiguo "77469/242043" (de antes de que la app guardara el nº "M4690000242043" de la
  // Ref. CemexGo). El número de CEMEX y el viejo COMPARTEN la cola (la parte tras la "/"):
  //   viejo "77469/242043"  →  prefijo "77469", cola "242043"
  //   CEMEX "M4690000242043" = "M" + plant(469) + ceros + cola(242043)
  // Para cruzar SIN falsos positivos exigimos 3 candados: (a) la cola coincide (5+ dígitos),
  // (b) entre el plant y la cola del nº CEMEX solo hay ceros, (c) el prefijo viejo termina
  // en ese mismo plant (469 = Begues áridos, 848 = cemento, etc.).
  const viejosCemex = [];
  records.forEach(r => {
    const raw = String(r.albaran || '').trim();
    const m = raw.match(/^(\d+)\/(\d+)$/); // formato viejo 77469/242043
    if (m && m[2].length >= 5) {
      viejosCemex.push({ rec: r, prefijo: m[1], cola: m[2] });
    }
  });
  const _matchColaVieja = (numCemex) => {
    if (!numCemex || numCemex[0] !== 'M') return null;
    const body = numCemex.slice(1); // dígitos tras la M, ej "4690000242043"
    for (const v of viejosCemex) {
      if (!body.endsWith(v.cola)) continue;                  // (a) misma cola
      const entre = body.slice(0, body.length - v.cola.length);
      const em = entre.match(/^(\d{3})0+$/);                 // (b) plant(3) + solo ceros
      if (!em) continue;
      if (!v.prefijo.endsWith(em[1])) continue;              // (c) prefijo viejo acaba en plant
      return v.rec;
    }
    return null;
  };

  const abonados = [];      // 🟢 cruzan (con o sin notas)
  const sinAlbaran = [];    // 📋 en autofactura pero sin albarán nuestro
  const idsAbonados = new Set();

  // J22: índice de TUS albaranes CEMEX por matrícula+fecha, para RESCATAR los que no
  // cruzan por número porque el número se leyó con un dígito mal al escanear
  // (ej. tú M4690000242234 / CEMEX M4690000244234 = mismo viaje). Solo albaranes con
  // pinta de CEMEX (empiezan por M) para no cruzar por error con uno de Holcim.
  const porMatFecha = new Map();
  records.forEach(r => {
    const n = _factNormAlb(r.albaran);
    if (!/^M\d{6,}$/.test(n)) return;
    const k = _factNormMat(r.tractora) + '|' + normFecha(r.fecha);
    if (!porMatFecha.has(k)) porMatFecha.set(k, []);
    porMatFecha.get(k).push(r);
  });
  // Busca un albarán tuyo con la MISMA matrícula+fecha y TN casi igual (±0,05).
  const _matchPorMFT = (L) => {
    const mat = _factNormMat(L.matricula);
    const fec = normFecha(L.fecha);
    if (!mat || !fec) return null;
    const cand = porMatFecha.get(mat + '|' + fec);
    if (!cand) return null;
    const tnL = _factNum(L.tn);
    for (const r of cand) {
      if (r.db_id && idsAbonados.has(String(r.db_id))) continue; // ya usado por otra línea
      const tnR = _factNum(r.tm);
      if (!isNaN(tnL) && !isNaN(tnR) && Math.abs(tnL - tnR) <= 0.05) return r;
    }
    return null;
  };

  lineasTodas.forEach(L => {
    const numA = _factNormAlb(L.numero_albaran);
    let match = null;
    let porFallback = false;
    if (numA && porNum.has(numA)) {
      const cand = porNum.get(numA);
      // Si hay varios con el mismo número, preferimos el que más datos cuadre.
      match = cand[0];
    }
    // v107FP — si no cuadró por número exacto, probamos por la COLA COMPARTIDA con los
    // albaranes viejos (formato "77469/242043"). Así los de antes del arreglo del nº M
    // también cuadran sin volver a subirlos.
    if (!match) {
      match = _matchColaVieja(numA);
    }
    // J22 — último intento: por matrícula + fecha + TN (rescata números mal leídos).
    if (!match) {
      match = _matchPorMFT(L);
      if (match) porFallback = true;
    }
    if (match) {
      // Comprobar diferencias en los datos de apoyo (nota corta).
      const difs = [];
      if (porFallback) {
        // Cruzó por matrícula+fecha+TN: el número de albarán no coincide (mal leído).
        difs.push('Nº de albarán NO coincide — tú: ' + (match.albaran || '—') + ' / CEMEX: ' + (L.numero_albaran || '—') + ' (revisa/corrige tu número)');
      } else {
        const matL = _factNormMat(L.matricula);
        const matR = _factNormMat(match.tractora);
        if (matL && matR && matL !== matR) difs.push('matrícula (tú: ' + (match.tractora || '—') + ' / CEMEX: ' + (L.matricula || '—') + ')');

        const tnL = _factNum(L.tn);
        const tnR = _factNum(match.tm);
        if (!isNaN(tnL) && !isNaN(tnR) && Math.abs(tnL - tnR) > 0.05) difs.push('TN (tú: ' + (match.tm || '—') + ' / CEMEX: ' + (L.tn || '—') + ')');

        const fL = normFecha(L.fecha);
        const fR = normFecha(match.fecha);
        if (fL && fR && fL !== fR) difs.push('fecha (tú: ' + (match.fecha || '—') + ' / CEMEX: ' + (L.fecha || '—') + ')');

        if (!_factDestinoIgual(L.destino, match.obra || match.destino)) difs.push('destino (tú: ' + (match.obra || match.destino || '—') + ' / CEMEX: ' + (L.destino || '—') + ')');
      }

      abonados.push({ linea: L, rec: match, difs: difs });
      if (match.db_id) idsAbonados.add(String(match.db_id));
    } else {
      sinAlbaran.push(L);
    }
  });

  // NO ABONADOS: albaranes del usuario que NO han salido en la autofactura.
  // Solo tiene sentido comparar con los de CEMEX. Como aquí no sabemos el
  // cliente de cada albarán con seguridad, mostramos como "no abonados" los
  // que NO se han cruzado pero cuyo número TIENE pinta de CEMEX (empieza por M
  // y es largo). Así no marcamos como "no abonado" un albarán de Holcim.
  // v107FL — limitar el aviso "NO ABONADOS" al/los MES(ES) de ESTA preliquidación.
  // Una autofactura CEMEX es mensual, así que solo tiene sentido avisar de albaranes
  // CEMEX tuyos del MISMO mes. Si subes la de abril, NO debe avisarte de los de mayo.
  const _factMes = (s) => {
    const f = normFecha(s); // DD/MM/YYYY
    const m = f.match(/^\d{1,2}\/(\d{2}\/\d{4})$/);
    return m ? m[1] : ''; // devuelve "MM/YYYY"
  };
  const mesesAuto = new Set();
  lineasTodas.forEach(L => { const mm = _factMes(L.fecha); if (mm) mesesAuto.add(mm); });

  const noAbonados = [];
  records.forEach(r => {
    if (r.db_id && idsAbonados.has(String(r.db_id))) return; // ya abonado en ESTA autofactura
    // J20: si ya está marcado como facturado por una autofactura ANTERIOR (otra empresa
    // u otra subida del mismo día), NO es un "no abonado". Esto evita que al subir la
    // autofactura de TYP2014 reaparezcan como "no abonados" los de Hispalis ya pagados.
    if (r.estado_facturacion === 'facturado') return;
    const n = _factNormAlb(r.albaran);
    if (!/^M\d{6,}$/.test(n)) return; // solo albaranes con pinta de CEMEX (empiezan por M)
    // Si sabemos el/los mes(es) de la autofactura, solo avisamos de los albaranes de ESE mes.
    // (Si por lo que sea no pudimos sacar el mes de un albarán, lo mostramos igual, por seguridad.)
    if (mesesAuto.size > 0) {
      const mr = _factMes(r.fecha);
      if (mr && !mesesAuto.has(mr)) return; // es de otro mes → no avisar
    }
    noAbonados.push(r);
  });

  _factAutoUltimo = { abonados, noAbonados, sinAlbaran, ajustes: _factAutoAjustesAcum, fichero: _factMesBonito(_factMesActual) + ' — ' + _factAutoFicheros.join('  +  '), fecha: new Date() };

  // Marcar los abonados como facturados (en memoria + Supabase en 2º plano).
  let marcados = 0;
  for (const a of abonados) {
    const r = a.rec;
    if (r.db_id && r.estado_facturacion !== 'facturado') {
      r.estado_facturacion = 'facturado';
      r.factura_fecha = new Date().toISOString();
      marcados++;
      // pintar icono si la fila está visible
      const celda = document.querySelector(`td[data-fact="${r.db_id}"]`) || document.querySelector(`td[data-fact="${r._id}"]`);
      if (celda) celda.innerHTML = `${rowBadge(r)} ${factIcon(r)}`;
      // guardar en 2º plano
      sb.from('albaranes').update({ estado_facturacion: 'facturado', factura_fecha: r.factura_fecha }).eq('id', r.db_id)
        .then(({ error }) => { if (error) console.warn('[v107FI] guardar facturado:', error); });
    }
  }

  setEstado('✅ Listo. ' + _factMesBonito(_factMesActual) + ': ' + abonados.length + ' abonados, ' + noAbonados.length + ' no abonados, ' + sinAlbaran.length + ' que no tenemos.');
  _factAutoMostrarInforme();
  toast(_factMesBonito(_factMesActual) + ': ' + abonados.length + ' abonados, ' + noAbonados.length + ' no abonados, ' + sinAlbaran.length + ' que no tenemos', 'ok');
}

// J21: vaciar el acumulado de autofacturas (para empezar un mes nuevo sin refrescar).
// NO toca los albaranes ni el punto verde ya guardado: solo olvida las líneas leídas
// de los PDF de autofactura de esta sesión.
function factAutoVaciar() {
  if (!_factAutoLineasAcum.length && !_factAutoFicheros.length) {
    toast('No hay autofacturas acumuladas', 'ok');
    return;
  }
  if (!confirm('¿Vaciar las autofacturas subidas y empezar de cero?\n\nEsto NO borra los puntos verdes ni tus albaranes: solo olvida las líneas leídas de los PDF para empezar un mes nuevo.')) return;
  _factAutoLineasAcum = [];
  _factAutoFicheros = [];
  _factAutoAjustesAcum = [];
  _factAutoUltimo = null;
  document.getElementById('ovFactAuto').classList.remove('open');
  const estado = document.getElementById('factAutoEstado');
  if (estado) { estado.style.display = 'none'; estado.innerHTML = ''; }
  toast('Listo, empezamos de cero. Sube las autofacturas del mes.', 'ok');
}

// --- Render del informe en el modal ---
function _factAutoMostrarInforme() {
  const u = _factAutoUltimo;
  if (!u) return;
  const body = document.getElementById('factAutoBody');
  const tit = document.getElementById('factAutoTitulo');
  if (tit) tit.textContent = 'AUTOFACTURA CEMEX — ' + (u.fichero || '');

  const esc = (s) => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

  // Bloque ABONADOS
  let h = '';
  h += _factBloqueArchivos(_factAutoArchivos, esc);
  h += '<div style="margin-bottom:18px">';
  h += '<div style="font-weight:700;color:var(--ok);margin-bottom:8px">🟢 ABONADOS (' + u.abonados.length + ')</div>';
  if (!u.abonados.length) {
    h += '<div style="font-size:12px;color:var(--mu)">Ninguno.</div>';
  } else {
    h += '<div style="font-size:12px;line-height:1.6">';
    u.abonados.forEach(a => {
      const nota = a.difs.length ? ' <span style="color:#e0a000">✅ Coincide todo menos ' + a.difs.map(esc).join(' y ') + '</span>' : '';
      h += '<div style="padding:4px 0;border-bottom:1px solid var(--bd)">'
        + esc(a.linea.numero_albaran) + ' · ' + esc(a.linea.matricula) + ' · ' + esc(a.linea.fecha)
        + ' · ' + esc(a.linea.tn) + ' TN · ' + esc(a.linea.importe) + '€' + nota + '</div>';
    });
    h += '</div>';
  }
  h += '</div>';

  // Bloque NO ABONADOS
  h += '<div style="margin-bottom:18px">';
  h += '<div style="font-weight:700;color:#e0a000;margin-bottom:8px">⚠️ NO ABONADOS (' + u.noAbonados.length + ')</div>';
  h += '<div style="font-size:11px;color:var(--mu);margin-bottom:6px">Albaranes tuyos (tipo CEMEX) que NO aparecen en esta autofactura. Revísalos: puede que falten, se paguen otro mes, o estén en otra autofactura que aún no hayas subido.</div>';
  if (!u.noAbonados.length) {
    h += '<div style="font-size:12px;color:var(--mu)">Ninguno.</div>';
  } else {
    h += '<div style="font-size:12px;line-height:1.6">';
    u.noAbonados.forEach(r => {
      h += '<div style="padding:4px 0;border-bottom:1px solid var(--bd)">'
        + esc(r.albaran) + ' · ' + esc(r.tractora) + ' · ' + esc(r.fecha)
        + ' · ' + esc(r.tm) + ' TN · ' + esc(r.obra || r.destino || '') + '</div>';
    });
    h += '</div>';
  }
  h += '</div>';

  // Bloque ABONADOS SIN ALBARÁN
  h += '<div style="margin-bottom:6px">';
  h += '<div style="font-weight:700;color:#7cc4ff;margin-bottom:8px">📋 ABONADOS QUE NO TENEMOS (' + u.sinAlbaran.length + ')</div>';
  h += '<div style="font-size:11px;color:var(--mu);margin-bottom:6px">CEMEX paga estas líneas pero no tienes el albarán en la app. Solo para que las veas (también salen en el Excel).</div>';
  if (!u.sinAlbaran.length) {
    h += '<div style="font-size:12px;color:var(--mu)">Ninguno.</div>';
  } else {
    h += '<div style="font-size:12px;line-height:1.6">';
    u.sinAlbaran.forEach(L => {
      h += '<div style="padding:4px 0;border-bottom:1px solid var(--bd)">'
        + esc(L.numero_albaran) + ' · ' + esc(L.matricula) + ' · ' + esc(L.fecha)
        + ' · ' + esc(L.tn) + ' TN · ' + esc(L.importe) + '€</div>';
    });
    h += '</div>';
  }
  h += '</div>';

  // J23: Bloque AJUSTES (cobros extra a tu favor: sábados/festivos, repercusión gasoil…)
  const ajustes = u.ajustes || [];
  let totalAj = 0;
  ajustes.forEach(L => { const n = _factNum(L.importe); if (!isNaN(n)) totalAj += n; });
  h += '<div style="margin-bottom:6px;margin-top:18px">';
  h += '<div style="font-weight:700;color:#b48be8;margin-bottom:8px">💶 AJUSTES (' + ajustes.length + ')'
    + (ajustes.length ? ' · Total: ' + (Math.round(totalAj * 100) / 100).toFixed(2) + '€' : '') + '</div>';
  h += '<div style="font-size:11px;color:var(--mu);margin-bottom:6px">Cobros extra que CEMEX te abona aparte de los viajes (mínimos por día, repercusión del gasoil, sábados/festivos…). Revísalos a mano para confirmar que están bien. También salen en el Excel.</div>';
  if (!ajustes.length) {
    h += '<div style="font-size:12px;color:var(--mu)">Ninguno.</div>';
  } else {
    h += '<div style="font-size:12px;line-height:1.6">';
    ajustes.forEach(L => {
      h += '<div style="padding:4px 0;border-bottom:1px solid var(--bd)">'
        + esc(L.matricula || '—') + ' · ' + esc(L.fecha || '') + ' · ' + esc(L.concepto || L.origen || '—')
        + ' · <strong>' + esc(L.importe) + '€</strong></div>';
    });
    h += '</div>';
  }
  h += '</div>';

  if (body) body.innerHTML = h;
  document.getElementById('ovFactAuto').classList.add('open');
}

// --- Excel resumen (3 hojas) ---
function factAutoExcel() {
  const u = _factAutoUltimo;
  if (!u) { toast('No hay datos que exportar', 'err'); return; }
  if (typeof XLSX === 'undefined') { toast('No se pudo cargar el generador de Excel', 'err'); return; }

  const wb = XLSX.utils.book_new();

  // Hoja 1: ABONADOS
  const aoaAb = [['Nº Albarán', 'Matrícula', 'Fecha', 'TN', 'Importe €', 'Origen', 'Destino', 'Observación']];
  u.abonados.forEach(a => {
    aoaAb.push([
      a.linea.numero_albaran || '', a.linea.matricula || '', a.linea.fecha || '',
      a.linea.tn || '', a.linea.importe || '', a.linea.origen || '', a.linea.destino || '',
      a.difs.length ? ('Coincide todo menos ' + a.difs.join(' y ')) : 'OK'
    ]);
  });
  XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(aoaAb), 'Abonados');

  // Hoja 2: NO ABONADOS
  const aoaNo = [['Nº Albarán', 'Matrícula', 'Fecha', 'TN', 'Origen', 'Destino']];
  u.noAbonados.forEach(r => {
    aoaNo.push([r.albaran || '', r.tractora || '', r.fecha || '', r.tm || '', r.planta || r.origen || '', r.obra || r.destino || '']);
  });
  XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(aoaNo), 'No abonados');

  // Hoja 3: ABONADOS SIN ALBARÁN
  const aoaSin = [['Nº Albarán', 'Matrícula', 'Fecha', 'TN', 'Importe €', 'Origen', 'Destino']];
  u.sinAlbaran.forEach(L => {
    aoaSin.push([L.numero_albaran || '', L.matricula || '', L.fecha || '', L.tn || '', L.importe || '', L.origen || '', L.destino || '']);
  });
  XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(aoaSin), 'Sin copia');

  // Hoja 4 (J23): AJUSTES
  const aoaAj = [['Matrícula', 'Fecha', 'Concepto', 'Importe €', 'SCD']];
  let totAj = 0;
  (u.ajustes || []).forEach(L => {
    aoaAj.push([L.matricula || '', L.fecha || '', L.concepto || L.origen || '', L.importe || '', L.scd || '']);
    const n = _factNum(L.importe); if (!isNaN(n)) totAj += n;
  });
  aoaAj.push(['', '', 'TOTAL', Math.round(totAj * 100) / 100, '']);
  XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(aoaAj), 'Ajustes');

  const nombre = 'Autofactura_CEMEX_' + new Date().toISOString().slice(0, 10) + '.xlsx';
  XLSX.writeFile(wb, nombre);
  toast('Excel descargado', 'ok');
}
// ============================================================
// v107GA — AUTOFACTURA HOLCIM (solo admin). Mismo patrón que CEMEX.
// Cruce doble: (1) por nº de albarán (Num. Entrega) para cemento/áridos/
// clinker/palets; (2) por fecha+matrícula+TN para materias primas (yeso,
// caliza) cuyo Num. Entrega no coincide con el nº guardado en la app.
// ============================================================
let _factHolcimUltimo = null;

async function callClaudeAutofacturaHolcim(b64, key, signal) {
  const prompt = 'Eres un OCR experto en LIQUIDACIONES / AUTOFACTURAS que HOLCIM ESPAÑA emite a sus transportistas (cabecera con logo "HOLCIM", "Holcim España, S.A.U.", "Referencia 33106943XX", "Periodo: DD.MM.YYYY-DD.MM.YYYY"). Holcim paga al transportista por cada porte. Es un PDF de varias páginas con una tabla de portes.\n\n'
    + 'Devuelve SIEMPRE un ARRAY JSON, un objeto por CADA línea de porte que tenga un "Num. Entrega".\n\n'
    + 'Las columnas de la tabla, en orden, son: Fecha de entrega | Num. Entrega | Matrícula | Nombre Proveedor/Cliente | Dirección | Zona | Material de servicio | Cta. | UoM | Precio neto | Mond | Extracoste | Valor neto.\n\n'
    + 'De cada línea saca:\n'
    + '- num_entrega: el valor de la columna "Num. Entrega" TAL CUAL, sin espacios. Es el dato MÁS importante (es el nº de albarán). Varios formatos posibles: 11 dígitos que empiezan por 31041/31042/31048 (cemento, áridos, clinker); 8 dígitos que empiezan por 55 o 56 (devolución de palets); formato semana tipo "16W2026-0000172"; o 10 dígitos que empiezan por 0 (materias primas). Cópialo entero, sin tocar.\n'
    + '- fecha: la "Fecha de entrega" en formato DD/MM/YYYY (en el PDF viene como DD.MM.YYYY, conviértela con barras).\n'
    + '- matricula: SOLO la matrícula TRACTORA, que es la que va ANTES de la "/" (ej. en "0755KMB / R8205BDG" la tractora es "0755KMB"). La de después empieza por "R" y es el REMOLQUE: NO la cojas. Sin espacios.\n'
    + '- material: el texto de "Material de servicio" (ej. "CEM II/A-L 42,5 R GRANEL", "AF-0/4-T-C", "PALET CEMENTO", "YESO", "Caliza Foj", "CLINKER").\n'
    + '- destino: el texto de la columna "Nombre Proveedor/Cliente" (o "Nombre Proveedor") de esa línea, TAL CUAL, que indica el destino/cliente del porte (ej. "La Roca", "Planta Hormigones Zona Franca", "Montcada (Hormig)", "CLINKER - GRAO DE CASTELLON", "Molienda Tarragona", "PROMOTORA MEDITERRANEA 2 S A", "SABADELL"). Es importante para separar después por destino (áridos a La Roca / Zona Franca / Montcada) y por tipo (clinker de Castellón / Tarragona). Si no se ve, null.\n'
    + '- tn: el valor de la columna "Cta." (cantidad), con punto decimal (ej 30.040). En las líneas de PALET es negativo (ej -10): cópialo igual.\n'
    + '- valor_neto: el valor de la última columna "Valor neto" en euros, con punto decimal (ej 160.78).\n'
    + '- transportista: el nombre de la fila de cabecera "Transportista :" que manda sobre ese bloque (ej "TRANSPORTES Y PORTES 2014", "TRANSPORTES HISPALIS 2016", "TRANSMARGAZ 2018"). Repítelo en cada línea de su bloque hasta que aparezca otra cabecera "Transportista :".\n\n'
    + 'REGLAS IMPORTANTES:\n'
    + '- Recorre TODAS las páginas y TODAS las líneas con Num. Entrega. Puede haber cientos. No te dejes ninguna.\n'
    + '- IGNORA por completo (NO las incluyas) las filas "Fin de semana" (no tienen Num. Entrega, su UoM es "UP", son un recargo). IGNORA también cabeceras, subtítulos, "Página X / Y", "Referencia", "Periodo", "Lafarge CEM Planta", direcciones de empresa y pies de página.\n'
    + '- Una misma matrícula encabeza un bloque y debajo van varias líneas: cada línea es un objeto, todas con esa matrícula hasta que cambie.\n'
    + '- 🔴 MUY IMPORTANTE (páginas SIN cabecera de columnas): cuando cambia de transportista (aparece otra fila "Transportista :") o simplemente al pasar de página, la tabla MUCHAS VECES continúa SIN volver a imprimir la fila de títulos de columna (Fecha | Num. Entrega | Matrícula | ... | Cta. | ...). Esas filas SON LÍNEAS DE PORTE VÁLIDAS y NO debes saltártelas: el orden de las columnas es SIEMPRE el mismo aunque no se vea la cabecera. Lee esas filas EXACTAMENTE igual que las de una página con cabecera (fecha, num_entrega, matrícula tractora antes de la "/", material, Cta. como tn, Valor neto). NO ignores una fila solo porque encima no tenga títulos de columna. Procesa TODAS las filas que tengan una fecha + Num. Entrega + matrícula, estén donde estén, en cualquier página, con o sin cabecera y bajo cualquier "Transportista :".\n'
    + '- NO te inventes números ni matrículas. Si un dato no se ve, ponlo null (pero num_entrega y matricula deben verse).\n'
    + '- 🔴 NO TE DEJES NINGUNA FILA: es PREFERIBLE que repitas una línea de más a que te dejes una sin leer. Si dudas si una fila ya la has puesto, ponla igualmente. Lo importante es que NO falte ninguna.\n'
    + '- 🔴 TOTAL DE CONTROL: si en ESTE PDF ves la fila final de totales (textos como "Total transporte", "Subtotal por PO" o "NNN Envíos"), añade al final del array UN objeto especial: {"_control": true, "envios": NÚMERO_DE_ENVÍOS, "total_tn": TONELADAS_TOTALES}. Ejemplo: si pone "7.257,270 T ... 245 Envíos" añade {"_control":true,"envios":245,"total_tn":7257.270}. Si en este PDF NO aparece esa fila de totales, NO añadas el objeto de control.\n\n'
    + 'SOLO JSON válido (array), sin markdown ni explicaciones.';

  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'x-api-key': key, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true' },
    body: JSON.stringify({
      model: 'claude-haiku-4-5',
      max_tokens: 32000,
      messages: [{ role: 'user', content: [
        { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: b64 } },
        { type: 'text', text: prompt }
      ] }]
    }),
    signal: signal
  });
  if (!res.ok) {
    let e = {}; try { e = await res.json(); } catch (_) {}
    const err = new Error(e.error?.message || `HTTP ${res.status}`);
    err.status = res.status;
    throw err;
  }
  const d = await res.json();
  const text = d.content.map(x => x.text || '').join('').trim().replace(/```json|```/g, '').trim();
  let parsed;
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    // v107GA: si el PDF es muy largo, la respuesta puede venir cortada → recuperar el
    // array hasta el último objeto completo en vez de fallar del todo.
    const lastObj = text.lastIndexOf('}');
    if (lastObj > -1) {
      let t2 = text.slice(0, lastObj + 1);
      if (!t2.trim().startsWith('[')) t2 = '[' + t2;
      parsed = JSON.parse(t2 + ']');
      console.warn('[v107GA] respuesta de Holcim recuperada parcialmente (PDF largo).');
    } else { throw e; }
  }
  return Array.isArray(parsed) ? parsed : [parsed];
}

async function factSubirAutofacturaHolcim(files) {
  const file = files && files[0];
  const inp = document.getElementById('factHolcimFileInput');
  if (inp) inp.value = '';
  if (!file) return;
  // v107GA — candado: SOLO admin.
  if (currentRole !== 'admin') { toast('La autofactura de Holcim es solo para admin', 'err'); return; }

  const key = getKey();
  if (!key) { toast('Falta la clave de IA (API key)', 'err'); return; }

  const estado = document.getElementById('factHolcimEstado');
  const setEstado = (html) => { if (estado) { estado.style.display = 'block'; estado.innerHTML = html; } };

  // J31: si esta liquidación YA está subida (mismo nombre), no la leas otra vez.
  const _fich = (file && file.name) || '';
  if (_fich) {
    const ya = await _factYaSubida(_fich, 'HOLCIM');
    if (ya > 0 && !confirm('Esta liquidación de Holcim ya la tienes subida:\n"' + _fich + '" (' + ya + ' líneas).\n\n¿Volver a leerla de todas formas?')) {
      setEstado('✅ No la he vuelto a leer: ya estaba subida (' + ya + ' líneas). Pulsa 📅 para revisar el mes.');
      return;
    }
  }

  setEstado('⏳ Leyendo la autofactura de Holcim… (puede tardar si tiene muchas páginas)');

  let lineas;
  try {
    lineas = await _leerAutofacturaGrande(file, key, callClaudeAutofacturaHolcim, setEstado);
  } catch (e) {
    setEstado('❌ No se pudo leer la autofactura: ' + (e.message || e));
    return;
  }
  if (!lineas || !lineas.length) {
    setEstado('⚠️ No he encontrado líneas de porte. ¿Seguro que es una liquidación de Holcim?');
    return;
  }
  // J34: avisar si alguna parte del PDF no se pudo leer (tras reintentos).
  if (window._factPartesFallidas && window._factPartesFallidas.length) {
    toast('⚠️ No pude leer la(s) parte(s) ' + window._factPartesFallidas.join(', ') + ' de esta liquidación. Vuelve a subirla para completarla.', 'err');
  }

  // v107J37: comprobar contra el TOTAL declarado en el PDF ("NNN Envíos").
  // Lo importante es NO dejarse líneas. Si leemos MENOS que el total, avisar fuerte.
  const _ctrl = window._factControl;
  if (_ctrl && _ctrl.envios) {
    const leidas = lineas.length;
    const declaradas = parseInt(_ctrl.envios, 10);
    if (!isNaN(declaradas) && declaradas > 0) {
      if (leidas < declaradas) {
        const faltan = declaradas - leidas;
        toast('⚠️ ATENCIÓN: el PDF dice ' + declaradas + ' envíos y solo he leído ' + leidas + '. FALTAN ' + faltan + ' líneas. Vuelve a subirla para que las lea todas.', 'err');
      } else {
        toast('✅ Leídas ' + leidas + ' líneas (el PDF declara ' + declaradas + ' envíos). No falta ninguna.', 'ok');
      }
    }
  }

  // J27: guardar PERMANENTE por mes (proveedor HOLCIM) y conciliar el mes entero.
  // v107J42: el "destino/cliente" de cada línea (La Roca, Zona Franca, Montcada, Molienda
  // Tarragona, Grao Castellón…) se guarda en la columna `origen` (que estaba libre/null),
  // porque `destino` ya se usa para el transportista. Sirve para el repaso por destino.
  const lineasGen = lineas.map(L => ({
    numero_albaran: L.num_entrega || null, fecha: L.fecha || null, matricula: L.matricula || null,
    origen: L.destino || null, destino: L.transportista || null, tn: L.tn, importe: L.valor_neto, scd: null,
    es_ajuste: false, concepto: L.material || null
  }));
  const mesDoc = _factMesDeLineas(lineas) || _factMesDeFichero(file && file.name) || 'sin-mes';
  setEstado('⏳ Guardando la liquidación de Holcim de ' + _factMesBonito(mesDoc) + '…');
  const urlPdf = await _factSubirPdf(file, 'HOLCIM', mesDoc);
  try {
    await _factGuardarEnTabla(lineasGen, mesDoc, (file && file.name) || ('holcim_' + Date.now()), 'HOLCIM', urlPdf);
  } catch (e) { setEstado('❌ No se pudo guardar: ' + (e.message || e)); return; }
  factCargarMesesHolcim();
  await factConciliarMesHolcim(mesDoc);
}

// J27: cruza las líneas de Holcim acumuladas (de la tabla, por mes) con tus albaranes y
// muestra el informe. Lo usan la subida de una liquidación Y el botón "Revisar mes".
function _factProcesarYMostrarHolcim(setEstado) {
  setEstado = setEstado || function () {};
  const lineas = _factHolcimLineasAcum;

  // --- CRUCE ---
  const porNum = new Map();
  records.forEach(r => {
    const n = _factNormAlb(r.albaran);
    if (n) { if (!porNum.has(n)) porNum.set(n, []); porNum.get(n).push(r); }
  });

  const abonados = [];   // v107GB: cuadran por nº de albarán → se marcan facturados
  const posibles = [];   // v107GB: cuadran por fecha+matrícula+TN → revisar y confirmar a mano
  const sinAlbaran = [];
  const idsMatched = new Set(); // abonados + posibles (para no marcarlos "no abonados")
  const usados = new Set();

  // v107GC — clasificación de cada línea de Holcim en 3 destinos:
  //   ABONADOS (verde solo): cuadra por nº de albarán, O materia prima con fecha+matrícula+TN EXACTAS.
  //   A REVISAR (uno a uno) : materia prima que NO cuadra del todo pero se parece (misma matrícula y TN
  //                           pero la fecha baila pocos días; o misma fecha pero TN distinta).
  //   SIN COPIA             : Holcim lo paga pero no tenemos ningún albarán parecido.
  const _diasEntre = (a, b) => {
    const p = s => { const m = String(s).match(/^(\d{2})\/(\d{2})\/(\d{4})$/); return m ? new Date(+m[3], +m[2] - 1, +m[1]) : null; };
    const da = p(a), db = p(b); if (!da || !db) return 999;
    return Math.abs(Math.round((da - db) / 86400000));
  };
  const TOL_TN = 0.05;   // margen mínimo de redondeo en toneladas
  const VENT_DIAS = 10;  // ventana de fecha para "a revisar" (Holcim arrastra portes días después)

  // v107J65 — CRUCE según reglas de Juan Carlos (08/06/2026), SIN emparejados "por parecido":
  //   • Áridos / cemento / clinker / palets → POR Nº DE ALBARÁN. Si el nº coincide, se comprueba
  //     matrícula + TN + FECHA: todo OK → ABONADO 🟢; nº OK pero falla algo → A REVISAR ⚠️.
  //   • Caliza / arena / yeso / arcilla / limonita (no llevan nº de Holcim) → matrícula + FECHA + TN
  //     exactas (fecha obligatoria). Si no cuadra → SIN COPIA 📋. Nunca se inventa por "parecido".
  lineas.forEach(L => {
    const numA = _factNormAlb(L.num_entrega);
    // v107J76 — corrige matrícula mal leída (ej. "9295LIZ"→"9295JJZ") antes de cruzar, encajándola con la
    // conocida por los 4 dígitos. Arregla en caliente las autofacturas ya guardadas con la matrícula mal.
    const matL = _factNormMat(_corregirMatAutof(L.matricula));
    if (!numA && !matL) return; // fila basura (ej. "Fin de semana")

    const fL = normFecha(L.fecha);
    const tnL = Math.abs(_factNum(L.tn));
    // v107J65 — ¿es materia prima? (caliza/arena/yeso/arcilla/limonita). Esas NO llevan el nº de Holcim,
    // así que se cruzan por matrícula+fecha+TN. El resto (áridos, cemento, clinker, palets) por número.
    const matUp = String(L.material || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
    const esMateriaPrima = /CALIZA|ARENA|YESO|ARCILLA|LIMONITA/.test(matUp);

    // 1) POR Nº DE ALBARÁN (cemento, áridos, clinker, palets) → ABONADO directo (el número manda).
    if (numA && porNum.has(numA)) {
      const cand = porNum.get(numA);
      const match = cand.find(c => !usados.has(String(c.db_id))) || cand[0];
      const difs = [];
      const matR = _factNormMat(match.tractora);
      if (matL && matR && matL !== matR) difs.push('matrícula (tú: ' + (match.tractora || '—') + ' / Holcim: ' + (L.matricula || '—') + ')');
      const tnR = _factNum(match.tm);
      if (!isNaN(tnL) && !isNaN(tnR) && Math.abs(tnL - tnR) > TOL_TN) difs.push('TN (tú: ' + (match.tm || '—') + ' / Holcim: ' + (L.tn || '—') + ')');
      const fR = normFecha(match.fecha);
      if (fL && fR && fL !== fR) difs.push('fecha (tú: ' + (match.fecha || '—') + ' / Holcim: ' + (L.fecha || '—') + ')');
      // v107J70/J71 — Reglas por familia cuando el Nº DE ALBARÁN ya coincide. La familia se decide por
      // NUESTRO material (match.producto), que es fiable; el material de la línea de Holcim no sirve porque
      // a la escoria la llama "Transporte de Residuos Sólidos" y al reciclado lo factura como servicio.
      //   • ADEC / escoria → nº + TN (matrícula y fecha bailan: Holcim usa su camión 7874LCM y su fecha).
      //   • Tecnocatalana / árido reciclado → SOLO Nº. Holcim paga POR VIAJE (importe fijo) y nosotros
      //     ponemos TN = 1 a propósito, así que la TN NUNCA coincide → no se mira ni TN ni matrícula ni fecha.
      //   • Resto (clinker/áridos/cemento) → las tres: nº + TN + fecha + matrícula.
      const _famR = _factFamiliaHolcim(match.producto, match.obra || match.destino || '');
      const esAdec = (_famR === 'Escorias / Adec');
      const esTecno = (_famR === 'Árido reciclado / Tecnocatalana');
      // v107J74 — Núcleo Garraf → Puerto: Holcim lo factura con SU camión fijo (0658HLF) y SU fecha de
      // liquidación, igual que la escoria de ADEC. Se cobra por TN → nº + TN basta; matrícula/fecha bailan.
      const esGarrafPuerto = (_famR === 'Núcleo Garraf → Puerto Barcelona');
      let difsBloquean;
      if (esTecno) difsBloquean = [];                                  // Tecnocatalana: solo nº
      else if (esAdec || esGarrafPuerto) difsBloquean = difs.filter(d => d.indexOf('TN') === 0); // ADEC / Garraf→Puerto: nº + TN
      else difsBloquean = difs;                                        // resto: nº + TN + fecha + matrícula
      if (difsBloquean.length === 0) {
        abonados.push({ linea: L, rec: match, difs: [], modo: esTecno ? 'nº (Tecno)' : ((esAdec || esGarrafPuerto) ? 'nº + TN' : 'nº albarán') });
      } else {
        // v107J65 — el nº coincide pero falla matrícula, TN o fecha → A REVISAR (no se da por bueno solo).
        posibles.push({ linea: L, rec: match, difs: difs, modo: 'nº albarán (revisar)' });
      }
      if (match.db_id) { idsMatched.add(String(match.db_id)); usados.add(String(match.db_id)); }
      return;
    }

    // 2) MATERIA PRIMA (caliza/arena/yeso/arcilla/limonita) → matrícula + FECHA + TN, las tres EXACTAS.
    // La fecha es OBLIGATORIA: si hay 2 viajes del mismo camión con la misma TN, la fecha los distingue.
    if (esMateriaPrima && matL) {
      // v107J75 — La FECHA puede bailar hasta 2 días en arena/materia prima (mismo viaje; Holcim a veces
      // pone la fecha de la liquidación, no la del día real — confirmado por Juan Carlos). Antes se exigía
      // EXACTA y generaba mucho "sin copia"/"no abonado" del mismo viaje. Seguimos exigiendo matrícula y TN
      // exactas (±0,05 T); solo la fecha tiene margen de ±2 días, ni uno más (para no reabrir falsos
      // positivos). La fecha exacta SIEMPRE gana: solo se usa el margen si no hay coincidencia el mismo día.
      const _diaNum = (s) => { const f = normFecha(s); const m = f.match(/^(\d{1,2})\/(\d{2})\/(\d{4})$/); return m ? new Date(parseInt(m[3],10), parseInt(m[2],10)-1, parseInt(m[1],10)).getTime() : null; };
      const tL = _diaNum(L.fecha);
      const cands = records.filter(r => !usados.has(String(r.db_id)) && _factNormMat(r.tractora) === matL && !_albNoEsParaHolcim(r));
      let exacto = null, mejorScore = Infinity, exDias = 0;
      for (const r of cands) {
        const d = Math.abs(_factNum(r.tm) - tnL);
        if (isNaN(d) || d > TOL_TN) continue;               // TN al céntimo (obligatoria)
        const tR = _diaNum(r.fecha);
        let diasDif;
        if (tL !== null && tR !== null) diasDif = Math.round(Math.abs(tL - tR) / 86400000);
        else { if (normFecha(r.fecha) !== fL) continue; diasDif = 0; } // sin fecha medible → exige exacta
        if (diasDif > 2) continue;                          // ventana ±2 días, ni uno más
        const score = diasDif * 1000 + d;                   // fecha más cercana primero, luego TN más cercana
        if (score < mejorScore) { exacto = r; mejorScore = score; exDias = diasDif; }
      }
      if (exacto) {
        abonados.push({ linea: L, rec: exacto, difs: [], modo: exDias === 0 ? 'fecha+matrícula+TN' : ('matrícula+TN (fecha ±' + exDias + 'd)') });
        idsMatched.add(String(exacto.db_id)); usados.add(String(exacto.db_id));
        return;
      }
    }

    // 3) Nada cuadra → Holcim lo paga pero no tenemos el albarán. NO se inventa por "parecido".
    sinAlbaran.push(L);
  });

  // NO ABONADOS: albaranes nuestros con pinta de Holcim, del periodo, no abonados.
  const _factMes = (s) => { const f = normFecha(s); const m = f.match(/^\d{1,2}\/(\d{2}\/\d{4})$/); return m ? m[1] : ''; };
  // v107J49 — VENTANA: del DÍA 20 DEL MES ANTERIOR al DÍA 5 DEL MES SIGUIENTE. Decisión JC:
  // la liquidación Holcim de un mes arranca hacia el 20-25 del mes anterior y cierra a primeros
  // del siguiente (no el 30/31). Con esta ventana se cubren todos los casos (calizas, áridos,
  // servicios). Lo que pague de más un mes, el siguiente ya lo verá en verde (abonado) y no
  // molesta. Los abonados se quedan abonados; aquí solo se decide qué se avisa como "no abonado".
  const _ventanaHolcim = (() => {
    const m = String(_factHolcimMesActual || '').match(/^(\d{4})-(\d{2})$/);
    if (!m) return null;
    const anio = parseInt(m[1], 10), mes = parseInt(m[2], 10);
    const desde = new Date(anio, mes - 2, 20); // día 20 del mes ANTERIOR (mes-1 en 1-based → mes-2 en 0-based)
    const hasta = new Date(anio, mes, 5);       // día 5 del mes SIGUIENTE
    return { desde, hasta };
  })();
  const _fechaEnVentana = (fechaStr) => {
    if (!_ventanaHolcim) return true;
    const f = normFecha(fechaStr); const mm = f.match(/^(\d{1,2})\/(\d{2})\/(\d{4})$/);
    if (!mm) return false;
    const d = new Date(parseInt(mm[3], 10), parseInt(mm[2], 10) - 1, parseInt(mm[1], 10));
    return d >= _ventanaHolcim.desde && d <= _ventanaHolcim.hasta;
  };

  const noAbonados = [];
  records.forEach(r => {
    if (r.db_id && idsMatched.has(String(r.db_id))) return;
    if (r.estado_facturacion === 'facturado') return; // J20: ya facturado por otra autofactura anterior
    // v107J54/J57 — Promsa y CEMEX áridos NO son Holcim (tienen su propia facturación) → FUERA del
    //   repaso. Señales: proveedor Promsa/Cemex (o nº Ref-CemexGo "M…") + material árido, o destino
    //   "Zona Franca II" (planta de Promsa). NO afecta a "Caliza Promsa"/"Caliza Cemex" (materia prima
    //   "CALIZA …", no entra en _esArido). La lista de Promsa se saca en su apartado propio (Promotora).
    {
      const _provU = String(r.proveedor || '').toUpperCase();
      const _albU = String(r.albaran || '').toUpperCase().replace(/\s/g, '');
      const _matU = String(r.producto || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
      const _destU = String(r.obra || r.destino || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
      const _esPromsa = /PROMOTORA\s+MEDITERR|PROMSA|MOLINS/.test(_provU);
      const _esCemex = /CEMEX/.test(_provU) || /^M\d{8,}$/.test(_albU);
      const _esArido = /^AF[-\s]|^AG[-\s]|ARIDO/.test(_matU) || /^A[FG]\d/.test(_matU);
      if (((_esPromsa || _esCemex) && _esArido) || /ZONA\s*FRANCA\s*II/.test(_destU)) return;
    }
    const n = _factNormAlb(r.albaran);
    // v107J46: un albarán es "Holcim" para el repaso si CUALQUIERA de estas cosas:
    //   (a) su nº empieza por 3104, (b) proveedor/cliente HOLCIM/LAFARGE, o
    //   (c) su MATERIAL es uno de los que paga Holcim (familia ≠ Otros), aunque el
    //   proveedor de origen sea otro (Guixos Canals yeso, Promotora Promsa…).
    const _famR = _factFamiliaHolcim(r.producto, r.obra || r.destino || '');
    const pareceHolcim = /^3104\d{7}$/.test(n)
      || /HOLCIM|LAFARGE/.test(String(r.proveedor || r.cliente || '').toUpperCase())
      || (_famR && _famR !== 'Otros');
    if (!pareceHolcim) return;
    // v107J48: solo dentro de la ventana de fechas precisa (no mes entero).
    if (!_fechaEnVentana(r.fecha)) return;
    noAbonados.push(r);
  });

  _factHolcimUltimo = { abonados, posibles, noAbonados, sinAlbaran, fichero: _factMesBonito(_factHolcimMesActual) + ' — ' + _factHolcimFicheros.join('  +  '), fecha: new Date() };
  window._factHolcimMatSel = null; // v107J40: empezar siempre mostrando TODOS los materiales
  window._factExcelMarcadas = new Set(); // v107J50: empezar sin familias marcadas para el Excel

  // Marcar abonados como facturados (memoria + Supabase en 2º plano).
  for (const a of abonados) {
    const r = a.rec;
    if (r.db_id && r.estado_facturacion !== 'facturado') {
      r.estado_facturacion = 'facturado';
      r.factura_fecha = new Date().toISOString();
      const celda = document.querySelector(`td[data-fact="${r.db_id}"]`);
      if (celda) celda.innerHTML = `${rowBadge(r)} ${factIcon(r)}`;
      sb.from('albaranes').update({ estado_facturacion: 'facturado', factura_fecha: r.factura_fecha }).eq('id', r.db_id)
        .then(({ error }) => { if (error) console.warn('[v107GA] guardar facturado:', error); });
    }
  }

  setEstado('✅ Listo. ' + _factMesBonito(_factHolcimMesActual) + ' (Holcim): ' + abonados.length + ' abonados · ' + posibles.length + ' a revisar · ' + noAbonados.length + ' no abonados · ' + sinAlbaran.length + ' sin copia.');
  _factHolcimMostrarInforme();
  toast('Holcim ' + _factMesBonito(_factHolcimMesActual) + ': ' + abonados.length + ' abonados · ' + posibles.length + ' a revisar · ' + noAbonados.length + ' no abonados · ' + sinAlbaran.length + ' sin copia', 'ok');
}

// v107J44 — FAMILIAS DE REPASO HOLCIM. Clasifica cada línea (material + destino) en una
// familia, para agrupar el repaso como lo hace Juan Carlos. El material viene canonizado
// (concepto/material) y el destino del campo `origen` (lo lee J42: La Roca, Zona Franca,
// Montcada, Molienda Tarragona, CLINKER - GRAO DE CASTELLON, NUCLEO GARRAF A PUERTO…).
function _factFamiliaHolcim(material, destino) {
  const m = String(material || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const d = String(destino || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  // 1) Núcleo Garraf → Puerto (obra temporal, familia propia). Se separa por destino.
  // v107J74 — clasificar por el DESTINO (Puerto de Barcelona / Núcleo Garraf), valga el material que
  // valga. Holcim lo factura como "Servicios de Transporte", pero NUESTRO albarán (Sodira) lo trae como
  // árido "AG-…" → antes caía en "Otros" y no cuadraba con la línea de Holcim. Así ambos van a la misma
  // familia. (La Roca / Zona Franca / Montcada NO contienen "Puerto de Barcelona" → no se ven afectados.)
  if (/PUERTO\s+DE\s+BARCELONA|BARCELONA\s*S1|NUCLEO\s+GARRAF/.test(d)) return 'Núcleo Garraf → Puerto Barcelona';
  // v107J56 — Escoria/siderúrgico y árido reciclado son MATERIA PRIMA que entra en Fábrica Montcada.
  // Se clasifican ANTES que los áridos de Garraf, porque su nombre contiene "ÁRIDO" y antes se
  // colaban en "Áridos Garraf → Montcada" (el destino "Fábrica Montcada" contiene "Montcada").
  if (/SIDERURGICO|ESCORIA/.test(m)) return 'Escorias / Adec';
  // v107J68 — Holcim factura la escoria con material "Transporte de Residuos Sólidos" y destino
  // "ESCORIAS VALLIRANA …". Como nuestro albarán dice "árido siderúrgico" (→ Escorias/Adec) pero su
  // línea de Holcim no lleva esa palabra en el material, el abonado se iba a "Otros" en el Excel.
  // Si el DESTINO menciona ESCORIA, es la misma familia → así abonado y no-abonado caen en la misma hoja.
  if (/ESCORIA/.test(d)) return 'Escorias / Adec';
  if (/RECICLADO/.test(m)) return 'Árido reciclado / Tecnocatalana';
  // 2) Áridos de Cantera Garraf: SOLO AF-/AG- (el "árido siderúrgico/reciclado" ya se filtró arriba),
  // separados por destino. v107J56: "Fábrica Montcada" NO es "Montcada" (eso es recepción de materia
  // prima en la fábrica Holcim, no venta de áridos a Hormigones Montcada).
  if (/^AF[-\s]|^AG[-\s]/.test(m) || /^A[FG]\d/.test(m)) {
    if (/ROCA/.test(d)) return 'Áridos Garraf → La Roca';
    if (/ZONA\s*FRANCA/.test(d)) return 'Áridos Garraf → Zona Franca';
    if (/MONTCADA/.test(d) && !/FABRICA\s+MONTCADA/.test(d)) return 'Áridos Garraf → Montcada';
    return 'Otros';
  }
  // 3) Clinker: un solo botón (dentro del Excel se separa por tipo con la columna Material/Destino).
  if (/CLINKER/.test(m)) return 'Clinker';
  // 5) Cisternas + Cementos + Sacos + Palets + Élite → TODO JUNTO en una familia.
  if (/SERVICIOS?\s+DE\s+TRANSPORTE/.test(m)) return 'Cisternas / Sacos / Palets';
  if (/CEM\s|CEMENTO|ECOPLANET|PALET|ENSACADO|MORTERO|GRANEL/.test(m)) return 'Cisternas / Sacos / Palets';
  // 6) Materia prima (cada una su familia, por el material canónico).
  if (/CALIZA\s+PROMSA/.test(m)) return 'Caliza Promsa';
  if (/CALIZA\s+FOJ/.test(m)) return 'Caliza Foj';
  if (/CALIZA\s+CEMEX/.test(m)) return 'Caliza Cemex';
  if (/CALIZA\s+GARRAF|ZAHORRA/.test(m)) return 'Caliza Garraf Zahorra';
  if (/ARENA/.test(m)) return 'Arena Martorell';
  if (/ARCILLA/.test(m)) return 'Arcilla';
  if (/YESO/.test(m)) return 'Yeso';
  if (/LIMONITA/.test(m)) return 'Limonita';
  if (/ESCOMBRO/.test(m)) return 'Escombros';
  return 'Otros';
}

// v107J63/J64 — una línea de Holcim NO debe emparejarse con un albarán que es de OTRO proveedor.
// Antes el cruce por matrícula+TN cogía un albarán de CEMEX ("M…"), Sodira ("1/01718/…") o Àrids
// Garcia (gravetas) del mismo camión y lo metía en "a revisar". Regla robusta (no proveedor a proveedor):
// solo cruza si es de HOLCIM (proveedor o nº 3104…) o si es MATERIA PRIMA que Holcim paga aunque el
// proveedor sea un tercero (Caliza Cemex/Promsa/Foj, Arena, Arcilla, Yeso, Árido siderúrgico/reciclado…).
// El resto de áridos/gravetas de terceros (CEMEX, Sodira, Àrids Garcia, etc.) queda FUERA del cruce.
function _albNoEsParaHolcim(r) {
  const prov = String(r.proveedor || '').toUpperCase();
  if (/HOLCIM|LAFARGE/.test(prov)) return false;            // es de Holcim → cruza
  const albN = _factNormAlb(r.albaran);
  if (/^3104\d{7}$/.test(albN)) return false;               // nº de Holcim (3104…) → cruza
  const matU = String(r.producto || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  // Materia prima que Holcim paga aunque el proveedor de origen sea un tercero:
  if (/CALIZA|ARCILLA|YESO|ARENA|LIMONITA|ESCOMBRO|SIDERURGIC|ESCORIA|RECICLAD|TECNOCATALANA|ADEC/.test(matU)) return false;
  // El resto (áridos/gravetas de CEMEX, Sodira, Àrids Garcia, etc.) NO es de Holcim → fuera del cruce.
  return true;
}

function _factHolcimMostrarInforme() {
  const u = _factHolcimUltimo;
  if (!u) return;
  const body = document.getElementById('factHolcimBody');
  const tit = document.getElementById('factHolcimTitulo');
  if (tit) tit.textContent = 'AUTOFACTURA HOLCIM — ' + (u.fichero || '');
  const esc = (s) => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

  // v107J40: REPASO POR MATERIAL. Cada línea de Holcim trae su material (a.linea.material,
  // de la columna concepto); cada albarán nuestro su producto. Canonizamos con fixMaterial
  // para agrupar variantes. _factHolcimMatSel = material elegido (null = todos). Los botones
  // de arriba filtran las 4 listas a ese material; el Excel saca una pestaña por material.
  // v107J44: agrupar por FAMILIA (no por material suelto). La familia se calcula con
  // material + destino. El destino de la línea está en L.destino (lo leyó J42); el de
  // un albarán nuestro (no abonados) en r.obra/r.destino.
  const _famLinea = (L) => _factFamiliaHolcim(L.material, L.destino);
  const _famAlb = (r) => _factFamiliaHolcim(r.producto, r.obra || r.destino || '');
  // v107J71 — abonado/a-revisar se clasifica por NUESTRO albarán (a.rec), no por la línea de Holcim
  // (Holcim renombra escoria→"residuos" y reciclado→"servicio"). Así caen en su familia correcta.
  const _famPar = (a) => (a && a.rec ? _famAlb(a.rec) : _famLinea(a.linea));
  // Conjunto de familias presentes en el informe (de las 4 listas)
  const _setMat = new Set();
  (u.abonados || []).forEach(a => _setMat.add(_famPar(a)));
  (u.posibles || []).forEach(a => _setMat.add(_famPar(a)));
  (u.noAbonados || []).forEach(r => _setMat.add(_famAlb(r)));
  (u.sinAlbaran || []).forEach(L => _setMat.add(_famLinea(L)));
  // Orden lógico de familias (las que existan en este informe)
  const _ORDEN_FAM = [
    'Caliza Promsa', 'Caliza Foj', 'Caliza Cemex', 'Caliza Garraf Zahorra',
    'Arena Martorell', 'Arcilla', 'Yeso', 'Limonita', 'Escombros',
    'Áridos Garraf → La Roca', 'Áridos Garraf → Zona Franca', 'Áridos Garraf → Montcada',
    'Núcleo Garraf → Puerto Barcelona',
    'Cisternas / Sacos / Palets',
    'Clinker',
    'Escorias / Adec', 'Árido reciclado / Tecnocatalana', 'Otros'
  ];
  const _materiales = _ORDEN_FAM.filter(f => _setMat.has(f));
  const _sel = window._factHolcimMatSel || null;
  // Filtros que aplican la familia elegida (si no hay, pasan todo)
  const _fAb = (u.abonados || []).filter(a => !_sel || _famPar(a) === _sel);
  const _fPo = (u.posibles || []).filter(a => !_sel || _famPar(a) === _sel);
  const _fNo = (u.noAbonados || []).filter(r => !_sel || _famAlb(r) === _sel);
  const _fSin = (u.sinAlbaran || []).filter(L => !_sel || _famLinea(L) === _sel);

  let h = '';
  h += _factBloqueArchivos(_factHolcimArchivos, esc);

  // v107J44 — barra de botones por FAMILIA (repaso por familia/servicio)
  h += '<div style="margin-bottom:14px;padding:10px;background:var(--s2);border-radius:8px">';
  h += '<div style="font-size:11px;color:var(--mu);margin-bottom:6px">Repasar por familia (pincha para filtrar el informe):</div>';
  h += '<div style="display:flex;flex-wrap:wrap;gap:4px">';
  const _btnTodos = !_sel ? 'background:#2563eb;color:#fff' : 'background:#1f2333;color:#9fc6ff';
  h += '<button class="bm" onclick="_factHolcimFiltrarMaterial(null)" style="margin:2px;padding:4px 10px;font-size:11px;' + _btnTodos + ';border:1px solid #2f3a5a;border-radius:6px;cursor:pointer">TODOS</button>';
  _materiales.forEach(m => {
    const activo = _sel === m ? 'background:#2563eb;color:#fff' : 'background:#1f2333;color:#9fc6ff';
    h += '<button class="bm" onclick="_factHolcimFiltrarMaterial(this.dataset.m)" data-m="' + esc(m) + '" style="margin:2px;padding:4px 10px;font-size:11px;' + activo + ';border:1px solid #2f3a5a;border-radius:6px;cursor:pointer">' + esc(m) + '</button>';
  });
  h += '</div>';
  // v107J50 — SELECCIÓN MÚLTIPLE PARA EL EXCEL. Los botones de arriba filtran lo que VES
  // (de uno en uno). Aquí abajo, casillas para MARCAR varias familias y sacar el Excel de
  // las marcadas. Si no marcas ninguna → saca TODAS. window._factExcelMarcadas = Set.
  if (!window._factExcelMarcadas) window._factExcelMarcadas = new Set();
  h += '<div style="margin-top:10px;padding-top:8px;border-top:1px solid var(--bd)">';
  h += '<div style="font-size:11px;color:var(--mu);margin-bottom:6px">📊 Para el Excel: marca las familias que quieras (si no marcas ninguna, salen TODAS):</div>';
  h += '<div style="display:flex;flex-wrap:wrap;gap:8px;margin-bottom:8px">';
  _materiales.forEach(m => {
    const chk = window._factExcelMarcadas.has(m) ? 'checked' : '';
    h += '<label style="font-size:11px;color:#cfe;display:inline-flex;align-items:center;gap:3px;cursor:pointer">'
      + '<input type="checkbox" ' + chk + ' onchange="_factExcelToggle(this.dataset.m)" data-m="' + esc(m) + '" style="cursor:pointer">'
      + esc(m) + '</label>';
  });
  h += '</div>';
  h += '<button class="btn bs" onclick="factHolcimExcelPorMaterial()" style="font-size:11px">📊 DESCARGAR EXCEL</button>';
  h += '</div>';
  h += '</div>';

  h += '<div style="margin-bottom:18px">';
  h += '<div style="font-weight:700;color:var(--ok);margin-bottom:8px">🟢 ABONADOS (' + _fAb.length + ')</div>';
  if (!_fAb.length) { h += '<div style="font-size:12px;color:var(--mu)">Ninguno.</div>'; }
  else {
    h += '<div style="font-size:12px;line-height:1.6">';
    _fAb.forEach(a => {
      const nota = a.difs.length ? ' <span style="color:#e0a000">✅ Coincide todo menos ' + a.difs.map(esc).join(' y ') + '</span>' : '';
      const via = ' <span style="color:var(--mu);font-size:10px">[' + esc(a.modo) + ']</span>';
      h += '<div style="padding:4px 0;border-bottom:1px solid var(--bd)">'
        + esc(a.linea.num_entrega) + ' · ' + esc(a.linea.matricula) + ' · ' + esc(a.linea.fecha)
        + ' · ' + esc(a.linea.tn) + ' · ' + esc(a.linea.material || '') + ' · ' + esc(a.linea.valor_neto) + '€' + via + nota + '</div>';
    });
    h += '</div>';
  }
  h += '</div>';

  // v107GB — POSIBLES (cuadran por fecha+matrícula+TN, requieren confirmación a mano)
  h += '<div style="margin-bottom:18px">';
  h += '<div style="font-weight:700;color:#ff9d3b;margin-bottom:8px">⚠️ A REVISAR — UNO A UNO (' + _fPo.length + ')</div>';
  h += '<div style="font-size:11px;color:var(--mu);margin-bottom:6px">Solo los que NO cuadran del todo: misma matrícula y TN pero la fecha baila unos días, o misma fecha pero TN distinta (típico de las fotos de cantera subidas antes del papel oficial). Los que coinciden enteros ya están en Abonados. Debajo de cada línea de Holcim tienes TU albarán; pulsa Confirmar en los que veas bien.</div>';
  if (!_fPo.length) { h += '<div style="font-size:12px;color:var(--mu)">Ninguna.</div>'; }
  else {
    h += '<div style="font-size:12px;line-height:1.5">';
    _fPo.forEach((a) => {
      const i = (u.posibles || []).indexOf(a); // índice real para Confirmar
      const tuyo = 'Tu albarán: ' + esc(a.rec.albaran || '—') + ' · ' + esc(a.rec.tractora || '') + ' · ' + esc(a.rec.fecha || '') + ' · ' + esc(a.rec.tm || '') + ' TN';
      const btn = a.confirmado
        ? '<span style="color:var(--ok);font-weight:700;font-size:11px">✅ Confirmado</span>'
        : '<button class="btn bs" style="font-size:10px;padding:3px 9px" onclick="factHolcimConfirmar(' + i + ')">Confirmar</button>';
      h += '<div style="padding:7px 0;border-bottom:1px solid var(--bd);display:flex;justify-content:space-between;align-items:center;gap:10px">'
        + '<div>Holcim: ' + esc(a.linea.num_entrega) + ' · ' + esc(a.linea.matricula) + ' · ' + esc(a.linea.fecha) + ' · ' + esc(a.linea.tn) + ' · ' + esc(a.linea.material || '') + ' · ' + esc(a.linea.valor_neto) + '€'
        + '<br><span style="color:var(--mu);font-size:11px">' + tuyo + '</span></div>'
        + '<div style="flex-shrink:0">' + btn + '</div></div>';
    });
    h += '</div>';
  }
  h += '</div>';

  // Bloque NO ABONADOS
  h += '<div style="margin-bottom:18px">';
  h += '<div style="font-weight:700;color:#e0a000;margin-bottom:8px">⚠️ NO ABONADOS (' + _fNo.length + ')</div>';
  h += '<div style="font-size:11px;color:var(--mu);margin-bottom:6px">Albaranes tuyos tipo Holcim que NO aparecen en esta autofactura. Revísalos: puede que falten o se paguen en otra liquidación.</div>';
  if (!_fNo.length) { h += '<div style="font-size:12px;color:var(--mu)">Ninguno.</div>'; }
  else {
    h += '<div style="font-size:12px;line-height:1.6">';
    _fNo.forEach(r => {
      h += '<div style="padding:4px 0;border-bottom:1px solid var(--bd)">'
        + esc(r.albaran) + ' · ' + esc(r.tractora) + ' · ' + esc(r.fecha)
        + ' · ' + esc(r.tm) + ' TN · ' + esc(r.producto || '') + ' · ' + esc(r.obra || r.destino || '') + '</div>';
    });
    h += '</div>';
  }
  h += '</div>';

  h += '<div style="margin-bottom:6px">';
  h += '<div style="font-weight:700;color:#7cc4ff;margin-bottom:8px">📋 ABONADOS SIN COPIA DE ALBARÁN (' + _fSin.length + ')</div>';
  h += '<div style="font-size:11px;color:var(--mu);margin-bottom:6px">Holcim paga estas líneas pero no tienes el albarán en la app (el conductor lo perdió, no se subió…). Como Holcim no paga sin porte, seguro que existieron. También salen en el Excel.</div>';
  if (!_fSin.length) { h += '<div style="font-size:12px;color:var(--mu)">Ninguno.</div>'; }
  else {
    h += '<div style="font-size:12px;line-height:1.6">';
    _fSin.forEach(L => {
      h += '<div style="padding:4px 0;border-bottom:1px solid var(--bd)">'
        + esc(L.num_entrega) + ' · ' + esc(L.matricula) + ' · ' + esc(L.fecha)
        + ' · ' + esc(L.tn) + ' · ' + esc(L.material || '') + ' · ' + esc(L.valor_neto) + '€</div>';
    });
    h += '</div>';
  }
  h += '</div>';

  if (body) body.innerHTML = h;
  document.getElementById('ovFactHolcim').classList.add('open');
}

// v107J40 — cambia el material seleccionado y repinta el informe
function _factHolcimFiltrarMaterial(m) {
  window._factHolcimMatSel = m;
  _factHolcimMostrarInforme();
}

// v107J50 — marca/desmarca una familia para el Excel (no repinta todo, solo el Set).
function _factExcelToggle(m) {
  if (!window._factExcelMarcadas) window._factExcelMarcadas = new Set();
  if (window._factExcelMarcadas.has(m)) window._factExcelMarcadas.delete(m);
  else window._factExcelMarcadas.add(m);
}

// v107J40 — Excel con UNA PESTAÑA POR MATERIAL. Cada pestaña lleva las 4 secciones
// (Abonados / A revisar / No abonados / Sin copia) de ese material, una debajo de otra.
function factHolcimExcelPorMaterial() {
  const u = _factHolcimUltimo;
  if (!u) { toast('No hay datos que exportar', 'err'); return; }
  if (typeof XLSX === 'undefined') { toast('No se pudo cargar el generador de Excel', 'err'); return; }
  const _famLinea = (L) => _factFamiliaHolcim(L.material, L.destino);
  const _famAlb = (r) => _factFamiliaHolcim(r.producto, r.obra || r.destino || '');
  // v107J71 — abonado/a-revisar se clasifica por NUESTRO albarán (a.rec), no por la línea de Holcim.
  const _famPar = (a) => (a && a.rec ? _famAlb(a.rec) : _famLinea(a.linea));
  // Reunir todas las familias presentes
  const setM = new Set();
  (u.abonados || []).forEach(a => setM.add(_famPar(a)));
  (u.posibles || []).forEach(a => setM.add(_famPar(a)));
  (u.noAbonados || []).forEach(r => setM.add(_famAlb(r)));
  (u.sinAlbaran || []).forEach(L => setM.add(_famLinea(L)));
  const _ORDEN_FAM = [
    'Caliza Promsa', 'Caliza Foj', 'Caliza Cemex', 'Caliza Garraf Zahorra',
    'Arena Martorell', 'Arcilla', 'Yeso', 'Limonita', 'Escombros',
    'Áridos Garraf → La Roca', 'Áridos Garraf → Zona Franca', 'Áridos Garraf → Montcada',
    'Núcleo Garraf → Puerto Barcelona',
    'Cisternas / Sacos / Palets',
    'Clinker',
    'Escorias / Adec', 'Árido reciclado / Tecnocatalana', 'Otros'
  ];
  const materiales = _ORDEN_FAM.filter(f => setM.has(f));
  if (!materiales.length) { toast('No hay familias', 'err'); return; }
  // v107J47: si hay una familia FILTRADA (botón pinchado), el Excel saca SOLO esa
  // pestaña (lo que ves en pantalla es lo que sale). Si estás en TODOS, saca todas.
  // v107J50: el Excel usa las familias MARCADAS con las casillas. Si no hay ninguna
  // marcada → saca TODAS. (Antes usaba el filtro de "ver", ahora la selección múltiple.)
  const _marc = window._factExcelMarcadas && window._factExcelMarcadas.size ? window._factExcelMarcadas : null;
  const materialesFinal = _marc ? materiales.filter(f => _marc.has(f)) : materiales;
  if (!materialesFinal.length) { toast('No hay datos de las familias marcadas', 'err'); return; }

  const wb = XLSX.utils.book_new();
  // Nombre de pestaña válido para Excel (máx 31 chars, sin : \ / ? * [ ])
  const _hoja = (s) => String(s).replace(/[:\\/?*\[\]→]/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 31) || 'Familia';
  const usados = {};

  // v107J53 — ordenar cada sección del Excel por MATRÍCULA y luego por FECHA (como vienen los PDF de Holcim).
  const _matKey = (s) => String(s || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
  const _fechaKey = (f) => { const m = String(f || '').match(/(\d{1,2})\/(\d{1,2})\/(\d{2,4})/); if (!m) return '9999-99-99'; const y = m[3].length === 2 ? ('20' + m[3]) : m[3]; return y + '-' + m[2].padStart(2, '0') + '-' + m[1].padStart(2, '0'); };
  const _cmpMatFecha = (mA, fA, mB, fB) => { const A = _matKey(mA), B = _matKey(mB); if (A < B) return -1; if (A > B) return 1; const FA = _fechaKey(fA), FB = _fechaKey(fB); return FA < FB ? -1 : (FA > FB ? 1 : 0); };

  // v107J55 — diferenciar por TRANSPORTISTA: columna nueva + orden transportista → matrícula → fecha.
  // El transportista sale del albarán (abonados/a revisar/no abonados); en "Sin copia" (sin albarán)
  // se deduce de la matrícula con getTransportista(). Si no se sabe, va vacío y al final del orden.
  const _trAb = (a) => (a.rec && a.rec.transportista) || getTransportista(a.linea && a.linea.matricula) || '';
  const _trNo = (r) => r.transportista || getTransportista(r.tractora) || '';
  const _trSin = (L) => getTransportista(L.matricula) || '';
  const _transKey = (t) => String(t || '').toUpperCase().replace(/[^A-Z0-9]/g, '') || 'ZZZZ';
  const _cmpTMF = (tA, mA, fA, tB, mB, fB) => { const TA = _transKey(tA), TB = _transKey(tB); if (TA < TB) return -1; if (TA > TB) return 1; return _cmpMatFecha(mA, fA, mB, fB); };

  materialesFinal.forEach(mat => {
    const ab = (u.abonados || []).filter(a => _famPar(a) === mat);
    const po = (u.posibles || []).filter(a => _famPar(a) === mat);
    const no = (u.noAbonados || []).filter(r => _famAlb(r) === mat);
    const sin = (u.sinAlbaran || []).filter(L => _famLinea(L) === mat);
    // Orden: TRANSPORTISTA primero, luego matrícula, luego fecha (para diferenciar por transportista).
    ab.sort((x, y) => _cmpTMF(_trAb(x), x.linea.matricula, x.linea.fecha, _trAb(y), y.linea.matricula, y.linea.fecha));
    po.sort((x, y) => _cmpTMF(_trAb(x), x.linea.matricula, x.linea.fecha, _trAb(y), y.linea.matricula, y.linea.fecha));
    no.sort((x, y) => _cmpTMF(_trNo(x), x.tractora, x.fecha, _trNo(y), y.tractora, y.fecha));
    sin.sort((x, y) => _cmpTMF(_trSin(x), x.matricula, x.fecha, _trSin(y), y.matricula, y.fecha));
    const aoa = [];
    aoa.push(['FAMILIA: ' + mat]);
    aoa.push([]);
    aoa.push(['🟢 ABONADOS (' + ab.length + ')']);
    aoa.push(['Transportista', 'Nº Albarán', 'Matrícula', 'Fecha', 'TN', 'Material', 'Destino', 'Observación']);
    ab.forEach(a => aoa.push([_trAb(a), a.linea.num_entrega || '', a.linea.matricula || '', a.linea.fecha || '', a.linea.tn || '', a.linea.material || '', a.linea.destino || '', a.difs.length ? ('Coincide todo menos ' + a.difs.join(' y ')) : 'OK']));
    aoa.push([]);
    aoa.push(['⚠️ A REVISAR (' + po.length + ')']);
    aoa.push(['Transportista', 'Holcim Nº', 'Matrícula', 'Fecha', 'TN', 'Material', 'Destino', 'Tu albarán', 'Tu matrícula', 'Tu fecha', 'Tu TN']);
    po.forEach(a => aoa.push([_trAb(a), a.linea.num_entrega || '', a.linea.matricula || '', a.linea.fecha || '', a.linea.tn || '', a.linea.material || '', a.linea.destino || '', a.rec.albaran || '', a.rec.tractora || '', a.rec.fecha || '', a.rec.tm || '']));
    aoa.push([]);
    aoa.push(['⚠️ NO ABONADOS (' + no.length + ')']);
    aoa.push(['Transportista', 'Albarán', 'Matrícula', 'Fecha', 'TN', 'Material', 'Destino']);
    no.forEach(r => aoa.push([_trNo(r), r.albaran || '', r.tractora || '', r.fecha || '', r.tm || '', r.producto || '', r.obra || r.destino || '']));
    aoa.push([]);
    aoa.push(['📋 SIN COPIA (' + sin.length + ')']);
    aoa.push(['Transportista', 'Nº Albarán', 'Matrícula', 'Fecha', 'TN', 'Material', 'Destino']);
    sin.forEach(L => aoa.push([_trSin(L), L.num_entrega || '', L.matricula || '', L.fecha || '', L.tn || '', L.material || '', L.destino || '']));

    const ws = XLSX.utils.aoa_to_sheet(aoa);
    ws['!cols'] = [{wch:22},{wch:16},{wch:12},{wch:12},{wch:10},{wch:28},{wch:22},{wch:14},{wch:12},{wch:12},{wch:10}];
    let nombre = _hoja(mat);
    if (usados[nombre]) { usados[nombre]++; nombre = _hoja(mat).slice(0, 28) + '_' + usados[nombre]; } else { usados[nombre] = 1; }
    XLSX.utils.book_append_sheet(wb, ws, nombre);
  });

  const _nomFich = (materialesFinal.length === 1)
    ? ('Holcim_' + materialesFinal[0].replace(/[^A-Za-z0-9]+/g, '_').slice(0, 30))
    : 'Holcim_por_familia';
  XLSX.writeFile(wb, _nomFich + '_' + new Date().toISOString().slice(0, 10) + '.xlsx');
  toast('✓ Excel descargado (' + materialesFinal.length + (materialesFinal.length === 1 ? ' familia)' : ' familias)'), 'ok');
}

// v107GB — Confirmar una "posible" (la marca facturada en memoria + Supabase y refresca el modal).
function factHolcimConfirmar(i) {
  const u = _factHolcimUltimo;
  if (!u || !u.posibles || !u.posibles[i]) return;
  const it = u.posibles[i];
  if (it.confirmado) return;
  it.confirmado = true;
  const r = it.rec;
  if (r && r.db_id && r.estado_facturacion !== 'facturado') {
    r.estado_facturacion = 'facturado';
    r.factura_fecha = new Date().toISOString();
    const celda = document.querySelector(`td[data-fact="${r.db_id}"]`);
    if (celda) celda.innerHTML = `${rowBadge(r)} ${factIcon(r)}`;
    sb.from('albaranes').update({ estado_facturacion: 'facturado', factura_fecha: r.factura_fecha }).eq('id', r.db_id)
      .then(({ error }) => { if (error) console.warn('[v107GB] confirmar posible:', error); });
  }
  _factHolcimMostrarInforme(); // re-pinta: esa línea pasa a "✅ Confirmado"
  toast('Confirmado y marcado facturado', 'ok');
}

function factHolcimExcel() {
  const u = _factHolcimUltimo;
  if (!u) { toast('No hay datos que exportar', 'err'); return; }
  if (typeof XLSX === 'undefined') { toast('No se pudo cargar el generador de Excel', 'err'); return; }
  const wb = XLSX.utils.book_new();

  const aoaAb = [['Num. Entrega', 'Matrícula', 'Fecha', 'Cta/TN', 'Material', 'Valor neto €', 'Cruce', 'Transportista', 'Observación']];
  u.abonados.forEach(a => {
    aoaAb.push([
      a.linea.num_entrega || '', a.linea.matricula || '', a.linea.fecha || '',
      a.linea.tn || '', a.linea.material || '', a.linea.valor_neto || '', a.modo || '',
      a.linea.transportista || '',
      a.difs.length ? ('Coincide todo menos ' + a.difs.join(' y ')) : 'OK'
    ]);
  });
  XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(aoaAb), 'Abonados');

  // v107GB — hoja de POSIBLES (cuadran por fecha+matrícula+TN, pendientes de confirmar)
  const aoaPos = [['Num. Entrega Holcim', 'Matrícula', 'Fecha', 'Cta/TN', 'Material', 'Valor neto €', 'Tu albarán', 'Confirmado']];
  (u.posibles || []).forEach(a => {
    aoaPos.push([
      a.linea.num_entrega || '', a.linea.matricula || '', a.linea.fecha || '',
      a.linea.tn || '', a.linea.material || '', a.linea.valor_neto || '',
      (a.rec.albaran || '') + ' (' + (a.rec.fecha || '') + ' · ' + (a.rec.tm || '') + ' TN)',
      a.confirmado ? 'SÍ' : 'no'
    ]);
  });
  XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(aoaPos), 'A revisar');

  const aoaNo = [['Nº Albarán', 'Matrícula', 'Fecha', 'TN', 'Origen', 'Destino']];
  u.noAbonados.forEach(r => { aoaNo.push([r.albaran || '', r.tractora || '', r.fecha || '', r.tm || '', r.planta || r.origen || '', r.obra || r.destino || '']); });
  XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(aoaNo), 'No abonados');

  const aoaSin = [['Num. Entrega', 'Matrícula', 'Fecha', 'Cta/TN', 'Material', 'Valor neto €', 'Transportista']];
  u.sinAlbaran.forEach(L => { aoaSin.push([L.num_entrega || '', L.matricula || '', L.fecha || '', L.tn || '', L.material || '', L.valor_neto || '', L.transportista || '']); });
  XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(aoaSin), 'Sin copia');

  const nombre = 'Autofactura_HOLCIM_' + new Date().toISOString().slice(0, 10) + '.xlsx';
  XLSX.writeFile(wb, nombre);
  toast('Excel descargado', 'ok');
}


// Init
initApp();